

delimiter //;
CREATE OR REPLACE PACKAGE CTP_MX_PCKG_INIT AS
  type ref_cursor IS ref CURSOR;
  --rcuror ref_cursor;

  PROCEDURE proc_get_appinfo(appinfo OUT ref_cursor);

  PROCEDURE proc_get_servinfo(appname IN varchar2, servinfo OUT ref_cursor);
  --end proc_get_servinfo;

  PROCEDURE proc_get_monitor_switch(appname    IN varchar2,
                                    switchinfo OUT ref_cursor);
  --end proc_get_monitor_switch;

  PROCEDURE proc_get_useablity_info(checkers OUT ref_cursor);
  --end proc_get_useablity_info;

  PROCEDURE proc_get_trade_define(trades OUT ref_cursor);
  --end proc_get_trade_define;

  PROCEDURE proc_get_resource_define(resources OUT ref_cursor);
  --end proc_get_resource_define;
  PROCEDURE proc_get_trade_info(tradeRef OUT ref_cursor);

  PROCEDURE proc_get_resource_info(resourceRef OUT ref_cursor);
  PROCEDURE proc_get_arm_config(in_hostname in varchar2,armRef      OUT ref_cursor);
  
  PROCEDURE proc_get_staticsparma_valve(paramRef OUT ref_cursor);
  
  PROCEDURE proc_get_staticsparma_period(paramRef OUT ref_cursor);
END;
//
CREATE OR REPLACE PACKAGE BODY      CTP_MX_PCKG_INIT AS

  PROCEDURE proc_get_appinfo(appinfo OUT ref_cursor) AS
  BEGIN
    OPEN appinfo FOR
      SELECT appname_en, version, type FROM ctp_mx_app_info;
  END;

  PROCEDURE proc_get_servinfo(appname IN varchar2, servinfo OUT ref_cursor) AS
  BEGIN
    OPEN servinfo FOR
      SELECT a.ip ip, b.port port
        FROM ctp_mx_server_ip a, ctp_mx_server_port b
       WHERE a.hostname = b.hostname
         AND a.hostName = appname;
  END;

  --end proc_get_servinfo;

  PROCEDURE proc_get_monitor_switch(appname    IN varchar2,
                                    switchinfo OUT ref_cursor) AS
  BEGIN
    OPEN switchinfo FOR
      SELECT switchtype, channeltype, action
        FROM ctp_mx_monitor_flag
       WHERE hostname = appname
       ORDER BY hostname, switchtype;
  END;

  --end proc_get_monitor_switch;

  PROCEDURE proc_get_useablity_info(checkers OUT ref_cursor) AS
  BEGIN
    OPEN checkers FOR
      SELECT name, modulecode, submodulecode, checker, status, msg
        FROM ctp_mx_usability_info
       WHERE ismonitor = '1'
       ORDER BY name;
  END;

  --end proc_get_useablity_info;

  PROCEDURE proc_get_trade_define(trades OUT ref_cursor) AS
  BEGIN
    OPEN trades FOR
      SELECT b.eventCode  eventCode,
             b.eventName  eventName,
             a.eventlevel eventlevel,
             a.trancode   trancode,
             a.occurtime  occurtime
        FROM ctp_mx_trans_error_level a, ctp_mx_trans_error_info b
       WHERE a.eventCode = b.eventCode
         AND b.ismonitor = '1'
       ORDER BY eventCode, trancode, occurtime;
  END;

  PROCEDURE proc_get_resource_define(resources OUT ref_cursor) AS
  BEGIN
    OPEN resources FOR
      SELECT b.resourcecode,
             b.resourcerate,
             b.type,
             b.monitor,
             a.occurtime,
             a.eventlevel
        FROM ctp_mx_resource_level_define a, ctp_mx_resource_info b
       WHERE b.resourcecode = a.resourcecode
         AND b.ismonitor = '1'
       ORDER BY resourcecode, a.occurtime, a.eventlevel;
  END;

--end proc_get_trade_define;
  PROCEDURE proc_get_trade_info(tradeRef OUT ref_cursor) AS
  BEGIN
    OPEN tradeRef FOR
      SELECT eventCode, eventName FROM ctp_mx_trans_error_info where ismonitor = '1';
  END;

  PROCEDURE proc_get_resource_info(resourceRef OUT ref_cursor) AS
  BEGIN
    OPEN resourceRef FOR
      SELECT resourceCode, resourceName FROM ctp_mx_resource_info where ismonitor = '1';
  END;
  PROCEDURE proc_get_arm_config(in_hostname in varchar2,
                                armRef      OUT ref_cursor) AS
  BEGIN
    OPEN armRef FOR
      SELECT opname, paramtype, paramvalue
        FROM ctp_arm_config
       where hostname = in_hostname;
  END;
  
  PROCEDURE proc_get_staticsparma_valve(paramRef OUT ref_cursor) AS
  BEGIN
    OPEN paramRef FOR
      SELECT name, trancode, valve,begintime,endtime
        FROM ctp_mx_statistics_valve;
  END;
  
  PROCEDURE proc_get_staticsparma_period(paramRef OUT ref_cursor) AS
  BEGIN
    OPEN paramRef FOR
      SELECT name, period
        FROM ctp_mx_statistics_period;
  END;
END CTP_MX_PCKG_INIT;
//


CREATE OR REPLACE package CTP_MX_PCKG_STAT is



  TYPE r_peak_list IS RECORD(
    indextype ctp_mx_stat_peak_info.indextype%TYPE,
    peakvalue number);
  TYPE cur_peak_list IS REF CURSOR RETURN r_peak_list;

  TYPE r_avgop_time IS RECORD(
    opname  ctp_mx_stat_opavgtime_info.opname%TYPE,
    avgtime number);
  TYPE cur_avgop_time IS REF CURSOR RETURN r_avgop_time;
  --插入统计峰值
  procedure proc_update_peak_value(i_hostname  in varchar2,
                                   i_indextype in varchar2,
                                   i_peakvalue number);
  --查询统计峰值
  procedure proc_qry_peak_value(o_peak_list OUT cur_peak_list);
  --删除统计峰值
  procedure proc_del_peak_value;

  --查询统计交易平均时间
  procedure proc_qry_avgop_time(o_avgop_time OUT cur_avgop_time);
  --删除统计峰值
  procedure proc_del_avgop_time;
  procedure proc_update_monitor_flag(i_switchType  in varchar2,
                                     i_channelType in varchar2,
                                     i_action      in varchar2,
                                     i_modifyuser  in varchar2,
                                     i_hostname    in varchar2);
end CTP_MX_PCKG_STAT;
//

CREATE OR REPLACE package body CTP_MX_PCKG_STAT is

  --插入统计峰值
  procedure proc_update_peak_value(i_hostname  in varchar2,
                                   i_indextype in varchar2,
                                   i_peakvalue number) is
  begin
    insert into ctp_mx_stat_peak_info
      (hostname, indextype, peakvalue, statDate)
    values
      (i_hostname, i_indextype, i_peakvalue, sysdate);
    commit;
  end proc_update_peak_value;

  --查询统计峰值
  procedure proc_qry_peak_value(o_peak_list OUT cur_peak_list) is
  begin
    OPEN o_peak_list FOR
      select indextype,
             ceil(sum(peakvalue) / count(peakvalue)) as peakvalue
        from (select indextype, hostname, max(peakvalue) as peakvalue
                from ctp_mx_stat_peak_info
               where indextype is not null
               group by indextype, hostname)
       group by indextype;

  end proc_qry_peak_value;

  --删除统计峰值
  procedure proc_del_peak_value is
  begin
    delete from ctp_mx_stat_peak_info;
    commit;
  end proc_del_peak_value;

  --查询统计峰值
  procedure proc_qry_avgop_time(o_avgop_time OUT cur_avgop_time) is
  begin
    OPEN o_avgop_time FOR
      select opname, avgtime
        from (select opname, ceil(sum(opTime) / sum(opcount)) as avgtime
                from ctp_mx_stat_opavgtime_info
               group by opname
               order by avgtime desc)
       where rownum <= 10;

  end proc_qry_avgop_time;

  --删除统计峰值
  procedure proc_del_avgop_time is
  begin
    delete from ctp_mx_stat_opavgtime_info;
    commit;
  end proc_del_avgop_time;

  --更新监控开关

  procedure proc_update_monitor_flag(i_switchType  in varchar2,
                                     i_channelType in varchar2,
                                     i_action      in varchar2,
                                     i_modifyuser  in varchar2,
                                     i_hostname    in varchar2) is
  begin
    if i_switchtype = '0' then
      if i_channelType = '0' then
        update ctp_mx_monitor_flag
           set action     = i_action,
               modifyuser = i_modifyuser,
               midifydate = sysdate
         where hostname = i_hostname;
      else
        update ctp_mx_monitor_flag
           set action     = i_action,
               modifyuser = i_modifyuser,
               midifydate = sysdate
         where hostname = i_hostname
           and channelType = i_channelType;
      end if;
    else
      if i_channelType = '0' then
        update ctp_mx_monitor_flag
           set action     = i_action,
               modifyuser = i_modifyuser,
               midifydate = sysdate
         where hostname = i_hostname
           and switchType = i_switchType;
      else
        update ctp_mx_monitor_flag
           set action     = i_action,
               modifyuser = i_modifyuser,
               midifydate = sysdate
         where hostname = i_hostname
           and switchType = i_switchType
           and channelType = i_channelType;
      end if;
    end if;

    commit;
  end proc_update_monitor_flag;
end CTP_MX_PCKG_STAT;
//

CREATE OR REPLACE PACKAGE ctp_pckg_genlogonmenu IS



	TYPE rec_temp_sel IS RECORD(
		itemid ctp_menu.id%TYPE);

	TYPE ref_temp_sel IS REF CURSOR RETURN rec_temp_sel;

	TYPE rec_temp IS RECORD(
		id     ctp_user_menu_rel.menu_id%TYPE, --树节点
		parent ctp_user_menu_rel.menu_id%TYPE, --父节点
		pri    ctp_user_menu_rel.privilege%TYPE, --当前节点访问权限
		flag   VARCHAR2(2)); --功能、菜单标志，0功能，1菜单

	TYPE ref_temp IS REF CURSOR RETURN rec_temp;

	TYPE rec_menu IS RECORD(
		id     ctp_menu.id%TYPE, --菜单或功能项编号.
		lable  ctp_menu.default_label%TYPE, --菜单或功能项的文字标识.
		parent ctp_menu.id%TYPE,
		LEVEL  VARCHAR2(3), -- 节点的深度.
		flag   VARCHAR2(2), -- 功能、菜单标志，0功能，1菜单
		url    ctp_item.url%TYPE --指向链接。
		);

	TYPE ref_menu IS REF CURSOR RETURN rec_menu;

	PROCEDURE ctp_proc_genlogonmenu(i_userid        IN VARCHAR2, --用户
											  i_defaultroleid IN VARCHAR2, --角色
											  i_sessionid     IN VARCHAR2,
											  i_nettype       IN VARCHAR2,
											  i_fullpath      IN VARCHAR2,
											  i_flag          IN VARCHAR2, --0：生成菜单预览，1：生成登录菜单
											  o_retcode       OUT VARCHAR2,
											  o_menuxmlstr    OUT clob); --可展现功能集合

	PROCEDURE ctp_proc_genusablemenu(i_userid        IN VARCHAR2, --用户
												i_defaultroleid IN VARCHAR2, --角色
												o_retcode       OUT VARCHAR2,
												ret_menu        OUT ref_menu); --可展现功能集合

	FUNCTION ctp_func_getusableitem(i_userid        IN VARCHAR2, --用户
											  i_defaultroleid IN VARCHAR2) RETURN VARCHAR2; --可展现功能集合
END ctp_pckg_genlogonmenu;
//

CREATE OR REPLACE PACKAGE BODY ctp_pckg_genlogonmenu IS
   --可展现功能集合
   FUNCTION ctp_func_getusableitem (i_userid          IN VARCHAR2,        --用户
                                    i_defaultroleid   IN VARCHAR2)
      RETURN VARCHAR2
   IS
      o_retcode        VARCHAR2 (2);
      v_num            VARCHAR2 (3);
      v_branchid       ctp_branch.id%TYPE;
      v_branchlevel    ctp_branch.branch_level%TYPE;

      temp_item_typ    ref_temp;
      v_temp_save_id   ctp_user_menu_rel.menu_id%TYPE;
      v_temp_id        ctp_user_menu_rel.menu_id%TYPE;
      v_temp_parent    ctp_user_menu_rel.menu_id%TYPE;
      v_temp_pri       ctp_user_menu_rel.privilege%TYPE;
      v_temp_flag      VARCHAR2 (2);

      temp_menu_typ    ref_temp_sel;
      v_temp_menu_id   ctp_user_menu_rel.menu_id%TYPE;
   BEGIN
      o_retcode := '0';

      -- 取用户所属机构、用户机构级别
      SELECT b.id, b.branch_level
        INTO v_branchid, v_branchlevel
        FROM ctp_user a, ctp_branch b
       WHERE a.id = i_userid AND a.branch_id = b.id;

      -- 用户可使用的、启用的激活的功能
	  /*
      INSERT INTO ctp_temp_item_table (id)
         SELECT a.id
           FROM ctp_item a, ctp_user_item_rel b
          WHERE     a.status = '1'
                AND a.id = b.item_id
                AND b.user_id = i_userid
                AND b.privilege = '1'
                AND                                                 --启用的激活的功能
                    (   (    a.item_branch_id IS NOT NULL
                         AND v_branchid = a.item_branch_id)
                     OR (    a.item_level IS NOT NULL
                         AND SUBSTR (a.item_level, v_branchlevel * 1, 1) =
                                '1'));  
*/								--用户可使用的功能

      OPEN temp_menu_typ FOR
         SELECT a.id
           FROM ctp_item a, ctp_user_item_rel b
          WHERE     a.status = '1'
                AND a.id = b.item_id
                AND b.user_id = i_userid
                AND b.privilege = '1'
                AND                                                 --启用的激活的功能
                    (   (    a.item_branch_id IS NOT NULL
                         AND v_branchid = a.item_branch_id)
                     OR (    a.item_level IS NOT NULL
                         AND SUBSTR (a.item_level, v_branchlevel * 1, 1) =
                                '1'));                              --用户可使用的功能

      LOOP
         FETCH temp_menu_typ INTO v_temp_menu_id;

         EXIT WHEN temp_menu_typ%NOTFOUND;
      END LOOP;

      CLOSE temp_menu_typ;

      -- 用户可使用的，非启用禁用的、且其父菜单节点对于用户最终为启用的激活的功能
      -- 用户可使用的、非用户启用禁用的、且其所有父菜单节点对于用户最终非启用禁用、且对于角色启用或其所有父菜单节点对于角色最终为启用的激活的功能
      OPEN temp_item_typ FOR
             SELECT id,
                    parent,
                    pri,
                    flag                                          --得到功能菜单对应关系
               FROM (SELECT UNIQUE d.item_id id,
                                   d.menu_id parent,
                                   '-1' pri,
                                   '0' flag
                       FROM ctp_menu_item_rel d, ctp_item e
                      WHERE     (   (    e.item_branch_id IS NOT NULL
                                     AND e.item_branch_id = v_branchid)
                                 OR (    e.item_level IS NOT NULL
                                     AND SUBSTR (e.item_level,
                                                 v_branchlevel * 1,
                                                 1) = '1'))
                            AND                                     --用户可使用的功能
                                (   e.id NOT IN (SELECT item_id
                                                   FROM ctp_user_item_rel
                                                  WHERE user_id = i_userid)
                                 OR e.id IN
                                       (SELECT item_id
                                          FROM ctp_user_item_rel
                                         WHERE     user_id = i_userid
                                               AND privilege = '-1'))
                            AND                                   --非启用禁用状态的功能
                               e.id = d.item_id
                            AND e.status = '1'                        --功能菜单对应
                     UNION
                     SELECT m.id id,
                            m.parent_id parent,
                            n.privilege pri,
                            '1' flag                              --得到菜单菜单对应关系
                       FROM ctp_menu m, ctp_user_menu_rel n
                      WHERE     m.id IN (SELECT menu_id
                                           FROM ctp_user_menu_rel
                                          WHERE user_id = i_userid)
                            AND m.id = n.menu_id
                            AND n.user_id = i_userid
                     UNION
                     SELECT m.id id,
                            m.parent_id parent,
                            '-1' pri,
                            '1' flag
                       FROM ctp_menu m
                      WHERE m.id NOT IN (SELECT menu_id
                                           FROM ctp_user_menu_rel
                                          WHERE user_id = i_userid) --用户菜单表中没有设置的权限默认为-1可选
                                                                   )
              WHERE (pri != -1 OR flag = 0) ;               --只取得功能，以及权限不为可选的菜单
         

    

      v_temp_save_id := NULL;

      LOOP
         FETCH temp_item_typ
         INTO v_temp_id, v_temp_parent, v_temp_pri, v_temp_flag;

         EXIT WHEN temp_item_typ%NOTFOUND;

         IF (v_temp_flag = '1' AND v_temp_save_id IS NOT NULL)
         THEN
            IF (v_temp_pri = '1')
            THEN
               --此处得到的是用户可使用的、非用户启用禁用的、且其所有父菜单节点对于用户最终为启用的功能
			   /*
               INSERT INTO ctp_temp_item_table (id)
                    VALUES (v_temp_save_id);
					*/
					null;
            END IF;

            v_temp_save_id := NULL;
         END IF;

         IF (v_temp_flag = '0')
         THEN
            IF (v_temp_save_id IS NOT NULL)
            THEN
               --此处得到的是用户可使用的、非用户启用禁用的、且其所有父菜单节点对于用户最终非启用禁用的功能

               SELECT COUNT (*)
                 INTO v_num
                 FROM ctp_role_item_rel
                WHERE role_id = i_defaultroleid AND item_id = v_temp_save_id;

               IF (v_num > 0)
               THEN
                  SELECT privilege
                    INTO v_temp_pri
                    FROM ctp_role_item_rel
                   WHERE     role_id = i_defaultroleid
                         AND item_id = v_temp_save_id;
               ELSE
                  v_temp_pri := '-1';
               END IF;

               IF (v_temp_pri = 1)
               THEN
                  --该功能如果对角色而言是启用的，则启用
				  /*
                  INSERT INTO ctp_temp_item_table (id)
                       VALUES (v_temp_save_id);
					   */
				null;
               END IF;

               IF (v_temp_pri = -1)
               THEN
                  --该功能如果对角色而言是可选的，则看该功能的父菜单节点对于角色的权限
                  OPEN temp_menu_typ FOR                       --取得当前功能所属的菜单集合
                     SELECT menu_id
                       FROM ctp_menu_item_rel
                      WHERE item_id = v_temp_save_id;

                  LOOP
                     FETCH temp_menu_typ INTO v_temp_menu_id;

                     EXIT WHEN temp_menu_typ%NOTFOUND;

                     SELECT COUNT (*)
                       INTO v_num
                       FROM (    SELECT id, pri
                                   FROM (SELECT id id, parent_id parent, '-1' pri
                                           FROM ctp_menu
                                          WHERE id NOT IN
                                                   (SELECT menu_id
                                                      FROM ctp_role_menu_rel
                                                     WHERE role_id =
                                                              i_defaultroleid)
                                         UNION
                                         SELECT a.id id,
                                                parent_id parent,
                                                b.privilege pri
                                           FROM ctp_menu a, ctp_role_menu_rel b
                                          WHERE     b.role_id = i_defaultroleid
                                                AND a.id = b.menu_id)
                                  WHERE pri != -1
                             CONNECT BY PRIOR parent = id
                             START WITH id = v_temp_menu_id);

                     IF (v_num > 0)
                     THEN
                        SELECT pri                        --取得该功能的所有父菜单对于角色的权限
                          INTO v_temp_pri
                          FROM (    SELECT id, pri
                                      FROM (SELECT id id,
                                                   parent_id parent,
                                                   '-1' pri
                                              FROM ctp_menu
                                             WHERE id NOT IN
                                                      (SELECT menu_id
                                                         FROM ctp_role_menu_rel
                                                        WHERE role_id =
                                                                 i_defaultroleid)
                                            UNION
                                            SELECT a.id id,
                                                   parent_id parent,
                                                   b.privilege pri
                                              FROM ctp_menu a,
                                                   ctp_role_menu_rel b
                                             WHERE     b.role_id =
                                                          i_defaultroleid
                                                   AND a.id = b.menu_id)
                                     WHERE pri != -1
                                CONNECT BY PRIOR parent = id
                                START WITH id = v_temp_menu_id)
                         WHERE ROWNUM = 1;
                     END IF;

                     IF (v_temp_pri = 1)
                     THEN
					 /*
                        INSERT INTO ctp_temp_item_table (id)
                             VALUES (v_temp_save_id);
							 */
							 null;
                     END IF;
                  END LOOP;

                  CLOSE temp_menu_typ;
               END IF;
            END IF;

            v_temp_save_id := v_temp_id; --v_temp_save_id中存放上一个flag为0的id，v_temp_id接下来的id
         END IF;
      END LOOP;

      CLOSE temp_item_typ;

      -- 对cursor最后一条数据进行处理(方法同上)
      IF (v_temp_save_id IS NOT NULL)
      THEN
         --此处得到的是用户可使用的、非用户启用禁用的、且其所有父菜单节点对于用户最终非启用禁用的功能
         SELECT COUNT (*)
           INTO v_num
           FROM ctp_role_item_rel
          WHERE role_id = i_defaultroleid AND item_id = v_temp_save_id;

         IF (v_num > 0)
         THEN
            SELECT privilege
              INTO v_temp_pri
              FROM ctp_role_item_rel
             WHERE role_id = i_defaultroleid AND item_id = v_temp_save_id;
         ELSE
            v_temp_pri := '-1';
         END IF;

         IF (v_temp_pri = 1)
         THEN
            --该功能如果对角色而言是启用的，则启用
			/*
            INSERT INTO ctp_temp_item_table (id)
                 VALUES (v_temp_save_id);
				 */
				 null;
         END IF;

         IF (v_temp_pri = -1)
         THEN
            --该功能如果对角色而言是可选的，则看该功能的父菜单节点对于角色的权限
            OPEN temp_menu_typ FOR                             --取得当前功能所属的菜单集合
               SELECT menu_id
                 FROM ctp_menu_item_rel
                WHERE item_id = v_temp_save_id;

            LOOP
               FETCH temp_menu_typ INTO v_temp_menu_id;

               EXIT WHEN temp_menu_typ%NOTFOUND;

               SELECT COUNT (*)
                 INTO v_num
                 FROM (    SELECT id, pri
                             FROM (SELECT id id, parent_id parent, '-1' pri
                                     FROM ctp_menu
                                    WHERE id NOT IN
                                             (SELECT menu_id
                                                FROM ctp_role_menu_rel
                                               WHERE role_id = i_defaultroleid)
                                   UNION
                                   SELECT a.id id,
                                          parent_id parent,
                                          b.privilege pri
                                     FROM ctp_menu a, ctp_role_menu_rel b
                                    WHERE     b.role_id = i_defaultroleid
                                          AND a.id = b.menu_id)
                            WHERE pri != -1
                       CONNECT BY PRIOR parent = id
                       START WITH id = v_temp_menu_id);

               IF (v_num > 0)
               THEN
                  SELECT pri                              --取得该功能的所有父菜单对于角色的权限
                    INTO v_temp_pri
                    FROM (    SELECT id, pri
                                FROM (SELECT id id, parent_id parent, '-1' pri
                                        FROM ctp_menu
                                       WHERE id NOT IN
                                                (SELECT menu_id
                                                   FROM ctp_role_menu_rel
                                                  WHERE role_id = i_defaultroleid)
                                      UNION
                                      SELECT a.id id,
                                             parent_id parent,
                                             b.privilege pri
                                        FROM ctp_menu a, ctp_role_menu_rel b
                                       WHERE     b.role_id = i_defaultroleid
                                             AND a.id = b.menu_id)
                               WHERE pri != -1
                          CONNECT BY PRIOR parent = id
                          START WITH id = v_temp_menu_id)
                   WHERE ROWNUM = 1;
               END IF;

               IF (v_temp_pri = 1)
               THEN
			   /*
                  INSERT INTO ctp_temp_item_table (id)
                       VALUES (v_temp_save_id);
					   */
					   null;
               END IF;
            END LOOP;

            CLOSE temp_menu_typ;
         END IF;
      END IF;

      RETURN o_retcode;
   EXCEPTION
      WHEN OTHERS
      THEN
         o_retcode := '-1';
         RETURN o_retcode;
   END;

   PROCEDURE ctp_proc_genlogonmenu (i_userid          IN     VARCHAR2,
                                    i_defaultroleid   IN     VARCHAR2,
                                    i_sessionid       IN     VARCHAR2,
                                    i_nettype         IN     VARCHAR2,
                                    i_fullpath        IN     VARCHAR2,
                                    i_flag            IN     VARCHAR2,
                                    o_retcode            OUT VARCHAR2,
                                    o_menuxmlstr         OUT CLOB)
   IS
      v_num             VARCHAR2 (3);
      ret_menu          ref_menu;
      v_menu_id         ctp_menu.id%TYPE;
      v_default_lable   ctp_menu.default_label%TYPE;
      v_menu_parent     ctp_menu.id%TYPE;
      v_menu_level      VARCHAR2 (3);
      v_flag            VARCHAR2 (2);
      v_item_url        ctp_item.url%TYPE;
      v_save_level      VARCHAR2 (3);
      v_endstring       VARCHAR2 (5000);
   BEGIN
      o_retcode := '0';

      --查询用户是否有对应的角色，如果没有，则设置标志为1，重新生成菜单
      IF (i_defaultroleid IS NOT NULL)
      THEN
         SELECT menuchg_flag, menustr
           INTO v_num, o_menuxmlstr
           FROM ctp_role_user_rel
          WHERE user_id = i_userid AND role_id = i_defaultroleid;
      ELSE
         v_num := '1';
      END IF;

      IF (v_num IS NULL OR v_num = '1')
      THEN
         o_retcode :=
            ctp_func_getusableitem (i_userid          => i_userid,
                                    i_defaultroleid   => i_defaultroleid);

         IF (o_retcode != '0')
         THEN
            RETURN;
         END IF;

         --查询是否有可展示功能
         SELECT COUNT (*) INTO v_num FROM ctp_temp_item_table;

         IF (v_num > 0)
         THEN
            --查询该用户当前角色是否存在快捷菜单，若有，则将快捷菜单做为菜单加入
            IF (i_defaultroleid IS NOT NULL)
            THEN
               SELECT COUNT (*)
                 INTO v_num
                 FROM ctp_user_shortcut_menu a, ctp_item b
                WHERE     a.user_id = i_userid
                      AND a.role_id = i_defaultroleid
                      AND a.item_id = b.id
                      AND b.id IN (SELECT id FROM ctp_temp_item_table);
            ELSE
               SELECT COUNT (*)
                 INTO v_num
                 FROM ctp_user_shortcut_menu a, ctp_item b
                WHERE     a.user_id = i_userid
                      AND a.role_id IS NULL
                      AND a.item_id = b.id
                      AND b.id IN (SELECT id FROM ctp_temp_item_table);
            END IF;

            --根据先前所取得的当前用户角色可展现功能，生成菜单树排序
            IF (v_num = 0)
            THEN
               OPEN ret_menu FOR
                             SELECT id,
                                    default_label,
                                    parent_id,
                                    LEVEL,
                                    flag,
                                    url
                               FROM (    SELECT UNIQUE *
                                           FROM (SELECT a.item_id id,
                                                        b.default_label default_label,
                                                        a.menu_id parent_id,
                                                        a.serialno menu_order,
                                                        '0' flag,
                                                        b.url url
                                                   FROM ctp_menu_item_rel a, ctp_item b
                                                  WHERE     a.item_id = b.id
                                                        AND a.item_id IN
                                                               (SELECT UNIQUE id
                                                                  FROM ctp_temp_item_table)
                                                 UNION
                                                 SELECT c.id id,
                                                        c.default_label default_label,
                                                        c.parent_id parent_id,
                                                        c.serialno menu_order,
                                                        '1' flag,
                                                        '' url
                                                   FROM ctp_menu c)
                                     CONNECT BY PRIOR parent_id = id
                                     START WITH id IN
                                                   (SELECT UNIQUE id
                                                      FROM ctp_temp_item_table))
                         CONNECT BY PRIOR id = parent_id
                         START WITH parent_id IS NULL
                  ORDER SIBLINGS BY menu_order ASC;
            ELSE
               IF (i_defaultroleid IS NULL)
               THEN
                  OPEN ret_menu FOR
                                SELECT id,
                                       default_label,
                                       parent_id,
                                       LEVEL,
                                       flag,
                                       url
                                  FROM (    SELECT UNIQUE *
                                              FROM (SELECT a.item_id id,
                                                           b.default_label default_label,
                                                           a.menu_id parent_id,
                                                           a.serialno menu_order,
                                                           '0' flag,
                                                           b.url url
                                                      FROM ctp_menu_item_rel a, ctp_item b
                                                     WHERE     a.item_id = b.id
                                                           AND a.item_id IN
                                                                  (SELECT UNIQUE id
                                                                     FROM ctp_temp_item_table)
                                                    UNION
                                                    SELECT c.id id,
                                                           c.default_label default_label,
                                                           c.parent_id parent_id,
                                                           c.serialno menu_order,
                                                           '1' flag,
                                                           '' url
                                                      FROM ctp_menu c
                                                    UNION    --将快捷菜单作为菜单放入菜单树中
                                                    SELECT 'xxxxxx' id,
                                                           '快捷菜单' default_label,
                                                           a.id parent_id,
                                                           -1 menu_order,
                                                           '1' flag,
                                                           '' url
                                                      FROM ctp_menu a
                                                     WHERE a.parent_id IS NULL
                                                    UNION
                                                    SELECT b.id id,
                                                           b.default_label default_label,
                                                           'xxxxxx' parent_id,
                                                           0 menu_order,
                                                           '0' flag,
                                                           b.url url
                                                      FROM ctp_user_shortcut_menu a,
                                                           ctp_item b
                                                     WHERE     a.user_id = i_userid
                                                           AND a.role_id IS NULL
                                                           AND a.item_id = b.id
                                                           AND b.id IN
                                                                  (SELECT id
                                                                     FROM ctp_temp_item_table))
                                        CONNECT BY PRIOR parent_id = id
                                        START WITH id IN
                                                      (SELECT UNIQUE id
                                                         FROM ctp_temp_item_table))
                            CONNECT BY PRIOR id = parent_id
                            START WITH parent_id IS NULL
                     ORDER SIBLINGS BY menu_order ASC;
               ELSE
                  OPEN ret_menu FOR
                                SELECT id,
                                       default_label,
                                       parent_id,
                                       LEVEL,
                                       flag,
                                       url
                                  FROM (    SELECT UNIQUE *
                                              FROM (SELECT a.item_id id,
                                                           b.default_label default_label,
                                                           a.menu_id parent_id,
                                                           a.serialno menu_order,
                                                           '0' flag,
                                                           b.url url
                                                      FROM ctp_menu_item_rel a, ctp_item b
                                                     WHERE     a.item_id = b.id
                                                           AND a.item_id IN
                                                                  (SELECT UNIQUE id
                                                                     FROM ctp_temp_item_table)
                                                    UNION
                                                    SELECT c.id id,
                                                           c.default_label default_label,
                                                           c.parent_id parent_id,
                                                           c.serialno menu_order,
                                                           '1' flag,
                                                           '' url
                                                      FROM ctp_menu c
                                                    UNION    --将快捷菜单作为菜单放入菜单树中
                                                    SELECT 'xxxxxx' id,
                                                           '快捷菜单' default_label,
                                                           a.id parent_id,
                                                           -1 menu_order,
                                                           '1' flag,
                                                           '' url
                                                      FROM ctp_menu a
                                                     WHERE a.parent_id IS NULL
                                                    UNION
                                                    SELECT b.id id,
                                                           b.default_label default_label,
                                                           'xxxxxx' parent_id,
                                                           0 menu_order,
                                                           '0' flag,
                                                           b.url url
                                                      FROM ctp_user_shortcut_menu a,
                                                           ctp_item b
                                                     WHERE     a.user_id = i_userid
                                                           AND a.role_id = i_defaultroleid
                                                           AND a.item_id = b.id
                                                           AND b.id IN
                                                                  (SELECT id
                                                                     FROM ctp_temp_item_table))
                                        CONNECT BY PRIOR parent_id = id
                                        START WITH id IN
                                                      (SELECT UNIQUE id
                                                         FROM ctp_temp_item_table))
                            CONNECT BY PRIOR id = parent_id
                            START WITH parent_id IS NULL
                     ORDER SIBLINGS BY menu_order ASC;
               END IF;
            END IF;

            --根据已生成的菜单树cursor，逐条取出，生成XML string

            o_menuxmlstr := '';
            v_endstring := '';
            v_save_level := 0;

            LOOP
               FETCH ret_menu
               INTO v_menu_id,
                    v_default_lable,
                    v_menu_parent,
                    v_menu_level,
                    v_flag,
                    v_item_url;

               EXIT WHEN ret_menu%NOTFOUND;

               IF (v_menu_level = 1)
               THEN
                  o_menuxmlstr :=
                        o_menuxmlstr
                     || '<TOPICLIST TYPE="'
                     || v_default_lable
                     || '">';
                  v_endstring := '</TOPICLIST>';
                  v_save_level := v_menu_level;
               ELSE
                  IF (v_menu_level < v_save_level)
                  THEN
                     FOR v_num IN 1 .. (v_save_level - v_menu_level)
                     LOOP
                        o_menuxmlstr := o_menuxmlstr || '</TOPICS>';
                     END LOOP;
                  END IF;

                  v_save_level := v_menu_level;

                  IF (v_flag = 1)
                  THEN
                     o_menuxmlstr :=
                           o_menuxmlstr
                        || '<TOPICS TYPE="'
                        || v_default_lable
                        || '">';
                  ELSE
                     v_num := INSTR (v_item_url, '?');

                     IF v_num = 0
                     THEN
                        o_menuxmlstr :=
                              o_menuxmlstr
                           || '<TOPIC><TITLE>'
                           || v_default_lable
                           || '</TITLE><URL>'
                           || '/fullPath/'
                           || REPLACE (REPLACE (v_item_url, '&', '&amp;'),
                                       'operationName',
                                       'dse_operationName')
                           || '?dse_sessionId='
                           || '&amp;netType='
                           || '&amp;item_id='
                           || v_menu_id
                           || '</URL></TOPIC>';
                     ELSE
                        o_menuxmlstr :=
                              o_menuxmlstr
                           || '<TOPIC><TITLE>'
                           || v_default_lable
                           || '</TITLE><URL>'
                           || '/fullPath/'
                           || REPLACE (REPLACE (v_item_url, '&', '&amp;'),
                                       'operationName',
                                       'dse_operationName')
                           || '&amp;dse_sessionId='
                           || '&amp;netType='
                           || '&amp;request=&amp;response=&amp;_clear_flowdata=true'
                           || '&amp;item_id='
                           || v_menu_id
                           || '</URL></TOPIC>';
                     END IF;
                  END IF;
               END IF;
            END LOOP;

            IF (v_save_level > 1)
            THEN
               FOR v_num IN 1 .. (v_save_level - 2)
               LOOP
                  o_menuxmlstr := o_menuxmlstr || '</TOPICS>';
               END LOOP;
            END IF;

            o_menuxmlstr := o_menuxmlstr || v_endstring;
         ELSE
            --当没有可展示功能
            o_menuxmlstr :=
               '<TOPICLIST><TOPICS TYPE="对不起！没有可展现菜单！"></TOPICS></TOPICLIST>';
         END IF;

         o_menuxmlstr :=
               '<?xml:stylesheet type="text/xsl" href="'
            || '/fullPath/'
            || 'css/menu.xsl"?>'
            || o_menuxmlstr;

         o_menuxmlstr :=
            '<?xml version="1.0" encoding="gb2312"?>' || o_menuxmlstr;

         --更新标志，将生成菜单存放在数据库中
         UPDATE ctp_role_user_rel
            SET menuchg_flag = '0', menustr = o_menuxmlstr
          WHERE user_id = i_userid AND role_id = i_defaultroleid;
      END IF;

      --根据当前登录信息，对菜单XMLString进行转换拼接，生成最终登录菜单

      IF i_flag = 0
      THEN
         o_menuxmlstr := REPLACE (o_menuxmlstr, 'menu.xsl', 'menu4show.xsl');
      END IF;

      o_menuxmlstr := REPLACE (o_menuxmlstr, '/fullPath/', i_fullpath);
      o_menuxmlstr :=
         REPLACE (o_menuxmlstr,
                  'dse_sessionId=',
                  'dse_sessionId=' || i_sessionid);
      o_menuxmlstr :=
         REPLACE (o_menuxmlstr, 'netType=', 'netType=' || i_nettype);
   EXCEPTION
      WHEN OTHERS
      THEN
         o_retcode := '-1';

         RETURN;
   END;

   --生成快捷菜单定制菜单
   PROCEDURE ctp_proc_genusablemenu (i_userid          IN     VARCHAR2,
                                     i_defaultroleid   IN     VARCHAR2,
                                     o_retcode            OUT VARCHAR2,
                                     ret_menu             OUT ref_menu)
   IS
   BEGIN
      o_retcode := '0';

      o_retcode :=
         ctp_func_getusableitem (i_userid          => i_userid,
                                 i_defaultroleid   => i_defaultroleid);

      IF (o_retcode != '0')
      THEN
         RETURN;
      END IF;

      IF (i_defaultroleid IS NULL)
      THEN
         OPEN ret_menu FOR
                       SELECT id,
                              default_label,
                              parent_id,
                              LEVEL,
                              flag,
                              url
                         FROM (    SELECT UNIQUE *
                                     FROM (SELECT a.item_id id,
                                                  b.default_label default_label,
                                                  a.menu_id parent_id,
                                                  a.serialno menu_order,
                                                  '0' flag,
                                                  b.url url
                                             FROM ctp_menu_item_rel a, ctp_item b
                                            WHERE     a.item_id = b.id
                                                  AND a.item_id IN
                                                         (SELECT UNIQUE id
                                                            FROM ctp_temp_item_table)
                                                  AND a.item_id NOT IN
                                                         (SELECT item_id
                                                            FROM ctp_user_shortcut_menu
                                                           WHERE     user_id = i_userid
                                                                 AND role_id IS NULL)
                                           UNION
                                           SELECT a.item_id id,
                                                  b.default_label default_label,
                                                  a.menu_id parent_id,
                                                  a.serialno menu_order,
                                                  '-1' flag,
                                                  b.url url
                                             FROM ctp_menu_item_rel a, ctp_item b
                                            WHERE     a.item_id = b.id
                                                  AND a.item_id IN
                                                         (SELECT UNIQUE id
                                                            FROM ctp_temp_item_table)
                                                  AND a.item_id IN
                                                         (SELECT item_id
                                                            FROM ctp_user_shortcut_menu
                                                           WHERE     user_id = i_userid
                                                                 AND role_id IS NULL)
                                           UNION
                                           SELECT c.id id,
                                                  c.default_label default_label,
                                                  c.parent_id parent_id,
                                                  c.serialno menu_order,
                                                  '1' flag,
                                                  '' url
                                             FROM ctp_menu c)
                               CONNECT BY PRIOR parent_id = id
                               START WITH id IN
                                             (SELECT UNIQUE id FROM ctp_temp_item_table))
                   CONNECT BY PRIOR id = parent_id
                   START WITH parent_id IS NULL
            ORDER SIBLINGS BY menu_order ASC;
      ELSE
         OPEN ret_menu FOR
                       SELECT id,
                              default_label,
                              parent_id,
                              LEVEL,
                              flag,
                              url
                         FROM (    SELECT UNIQUE *
                                     FROM (SELECT a.item_id id,
                                                  b.default_label default_label,
                                                  a.menu_id parent_id,
                                                  a.serialno menu_order,
                                                  '0' flag,
                                                  b.url url
                                             FROM ctp_menu_item_rel a, ctp_item b
                                            WHERE     a.item_id = b.id
                                                  AND a.item_id IN
                                                         (SELECT UNIQUE id
                                                            FROM ctp_temp_item_table)
                                                  AND a.item_id NOT IN
                                                         (SELECT item_id
                                                            FROM ctp_user_shortcut_menu
                                                           WHERE     user_id = i_userid
                                                                 AND role_id =
                                                                        i_defaultroleid)
                                           UNION
                                           SELECT a.item_id id,
                                                  b.default_label default_label,
                                                  a.menu_id parent_id,
                                                  a.serialno menu_order,
                                                  '-1' flag,
                                                  b.url url
                                             FROM ctp_menu_item_rel a, ctp_item b
                                            WHERE     a.item_id = b.id
                                                  AND a.item_id IN
                                                         (SELECT UNIQUE id
                                                            FROM ctp_temp_item_table)
                                                  AND a.item_id IN
                                                         (SELECT item_id
                                                            FROM ctp_user_shortcut_menu
                                                           WHERE     user_id = i_userid
                                                                 AND role_id =
                                                                        i_defaultroleid)
                                           UNION
                                           SELECT c.id id,
                                                  c.default_label default_label,
                                                  c.parent_id parent_id,
                                                  c.serialno menu_order,
                                                  '1' flag,
                                                  '' url
                                             FROM ctp_menu c)
                               CONNECT BY PRIOR parent_id = id
                               START WITH id IN
                                             (SELECT UNIQUE id FROM ctp_temp_item_table))
                   CONNECT BY PRIOR id = parent_id
                   START WITH parent_id IS NULL
            ORDER SIBLINGS BY menu_order ASC;
      END IF;
   EXCEPTION
      WHEN OTHERS
      THEN
         o_retcode := '-1';
         RETURN;
   END;
END ctp_pckg_genlogonmenu;
//
CREATE OR REPLACE PACKAGE ctp_pckg_menumgmt IS

	-- Author  : LINGB
	-- Created : 2005-9-23 10:25:27
	-- Purpose : 本程序包提供菜单相关的处理功能.
	-- Public function and procedure declarations
	TYPE r_menu_list IS RECORD(
		menu_id        ctp_menu.id%TYPE, --1:Ctp_Menu.Id%Type, --菜单或功能项编号.
		menu_label     ctp_menu.default_label%TYPE, --2:Ctp_Menu.Default_Label%Type, --菜单或功能项的文字标识.
		menu_deep      VARCHAR2(2), --3:Ctp_Menu.Menu_Level%Type, -- 节点的深度.
		menu_parent_id ctp_menu.parent_id%TYPE, --4:Ctp_Menu.Parent_Id%Type, --父节点编号.
		menu_order     ctp_menu.serialno%TYPE, --5:Ctp_Menu.Serialno%Type, -- 显式序号
		menu_type      CHAR(1), -- 6:M表示菜单,I表示是功能项.
		menu_url       ctp_item.url%TYPE --7Ctp_Item.Url%Type --指向链接。
		);
	TYPE c_menu_list IS REF CURSOR RETURN r_menu_list;
	TYPE t_table IS TABLE OF VARCHAR2(100) INDEX BY BINARY_INTEGER;

	PROCEDURE ctp_proc_get_menu_list(o_retcode   OUT VARCHAR2,
												o_menu_list OUT c_menu_list);
	PROCEDURE ctp_proc_del_menu_node(i_menu_id     IN VARCHAR2,
												i_del_mode    IN VARCHAR2,
												o_retcod      OUT VARCHAR2,
												o_result_info OUT VARCHAR2);
	PROCEDURE log(proc_name IN VARCHAR2,
					  info      IN VARCHAR2);
	PROCEDURE ctp_proc_chain_item(i_menu_id IN VARCHAR2,
											i_item_id IN VARCHAR2,
											o_retcod  OUT VARCHAR2);
	FUNCTION str2table(i_str VARCHAR2,
							 t     OUT t_table) RETURN VARCHAR2;
	PROCEDURE test_str2table(r OUT VARCHAR2);
	PROCEDURE ctp_proc_update_order(i_menu_id   IN VARCHAR2,
											  i_menu_type IN VARCHAR2,
											  i_item_id   IN VARCHAR2,
											  i_order     IN VARCHAR2,
											  o_retcod    OUT VARCHAR2);
	FUNCTION set_menu_updatable RETURN VARCHAR2;

END ctp_pckg_menumgmt;
//

CREATE OR REPLACE PACKAGE BODY ctp_pckg_menumgmt IS

	FUNCTION set_menu_updatable RETURN VARCHAR2 IS
	BEGIN
		UPDATE ctp_role_user_rel t
			SET t.menuchg_flag = '1';
		RETURN '0';
	EXCEPTION
		WHEN OTHERS THEN
			RETURN SQLCODE;
	END;

	FUNCTION str2table(i_str VARCHAR2,
							 t     OUT t_table) RETURN VARCHAR2 IS
		ret_cod INTEGER;
		e_no_required_param EXCEPTION;
		i          INTEGER;
		j          INTEGER;
		item       VARCHAR2(100);
		data_begin BOOLEAN;
		len        INTEGER;
		c          VARCHAR2(1);
		log_info   LONG;
		one        VARCHAR2(100);
	BEGIN
		ret_cod := '0';
		IF i_str IS NULL THEN
			RAISE e_no_required_param;
		END IF;
		data_begin := FALSE;
		i          := 0;
		j          := 0;
		len        := length(i_str);
		LOOP
			i := i + 1;
			IF i > len THEN
				IF NOT (item IS NULL) THEN
					j := j + 1;
					t(j) := item;
					log_info := log_info || 'add last element:' || t(j) || chr(10);
				ELSE
					IF NOT (one IS NULL) THEN
						j := j + 1;
						t(j) := one;
						log_info := log_info || 'add last element:' || t(j) ||
										chr(10);
					END IF;
				END IF;
				EXIT;
			END IF;
			c := substr(i_str
						  ,i
						  ,1);
			IF (c = '$') OR (c = '|') THEN
				data_begin := TRUE;
				IF NOT (item IS NULL) THEN
					j := j + 1;
					t(j) := item;
					log_info := log_info || 'add element:' || t(j) || chr(10);
				END IF;
				item := '';
			ELSE
				IF data_begin THEN
					item := item || c;
				ELSE
					one := one || c;
				END IF;
			END IF;
		END LOOP;
		log_info := log_info || 't.first=' || to_char(t.FIRST) || chr(10);
		log_info := log_info || 't.last=' || to_char(t.LAST) || chr(10);
		IF NOT t.FIRST IS NULL THEN
			FOR i IN t.FIRST .. t.LAST
			LOOP
				log_info := log_info || 't[' || i || ']=' || t(i) || chr(10);
			END LOOP;
		END IF;
		log('str2table'
			,log_info);
		RETURN ret_cod;
	EXCEPTION
		WHEN e_no_required_param THEN
			ret_cod := 'e_no_required_param for str2table';
			RETURN ret_cod;
		WHEN OTHERS THEN
			ret_cod := 'e_unknown_error in str2table';
			RETURN ret_cod;
	END;

	PROCEDURE test_str2table(r OUT VARCHAR2) IS
		t t_table;
		s VARCHAR2(1000);
		k VARCHAR2(20);
	BEGIN
		s := '17$|$111$|$001$|$0011$|$00111$|$00112$|$00114$|$';
		k := str2table(s
						  ,t);
		r := to_char(t.LAST) || chr(10);
		IF k = '0' THEN
			FOR i IN t.FIRST .. t.LAST
			LOOP
				r := r || 'item(' || i || ')' || t(i) || chr(10);
			END LOOP;
		END IF;
	END;

	PROCEDURE ctp_proc_del_menu_node(i_menu_id     IN VARCHAR2,
												i_del_mode    IN VARCHAR2,
												o_retcod      OUT VARCHAR2,
												o_result_info OUT VARCHAR2) IS
		v_count INTEGER;
		e_cant_del_by_child EXCEPTION;
		e_no_required_param EXCEPTION;
		v_del_mode VARCHAR2(3);
		e_del_mode_param_error EXCEPTION;
		e_cant_del_by_item EXCEPTION;
		e_no_menu_id EXCEPTION;
		e_set_menu_updatable EXCEPTION;
		r VARCHAR2(100);
	BEGIN
		o_retcod      := '0';
		o_result_info := 'begin running ' || chr(10);
		o_result_info := 'i_menu_id=' || i_menu_id || chr(10);
		o_result_info := o_result_info || 'deltype=' || i_del_mode || chr(10);
		IF i_menu_id IS NULL THEN
			RAISE e_no_required_param;
		END IF;
		IF i_del_mode IS NULL THEN
			v_del_mode := '0';
		ELSE
			v_del_mode := i_del_mode;
		END IF;
		o_result_info := o_result_info || ' 检查指定菜单项是否存在' || chr(10);
		v_count       := 0;
		SELECT COUNT(*)
		  INTO v_count
		  FROM ctp_menu
		 WHERE id = i_menu_id;
		IF v_count = 0 THEN
			RAISE e_no_menu_id;
		END IF;
		CASE
			WHEN v_del_mode = '0' THEN
				o_result_info := o_result_info || ' 检查指定菜单项是否有子菜单' ||
									  chr(10);
				v_count       := 0;
				SELECT COUNT(*)
				  INTO v_count
				  FROM ctp_menu
				 WHERE parent_id = i_menu_id;
				IF v_count > 0 THEN
					-- 有子菜单项的情况下，不允许删除指定的菜单
					RAISE e_cant_del_by_child;
				END IF;
				o_result_info := o_result_info || ' 检查指定菜单项是否下挂功能项' ||
									  chr(10);
				v_count       := 0;
				SELECT COUNT(*)
				  INTO v_count
				  FROM ctp_menu_item_rel t
				 WHERE t.menu_id = i_menu_id;
				IF v_count > 0 THEN
					-- 有下挂功能项的情况下，不允许删除指定的菜单
					RAISE e_cant_del_by_item;
				END IF;
				o_result_info := o_result_info || ' 条件满足，删除菜单项' ||
									  chr(10);
				DELETE ctp_menu
				 WHERE id = i_menu_id;
			WHEN v_del_mode = '1' THEN
				--删除子菜单及其所有子菜单。
				o_result_info := o_result_info || '删除菜单子树下挂的所有功能项' ||
									  chr(10);
				DELETE ctp_menu_item_rel
				 WHERE menu_id IN (SELECT id
											FROM ctp_menu
										 CONNECT BY PRIOR id = parent_id
										  START WITH parent_id = i_menu_id
										 UNION
										 SELECT id
											FROM ctp_menu
										  WHERE id = i_menu_id);
				o_result_info := o_result_info || '删除菜单子树' || chr(10);
				DELETE ctp_menu
				 WHERE id IN (SELECT id
									 FROM ctp_menu
								  CONNECT BY PRIOR id = parent_id
									START WITH parent_id = i_menu_id
								  UNION
								  SELECT id
									 FROM ctp_menu
									WHERE id = i_menu_id);

			ELSE
				RAISE e_del_mode_param_error;
		END CASE;
		r             := set_menu_updatable;
		o_result_info := o_result_info || '置菜单变更标志' || chr(10);
		IF NOT r = '0' THEN
			RAISE e_set_menu_updatable;
		END IF;
		COMMIT;
		o_result_info := o_result_info || '已经提交修改.' || chr(10);
		log('ctp_proc_del_menu_node'
			,o_result_info);
		RETURN;
	EXCEPTION
		WHEN e_set_menu_updatable THEN
			o_result_info := o_result_info || '置菜单变更标志出错。';
			o_retcod      := r;
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
		WHEN e_no_menu_id THEN
			o_result_info := o_result_info || '未找到指定要删除的菜单项';
			o_retcod      := '1';
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
		WHEN e_no_required_param THEN
			o_result_info := o_result_info || '没有传入指定的参数给存储过程。';
			o_retcod      := '2';
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
		WHEN e_cant_del_by_child THEN
			o_result_info := o_result_info ||
								  '因菜单项含有子菜单项，所有不能删除指定的菜单项';
			o_retcod      := '3';
			ROLLBACK;
			RETURN;
		WHEN e_cant_del_by_item THEN
			o_result_info := o_result_info ||
								  '因菜单项下挂功能项，所有不能删除指定的菜单项';
			o_retcod      := '4';
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
		WHEN e_del_mode_param_error THEN
			o_result_info := o_result_info ||
								  '删除模式的参数设置错误，请检查参数。只能设置"0"或"1"模式.';
			o_retcod      := '5';
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
		WHEN OTHERS THEN
			o_result_info := o_result_info || '发生了未能捕捉到的错误' || chr(10);
			o_result_info := o_result_info || SQLERRM(SQLCODE);
			o_retcod      := '-1';
			ROLLBACK;
			o_result_info := o_result_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,o_result_info);
			RETURN;
	END;
	PROCEDURE ctp_proc_update_order(i_menu_id   IN VARCHAR2,
											  i_menu_type IN VARCHAR2,
											  i_item_id   IN VARCHAR2,
											  i_order     IN VARCHAR2,
											  o_retcod    OUT VARCHAR2) IS
		r  VARCHAR2(20);
		i  INTEGER := 0;
		tm t_table;
		ty t_table;
		ti t_table;
		tr t_table;
		e_no_required_param EXCEPTION;
		log_info LONG;
		e_str2table EXCEPTION;
		e_param_array_not_correct EXCEPTION;
		e_set_menu_updatable EXCEPTION;
	BEGIN
		o_retcod := '0';
		log_info := log_info || 'ctp_proc_update_order 执行过程:' || i_menu_id ||
						chr(10);
		log_info := log_info || 'i_menu_id=' || i_menu_id || chr(10);
		log_info := log_info || 'i_menu_type=' || i_menu_type || chr(10);
		log_info := log_info || 'i_order=' || i_order || chr(10);
		log_info := log_info || 'i_item_id=' || i_item_id || chr(10);
		log_info := log_info || '检查各个参数是否已经提供给存储过程' || chr(10);
		IF (i_menu_id IS NULL) OR (i_menu_type IS NULL) OR (i_item_id IS NULL) OR
			(i_order IS NULL) THEN
			RAISE e_no_required_param;
		END IF;
		log_info := log_info || '将菜单项参数分解成数组' || chr(10);
		r        := str2table(i_menu_id
									,tm);
		IF NOT (r = '0') THEN
			RAISE e_str2table;
		END IF;
		log_info := log_info || '将菜单类型参数分解成数组' || chr(10);
		r        := str2table(i_menu_type
									,ty);
		IF NOT (r = '0') THEN
			RAISE e_str2table;
		END IF;
		log_info := log_info || '将功能项参数分解成数组' || chr(10);
		r        := str2table(i_item_id
									,ti);
		IF NOT (r = '0') THEN
			RAISE e_str2table;
		END IF;
		log_info := log_info || '将显示序号参数分解成数组' || chr(10);
		r        := str2table(i_order
									,tr);
		IF NOT (r = '0') THEN
			RAISE e_str2table;
		END IF;
		log_info := log_info || '比较各个数组的个数是否一致' || chr(10);
		IF (tm.LAST <> ty.LAST) OR (tm.LAST <> ti.LAST) OR (tm.LAST <> tr.LAST) THEN
			RAISE e_param_array_not_correct;
		END IF;
		log_info := log_info || '循环处理更新显示序号' || chr(10);
		FOR i IN tm.FIRST .. tm.LAST
		LOOP
			IF ty(i) = 'I' THEN
				--this record is item;
				log_info := log_info || '更新下挂在菜单' || tm(i) || '的' ||
								'功能项' || ti(i) || '的显示序号为：' || tr(i) ||
								chr(10);
				UPDATE ctp_menu_item_rel a
					SET a.serialno = tr(i)
				 WHERE item_id = ti(i) AND menu_id = tm(i);
			END IF;
			IF ty(i) = 'M' THEN
				--this record is menu;
				log_info := log_info || '更新菜单项' || ti(i) || '的的显示序号为:' ||
								tr(i) || chr(10);
				UPDATE ctp_menu a
					SET a.serialno = tr(i)
				 WHERE a.id = ti(i);
			END IF;
		END LOOP;
		r        := set_menu_updatable;
		log_info := log_info || '置菜单变更标志' || chr(10);
		IF NOT r = '0' THEN
			RAISE e_set_menu_updatable;
		END IF;
		COMMIT;
		log_info := log_info || 'sql commit , 更新完毕。' || chr(10);
		log('ctp_proc_update_order'
			,log_info);
		RETURN;
	EXCEPTION
		WHEN e_set_menu_updatable THEN
			log_info := log_info || '置菜单变更标志出错。';
			o_retcod := r;
			ROLLBACK;
			log_info := log_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,log_info);
			RETURN;
		WHEN e_no_required_param THEN
			log_info := log_info || 'raise error:e_no_required_param';
			log('ctp_proc_update_order'
				,log_info);
			o_retcod := 'e_no_required_param';
			RETURN;
		WHEN e_str2table THEN
			log_info := log_info || 'raise error:' || r;
			log('ctp_proc_update_order'
				,log_info);
			o_retcod := r;
			RETURN;
		WHEN e_param_array_not_correct THEN
			log_info := log_info || 'raise error:e_param_array_not_correctm';
			log('ctp_proc_update_order'
				,log_info);
			o_retcod := 'e_param_array_not_correct';
			RETURN;
		WHEN OTHERS THEN
			log_info := log_info || SQLERRM(SQLCODE);
			ROLLBACK;
			log('ctp_proc_update_order'
				,log_info);
			o_retcod := 'e_unkown_exception';
			RETURN;
	END;
	PROCEDURE ctp_proc_chain_item(i_menu_id IN VARCHAR2,
											i_item_id IN VARCHAR2,
											o_retcod  OUT VARCHAR2) IS
		log_info LONG;
		e_no_required_param EXCEPTION;
		e_str2table EXCEPTION;
		e_set_menu_updatable EXCEPTION;
		r       VARCHAR2(100);
		i       INTEGER;
		item_id VARCHAR2(200);
		t       t_table;
	BEGIN
		o_retcod := '0';
		log_info := ' ctp_proc_chain_item 执行过程如下:' || chr(10);
		log_info := log_info || 'i_menu_id =' || i_menu_id || chr(10);
		log_info := log_info || 'i_item_id =' || i_item_id || chr(10);
		IF (i_menu_id IS NULL) THEN
			RAISE e_no_required_param;
		END IF;
		item_id  := '';
		log_info := log_info ||
						'在下挂菜单前，首先删除关系表指定menu_id中的下挂功能项数据' ||
						chr(10);
		DELETE ctp_menu_item_rel
		 WHERE menu_id = i_menu_id;
		IF i_item_id IS NULL THEN
			log_info := log_info || '清空指定的菜单项下的所有功能项,正常处理完毕.';
			log('ctp_proc_chain_item'
				,log_info);
			r        := set_menu_updatable;
			log_info := log_info || '置菜单变更标志' || chr(10);
			IF NOT r = '0' THEN
				RAISE e_set_menu_updatable;
			END IF;
			COMMIT;
			RETURN;
		END IF;
		r := str2table(i_item_id
						  ,t);
		IF NOT (r = '0') THEN
			RAISE e_str2table;
		END IF;
		log_info := log_info || '------以下进入参数循环处理-----------' ||
						chr(10);
		IF r = '0' THEN
			FOR i IN t.FIRST .. t.LAST
			LOOP
				log_info := log_info || ' 将功能项 <' || t(i) || '>' ||
								'下挂在菜单项 <' || i_menu_id || '>之下' || chr(10);
				INSERT INTO ctp_menu_item_rel
					(menu_id, item_id, serialno)
				VALUES
					(i_menu_id, t(i), 0);
			END LOOP;
			r        := set_menu_updatable;
			log_info := log_info || '置菜单变更标志' || chr(10);
			IF NOT r = '0' THEN
				RAISE e_set_menu_updatable;
			END IF;
			COMMIT;
			log_info := log_info || '正常处理完毕';
			log('ctp_proc_chain_item'
				,log_info);
		ELSE
			RAISE e_str2table;
		END IF;
	EXCEPTION
		WHEN e_set_menu_updatable THEN
			log_info := log_info || '置菜单变更标志出错。';
			o_retcod := r;
			ROLLBACK;
			log_info := log_info || chr(10) || 'ROLLBACK.';
			log('ctp_proc_del_menu_node'
				,log_info);
			RETURN;
		WHEN e_no_required_param THEN
			log_info := log_info || 'raise exception:no required parameter.';
			log('ctp_proc_chain_item'
				,log_info);
			o_retcod := 'e_no_required_param';
			RETURN;
		WHEN e_str2table THEN
			log_info := log_info || 'raise exception:str2Table executing error.';
			log('ctp_proc_chain_item'
				,log_info);
			o_retcod := r;
			RETURN;
		WHEN OTHERS THEN
			log_info := log_info || SQLERRM(SQLCODE);
			ROLLBACK;
			log('ctp_proc_chain_item'
				,log_info);
			o_retcod := SQLERRM(SQLCODE);
			RETURN;
	END;

	PROCEDURE ctp_proc_get_menu_list(o_retcode   OUT VARCHAR2,
												o_menu_list OUT c_menu_list) IS
		menu_flag VARCHAR2(10);
		item_flag VARCHAR2(10);
	BEGIN
		o_retcode := '0';
		menu_flag := 'm';
		item_flag := 'i';
		OPEN o_menu_list FOR
			SELECT substr(menu_id
							  ,1
							  ,length(menu_id) - 1), --因为length(menu_flag)=1或者length(item_flag）=1;
					 menu_label, LEVEL menu_deep, substr(menu_parent_id
							  ,1
							  ,length(menu_parent_id) - 1), menu_order, menu_type, menu_url
			  FROM (SELECT id || menu_flag menu_id, default_label menu_label, parent_id ||
								  menu_flag menu_parent_id, serialno menu_order, 'M' menu_type, '' menu_url
						  FROM ctp_menu
						UNION
						SELECT i.id || item_flag menu_id, i.default_label menu_label, r.menu_id ||
								  menu_flag menu_parent_id, r.serialno menu_order, 'I' menu_type, i.url menu_url
						  FROM ctp_item i, ctp_menu_item_rel r
						 WHERE i.id = r.item_id)
			CONNECT BY PRIOR menu_id = menu_parent_id
			 START WITH menu_parent_id = menu_flag
			 ORDER SIBLINGS BY menu_order ASC;
		RETURN;
	EXCEPTION
		WHEN OTHERS THEN
			log('ctp_proc_get_menu_list()'
				,SQLERRM(SQLCODE));
			o_retcode := SQLERRM(SQLCODE);
			RETURN;
	END;

	FUNCTION check_log_on RETURN BOOLEAN IS
	BEGIN
		RETURN TRUE;
	END;

	PROCEDURE log(proc_name IN VARCHAR2,
					  info      IN VARCHAR2) IS
		PRAGMA AUTONOMOUS_TRANSACTION;
		time_str VARCHAR2(100);
	BEGIN
		--IF check_log_on THEN
		SELECT to_char(SYSDATE
							,'mm - dd - yyyy hh24 :mi :ss')
		  INTO time_str
		  FROM dual;
		INSERT INTO ctp_proc_log
		VALUES
			(proc_name, time_str, info);
		COMMIT;
		--END IF;
		RETURN;
	END;

END ctp_pckg_menumgmt;
