CREATE OR REPLACE PACKAGE ctp_pckg_signininfo AS
	TYPE rec_userrole IS RECORD(
		roleid   ctp_role.id%TYPE,
		rolename ctp_role.NAME%TYPE);

	TYPE ref_userrole IS REF CURSOR RETURN rec_userrole;

	PROCEDURE ctp_proc_getsyssignininfo(i_userid      IN VARCHAR2,
													i_pw          IN VARCHAR2,
													i_ssicflag    IN VARCHAR2,
													o_retcode     OUT VARCHAR2,
													o_branchid    OUT VARCHAR2,
													o_branchlevel OUT VARCHAR2,
													o_areacode    OUT VARCHAR2,
													o_netterminal OUT VARCHAR2,
													ret_userrole  OUT ref_userrole);

END;
//
CREATE OR REPLACE package PCKG_LOG is

  PROCEDURE RECORD_LOG(i_op_type    IN VARCHAR2, --日志类型
                       i_userId     IN VARCHAR2, --用户ID
                       i_op_time    IN TIMESTAMP, --操作时间
                       i_op_target  IN VARCHAR2, --操作目标
                       i_extra_info IN VARCHAR2 --扩展信息
                       );

  PROCEDURE RECORD_LOG_F(i_op_type    IN VARCHAR2, --日志类型
                         i_userId     IN VARCHAR2, --用户ID
                         i_op_time    IN TIMESTAMP, --操作时间
                         i_op_target  IN VARCHAR2, --操作目标
                         i_extra_info IN VARCHAR2, --扩展信息
                         o_retcode    OUT VARCHAR2, --0  成功  1 失败
                         o_msg        OUT VARCHAR2);

end PCKG_LOG;
//
CREATE OR REPLACE PACKAGE BODY      ctp_pckg_signininfo AS
	PROCEDURE ctp_proc_getsyssignininfo(i_userid      IN VARCHAR2,
													i_pw          IN VARCHAR2,
													i_ssicflag    IN VARCHAR2,
													o_retcode     OUT VARCHAR2,
													o_branchid    OUT VARCHAR2,
													o_branchlevel OUT VARCHAR2,
													o_areacode    OUT VARCHAR2,
													o_netterminal OUT VARCHAR2,
													ret_userrole  OUT ref_userrole) IS
		v_num      VARCHAR2(2);
		v_userid   VARCHAR2(20);
		v_pw       VARCHAR2(200);
		v_status   VARCHAR2(2);
		v_branchid VARCHAR2(20);
	BEGIN
		o_retcode := '0';
    
    
    PCKG_LOG.RECORD_LOG('1', i_userid, sysdate, null, null);--记录登录日志

		SELECT COUNT(*)
		  INTO v_num
		  FROM ctp_user
		 WHERE id = i_userid;

		--用户不存在
		IF (v_num = 0) THEN
			o_retcode := '1';
			RETURN;
		ELSE
			SELECT id, password, status, branch_id
			  INTO v_userid, v_pw, v_status, v_branchid
			  FROM ctp_user
			 WHERE id = i_userid;

			--非统一认证，密码不正确
			IF (i_ssicflag != 1 AND (v_pw is null or i_pw is null or v_pw != i_pw)) THEN
				o_retcode := '2';
				RETURN;
			ELSE
				--用户状态不正确
				IF (v_status = '0') THEN
					o_retcode := '3';
					RETURN;
				ELSE
					--用户所属机构状态不正确
					SELECT COUNT(*)
					  INTO v_num
					  FROM (SELECT id, status
								  FROM ctp_branch
								CONNECT BY PRIOR parent_id = id
								 START WITH id = v_branchid)
					 WHERE status = '0';
					IF (v_num > 0) THEN
						o_retcode := '4';
						RETURN;
					ELSE
						--用户所属机构
						o_branchid := v_branchid;

						--用户所属机构级别
						SELECT branch_level, region_id, net_terminal
						  INTO o_branchlevel, o_areacode, o_netterminal
						  FROM ctp_branch
						 WHERE id = o_branchid;

						--当前用户所有角色
						OPEN ret_userrole FOR
							SELECT a.id roleid, a.NAME rolename
							  FROM ctp_role a, ctp_role_user_rel b
							 WHERE b.user_id = i_userid AND b.role_id = a.id;
					END IF;
				END IF;
			END IF;
		END IF;
		RETURN;
	EXCEPTION
		WHEN OTHERS THEN
			o_retcode := '-1';
			RETURN;
	END;
END;
//
CREATE OR REPLACE PACKAGE CTP_PCKG_USER AS
  PROCEDURE CLEAN_UNLOGIN_USERS(o_retcode OUT VARCHAR2);
END;
//
CREATE OR REPLACE PACKAGE BODY CTP_PCKG_USER AS
  PROCEDURE CLEAN_UNLOGIN_USERS(o_retcode OUT VARCHAR2) IS
  BEGIN
    o_retcode := '0';
  
    insert into log_app_operation
      (op_type, user_id, op_time, extra_info)
      select '2', id, sysdate, '6个月未登录，将用户锁定 by system'
        from ctp_user u
       WHERE STATUS = '1'
         and not exists (select 1
                from log_app_operation l
               where op_type = '1'
                 and op_time > add_months(sysdate, -6)
                 and l.user_id = u.id);

    UPDATE CTP_USER u
       SET STATUS = '0'
     WHERE STATUS = '1'
       and not exists (select 1
              from log_app_operation l
             where op_type = '1'
               and op_time > add_months(sysdate, -6)
               and l.user_id = u.id);
  
    commit;
  EXCEPTION
    WHEN OTHERS THEN
      o_retcode := '-1';
      RETURN;
  END;
END;
