CREATE OR REPLACE PACKAGE PACK_CAP_FILE_RECODES IS


  PROCEDURE PROC_FILE_RECODES_201005(P_I_DATE    IN VARCHAR2,
                                     P_O_SUCCEED OUT VARCHAR2);

  PROCEDURE PROC_FILE_RECODES_20160402(P_I_DATE    IN VARCHAR2,
                                       P_O_SUCCEED OUT VARCHAR2);

  PROCEDURE PROC_FILE_RECODES_20160403(P_I_DATE    IN VARCHAR2,
                                       P_O_SUCCEED OUT VARCHAR2);

END PACK_CAP_FILE_RECODES;
//

CREATE OR REPLACE PACKAGE BODY PACK_CAP_FILE_RECODES IS

  PROCEDURE PROC_FILE_RECODES_201005(P_I_DATE    IN VARCHAR2,
                                     P_O_SUCCEED  OUT VARCHAR2) IS
    V_SQL   VARCHAR2(600); --sql语句
    V_FILE  VARCHAR2(100); --文件名
    V_DIR   VARCHAR2(50); --目录
    V_DELI  VARCHAR2(2); --分隔符
    V_FLAG  VARCHAR2(100);
    V_MSG   VARCHAR2(100);
    V_COUNT NUMBER(20);
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_CAP_FILE_RECODES.PROC_FILE_RECODES_201005';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------
    --先删除
    DELETE FROM CAP_FILE_RECORDS WHERE JOB_NO IN ('201005','2010052') and WORKDATE = P_I_DATE;
    --CAP_CKXS文件统计
      SELECT COUNT(1) INTO V_COUNT
        FROM PRM_CS10 A, PRM_XS10 B
       WHERE A.PRODUCT_ID = B.THPRODUCT
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND B.START_DATE <= P_I_DATE
         AND B.END_DATE > P_I_DATE
         AND A.SUBJECT_APP = 1 ;
         
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','PRM_CS10','CAP_CKXS',V_COUNT,P_I_DATE);
     COMMIT;
     
        --SUB_XS文件统计
      SELECT COUNT(1) INTO V_COUNT
      FROM (
      SELECT A.SUBJECT_CODE, A.SUBJECT_TYPE, B.QUOTIETY     --银行卡透支
        FROM PRM_CS081 A, PRM_XS081 B
       WHERE A.PRODUCT_ID = B.THPRODUCT
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND B.START_DATE <= P_I_DATE
         AND B.END_DATE > P_I_DATE
         AND A.SUBJECT_APP = 1
   union all
      SELECT A.SUBJECT_CODE, A.SUBJECT_TYPE, B.PZXS         --债券投资
        FROM PRM_CS061 A, PRM_XS061 B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND B.START_DATE <= P_I_DATE
         AND B.END_DATE > P_I_DATE
         AND A.SUBJECT_APP = 1
   union all
      SELECT A.SUBJECT_CODE, A.SUBJECT_TYPE, B.PAR_COEF     --资金业务
        FROM PRM_CS05A A, PRM_XSZJ1 B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND B.START_DATE <= P_I_DATE
         AND B.END_DATE > P_I_DATE
         AND A.SUBJECT_APP = 1
   union all
      SELECT A.SUBJECT_CODE, A.SUBJECT_TYPE, B.XS_VALUE     --表外资产
        FROM PRM_CS05C A, PRM_XS051 B
       WHERE A.PRODUCT_ID = B.PRODUCT_NAME3
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND B.START_DATE <= P_I_DATE
         AND B.END_DATE > P_I_DATE
         AND A.SUBJECT_APP = 1 ) T;
         
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','PRM_XS','SUB_XS',V_COUNT,P_I_DATE);
     COMMIT;
     
    --CAP_PJZB文件统计
    
    SELECT COUNT(1) INTO V_COUNT  
    FROM DW_MOD_PJTX  WHERE START_DATE=P_I_DATE ;
    
    INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','DW_MOD_PJTX','CAP_PJZB',V_COUNT,P_I_DATE);
    COMMIT;
    
    --CAP_PRM_CSPJ2文件统计
    SELECT COUNT(1) INTO V_COUNT
      FROM PRM_CSPJ2
     WHERE START_DATE <= P_I_DATE
       AND END_DATE > P_I_DATE;
     
    INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','PRM_CSPJ2','CAP_PRM_CSPJ2',V_COUNT,P_I_DATE);
    COMMIT;
    
    --CAP_PRM_PRODUCT文件统计
     SELECT COUNT(1) INTO V_COUNT
       FROM PRM_PRODUCT
      WHERE START_DATE <= P_I_DATE
        AND END_DATE > P_I_DATE;
         
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','PRM_PRODUCT','CAP_PRM_PRODUCT',V_COUNT,P_I_DATE);
     COMMIT;    
     
     --CAP_PRM_XS071文件统计
     SELECT COUNT(1) INTO V_COUNT
       FROM PRM_XS071
      WHERE START_DATE <= P_I_DATE
        AND END_DATE > P_I_DATE;    
    
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','PRM_XS071','CAP_PRM_XS071',V_COUNT,P_I_DATE);
     COMMIT;   
     
     --CAP_FRDK 文件统计 
     SELECT COUNT(1) INTO V_COUNT
     FROM DM_CS_ZFRDK 
     WHERE CURRTYPE in ('001','992','994');
     
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','DM_CS_ZFRDK','CAP_FRDK',V_COUNT,P_I_DATE);
     COMMIT;
     
     --CAP_GRDK文件统计 
     SELECT COUNT(1) INTO V_COUNT
     FROM  DM_CS_ZGRDK_UG 
     WHERE CURRTYPE in ('001','992','994') ;
     
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','DM_CS_ZGRDK_UG','CAP_GRDK',V_COUNT,P_I_DATE);
     COMMIT;
     
     --CAP_PJTX文件统计
     SELECT COUNT(1) INTO V_COUNT
     FROM DM_CS_ZPJTX 
     WHERE CURRTYPE in ('001','992','994') ;
     
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('201005','F-CAP','DM_CS_ZPJTX','CAP_PJTX',V_COUNT,P_I_DATE);
     COMMIT;
     
     --CAP_CAPGRDKEDW0000000000文件统计
     IF P_I_DATE = TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYYMMDD')), 'YYYYMMDD')  THEN
           SELECT COUNT(1) INTO V_COUNT
           FROM DW_MOD_GRDK_UG  
           WHERE DATA_DATE =  P_I_DATE ;  
     ELSE
           V_COUNT := 0 ;
     END IF;
     
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('2010052','F-CAP','DW_MOD_GRDK_UG','CAP_CAPGRDKEDW0000000000',V_COUNT,P_I_DATE);
     COMMIT; 
     
     --CAP_FRDK_IN_YYYYMMDD文件统计
     SELECT COUNT(1) INTO V_COUNT
     FROM DW_MOD_FRDK  
     WHERE START_DATE=P_I_DATE ;
     
     INSERT INTO CAP_FILE_RECORDS(JOB_NO,APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE) VALUES ('2010052','F-CAP','DW_MOD_FRDK','CAP_FRDK_IN_YYYYMMDD',V_COUNT,P_I_DATE);
     COMMIT;    
         
    V_SQL  := 'SELECT APP_ID,TABLE_NAME,BIN_NAME,COUNT_YB,WORKDATE,FIELD1,FIELD2 FROM CAP_FILE_RECORDS WHERE WORKDATE = '''||P_I_DATE||''' AND JOB_NO IN (''201005'',''2010052'')';
    V_FILE := 'CAP1_FILE_RECORDS-'||P_I_DATE||'.BIN';
    V_DIR  := 'CAP_BDP';
    V_DELI := CHR(27);
    
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_FILE_RECODES_201005;
