CREATE OR REPLACE PACKAGE PACK_DEAL_GRDK_P is

  
   PROCEDURE PROC_DEAL_GRDK_PRETREAT(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);
  --ods进stg表
  PROCEDURE PROC_DEAL_GRDK_MAIN(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);
  PROCEDURE PROC_DEAL_GRDK(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);
    --ods进stg_bak表
  PROCEDURE PROC_DEAL_GRDK_MON(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);
  --stg表进dw表
  PROCEDURE PROC_GRDK_DM(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);
  --机构汇总
  PROCEDURE PROC_GRDK_DM_SUM(P_I_DATE IN VARCHAR2,P_O_SUCCEED OUT VARCHAR2);

  --恢复过程
  PROCEDURE PROC_RESUME_GRDK(P_I_DATE    IN VARCHAR2,
                             P_I_ZONENO  IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2);
  PROCEDURE PROC_DEAL_GRDK_BAK(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);

  -- 个人贷款科目转产品特殊处理

  FUNCTION FUNC_PRM_CS044(I_DATEDATE      IN VARCHAR2,
                          IN_SUBJECT_CODE IN VARCHAR2) RETURN VARCHAR2;
end PACK_DEAL_GRDK_P;
