CREATE OR REPLACE PACKAGE BODY PACK_DEAL_GRDK_P is
PROCEDURE PROC_DEAL_GRDK_PRETREAT(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2)IS


BEGIN

  P_O_SUCCEED:= '0';


  COMMIT;
  --出错处理
  EXCEPTION  WHEN OTHERS THEN
    ROLLBACK;
    P_O_SUCCEED := '1';

    RAISE;

  END PROC_DEAL_GRDK_PRETREAT;


PROCEDURE PROC_DEAL_GRDK_MAIN(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2)IS

V_OPEN_DAY DIC_ALL_KIND.KIND_ID%TYPE;
BEGIN

  --徐敏10月版本修改 13年启用新接口表数据
  BEGIN
    SELECT T.KIND_ID
      INTO V_OPEN_DAY
      FROM DIC_ALL_KIND T
     WHERE T.OPERATION_KIND = 'ADJUST_DATE_UG';
  EXCEPTION
    WHEN OTHERS THEN
      V_OPEN_DAY := '20130101';
  END;

  IF P_I_DATE >= V_OPEN_DAY THEN
    NULL;

  ELSE

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYYMMDD')), 'YYYYMMDD') THEN

      PROC_DEAL_GRDK_MON(P_I_DATE, P_I_ZONENO, P_O_SUCCEED);
    ELSE
      --投产日前,使用老报表逻辑
      PROC_DEAL_GRDK(P_I_DATE, P_I_ZONENO, P_O_SUCCEED);
    END IF;

  END IF;
--------------------------------------------------------------------------------------
  --成功记录存储过程运行日志
  P_O_SUCCEED:= '0';


  COMMIT;
  --出错处理
  EXCEPTION  WHEN OTHERS THEN
    ROLLBACK;
    P_O_SUCCEED := '1';

    RAISE;

  END PROC_DEAL_GRDK_MAIN;

PROCEDURE PROC_DEAL_GRDK(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_MONTH_DAY  NUMBER(3); --当月天数
    V_X042       CPMG.PRM_XS042.QUOTIETY%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_GRDK_1005.PROC_DEAL_GRDK';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';

    V_STEP_NO := '2.5';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    SELECT LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')) -
           TO_DATE(SUBSTR(P_I_DATE, 1, 6) || '01', 'yyyymmdd') + 1
      INTO V_MONTH_DAY
      FROM DUAL;


    SELECT MAX(X.QUOTIETY)
      INTO V_X042
      FROM CPMG.PRM_XS042 X
     WHERE X.START_DATE <= P_I_DATE
       AND X.END_DATE > P_I_DATE;

    IF V_X042 IS NULL THEN
      V_X042 := 1;
    END IF;

    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO := '2.6';
    --个人贷款模型中间表关联参数表向个人贷款模型结果表临时表插入数据


    V_STEP_NO := '2.7';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --加载dw_mod表


    UPDATE /*+full(dwg)*/CPMG.DW_MOD_GRDK DWG
       SET DWG.END_DATE = TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1,
                                  'YYYYMMDD')
     WHERE EXISTS (SELECT '1'
              FROM CPMG.Ods_Tmp_Grdk2 ODS
             WHERE DWG.ACCNO = ODS.PCACCNO--ST.ACCNO
               AND DWG.LNCODE = ODS.PRODCODE --ST.LNCODE
               AND DWG.MEMNO =ODS.MEMNO-- ST.MEMNO
               AND DWG.LNNO = ODS.LNNO--ST.LNNO
               AND DWG.CURRTYPE = ODS.CURRTYPE--ST.CURRTYPE
               AND ODS.ZONENO_FOR_PART=P_I_ZONENO
               --AND SUBSTR(ODS.ZONENO,0,2)=P_I_ZONENO
               )
       AND DWG.END_DATE = '99991231'
       AND dwg.start_date >= TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(SUBSTR(p_i_date,1,6),'YYYYMM'),-1)),'YYYYMMDD')
         AND dwg.start_date< p_i_date
       AND DWG.ZONENO_FOR_PART=P_I_ZONENO; ---ADD BY CHENST

    V_STEP_NO := '2.8';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');


    INSERT INTO CPMG.Dw_Mod_Grdk
  (ACCNO,
       LNCODE,
       MEMNO,
       LNNO,
       ZONENO,
       ACTBRNO,
       SUBCODE,
       CURRTYPE,
       BALANCE,
       TA500261001,
       PRODUCT_ID3,
       PRODUCT_NAME3,
       TA500261003,
       TA500261004,
       TA500261008,
       TA500261013,
       TA500261018,
       TA500261016,
       TA500251012,
       TA500251018,
       TA500251014,
       TA500251013,
       TA500271009,
       TA500281016,
       TA500291012,
       TA500294008,
       OTHER_AMOUNT,
       INVAILD_AMOUNT,
       XYAMOUNT,
       TA500251054,
       TOTALAMOUNT,
       TA290001004,
       TA290001005,
       TA290001006,
       TA290008004,
       TA290008009,
       TA500251097,
       DKYQ_YEAR,
       BBPRECENT,
       YYBB,
       SYBB,
       ZCAMOUNT,
       JJZB_XS,
       ECOST,
       START_DATE,
       END_DATE,
       DKYQ_ID,
       ECOST_RJ,
       BAL_RJ,
       STATUS,
       ZONENO_FOR_PART)
  SELECT /*+ordered*/
                 ODS.PCACCNO ACCNO,
                 ODS.PRODCODE LNCODE,
                 ODS.MEMNO MEMNO,
                 ODS.LNNO LNNO,
                 ODS.ZONENO,

                 ODS.PHYBRNO ACTBRNO,
                 ODS.SUBCODE SUBCODE,
                 ODS.CURRTYPE CURRTYPE,
                 DECODE(ODS.STATUS, '6',0, '8', 0, '9', 0,NVL(ABS(ODS.LNBALANCE), 0)) BALANCE,
                 --0 BACM,
                 ODS.RELATEDNO TA500261001,
                 P.PRODUCT_ID,
                 P.PRODUCT_NAME,
                 ODS.CUSTID TA500261003,
                 ODS.CUSTCIS TA500261004,
                 ODS.LOANTYPE TA500261008,
                 ODS.LOANDATE TA500261013,
                 nvl(ODS.LEVELFIVE,'1') TA500261018,
                 ODS.DUEDATE TA500261016,
                 ODS.LNAMOUNT TA500251012,
                --ODS.LNAMOUNT AVG_TA500251012,
                 ODS.AVCHTYPE TA500251018,
                 ODS.RATE TA500251014,
                 ODS.LOANTERM TA500251013,
             
                 NVL(ODS.AVCHAMT, 0) TA500271009,
                -- NVL(ODS.AVCHAMT, 0) TA500271009_CM,
                 NVL(ODS.MGAMT, 0) TA500281016,
               --  NVL(ODS.MGAMT, 0) TA500281016_CM,
                 NVL(ODS.MPAMT, 0) TA500291012,
               --  NVL(ODS.MPAMT, 0) TA500291012_CM,
                 NVL(ODS.ASSUREAMT, 0) TA500294008,
               --  NVL(ODS.ASSUREAMT, 0) TA500294008_CM,
                 NVL(ODS.OTHERAMT, 0) OTHER_AMOUNT,
                 --NVL(ODS.OTHERAMT, 0) OTHER_AMOUNT_CM,
                 NVL(ODS.INVALIDAMT, 0) INVAILD_AMOUNT,
                -- NVL(ODS.INVALIDAMT, 0) INVAILD_AMOUNT_CM,
                 NVL(ODS.CREDITAMT, 0) XYAMOUNT,
                 ODS.TA500251054 TA500251054,

                 NVL(ODS.TOTALAMT, 0) TOTALAMOUNT,
                 ODS.CUSTNAME TA290001004,
                 ODS.REGTYPE TA290001005,
                 ODS.REGNO TA290001006,
                 ODS.CREDITLEVEL TA290008004,
                 ODS.ECUSFLAG TA290008009,
                 ODS.SURVEYOR TA500251097,
                 TO_DATE(ODS.DUEDATE, 'YYYYMMDD') - TO_DATE(P_I_DATE, 'YYYYMMDD'),

                 x42.bbprecent, --拨备计划比例
                 decode(NVL(ODS.TOTALAMT, 0), 0, 0, NVL(ODS.TOTALAMT, 0) * x42.bbprecent), --应保有拨备额
                 0, --实际保有拨备额 本次不计算
                 DECODE(ODS.STATUS, '6',0, '8', 0, '9', 0,NVL(ABS(ODS.LNBALANCE), 0)), --资产净额直接取余额
                 --经济资本加权分配系数
                 decode(NVL(ODS.TOTALAMT, 0),
          0,
          0,
          (NVL(ODS.AVCHAMT, 0) * X41.BZXS_VALUE +
          NVL(ODS.MGAMT, 0) * X41.DYXS_VALUE +
          NVL(ODS.MPAMT, 0) * X41.ZYXS_VALUE +
          NVL(ODS.ASSUREAMT, 0) * X41.BDXS_VALUE +
          NVL(ODS.OTHERAMT, 0) * X41.QTXS_VALUE +
          NVL(ODS.INVALIDAMT, 0) * X41.WXXS_VALUE +
          NVL(ODS.CREDITAMT, 0) * X41.XYXS_VALUE) *
          NVL(X42.QUOTIETY,
              V_X042 ----如空 则取这个产品最大的调整系数
              ) * X43.XS_VALUE / NVL(ODS.TOTALAMT, 0)),
   DECODE(ODS.STATUS, '6',0, '8', 0, '9', 0,NVL(ABS( ODS.LNBALANCE), 0)) *
   decode(NVL(ODS.TOTALAMT, 0),
          0,
          0,
          ((NVL(ODS.AVCHAMT, 0) * X41.BZXS_VALUE +
          NVL(ODS.MGAMT, 0) * X41.DYXS_VALUE +
          NVL(ODS.MPAMT, 0) * X41.ZYXS_VALUE +
          NVL(ODS.ASSUREAMT, 0) * X41.BDXS_VALUE +
          NVL(ODS.OTHERAMT, 0) * X41.QTXS_VALUE +
          NVL(ODS.INVALIDAMT, 0) * X41.WXXS_VALUE +
          NVL(ODS.CREDITAMT, 0) * X41.XYXS_VALUE) *
          NVL(X42.QUOTIETY, --如空 则取这个产品最大的调整系数
               V_X042) * X43.XS_VALUE / NVL(ODS.TOTALAMT, 0))),
               P_I_DATE,
               '99991231',
                X43.QXDC_ID,
                0,
                0,
                ODS.STATUS STATUS,
                ODS.ZONENO_FOR_PART



    FROM 
          ODS_TMP_GRDK2 ODS,
          PRM_PRODUCT_SUBJECT P,
         --CPMG.PRM_PRODUCT PR, --一二三级产品参数表
         CPMG.PRM_XS041 X41, --个人贷款信用风险系数表
         (SELECT a.fl5_id fl5_id, a.bbprecent bbprecent, b.quotiety quotiety
            FROM prm_cs042 a, prm_xs042 b
           WHERE a.start_date <= p_i_date
             AND a.end_date > p_i_date
             AND b.start_date <= p_i_date
             AND b.End_Date > p_i_date
             AND a.fl5_id = b.qclass) X42, --个人贷款信用风险贷款质量调节系数表 关联条件不用产品
         CPMG.PRM_XS043 X43 --个人贷款信用风险余期调节系数表
   WHERE 
     P.PRODUCT_ID=X41.PRODUCT_ID  
     AND X41.START_DATE <= P_I_DATE
     AND X41.END_DATE > P_I_DATE

     AND ODS.LEVELFIVE=X42.FL5_ID(+)
     --AND SDG.TA500261018 = X42.Fl5_Id
     AND TO_DATE(ODS.DUEDATE, 'YYYYMMDD') -
         TO_DATE(P_I_DATE, 'YYYYMMDD') >
         DECODE(X43.LEFT_IN,
                '1',
                X43.LEFT_VALUE,
                '2',
                X43.LEFT_VALUE - 0.000000001)
       AND TO_DATE(ODS.DUEDATE, 'YYYYMMDD') -
         TO_DATE(P_I_DATE, 'YYYYMMDD') <
         DECODE(X43.RIGHT_IN,
                '1',
                X43.RIGHT_VALUE,
                '2',
                X43.RIGHT_VALUE + 0.000000001)
    
     AND X43.START_DATE <= P_I_DATE
     AND X43.END_DATE > P_I_DATE

     AND ODS.SUBCODE=P.SUBJECT_CODE
    -- AND SIGN(ODS.LNBALANCE) = -1
     AND P.PRODUCT_NAME='2'  ---1 法贷，2个贷
     AND ODS.ZONENO_FOR_PART=P_I_ZONENO;


    COMMIT;

    P_O_SUCCEED := '0';
    --记载数据处理日志
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_DEAL_GRDK;


PROCEDURE PROC_DEAL_GRDK_MON(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_MONTH_DAY  NUMBER(3); --当月天数
    V_X042       CPMG.PRM_XS042.QUOTIETY%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_GRDK_1005.PROC_DEAL_GRDK';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';


    --更新STG表
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.3';

    --------------对于本次STG表中有数据，而ODS表当日没有提供的数据，进行复制上一天的月积数进行月积数的统计

    UPDATE STG_DAT_GRDK T
       SET T.BACM              = T.BACM + T.BALANCE,
           T.TA500271009_CM    = T.TA500271009_CM + T.TA500271009,
           T.TA500281016_CM    = T.TA500281016_CM + T.TA500281016,
           T.TA500291012_CM    = T.TA500291012_CM + T.TA500291012,
           T.TA500294008_CM    = T.TA500294008_CM + T.TA500294008,
           T.OTHER_AMOUNT_CM   = T.OTHER_AMOUNT_CM + T.OTHER_AMOUNT,
           T.INVAILD_AMOUNT_CM = T.INVAILD_AMOUNT_CM + T.INVAILD_AMOUNT,
           T.XYAMOUNT_CM = T.XYAMOUNT_CM +T.XYAMOUNT,
           T.TOTALAMOUNT_CM = T.TOTALAMOUNT_CM +T.TOTALAMOUNT
           --T.MODIFY_DATE       = P_I_DATE
     WHERE NOT EXISTS (SELECT 1
              FROM ODS_TMP_GRDK2 ODS
             WHERE T.ACCNO = ODS.PCACCNO
               AND T.LNCODE = ODS.PRODCODE
               AND T.MEMNO = ODS.MEMNO
               AND T.LNNO = ODS.LNNO
               AND T.ZONENO=ODS.ZONENO
               AND ODS.ZONENO_FOR_PART=P_I_ZONENO)
               AND T.ZONENO_FOR_PART = P_I_ZONENO;

    V_STEP_NO    := '2.4';
    -----------STG进行存量--增量更新
    MERGE/*+use_hash(SG ODS)*/ INTO CPMG.STG_DAT_GRDK SG
    USING ( SELECT O.*,P.PRODUCT_ID PD
          FROM ODS_TMP_GRDK2 O,PRM_PRODUCT_SUBJECT P
                 WHERE O.SUBCODE=P.SUBJECT_CODE
                -- AND SIGN(O.LNBALANCE) = -1
                 AND P.PRODUCT_NAME='2'  ---1 法贷，2个贷
                 AND O.Zoneno_For_Part=P_I_ZONENO

    ) ODS
    ON (SG.ZONENO_FOR_PART=P_I_ZONENO AND SG.ACCNO = ODS.PCACCNO AND SG.LNCODE = ODS.PRODCODE AND SG.MEMNO = ODS.MEMNO AND SG.LNNO = ODS.LNNO)
    WHEN MATCHED THEN
      UPDATE
         SET 
             SG.ZONENO = ODS.ZONENO,

             SG.ACTBRNO           = ODS.PHYBRNO,
             SG.SUBCODE           = ODS.SUBCODE,
             SG.CURRTYPE          = ODS.CURRTYPE,
             
             SG.BALANCE           = DECODE(ODS.STATUS,'6',0,'8',0,'9',0,NVL(ABS(ODS.LNBALANCE), 0)),
             SG.BACM              = DECODE(ODS.STATUS,'6',0,'8',0,'9',0,NVL(ABS(ODS.LNBALANCE), 0)) + SG.BACM,
             SG.TA500261001       = ODS.RELATEDNO,
             SG.TA500261003       = ODS.CUSTID,
             SG.TA500261004       = ODS.CUSTCIS,
             SG.TA500261008       = ODS.LOANTYPE,
             SG.TA500261013       = ODS.LOANDATE,
             SG.TA500261018       = ODS.LEVELFIVE,
             SG.TA500261016       = ODS.DUEDATE,
             SG.TA500251012       = ODS.LNAMOUNT,
             SG.AVG_TA500251012   = ODS.LNAMOUNT,
             SG.TA500251018       = ODS.AVCHTYPE,
             SG.TA500251014       = ODS.RATE,
             SG.TA500251013       = ODS.LOANTERM,
             SG.TA500251097       = ODS.SURVEYOR,
             SG.TA500251054       = ODS.TA500251054,
             SG.TA290001004       = ODS.CUSTNAME,
             SG.TA290001005       = ODS.REGTYPE,
             SG.TA290001006       = ODS.REGNO,
             SG.TA290008004       = ODS.CREDITLEVEL,
             SG.TA290008009       = ODS.ECUSFLAG,
             SG.TA500271009       = NVL(ODS.AVCHAMT,0),
             SG.TA500271009_CM    = NVL(ODS.AVCHAMT,0) + SG.TA500271009_CM,
             SG.TA500281016       = NVL(ODS.MGAMT,0),
             SG.TA500281016_CM    = NVL(ODS.MGAMT,0) + SG.TA500281016_CM,
             SG.TA500291012       = NVL(ODS.MPAMT,0),
             SG.TA500291012_CM    = NVL(ODS.MPAMT,0) + SG.TA500291012_CM,
             SG.TA500294008       = NVL(ODS.ASSUREAMT,0),
             SG.TA500294008_CM    = NVL(ODS.ASSUREAMT,0) + SG.TA500294008_CM,
             SG.OTHER_AMOUNT      = NVL(ODS.OTHERAMT,0),
             SG.OTHER_AMOUNT_CM   = NVL(ODS.OTHERAMT,0) + SG.OTHER_AMOUNT_CM,
             SG.INVAILD_AMOUNT    = NVL(ODS.INVALIDAMT,0),
             SG.INVAILD_AMOUNT_CM = NVL(ODS.INVALIDAMT,0) + SG.INVAILD_AMOUNT_CM,
             SG.XYAMOUNT          = NVL(ODS.CREDITAMT,0),
             SG.TOTALAMOUNT       = NVL(ODS.TOTALAMT,0),
             SG.MODIFY_DATE       = P_I_DATE,
             SG.XYAMOUNT_CM = ODS.CREDITAMT + SG.XYAMOUNT_CM,
             SG.TOTALAMOUNT_CM = ODS.TOTALAMT + SG.TOTALAMOUNT_CM,
             sg.product_id=ODS.PD
    WHEN NOT MATCHED THEN
      INSERT
        (SG.ACCNO,
         SG.LNCODE,
         SG.MEMNO,
         SG.LNNO,
         SG.ZONENO,
         SG.ACTBRNO,
         SG.SUBCODE,
         SG.CURRTYPE,
         SG.BALANCE,
         SG.BACM,
         SG.TA500261001,
         SG.TA500261003,
         SG.TA500261004,
         SG.TA500261008,
         SG.TA500261013,
         SG.TA500261018,
         SG.TA500261016,
         SG.TA500251012,
         SG.AVG_TA500251012,
         SG.TA500251018,
         SG.TA500251014,
         SG.TA500251013,
         SG.TA500251097,
         SG.TA500251054,
         SG.TA290001004,
         SG.TA290001005,
         SG.TA290001006,
         SG.TA290008004,
         SG.TA290008009,
         SG.TA500271009,
         SG.TA500271009_CM,
         SG.TA500281016,
         SG.TA500281016_CM,
         SG.TA500291012,
         SG.TA500291012_CM,
         SG.TA500294008,
         SG.TA500294008_CM,
         SG.OTHER_AMOUNT,
         SG.OTHER_AMOUNT_CM,
         SG.INVAILD_AMOUNT,
         SG.INVAILD_AMOUNT_CM,
         SG.XYAMOUNT,
         SG.TOTALAMOUNT,
         SG.MODIFY_DATE,
         SG.STATUS,
         SG.ETL_TX_DT,
         SG.XYAMOUNT_CM,
         SG.TOTALAMOUNT_CM,
         --新增by徐敏科目转产品
         SG.PRODUCT_ID,
         SG.ZONENO_FOR_PART)
      VALUES
        (ODS.PCACCNO,

         ODS.PRODCODE,
         ODS.MEMNO,
         ODS.LNNO,
         ODS.ZONENO,

         ODS.PHYBRNO,
         ODS.SUBCODE,
         ODS.CURRTYPE,
         
         DECODE(ODS.STATUS,'6',0,'8',0,'9',0,NVL(ABS(ODS.LNBALANCE), 0)),
         DECODE(ODS.STATUS,'6',0,'8',0,'9',0,NVL(ABS(ods.LNBALANCE), 0)),
         ODS.RELATEDNO,
         ODS.CUSTID,
         ODS.CUSTCIS,
         ODS.LOANTYPE,
         ODS.LOANDATE,
         ODS.LEVELFIVE,
         ODS.DUEDATE,
         ODS.LNAMOUNT,
         ODS.LNAMOUNT,
         ODS.AVCHTYPE,
         ODS.RATE,
         ODS.LOANTERM,
         ODS.SURVEYOR,
         ODS.TA500251054,
         ODS.CUSTNAME,
         ODS.REGTYPE,
         ODS.REGNO,
         ODS.CREDITLEVEL,
         ODS.ECUSFLAG,
         NVL(ODS.AVCHAMT,0),
         NVL(ODS.AVCHAMT,0),
         NVL(ODS.MGAMT,0),
         NVL(ODS.MGAMT,0),
         NVL(ODS.MPAMT,0),
         NVL(ODS.MPAMT,0),
         NVL(ODS.ASSUREAMT,0),
         NVL(ODS.ASSUREAMT,0),
         NVL(ODS.OTHERAMT,0),
         NVL(ODS.OTHERAMT,0),
         NVL(ODS.INVALIDAMT,0),
         NVL(ODS.INVALIDAMT,0),
         NVL(ODS.CREDITAMT,0),
         NVL(ODS.TOTALAMT,0),
         P_I_DATE,
         ODS.STATUS,
         NULL,
         NVL(ODS.CREDITAMT,0),
         NVL(ODS.TOTALAMT,0),
         ODS.PD,
         P_I_ZONENO);

    V_STEP_NO := '2.5';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    SELECT LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')) -
           TO_DATE(SUBSTR(P_I_DATE, 1, 6) || '01', 'yyyymmdd') + 1
      INTO V_MONTH_DAY
      FROM DUAL;


    SELECT MAX(X.QUOTIETY)
      INTO V_X042
      FROM CPMG.PRM_XS042 X
     WHERE X.START_DATE <= P_I_DATE
       AND X.END_DATE > P_I_DATE;

    IF V_X042 IS NULL THEN
      V_X042 := 1;
    END IF;

    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO := '2.6';
    --个人贷款模型中间表关联参数表向个人贷款模型结果表临时表插入数据


    V_STEP_NO := '2.7';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --加载dw_mod表

      INSERT INTO CPMG.dw_mod_grdk
      (ACCNO,
       LNCODE,
       MEMNO,
       LNNO,
       ZONENO,
       ACTBRNO,
       SUBCODE,
       CURRTYPE,
       BALANCE,
       TA500261001,
       PRODUCT_ID3,
       PRODUCT_NAME3,
       TA500261003,
       TA500261004,
       TA500261008,
       TA500261013,
      -- TA500261014,
       TA500261018,
       TA500261016,
       TA500251012,
       TA500251018,
       TA500251014,
       TA500251013,
       TA500271009,
       TA500281016,
       TA500291012,
       TA500294008,
       OTHER_AMOUNT,
       INVAILD_AMOUNT,
       XYAMOUNT,
       TA500251054,
       --TA500270002,
       TOTALAMOUNT,
       TA290001004,
       TA290001005,
       TA290001006,
       TA290008004,
       TA290008009,
       TA500251097,
       DKYQ_YEAR,
       BBPRECENT,
       YYBB,
       SYBB,
       ZCAMOUNT,
       JJZB_XS,
       ECOST,
       START_DATE,
       END_DATE,
       DKYQ_ID,
       ECOST_RJ,
       BAL_RJ,
    --   JJZB_XS_RJ,
       STATUS,
       ZONENO_FOR_PART)
      SELECT/*+ordered*/  SDG.ACCNO,
             SDG.LNCODE,
             SDG.MEMNO,
             SDG.LNNO,
             SDG.ZONENO,
             SDG.ACTBRNO,
             SDG.SUBCODE,
             SDG.CURRTYPE,
             ABS(SDG.BALANCE),
             SDG.TA500261001,
             SDG.PRODUCT_ID,
             PR.PRODUCT_NAME,
             SDG.TA500261003,
             SDG.TA500261004,
             SDG.TA500261008,
             SDG.TA500261013,
           --  SDG.TA500251014,
             nvl(SDG.TA500261018,'1'),
             SDG.TA500261016,
             SDG.TA500251012,
             SDG.TA500251018,
             SDG.TA500251014,
             SDG.TA500251013,
             SDG.TA500271009,
             SDG.TA500281016,
             SDG.TA500291012,
             SDG.TA500294008,
             SDG.OTHER_AMOUNT,
             SDG.INVAILD_AMOUNT,
             SDG.XYAMOUNT,
             SDG.TA500251054,
      --       NULL, --相关合同号/相关合同申请号取不到
             SDG.TOTALAMOUNT,
             SDG.TA290001004,
             SDG.TA290001005,
             SDG.TA290001006,
             SDG.TA290008004,
             SDG.TA290008009,
             SDG.TA500251097,
             TO_DATE(SDG.TA500261016, 'YYYYMMDD') -
                   TO_DATE(P_I_DATE, 'YYYYMMDD'), --贷款期限 年
             x42.bbprecent, --拨备计划比例
             decode(sdg.TOTALAMOUNT,0,0,sdg.balance*x42.bbprecent), --应保有拨备额
             0, --实际保有拨备额 本次不计算
             SDG.BALANCE, --资产净额直接取余额
             --经济资本加权分配系数
             decode(sdg.Totalamount,0,0,(SDG.TA500271009 * X41.BZXS_VALUE +
             SDG.TA500281016 * X41.DYXS_VALUE +
             SDG.TA500291012 * X41.ZYXS_VALUE +
             SDG.TA500294008 * X41.BDXS_VALUE +
             SDG.OTHER_AMOUNT * X41.QTXS_VALUE +
             SDG.INVAILD_AMOUNT * X41.WXXS_VALUE +
             SDG.XYAMOUNT * X41.XYXS_VALUE) *
             NVL(X42.QUOTIETY,
                 V_X042 ----如空 则取这个产品最大的调整系数
                 ) * X43.XS_VALUE / SDG.TOTALAMOUNT),
             SDG.BALANCE *
             decode(sdg.totalamount,0,0,((SDG.TA500271009 * X41.BZXS_VALUE +
             SDG.TA500281016 * X41.DYXS_VALUE +
             SDG.TA500291012 * X41.ZYXS_VALUE +
             SDG.TA500294008 * X41.BDXS_VALUE +
             SDG.OTHER_AMOUNT * X41.QTXS_VALUE +
             SDG.INVAILD_AMOUNT * X41.WXXS_VALUE +
             SDG.XYAMOUNT * X41.XYXS_VALUE) *
             NVL(X42.QUOTIETY, --如空 则取这个产品最大的调整系数
                  V_X042) * X43.XS_VALUE / SDG.TOTALAMOUNT)),
             P_I_DATE,
             '99991231',
             X43.QXDC_ID,
             decode(sdg.totalamount_cm,0,0,(SDG.BACM / V_MONTH_DAY) *
             ((SDG.TA500271009_CM / V_MONTH_DAY * X41.BZXS_VALUE + --日均经济资本计算
             SDG.TA500281016_CM / V_MONTH_DAY * X41.DYXS_VALUE +
             SDG.TA500291012_CM / V_MONTH_DAY * X41.ZYXS_VALUE +
             SDG.TA500294008_CM / V_MONTH_DAY * X41.BDXS_VALUE +
             SDG.OTHER_AMOUNT_CM / V_MONTH_DAY * X41.QTXS_VALUE +
             SDG.INVAILD_AMOUNT_CM / V_MONTH_DAY * X41.WXXS_VALUE +
             SDG.XYAMOUNT_CM / V_MONTH_DAY * X41.XYXS_VALUE) *
             NVL(X42.QUOTIETY, --如空 则取这个产品最大的调整系数
                  V_X042) * X43.XS_VALUE) / (SDG.TOTALAMOUNT_CM/V_MONTH_DAY)),
             SDG.BACM / V_MONTH_DAY, 
             SDG.STATUS,
             SDG.ZONENO_FOR_PART
        FROM CPMG.STG_DAT_GRDK SDG,
             --CPMG.prm_cs042 C42,--计算应提拨备
             --CPMG.PRM_CS044    P44, --个人贷款产品科目对照参数表
             CPMG.PRM_PRODUCT  PR, --一二三级产品参数表
             CPMG.PRM_XS041    X41, --个人贷款信用风险系数表
             (SELECT a.fl5_id fl5_id,a.bbprecent bbprecent,b.quotiety quotiety FROM prm_cs042 a,prm_xs042 b
WHERE a.start_date<=p_i_date
AND a.end_date>p_i_date
AND b.start_date<=p_i_date
AND b.End_Date>p_i_date
AND a.fl5_id=b.qclass)    X42, --个人贷款信用风险贷款质量调节系数表 关联条件不用产品
             CPMG.PRM_XS043    X43 --个人贷款信用风险余期调节系数表
       WHERE   SDG.PRODUCT_ID = PR.PRODUCT_ID
         AND PR.START_DATE <= P_I_DATE
         AND PR.END_DATE > P_I_DATE
         AND SDG.PRODUCT_ID = X41.PRODUCT_ID --信用风险取值
         AND X41.START_DATE <= P_I_DATE
         AND X41.END_DATE > P_I_DATE
         AND SDG.TA500261018 = X42.Fl5_Id(+)
         AND TO_DATE(SDG.TA500261016, 'YYYYMMDD') -
                   TO_DATE(P_I_DATE, 'YYYYMMDD') > DECODE(X43.LEFT_IN,
                               '1',
                               X43.LEFT_VALUE,
                               '2',
                               X43.LEFT_VALUE - 0.000000001)
         AND TO_DATE(SDG.TA500261016, 'YYYYMMDD') -
                   TO_DATE(P_I_DATE, 'YYYYMMDD') < DECODE(X43.RIGHT_IN,
                               '1',
                               X43.RIGHT_VALUE,
                               '2',
                               X43.RIGHT_VALUE + 0.000000001)
         AND X43.START_DATE <= P_I_DATE
         AND X43.END_DATE > P_I_DATE

         --AND SDG.TOTALAMOUNT <> 0
         AND SDG.MODIFY_DATE = P_I_DATE
         AND SDG.ZONENO_FOR_PART=P_I_ZONENO;

    COMMIT;

    P_O_SUCCEED := '0';
    --记载数据处理日志
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_DEAL_GRDK_MON;

  PROCEDURE PROC_GRDK_DM(P_I_DATE IN VARCHAR2, P_I_ZONENO IN VARCHAR2,P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_MONTH_DAY  NUMBER(3); --当月天数
    V_OPEN_DAY   DIC_ALL_KIND.KIND_ID%TYPE;
    --V_RMB_USD    PRM_EXCHANGE_RATE.USCVRATE%TYPE;
    --V_EXCHANG_RATE_US   PRM_EXCHANGE_RATE.USCVRATE%TYPE;
  BEGIN




    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_GRDK_1005.PROC_GRDK_DM';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    SELECT LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')) -
           TO_DATE(SUBSTR(P_I_DATE, 1, 6) || '01', 'yyyymmdd') + 1
      INTO V_MONTH_DAY
      FROM DUAL;




    --徐敏10月版本修改 13年启用新接口表数据
  BEGIN
    SELECT T.KIND_ID
      INTO V_OPEN_DAY
      FROM DIC_ALL_KIND T
     WHERE T.OPERATION_KIND = 'ADJUST_DATE_UG';
  EXCEPTION
    WHEN OTHERS THEN
      V_OPEN_DAY := '20130101';
  END;

  IF P_I_DATE >= V_OPEN_DAY THEN
    NULL;

  ELSE

    --读取系统时间记载开始处理时间
    V_STEP_NO    := '2.2';
    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    --开始删除DM表中数据
    V_STEP_NO    := '2.3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');


   DELETE FROM DM_CS_ZGRDK T WHERE T.ZONENO_FOR_PART=P_I_ZONENO;

    --人民币数据写入DM表
    IF P_I_DATE <> TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE,'YYYYMMDD')),'YYYYMMDD') THEN

    INSERT INTO DM_CS_ZGRDK
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       PRODID,
       CURRTYPE,
       LOANSHAPE,
       CREDITRANK,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04,
       VALUE05,
       VALUE06,
       VALUE07,
       VALUE08,
       VALUE09,
       VALUE010,
       VALUE011,
       VALUE012,
       ZONENO_FOR_PART)
      SELECT/*+full(dmg)*/ DMG.ZONENO,
             DMG.ACTBRNO,
             '0',
             nvl(DMG.DKYQ_ID,'null'),
             nvl(DMG.PRODUCT_ID3,'null'),
             nvl(DMG.CURRTYPE,'null'),
             nvl(DMG.TA500261018,'1'),
             nvl(DMG.TA290008004,'null'),
            decode(sign(SUM(DMG.TA500251012)),             -1,0,SUM(DMG.TA500251012)),
             decode(sign(SUM(DMG.BALANCE)),                 -1,0,SUM(DMG.BALANCE)),
             decode(sign(SUM(DMG.YYBB)),                    -1,0,SUM(DMG.YYBB)),
             decode(sign(SUM(DMG.SYBB)),                    -1,0,SUM(DMG.SYBB)),
             decode(sign(SUM(DMG.ZCAMOUNT)),                -1,0,SUM(DMG.ZCAMOUNT)),
             decode(sign(SUM(DMG.ECOST)),                   -1,0,SUM(DMG.ECOST)),
             decode(sign(SUM(DMG.TA500251012)), -1,0,SUM(DMG.TA500251012)),
             decode(sign(SUM(DMG.BAL_RJ)),                  -1,0,SUM(DMG.BAL_RJ)),
             decode(sign(SUM(DMG.YYBB)),        -1,0,SUM(DMG.YYBB)),
             decode(sign(SUM(DMG.SYBB)),        -1,0,SUM(DMG.SYBB)),
             decode(sign(SUM(DMG.BAL_RJ)),                  -1,0,SUM(DMG.BAL_RJ)),
             decode(sign(SUM(DMG.ECOST_RJ)),                -1,0,SUM(DMG.ECOST_RJ)),
             P_I_ZONENO
        FROM (SELECT * FROM (SELECT DM.*,row_number() over(PARTITION BY DM.ACCNO, DM.LNCODE, DM.MEMNO, DM.LNNO, DM.CURRTYPE ORDER BY START_DATE DESC) seq FROM DW_MOD_GRDK DM
       WHERE DM.START_DATE >=TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(SUBSTR(P_I_DATE,1,6),'YYYYMM'),-1)),'YYYYMMDD')
         AND DM.ZONENO_FOR_PART=P_I_ZONENO) WHERE SEQ=1) DMG
       GROUP BY DMG.ZONENO,
                DMG.ACTBRNO,
                DMG.DKYQ_ID,
                DMG.PRODUCT_ID3,
                DMG.CURRTYPE,
                DMG.TA500261018,
                DMG.TA290008004;


ELSE
       INSERT INTO DM_CS_ZGRDK
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       PRODID,
       CURRTYPE,
       LOANSHAPE,
       CREDITRANK,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04,
       VALUE05,
       VALUE06,
       VALUE07,
       VALUE08,
       VALUE09,
       VALUE010,
       VALUE011,
       VALUE012,
       ZONENO_FOR_PART)
      SELECT/*+full(dmg)*/ DMG.ZONENO,
             DMG.ACTBRNO,
             '0',
             nvl(DMG.DKYQ_ID,'null'),
             nvl(DMG.PRODUCT_ID3,'null'),
             nvl(DMG.CURRTYPE,'null'),
             nvl(DMG.TA500261018,'1'),
             nvl(DMG.TA290008004,'null'),
            decode(sign(SUM(DMG.TA500251012)),             -1,0,SUM(DMG.TA500251012)),
             decode(sign(SUM(DMG.BALANCE)),                 -1,0,SUM(DMG.BALANCE)),
             decode(sign(SUM(DMG.YYBB)),                    -1,0,SUM(DMG.YYBB)),
             decode(sign(SUM(DMG.SYBB)),                    -1,0,SUM(DMG.SYBB)),
             decode(sign(SUM(DMG.ZCAMOUNT)),                -1,0,SUM(DMG.ZCAMOUNT)),
             decode(sign(SUM(DMG.ECOST)),                   -1,0,SUM(DMG.ECOST)),
             decode(sign(SUM(DMG.TA500251012)), -1,0,SUM(DMG.TA500251012)),
             decode(sign(SUM(DMG.BAL_RJ)),                  -1,0,SUM(DMG.BAL_RJ)),
             decode(sign(SUM(DMG.YYBB)),        -1,0,SUM(DMG.YYBB)),
             decode(sign(SUM(DMG.SYBB)),        -1,0,SUM(DMG.SYBB)),
             decode(sign(SUM(DMG.BAL_RJ)),                  -1,0,SUM(DMG.BAL_RJ)),
             decode(sign(SUM(DMG.ECOST_RJ)),                -1,0,SUM(DMG.ECOST_RJ)),
             P_I_ZONENO
        FROM DW_MOD_GRDK DMG
       WHERE DMG.START_DATE = P_I_DATE
       AND DMG.ZONENO_FOR_PART=P_I_ZONENO
         --AND DMG.END_DATE > P_I_DATE
       GROUP BY DMG.ZONENO,
                DMG.ACTBRNO,
                DMG.DKYQ_ID,
                DMG.PRODUCT_ID3,
                DMG.CURRTYPE,
                DMG.TA500261018,
                DMG.TA290008004;


    END IF;

    ---开始折币
    V_STEP_NO    := '2.4';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    ---------------------开始外币折美元-----------------
    INSERT INTO DM_CS_ZGRDK
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       PRODID,
       CURRTYPE,
       LOANSHAPE,
       CREDITRANK,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04,
       VALUE05,
       VALUE06,
       VALUE07,
       VALUE08,
       VALUE09,
       VALUE010,
       VALUE011,
       VALUE012,
       ZONENO_FOR_PART)
      SELECT A.ZONENO,
             A.BRNO,
             '0',
             A.QX,
             A.PRODID,
             '992',
             A.LOANSHAPE,
             A.CREDITRANK,
             SUM(A.VALUE01 * B.USCVRATE),
             SUM(A.VALUE02 * B.USCVRATE),
             SUM(A.VALUE03 * B.USCVRATE),
             SUM(A.VALUE04 * B.USCVRATE),
             SUM(A.VALUE05 * B.USCVRATE),
             SUM(A.VALUE06 * B.USCVRATE),
             SUM(A.VALUE07 * B.USCVRATE),
             SUM(A.VALUE08 * B.USCVRATE),
             SUM(A.VALUE09 * B.USCVRATE),
             SUM(A.VALUE010 * B.USCVRATE),
             SUM(A.VALUE011 * B.USCVRATE),
             SUM(A.VALUE012 * B.USCVRATE),
             P_I_ZONENO
        FROM DM_CS_ZGRDK A, PRM_CURRENCY_RATE B--PRM_EXCHANGE_RATE B
       WHERE A.CURRTYPE <> '001'
        -- AND A.ZONENO = B.ZONE_NO
         AND A.CURRTYPE = B.CURRENCY
       --  AND P_I_DATE >= B.START_DATE
       --  AND P_I_DATE < B.END_DATE
        AND A.ZONENO_FOR_PART=P_I_ZONENO
       GROUP BY A.ZONENO,
                A.BRNO,
                A.QX,
                A.PRODID,
                A.CURRTYPE,
                A.LOANSHAPE,
                A.CREDITRANK;

    V_STEP_NO    := '2.5';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    ----------------开始本外币折人民币----------------
    INSERT INTO DM_CS_ZGRDK
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       PRODID,
       CURRTYPE,
       LOANSHAPE,
       CREDITRANK,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04,
       VALUE05,
       VALUE06,
       VALUE07,
       VALUE08,
       VALUE09,
       VALUE010,
       VALUE011,
       VALUE012,
       ZONENO_FOR_PART)
      SELECT A.ZONENO,
             A.BRNO,
             '0',
             A.QX,
             A.PRODID,
             '994',
             A.LOANSHAPE,
             A.CREDITRANK,
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE01,
                        A.VALUE01 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE02,
                        A.VALUE02 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE03,
                        A.VALUE03 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE04,
                        A.VALUE04 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE05,
                        A.VALUE05 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE06,
                        A.VALUE06 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE07,
                        A.VALUE07 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE08,
                        A.VALUE08 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE09,
                        A.VALUE09 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE010,
                        A.VALUE010 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE011,
                        A.VALUE011 / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.VALUE012,
                        A.VALUE012 / B.USCVRATE)),
             P_I_ZONENO
        FROM DM_CS_ZGRDK A, PRM_CURRENCY_RATE B--PRM_EXCHANGE_RATE B
       WHERE A.CURRTYPE IN ('001', '992')
       --  AND A.ZONENO = B.ZONE_NO
         AND B.CURRENCY = '001'
        /* AND P_I_DATE >= B.START_DATE
         AND P_I_DATE < B.END_DATE*/
        AND A.ZONENO_FOR_PART=P_I_ZONENO
       GROUP BY A.ZONENO,
                A.BRNO,
                A.QX,
                A.PRODID,
                A.CURRTYPE,
                A.LOANSHAPE,
                A.CREDITRANK;



   END IF;

    COMMIT;
    -----------

    -----------------------
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_GRDK_DM;


  PROCEDURE PROC_GRDK_DM_SUM(P_I_DATE IN VARCHAR2,P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_MONTH_DAY  NUMBER(3); --当月天数
    V_OPEN_DAY   DIC_ALL_KIND.KIND_ID%TYPE;
    --V_EXCHANG_RATE_US   PRM_EXCHANGE_RATE.USCVRATE%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_GRDK_1005.PROC_GRDK_DM_SUM';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    SELECT LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')) -
           TO_DATE(SUBSTR(P_I_DATE, 1, 6) || '01', 'yyyymmdd') + 1
      INTO V_MONTH_DAY
      FROM DUAL;



    --读取系统时间记载开始处理时间
    V_STEP_NO    := '2.2';
    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;



    --徐敏10月版本修改 13年启用新接口表数据
  BEGIN
    SELECT T.KIND_ID
      INTO V_OPEN_DAY
      FROM DIC_ALL_KIND T
     WHERE T.OPERATION_KIND = 'ADJUST_DATE_UG';
  EXCEPTION
    WHEN OTHERS THEN
      V_OPEN_DAY := '20130101';
  END;

  IF P_I_DATE >= V_OPEN_DAY THEN
    NULL;

  ELSE

    --开始汇总
    FOR V_FLAG IN 2 .. 5 LOOP
      MERGE INTO DM_CS_ZGRDK DM
      USING (SELECT PRM.BELONG_ZONENO ZONENO,
                    PRM.BELONG_BRNO BRNO,
                    PRM.BELONG_BANK_FLAG BANKFLAG,
                    DM.QX,
                    DM.PRODID,
                    DM.CURRTYPE,
                    DM.LOANSHAPE,
                    DM.CREDITRANK,
                    SUM(DM.VALUE01) VALUE01,
                    SUM(DM.VALUE02) VALUE02,
                    SUM(DM.VALUE03) VALUE03,
                    SUM(DM.VALUE04) VALUE04,
                    SUM(DM.VALUE05) VALUE05,
                    SUM(DM.VALUE06) VALUE06,
                    SUM(DM.VALUE07) VALUE07,
                    SUM(DM.VALUE08) VALUE08,
                    SUM(DM.VALUE09) VALUE09,
                    SUM(DM.VALUE010) VALUE010,
                    SUM(DM.VALUE011) VALUE011,
                    SUM(DM.VALUE012) VALUE012,
                    SUBSTR(PRM.BELONG_ZONENO,1,2) ZONENO_FOR_PART
               FROM DM_CS_ZGRDK DM, PRM_IRA_ORGAN PRM
              WHERE DM.ZONENO = PRM.ZONE_NO
                AND DM.BRNO = PRM.BR_NO
                AND DM.BANKFLAG = PRM.BANK_FLAG
                AND PRM.BELONG_BANK_FLAG = V_FLAG
                AND PRM.BANK_FLAG <> V_FLAG
                AND P_I_DATE >= PRM.START_DATE
                AND P_I_DATE < PRM.END_DATE
              GROUP BY PRM.BELONG_ZONENO,
                       PRM.BELONG_BRNO,
                       PRM.BELONG_BANK_FLAG,
                       DM.QX,
                       DM.PRODID,
                       DM.CURRTYPE,
                       DM.LOANSHAPE,
                       DM.CREDITRANK) TMP
      ON (DM.ZONENO = TMP.ZONENO AND DM.BRNO = TMP.BRNO AND DM.BANKFLAG = TMP.BANKFLAG AND DM.QX = TMP.QX AND DM.PRODID = TMP.PRODID AND DM.CURRTYPE = TMP.CURRTYPE AND DM.LOANSHAPE = TMP.LOANSHAPE AND DM.CREDITRANK = TMP.CREDITRANK)
      WHEN MATCHED THEN
        UPDATE
           SET DM.VALUE01  = DM.VALUE01 + TMP.VALUE01,
               DM.VALUE02  = DM.VALUE02 + TMP.VALUE02,
               DM.VALUE03  = DM.VALUE03 + TMP.VALUE03,
               DM.VALUE04  = DM.VALUE04 + TMP.VALUE04,
               DM.VALUE05  = DM.VALUE05 + TMP.VALUE05,
               DM.VALUE06  = DM.VALUE06 + TMP.VALUE06,
               DM.VALUE07  = DM.VALUE07 + TMP.VALUE07,
               DM.VALUE08  = DM.VALUE08 + TMP.VALUE08,
               DM.VALUE09  = DM.VALUE09 + TMP.VALUE09,
               DM.VALUE010 = DM.VALUE010 + TMP.VALUE010,
               DM.VALUE011 = DM.VALUE011 + TMP.VALUE011,
               DM.VALUE012 = DM.VALUE012 + TMP.VALUE012
      WHEN NOT MATCHED THEN
        INSERT
          (ZONENO,
           BRNO,
           BANKFLAG,
           QX,
           PRODID,
           CURRTYPE,
           LOANSHAPE,
           CREDITRANK,
           VALUE01,
           VALUE02,
           VALUE03,
           VALUE04,
           VALUE05,
           VALUE06,
           VALUE07,
           VALUE08,
           VALUE09,
           VALUE010,
           VALUE011,
           VALUE012,
           ZONENO_FOR_PART)
        VALUES
          (TMP.ZONENO,
           TMP.BRNO,
           TMP.BANKFLAG,
           TMP.QX,
           TMP.PRODID,
           TMP.CURRTYPE,
           TMP.LOANSHAPE,
           TMP.CREDITRANK,
           TMP.VALUE01,
           TMP.VALUE02,
           TMP.VALUE03,
           TMP.VALUE04,
           TMP.VALUE05,
           TMP.VALUE06,
           TMP.VALUE07,
           TMP.VALUE08,
           TMP.VALUE09,
           TMP.VALUE010,
           TMP.VALUE011,
           TMP.VALUE012,
           SUBSTR(TMP.ZONENO,1,2));
    END LOOP;

    END IF;

    COMMIT;
    -----------

    -----------------------
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_GRDK_DM_SUM;

  PROCEDURE PROC_RESUME_GRDK(P_I_DATE    IN VARCHAR2,
                             P_I_ZONENO  IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_COUNT      VARCHAR2(10); --记录数
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_RESUME_GRDK';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';

    --从模型结果表中删除当日日批错误数据
    DELETE FROM CPMG.DW_MOD_GRDK A WHERE A.START_DATE >= P_I_DATE;

    V_STEP_NO    := '2.2';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --将结束日期为恢复日-1的记录置为99991231
    UPDATE CPMG.DW_MOD_GRDK A
       SET A.END_DATE = '99991231'
     WHERE A.END_DATE =
           TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD');

    V_STEP_NO    := '2.3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --从中间表中删除当日日批错误数据
    DELETE FROM CPMG.STG_DAT_GRDK A WHERE A.MODIFY_DATE >= P_I_DATE;
    COMMIT;

    V_STEP_NO    := '2.4';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --判断错误恢复日期是否在备份表中存在
    SELECT COUNT(*)
      INTO V_COUNT
      FROM CPMG.STG_BAK_GRDK A
     WHERE A.DATA_DATE = P_I_DATE;

    V_STEP_NO    := '2.5';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    --回退BAK表当日修改的数据进STG_DAT表
    IF V_COUNT <> 0 THEN
      INSERT INTO CPMG.STG_DAT_GRDK
        (ACCNO,
         LNCODE,
         MEMNO,
         LNNO,
         ZONENO,
         ACTBRNO,
         SUBCODE,
         CURRTYPE,
         BALANCE,
         BACM,
         TA500261001,
         TA500261003,
         TA500261004,
         TA500261008,
         TA500261013,
         TA500261018,
         TA500261016,
         TA500251012,
         TA500251018,
         TA500251014,
         TA500251013,
         TA500251097,
         TA500251054,
         TA290001004,
         TA290001005,
         TA290001006,
         TA290008004,
         TA290008009,
         TA500271009,
         TA500271009_CM,
         TA500281016,
         TA500281016_CM,
         TA500291012,
         TA500291012_CM,
         TA500294008,
         TA500294008_CM,
         OTHER_AMOUNT,
         OTHER_AMOUNT_CM,
         INVAILD_AMOUNT,
         INVAILD_AMOUNT_CM,
         XYAMOUNT,
         TOTALAMOUNT,
         MODIFY_DATE,
         PRODUCT_ID,
         ZONENO_FOR_PART)
        SELECT A.ACCNO,
               A.LNCODE,
               A.MEMNO,
               A.LNNO,
               A.ZONENO,
               A.ACTBRNO,
               A.SUBCODE,
               A.CURRTYPE,
               A.BALANCE,
               A.BACM,
               A.TA500261001,
               A.TA500261003,
               A.TA500261004,
               A.TA500261008,
               A.TA500261013,
               A.TA500261018,
               A.TA500261016,
               A.TA500251012,
               A.TA500251018,
               A.TA500251014,
               A.TA500251013,
               A.TA500251097,
               A.TA500251054,
               A.TA290001004,
               A.TA290001005,
               A.TA290001006,
               A.TA290008004,
               A.TA290008009,
               A.TA500271009,
               A.TA500271009_CM,
               A.TA500281016,
               A.TA500281016_CM,
               A.TA500291012,
               A.TA500291012_CM,
               A.TA500294008,
               A.TA500294008_CM,
               A.OTHER_AMOUNT,
               A.OTHER_AMOUNT_CM,
               A.INVAILD_AMOUNT,
               A.INVAILD_AMOUNT_CM,
               A.XYAMOUNT,
               A.TOTALAMOUNT,
               A.MODIFY_DATE,
               A.PRODUCT_ID,
               A.ZONENO_FOR_PART
          FROM CPMG.STG_BAK_GRDK A
         WHERE A.DATA_DATE = P_I_DATE;
      COMMIT;
    END IF;

    P_O_SUCCEED := '0';
    COMMIT;
    --记载数据处理日志
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_RESUME_GRDK;


  PROCEDURE PROC_DEAL_GRDK_BAK(P_I_DATE IN VARCHAR2,P_I_ZONENO IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_OPEN_DAY   DIC_ALL_KIND.KIND_ID%TYPE;
    --V_MONTH_DAY  NUMBER(3); --当月天数
    --V_X042       CPMG.PRM_XS042.QUOTIETY%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_GRDK_1005.PROC_DEAL_GRDK_BAK';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';

    --徐敏10月版本修改 13年启用新接口表数据
  BEGIN
    SELECT T.KIND_ID
      INTO V_OPEN_DAY
      FROM DIC_ALL_KIND T
     WHERE T.OPERATION_KIND = 'ADJUST_DATE_UG';
  EXCEPTION
    WHEN OTHERS THEN
      V_OPEN_DAY := '20130101';
  END;

  IF P_I_DATE >= V_OPEN_DAY THEN
    NULL;

  ELSE


    IF p_i_date =
               TO_CHAR (LAST_DAY (TO_DATE (p_i_date, 'yyyymmdd')), 'YYYYMMDD')
     THEN
     --将上月末数据的enddate 更新为 本月初
     UPDATE CPMG.DW_MOD_GRDK DMG SET DMG.END_DATE =TO_CHAR(LAST_DAY(TO_DATE(SUBSTR(P_I_DATE,1,6),'YYYYMM')),'YYYYMMDD')
            WHERE DMG.START_DATE=TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(SUBSTR(P_I_DATE,1,6),'YYYYMM'),-1)),'YYYYMMDD')
            AND DMG.ZONENO_FOR_PART=P_I_ZONENO;

     DELETE FROM CPMG.DW_MOD_GRDK DMG
     WHERE DMG.START_DATE>=SUBSTR(P_I_DATE,1,6)||'01'
     AND DMG.START_DATE<= TO_CHAR(LAST_DAY(TO_DATE(SUBSTR(P_I_DATE,1,6),'YYYYMM'))-1,'YYYYMMDD')
     AND DMG.ZONENO_FOR_PART=P_I_ZONENO;

     END IF;

  END IF;
     COMMIT;

    P_O_SUCCEED := '0';
    --记载数据处理日志
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_DEAL_GRDK_BAK;


  FUNCTION FUNC_prm_cs044(I_DATEDATE    IN VARCHAR2,
                          IN_SUBJECT_CODE IN VARCHAR2)
    RETURN VARCHAR2 IS

    OUT_PRODUCT prm_cs044.Product_Id%TYPE; --
  BEGIN

    SELECT MAX(C44.PRODUCT_ID)
      INTO OUT_PRODUCT
      FROM CPMG.PRM_CS044 C44
     WHERE C44.SUBJECT_CODE = IN_SUBJECT_CODE
       AND C44.SUBJECT_TYPE = '2'
       AND C44.SUBJECT_APP = 1
       AND C44.START_DATE <= I_DATEDATE
       AND C44.END_DATE > I_DATEDATE;

    IF OUT_PRODUCT IS NULL THEN

      SELECT MAX(C44.PRODUCT_ID)
      INTO OUT_PRODUCT
      FROM CPMG.PRM_CS044 C44
     WHERE C44.SUBJECT_CODE = SUBSTR(IN_SUBJECT_CODE,1,4)
       AND C44.SUBJECT_TYPE = '1'
       AND C44.SUBJECT_APP = 1
       AND C44.START_DATE <= I_DATEDATE
       AND C44.END_DATE > I_DATEDATE;

      RETURN OUT_PRODUCT;

    ELSE
      RETURN OUT_PRODUCT;
    END IF;
  EXCEPTION
    WHEN OTHERS THEN
      RETURN NULL;
  END;
end PACK_DEAL_GRDK_P;
