  ------------------------------------------------------
  PROCEDURE PROC_DEAL_PJTX(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    -- V_ZL     PRM_XSCZ2.SUM_COEF%TYPE; --总量调节系数
    V_DAY NUMBER;
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_YHK_1005.PROC_DEAL_PJTX';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------

    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;

    SELECT LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')) -
           TO_DATE(SUBSTR(P_I_DATE, 1, 6) || '01', 'yyyymmdd') + 1
      INTO V_DAY
      FROM DUAL;

    V_STEP_NO := '2.1';

     --去逐渐重复
       delete from ods_tmp_pjtx a
  where a.rowid <>
  (select max(b.rowid) from ods_tmp_pjtx b
    where a.innerno=b.innerno

      );
      commit;

    --月初更新月积数字段
    IF SUBSTR(P_I_DATE, 7, 2) = '01' THEN
      UPDATE STG_DAT_PJTX STG SET STG.BILLAMT_CM = 0;
    END IF;
     DELETE FROM STG_BAK_PJTX A WHERE A.data_DATE >= P_I_DATE;
    --备份
    INSERT INTO STG_BAK_PJTX
      (ZONENO,
       ACTBRNO,
       INNERNO,
       BILLNO,
       SUBCODE,
       BILLAMT,
       BILLAMT_CM,
       BILLTYPE,
       BUYTYPE,
       FIRSTTYPE,
       DRAWERBANK,
       HOLDER,
       HOLDERTYPE,
       CREDITLEVEL,
       MANAGERNO,
       LEVELFIVE,
       DISCOUNTDATE,
       REALMATURITY,
       RETMATURITY,
       CAPCOST,
       INTINCOME,
       MODIFY_DATE,
       QXDC_ID,
       DATA_DATE,
       bearer_name,
       croup_num,
       croup_name)
      SELECT STG.ZONENO,
             STG.ACTBRNO,
             STG.INNERNO,
             STG.BILLNO,
             STG.SUBCODE,
             STG.BILLAMT,
             STG.BILLAMT_CM,
             STG.BILLTYPE,
             STG.BUYTYPE,
             STG.FIRSTTYPE,
             STG.DRAWERBANK,
             STG.HOLDER,
             STG.HOLDERTYPE,
             STG.CREDITLEVEL,
             STG.MANAGERNO,
             STG.LEVELFIVE,
             STG.DISCOUNTDATE,
             STG.REALMATURITY,
             STG.RETMATURITY,
             STG.CAPCOST,
             STG.INTINCOME,
             STG.MODIFY_DATE,
             STG.QXDC_ID,
             P_I_DATE,
             stg.bearer_name,
             stg.croup_num,
             stg.croup_name
        FROM STG_DAT_PJTX STG, ODS_TMP_PJTX ODS
       WHERE STG.INNERNO = ODS.INNERNO
       AND STG.MODIFY_DATE=TO_CHAR(TO_DATE(P_I_DATE,'YYYYMMDD')-1,'YYYYMMDD');

    --ods表数据进stg_dat表
    MERGE INTO STG_DAT_PJTX STG
    USING (SELECT ZONENO,
                  ACTBRNO,
                  INNERNO,
                  BILLNO,
                  SUBCODE,
                  BILLAMT,
                  BILLTYPE,
                  BUYTYPE,
                  FIRSTTYPE,
                  DRAWERBANK,
                  HOLDER,
                  HOLDERTYPE,
                  CREDITLEVEL,
                  MANAGERNO,
                  LEVELFIVE,
                  DISCOUNTDATE,
                  REALMATURITY,
                  RETMATURITY,
                  CAPCOST,
                  INTINCOME,
                  PRM.QXDC_ID,
                  bearer_name,
                  croup_num,
                  croup_name
             FROM ODS_TMP_PJTX ODS, PRM_CSPJ2 PRM
            WHERE PRM.START_DATE <= P_I_DATE
              AND PRM.END_DATE > P_I_DATE
              AND TO_DATE(REALMATURITY, 'yyyymmdd') -
                  TO_DATE(P_I_DATE, 'yyyymmdd') >
                  DECODE(PRM.LEFT_IN,
                         '1',
                         PRM.LEFT_VALUE ,
                         '2',
                         PRM.LEFT_VALUE-1)
              AND TO_DATE(REALMATURITY, 'yyyymmdd') -
                  TO_DATE(P_I_DATE, 'yyyymmdd') <
                  DECODE(PRM.RIGHT_IN,
                         '1',
                         PRM.RIGHT_VALUE ,
                         '2',
                         PRM.RIGHT_VALUE+1)) TMP
    ON (STG.INNERNO = TMP.INNERNO)
    WHEN MATCHED THEN
      UPDATE
         SET STG.ZONENO  =  CASE TMP.ZONENO || TMP.actBRNO
--               WHEN '13110400' THEN
--                '1318'
--               WHEN '13110380' THEN
--                '1318'
--               WHEN '13110430' THEN
--                '1318'
--               WHEN '13113228' THEN
--                '1318'
               WHEN '23074881' THEN
                '2321'
               WHEN '23074921' THEN
                '2321'
               WHEN '23074931' THEN
                '2321'
               WHEN '23074891' THEN
                '2321'
               ELSE
                TMP.ZONENO
             END,
             STG.ACTBRNO = TMP.ACTBRNO,
             -- STG.INNERNO      = TMP.INNERNO,
             STG.BILLNO       = TMP.BILLNO,
             STG.SUBCODE      = TMP.SUBCODE,
             STG.BILLAMT      = TMP.BILLAMT,
             STG.BILLAMT_CM   = STG.BILLAMT_CM + TMP.BILLAMT,
             STG.BILLTYPE     = TMP.BILLTYPE,
             STG.BUYTYPE      = TMP.BUYTYPE,
             STG.FIRSTTYPE    = TMP.FIRSTTYPE,
             STG.DRAWERBANK   = TMP.DRAWERBANK,
             STG.HOLDER       = TMP.HOLDER,
             STG.HOLDERTYPE   = TMP.HOLDERTYPE,
             STG.CREDITLEVEL  = TMP.CREDITLEVEL,
             STG.MANAGERNO    = TMP.MANAGERNO,
             STG.LEVELFIVE    = TMP.LEVELFIVE,
             STG.DISCOUNTDATE = TMP.DISCOUNTDATE,
             STG.REALMATURITY = TMP.REALMATURITY,
             STG.RETMATURITY  = TMP.RETMATURITY,
             STG.CAPCOST      = TMP.CAPCOST,
             STG.INTINCOME    = TMP.INTINCOME,
             STG.MODIFY_DATE  = P_I_DATE,
             STG.QXDC_ID      = TMP.QXDC_ID,
             stg.bearer_name=tmp.bearer_name,
             stg.croup_num=tmp.croup_num,
             stg.croup_name=tmp.croup_name
    WHEN NOT MATCHED THEN
      INSERT
        (STG.ZONENO,
         STG.ACTBRNO,
         STG.INNERNO,
         STG.BILLNO,
         STG.SUBCODE,
         STG.BILLAMT,
         STG.BILLAMT_CM,
         STG.BILLTYPE,
         STG.BUYTYPE,
         STG.FIRSTTYPE,
         STG.DRAWERBANK,
         STG.HOLDER,
         STG.HOLDERTYPE,
         STG.CREDITLEVEL,
         STG.MANAGERNO,
         STG.LEVELFIVE,
         STG.DISCOUNTDATE,
         STG.REALMATURITY,
         STG.RETMATURITY,
         STG.CAPCOST,
         STG.INTINCOME,
         STG.MODIFY_DATE,
         STG.QXDC_ID,
         stg.bearer_name,
         stg.croup_num,
         stg.croup_name)
      VALUES
        (CASE TMP.ZONENO || TMP.actBRNO
--               WHEN '13110400' THEN
--                '1318'
--               WHEN '13110380' THEN
--                '1318'
--               WHEN '13110430' THEN
--                '1318'
--               WHEN '13113228' THEN
--                '1318'
               WHEN '23074881' THEN
                '2321'
               WHEN '23074921' THEN
                '2321'
               WHEN '23074931' THEN
                '2321'
               WHEN '23074891' THEN
                '2321'
               ELSE
                TMP.ZONENO
             END,
         TMP.ACTBRNO,
         TMP.INNERNO,
         TMP.BILLNO,
         TMP.SUBCODE,
         TMP.BILLAMT,
         TMP.BILLAMT,
         TMP.BILLTYPE,
         TMP.BUYTYPE,
         TMP.FIRSTTYPE,
         TMP.DRAWERBANK,
         TMP.HOLDER,
         TMP.HOLDERTYPE,
         TMP.CREDITLEVEL,
         TMP.MANAGERNO,
         TMP.LEVELFIVE,
         TMP.DISCOUNTDATE,
         TMP.REALMATURITY,
         TMP.RETMATURITY,
         TMP.CAPCOST,
         TMP.INTINCOME,
         P_I_DATE,
         TMP.QXDC_ID,
         tmp.bearer_name,
         tmp.croup_num,
         tmp.croup_name);
         -------计算月积数
        /* UPDATE STG_DAT_PJTX stg SET stg.billamt_cm=nvl(stg.billamt_cm,0)+nvl(stg.billamt,0)
         WHERE stg.MODIFY_DATE=P_I_DATE;*/
    --------------计算经济资本
        EXECUTE IMMEDIATE 'TRUNCATE TABLE CPMG.STG_TMP_PJTX';
    INSERT INTO STG_TMP_PJTX
      (ZONENO,
       ACTBRNO,
       INNERNO,
       BILLNO,
       SUBCODE,
       BILLAMT,
       BILLAMT_CM,
       BILLTYPE,
       BUYTYPE,
       FIRSTTYPE,
       DRAWERBANK,
       HOLDER,
       HOLDERTYPE,
       CREDITLEVEL,
       MANAGERNO,
       LEVELFIVE,
       DISCOUNTDATE,
       REALMATURITY,
       RETMATURITY,
       CAPCOST,
       INTINCOME,
       PRODUCT,
       QX,
       XSPJ1,
       XSPJ2,
       XSPJ3,
       XS,
       EC,
       EC_CM,
       START_DATE,
       END_DATE,
       bearer_name,
       croup_num,
       croup_name)
      SELECT STG.ZONENO,
             STG.ACTBRNO,
             STG.INNERNO,
             STG.BILLNO,
             STG.SUBCODE,
             STG.BILLAMT,
             STG.BILLAMT_CM / V_DAY,
             STG.BILLTYPE,
             STG.BUYTYPE,
             STG.FIRSTTYPE,
             STG.DRAWERBANK,
             STG.HOLDER,
             STG.HOLDERTYPE,
             STG.CREDITLEVEL,
             STG.MANAGERNO,
             STG.LEVELFIVE,
             STG.DISCOUNTDATE,
             STG.REALMATURITY,
             STG.RETMATURITY,
             STG.CAPCOST,
             STG.INTINCOME,
             C71.PRODUCT_ID,
             STG.QXDC_ID,
             X71.PAR_COEF,
             X73.QUOTIETY,
             DECODE(STG.HOLDERTYPE, '1', X74.BQUOTIETY, X74.EQUOTIETY),
             X71.PAR_COEF * X73.QUOTIETY *
             DECODE(STG.HOLDERTYPE, '1', X74.BQUOTIETY, X74.EQUOTIETY),
             STG.BILLAMT * X71.PAR_COEF * X73.QUOTIETY *
             DECODE(STG.HOLDERTYPE, '1', X74.BQUOTIETY, X74.EQUOTIETY),
             STG.BILLAMT_CM * X71.PAR_COEF * X73.QUOTIETY *
             DECODE(STG.HOLDERTYPE, '1', X74.BQUOTIETY, X74.EQUOTIETY) /
             V_DAY,
             P_I_DATE,
             --20101101增存量修改
             P_I_DATE,
             stg.bearer_name,
             stg.croup_num,
             stg.croup_name
        FROM STG_DAT_PJTX STG,
             PRM_CS071    C71,
             PRM_XS073    X73,
             PRM_XS071    X71,
             PRM_XS074    X74
       WHERE DECODE(C71.SUBJECT_TYPE,
                    1,
                    SUBSTR(STG.SUBCODE, 1, 4),
                    STG.SUBCODE) = C71.SUBJECT_CODE
         AND C71.PRODUCT_ID = X71.PRODUCT_ID
         AND STG.QXDC_ID = X71.QXDC_ID
         AND STG.LEVELFIVE = X73.QCLASS
         AND STG.CREDITLEVEL = X74.QCLASS
         AND C71.START_DATE <= P_I_DATE
         AND C71.END_DATE > P_I_DATE
         AND X71.START_DATE <= P_I_DATE
         AND X71.END_DATE > P_I_DATE
         AND X73.START_DATE <= P_I_DATE
         AND X73.END_DATE > P_I_DATE
         AND X74.START_DATE <= P_I_DATE
         AND X74.END_DATE > P_I_DATE
         AND STG.MODIFY_DATE = P_I_DATE;
    --月末特殊处理
     IF p_i_date =
       TO_CHAR(LAST_DAY(TO_DATE(p_i_date, 'yyyymmdd')), 'YYYYMMDD') THEN
      ---删除增量的数据，只保留一份月末存量
      delete from dw_mod_pjtx
       where start_date >= substr(p_i_date, 1, 6) || '01'
         and start_date < p_i_date;
     
    end if;
   
    INSERT INTO DW_MOD_PJTX
      (ZONENO,
       ACTBRNO,
       INNERNO,
       BILLNO,
       SUBCODE,
       BILLAMT,
       BILLAMT_CM,
       BILLTYPE,
       BUYTYPE,
       FIRSTTYPE,
       DRAWERBANK,
       HOLDER,
       HOLDERTYPE,
       CREDITLEVEL,
       MANAGERNO,
       LEVELFIVE,
       DISCOUNTDATE,
       REALMATURITY,
       RETMATURITY,
       CAPCOST,
       INTINCOME,
       PRODUCT,
       QX,
       XSPJ1,
       XSPJ2,
       XSPJ3,
       XS,
       EC,
       EC_CM,
       START_DATE,
       END_DATE,
       bearer_name,
       croup_num,
       croup_name)
      SELECT ZONENO,
             ACTBRNO,
             INNERNO,
             BILLNO,
             SUBCODE,
             BILLAMT,
             BILLAMT_CM,
             BILLTYPE,
             BUYTYPE,
             FIRSTTYPE,
             DRAWERBANK,
             HOLDER,
             HOLDERTYPE,
             CREDITLEVEL,
             MANAGERNO,
             LEVELFIVE,
             DISCOUNTDATE,
             REALMATURITY,
             RETMATURITY,
             CAPCOST,
             INTINCOME,
             PRODUCT,
             QX,
             XSPJ1,
             XSPJ2,
             XSPJ3,
             XS,
             EC,
             EC_CM,
             START_DATE,
             END_DATE,
             bearer_name,
             croup_num,
             croup_name
        FROM STG_TMP_PJTX;
    COMMIT;
    
    P_O_SUCCEED := '0';
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_DEAL_PJTX;
  --------------------
  PROCEDURE PROC_DEAL_PJTXWB(P_I_DATE    IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS
    V_DAY NUMBER;
    V_XS  PRM_XS071.PAR_COEF%TYPE;
    V_ID  PRM_XS071.QXDC_ID%TYPE;
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_YHK_1005.PROC_DEAL_PJTXWB';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --读取最大系数
    V_STEP_NO := '2.1';
    SELECT MAX(PAR_COEF)
      INTO V_XS
      FROM PRM_XS071 PRM
     WHERE P_I_DATE >= PRM.START_DATE
       AND P_I_DATE < PRM.END_DATE;
    --读取该月的天数
    SELECT EXTRACT(DAY FROM LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')))
      INTO V_DAY
      FROM DUAL;
    --读取某个期限档次编号
    SELECT QXDC_ID
      INTO V_ID
      FROM PRM_XS071 PRM
     WHERE P_I_DATE >= PRM.START_DATE
       AND P_I_DATE < PRM.END_DATE
       AND ROWNUM = 1;
    --------------------------------------------------------------------------------------------

    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    --
    DELETE FROM  DW_MOD_BMSBILL_WB dw WHERE dw.data_date>=p_i_date;
    INSERT INTO DW_MOD_BMSBILL_WB
      (ZONENO,
       BRNO,
       DATA_DATE,
       CURRTYPE,
       PRODUCT,
       BALANCE,
       QUOTIETY,
       CAPITAL,
       AVG_BALANCE,
       AVG_CAPITAL,
       BANKFLAG)
      SELECT ZONENO,
             BRNO,
             P_I_DATE,
             CURRTYPE,
             PRODUCT_ID,
             SUM(VALUE01),
             VALUE_FXX,
             SUM(VALUE02),
             SUM(VALUE03),
             SUM(VALUE04),
             BANKFLAG
        FROM (SELECT STG.ZONENO,
                     STG.BRNO,
                     STG.CURRTYPE,
                     PRC.PRODUCT_ID,
                     SUM(STG.TDDRBAL * PRC.SUBJECT_APP) VALUE01,
                     NVL(PRX.PAR_COEF, V_XS) VALUE_FXX,
                     SUM(STG.TDDRBAL * NVL(PRX.PAR_COEF, V_XS) *
                         PRC.SUBJECT_APP) VALUE02,
                     SUM(STG.SUMDRBAL * PRC.SUBJECT_APP / V_DAY) VALUE03,
                     SUM(STG.SUMDRBAL * PRC.SUBJECT_APP / V_DAY *
                         NVL(PRX.PAR_COEF, V_XS)) VALUE04,
                     STG.BANKFLAG
                FROM STG_DAT_NFGNLED STG, PRM_CS071 PRC, PRM_XS071 PRX
               WHERE DECODE(PRC.SUBJECT_TYPE,
                            1,
                            SUBSTR(STG.SUBCODE, 1, 4),
                            STG.SUBCODE) = PRC.SUBJECT_CODE
                 AND PRC.PRODUCT_ID = PRX.PRODUCT_ID(+)
                 AND P_I_DATE >= PRC.START_DATE
                 AND P_I_DATE < PRC.END_DATE
                 AND P_I_DATE >= PRX.START_DATE(+)
                 AND P_I_DATE < PRX.END_DATE(+)
                 AND STG.SUBCODE = '161004'
                 AND PRX.QXDC_ID = V_ID
                 AND stg.currtype NOT IN ('992','994')
               GROUP BY STG.ZONENO,
                        STG.BRNO,
                        STG.CURRTYPE,
                        PRC.PRODUCT_ID,
                        NVL(PRX.PAR_COEF, V_XS),
                        SUBSTR(STG.SUBCODE, 1, 4),
                        STG.BANKFLAG)
       GROUP BY ZONENO, BRNO, CURRTYPE, PRODUCT_ID, BANKFLAG, VALUE_FXX;
    COMMIT;

    -----------
    COMMIT;

    -----------------------
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_DEAL_PJTXWB;
  ---------------------
  PROCEDURE PROC_PJTX_DM(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    V_FLAG NUMBER(1) := 3; --行级别
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_YHK_1005.PROC_PJTX_DM';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------

    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    --开始删除DM表中数据
    EXECUTE IMMEDIATE 'TRUNCATE TABLE DM_CS_ZPJTX';
    --把操作风险数据插入dm表
    INSERT INTO DM_CS_ZPJTX
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       CURRTYPE,
       PRODCODE,
       LOANSHAPE,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04)
      SELECT DW.ZONENO,
             DW.ACTBRNO,
             '2',
             DW.QX,
             '001',
             DW.PRODUCT,
             DW.LEVELFIVE,
             decode(sign(SUM(DW.BILLAMT)),-1,0,SUM(DW.BILLAMT)),
             decode(sign(SUM(DW.EC)),-1,0,SUM(DW.EC)),
             decode(sign(SUM(DW.BILLAMT_CM)),-1,0,SUM(DW.BILLAMT_CM)),
             decode(sign(SUM(DW.EC_CM)),-1,0,SUM(DW.EC_CM))
        FROM DW_MOD_PJTX DW
       WHERE DW.START_DATE = P_I_DATE
         --AND DW.END_DATE = P_I_DATE
       GROUP BY DW.ZONENO, DW.ACTBRNO, DW.QX, DW.PRODUCT, DW.LEVELFIVE;
    ------------
    INSERT INTO DM_CS_ZPJTX
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       CURRTYPE,
       PRODCODE,
       LOANSHAPE,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04)
      SELECT DW.ZONENO,
             DW.BRNO,
             DW.BANKFLAG,
             '001',
             DW.CURRTYPE,
             DW.PRODUCT,
             '1',
             decode(sign(SUM(DW.BALANCE)),-1,0,SUM(DW.BALANCE)),
             decode(sign(SUM(DW.CAPITAL)),-1,0,SUM(DW.CAPITAL)),
             decode(sign(SUM(DW.AVG_BALANCE)),-1,0,SUM(DW.AVG_BALANCE)),
             decode(sign(SUM(DW.AVG_CAPITAL)),-1,0,SUM(DW.AVG_CAPITAL))
        FROM DW_MOD_BMSBILL_WB DW
       WHERE DW.DATA_DATE = P_I_DATE
       GROUP BY DW.ZONENO, DW.BRNO, DW.CURRTYPE, DW.PRODUCT, DW.BANKFLAG;

       --外币折美元
          INSERT INTO DM_CS_zpjtx
        (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       CURRTYPE,
       PRODCODE,
       LOANSHAPE,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               a.qx,
               '992',
               a.prodcode,
               a.loanshape,
               SUM(A.value01 * B.USCVRATE),
               SUM(A.value02 * B.USCVRATE),
               SUM(A.value03 * B.USCVRATE),
               SUM(A.value04 * B.USCVRATE)
          FROM DM_CS_zpjtx A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE <> '001'
           AND A.ZONENO = B.ZONE_NO
           AND A.CURRTYPE = B.CURRENCY
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG,qx, PRODCODE,loanshape;
    --本外币折人民币

    INSERT INTO DM_CS_ZPJTX
      (ZONENO,
       BRNO,
       BANKFLAG,
       QX,
       CURRTYPE,
       PRODCODE,
       LOANSHAPE,
       VALUE01,
       VALUE02,
       VALUE03,
       VALUE04)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               a.qx,
               '994',
               A.PRODCODE,
               a.loanshape,
               SUM(DECODE(A.CURRTYPE, '001', A.Value01, A.Value01 / B.USCVRATE)),
               SUM(DECODE(A.CURRTYPE, '001', A.Value02, A.Value02 / B.USCVRATE)),
               SUM(DECODE(A.CURRTYPE, '001', A.Value03, A.Value03 / B.USCVRATE)),
               SUM(DECODE(A.CURRTYPE, '001', A.Value04, A.Value04 / B.USCVRATE))
          FROM DM_CS_zpjtx A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE IN ('001', '992')
           AND A.ZONENO = B.ZONE_NO
           AND B.CURRENCY = '001'
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, qx,PRODCODE,loanshape;

    ---进行机构汇总
    --开始汇总
    FOR V_FLAG IN 3 .. 5 LOOP
      MERGE INTO DM_CS_ZPJTX DM
      USING (SELECT PRM.BELONG_ZONENO ZONENO,
                    PRM.BELONG_BRNO BRNO,
                    PRM.BELONG_BANK_FLAG BANKFLAG,
                    DM.QX,
                    DM.PRODCODE,
                    DM.CURRTYPE,
                    DM.LOANSHAPE,
                    SUM(DM.VALUE01) VALUE01,
                    SUM(DM.VALUE02) VALUE02,
                    SUM(DM.VALUE03) VALUE03,
                    SUM(DM.VALUE04) VALUE04
               FROM DM_CS_ZPJTX DM, PRM_IRA_ORGAN PRM
              WHERE DM.ZONENO = PRM.ZONE_NO
                AND DM.BRNO = PRM.BR_NO
                AND DM.BANKFLAG = PRM.BANK_FLAG
                AND PRM.BELONG_BANK_FLAG = V_FLAG
                AND PRM.BANK_FLAG <> V_FLAG
                AND P_I_DATE >= PRM.START_DATE
                AND P_I_DATE < PRM.END_DATE
              GROUP BY PRM.BELONG_ZONENO,
                       PRM.BELONG_BRNO,
                       PRM.BELONG_BANK_FLAG,
                       DM.QX,
                       DM.PRODCODE,
                       DM.CURRTYPE,
                       DM.LOANSHAPE) TMP
      ON (DM.ZONENO = TMP.ZONENO AND DM.BRNO = TMP.BRNO AND DM.BANKFLAG = TMP.BANKFLAG AND DM.QX = TMP.QX AND DM.PRODCODE = TMP.PRODCODE AND DM.CURRTYPE = TMP.CURRTYPE AND DM.LOANSHAPE = TMP.LOANSHAPE)
      WHEN MATCHED THEN
        UPDATE
           SET DM.VALUE01 = DM.VALUE01 + TMP.VALUE01,
               DM.VALUE02 = DM.VALUE02 + TMP.VALUE02,
               DM.VALUE03 = DM.VALUE03 + TMP.VALUE03,
               DM.VALUE04 = DM.VALUE04 + TMP.VALUE04
      WHEN NOT MATCHED THEN
        INSERT
          (DM.ZONENO,
           DM.BRNO,
           DM.BANKFLAG,
           DM.QX,
           DM.PRODCODE,
           DM.CURRTYPE,
           DM.LOANSHAPE,
           DM.VALUE01,
           DM.VALUE02,
           DM.VALUE03,
           DM.VALUE04)
        VALUES
          (TMP.ZONENO,
           TMP.BRNO,
           TMP.BANKFLAG,
           TMP.QX,
           TMP.PRODCODE,
           TMP.CURRTYPE,
           TMP.LOANSHAPE,
           TMP.VALUE01,
           TMP.VALUE02,
           TMP.VALUE03,
           TMP.VALUE04);
    END LOOP;
    ----------------







    -----------
    COMMIT;

    -----------------------
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_PJTX_DM;
  ----------------
  PROCEDURE PROC_RESUME_PJTX(P_I_DATE    IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS
   V_COUNT      VARCHAR2(10); --记录数
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_DEAL_YHK_1005.PROC_RESUME_PJTX';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------

    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    ----
    --从模型结果表中删除当日日批错误数据
    DELETE FROM DW_MOD_PJTX A WHERE A.START_DATE >= P_I_DATE;

    --将结束日期为恢复日-1的记录置为99991231
    /*UPDATE CPMG.DW_MOD_PJTX A
       SET A.END_DATE = '99991231'
     WHERE A.END_DATE =
           TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD');*/

    --从中间表中删除当日日批错误数据
    DELETE FROM CPMG.STG_DAT_PJTX A WHERE A.MODIFY_DATE >= P_I_DATE;
    COMMIT;

    --判断错误恢复日期是否在备份表中存在
    SELECT COUNT(*)
      INTO V_COUNT
      FROM CPMG.STG_BAK_PJTX A
     WHERE A.DATA_DATE = P_I_DATE;

    --回退BAK表当日修改的数据进STG_DAT表
    IF V_COUNT <> 0 THEN
      INSERT INTO CPMG.STG_DAT_PJTX
        (ZONENO,
         ACTBRNO,
         INNERNO,
         BILLNO,
         SUBCODE,
         BILLAMT,
         BILLAMT_CM,
         BILLTYPE,
         BUYTYPE,
         FIRSTTYPE,
         DRAWERBANK,
         HOLDER,
         HOLDERTYPE,
         CREDITLEVEL,
         MANAGERNO,
         LEVELFIVE,
         DISCOUNTDATE,
         REALMATURITY,
         RETMATURITY,
         CAPCOST,
         INTINCOME,
         MODIFY_DATE,
         QXDC_ID,
         BEARER_NAME,
         CROUP_NUM,
         CROUP_NAME)
        SELECT A.ZONENO,
               A.ACTBRNO,
               A.INNERNO,
               A.BILLNO,
               A.SUBCODE,
               A.BILLAMT,
               A.BILLAMT_CM,
               A.BILLTYPE,
               A.BUYTYPE,
               A.FIRSTTYPE,
               A.DRAWERBANK,
               A.HOLDER,
               A.HOLDERTYPE,
               A.CREDITLEVEL,
               A.MANAGERNO,
               A.LEVELFIVE,
               A.DISCOUNTDATE,
               A.REALMATURITY,
               A.RETMATURITY,
               A.CAPCOST,
               A.INTINCOME,
               A.MODIFY_DATE,
               A.QXDC_ID,
               A.BEARER_NAME,
               A.CROUP_NUM,
               A.CROUP_NAME
          FROM CPMG.STG_BAK_PJTX A
         WHERE A.DATA_DATE = P_I_DATE;
      COMMIT;
    END IF;

    -----------
    COMMIT;

    -----------------------
    P_O_SUCCEED := '0';

    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_RESUME_PJTX;
  
END PACK_DEAL_PJTX_1005;
