CREATE OR REPLACE PACKAGE BODY PACK_DEAL_PVMSDATA IS

  --处理票据贴现本币经济资本
  PROCEDURE PROC_DEAL_PJTXBB(P_I_DATE    IN VARCHAR2, --输入日期
                             P_O_SUCCEED OUT VARCHAR2 --输出标志
                             ) IS
    V_FLAG       NUMBER(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;

  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_PJTXBB';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    V_STEP_NO := '2';

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_pjtxbb';
      INSERT INTO STG_TMP_PJTXBB
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT ZONENO,
               ACTBRNO,
               '2',
               SUBCODE,
               '001',
               SUM(EC),
               P_I_DATE,
               '100'
          FROM DW_MOD_PJTX --dw_mod_bmsbill
         WHERE START_DATE = P_I_DATE
         GROUP BY ZONENO, ACTBRNO, SUBCODE;
      /* --特殊地区改变地区号
      update stg_tmp_pjtxbb a
         set a.ZONENO = (select b.zoneno_m
                           from prm_organmap b
                          where a.ZONENO = b.ZONENO
                            and a.brno = b.brno)
       where a.zoneno in (select zoneno from prm_organmap b)
         and a.brno in (select brno from prm_organmap b);*/
      -----------------------------------------------------------------
      ----------开始汇总-----------------------
      FOR V_FLAG IN 3 .. 4 LOOP
        MERGE INTO STG_TMP_PJTXBB STG
        USING (SELECT PRM.BELONG_ZONENO ZONENO,
                      PRM.BELONG_BRNO BRNO,
                      PRM.BELONG_BANK_FLAG BANKFLAG,
                      STG.SUBCODE,
                      STG.CURRTYPE,
                      SUM(STG.ECOST) ECOST,
                      STG.DATA_DATE,
                      STG.DICCODE
                 FROM STG_TMP_PJTXBB STG, PRM_IRA_ORGAN PRM
                WHERE STG.ZONENO = PRM.ZONE_NO
                  AND STG.BRNO = PRM.BR_NO
                  AND STG.BANKFLAG = PRM.BANK_FLAG
                  AND PRM.BELONG_BANK_FLAG = V_FLAG
                  AND PRM.BANK_FLAG <> V_FLAG
                  AND P_I_DATE >= PRM.START_DATE
                  AND P_I_DATE < PRM.END_DATE
                GROUP BY PRM.BELONG_ZONENO,
                         PRM.BELONG_BRNO,
                         PRM.BELONG_BANK_FLAG,
                         STG.SUBCODE,
                         STG.CURRTYPE,
                         STG.DATA_DATE,
                         STG.DICCODE) TMP
        ON (STG.ZONENO = TMP.ZONENO AND STG.BRNO = TMP.BRNO AND STG.BANKFLAG = TMP.BANKFLAG AND STG.SUBCODE = TMP.SUBCODE AND STG.CURRTYPE = TMP.CURRTYPE AND STG.DATA_DATE = TMP.DATA_DATE AND STG.DICCODE = TMP.DICCODE)
        WHEN MATCHED THEN
          UPDATE SET STG.ECOST = STG.ECOST + TMP.ECOST
        WHEN NOT MATCHED THEN
          INSERT
            (STG.ZONENO,
             STG.BRNO,
             STG.BANKFLAG,
             STG.SUBCODE,
             STG.CURRTYPE,
             STG.ECOST,
             STG.DATA_DATE,
             STG.DICCODE)
          VALUES
            (TMP.ZONENO,
             TMP.BRNO,
             TMP.BANKFLAG,
             TMP.SUBCODE,
             TMP.CURRTYPE,
             TMP.ECOST,
             TMP.DATA_DATE,
             TMP.DICCODE);
      END LOOP;

      ---------------------本外币折本币----------------------------------
      INSERT INTO STG_TMP_PJTXBB
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               '994',
               SUM(DECODE(A.CURRTYPE, '001', ECOST, ECOST / USCVRATE)),
               DATA_DATE,
               DICCODE
          FROM STG_TMP_PJTXBB A, PRM_EXCHANGE_RATE B
         WHERE A.ZONENO = B.ZONE_NO
           AND A.CURRTYPE IN ('001', '992')
              --and a.currtype = b.currency
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
           AND B.CURRENCY = '001'
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE, DATA_DATE, DICCODE;

      -----------------------
      P_O_SUCCEED := '0';
      COMMIT;
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
    ---------------------结束票据贴现本币汇总存储过程------------
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_PJTXBB;
  -----------------------------------------------------------
  ---------处理银行卡经济资本---------------
  PROCEDURE PROC_DEAL_YHK(P_I_DATE    IN VARCHAR2, --输入日期
                          P_O_SUCCEED OUT VARCHAR2 --输出标志
                          ) IS
    /*V_FLAG       NUMBER(1) := 3; --行级别*/
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    V_XS       PRM_XS081.QUOTIETY%TYPE;
    v_open_day dic_all_kind.KIND_ID%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_YHK';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    V_STEP_NO := '2';
    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_yhk';

       --徐敏10月版本修改 13年启用新接口表数据
    BEGIN
    SELECT t.KIND_ID INTO v_open_day  from dic_all_kind t WHERE t.OPERATION_KIND='ADJUST_DATE_UG';
    EXCEPTION
    WHEN OTHERS THEN
    v_open_day:='20130101';
    END ;

    IF P_I_DATE>=v_open_day
    THEN
    INSERT INTO STG_TMP_YHK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
     SELECT T.OPENZONO,
               T.OPENBRNO,
               '0',
               T.SUBCODE,
               T.CURRTYPE,
               SUM(T.ECOST),
               P_I_DATE,
               '102'
          FROM DW_MOD_YHK_UG T
          WHERE T.DATA_DATE=P_I_DATE
         GROUP BY T.OPENZONO, T.OPENBRNO,T.SUBCODE,T.CURRTYPE;

     for v_flag in 2 .. 4 loop
          merge into stg_tmp_yhk stg
          using (select prm.belong_zoneno zoneno,
                        prm.belong_brno brno,
                        prm.belong_bank_flag bankflag,
                        stg.subcode,
                        stg.currtype,
                        sum(stg.ecost) ecost,
                        stg.data_date,
                        stg.diccode
                   from stg_tmp_yhk stg, prm_ira_organ prm
                  where stg.zoneno = prm.zone_no
                    and stg.brno = prm.br_no
                    and stg.bankflag = prm.bank_flag
                    and prm.belong_bank_flag = v_flag
                    and prm.bank_flag <> v_flag
                    and p_i_date >= prm.start_date
                    and p_i_date < prm.end_date
                  group by prm.belong_zoneno,
                           prm.belong_brno,
                           prm.belong_bank_flag,
                           stg.subcode,
                           stg.currtype,
                           stg.data_date,
                           stg.diccode) tmp
          on (stg.zoneno = tmp.zoneno and stg.brno = tmp.brno and stg.bankflag = tmp.bankflag and stg.subcode = tmp.subcode and stg.currtype = tmp.currtype and stg.data_date = tmp.data_date and stg.diccode = tmp.diccode)
          when matched then
            update set stg.ecost = stg.ecost + tmp.ecost
          when not matched then
            insert
              (stg.zoneno,
               stg.brno,
               stg.bankflag,
               stg.subcode,
               stg.currtype,
               stg.ecost,
               stg.data_date,
               stg.diccode)
            values
              (tmp.zoneno,
               tmp.brno,
               tmp.bankflag,
               tmp.subcode,
               tmp.currtype,
               tmp.ecost,
               tmp.data_date,
               tmp.diccode);
        end loop;

        ---------------------开始外币折美元-----------------
        insert into stg_tmp_yhk
          (zoneno,
           brno,
           bankflag,
           subcode,
           currtype,
           ecost,
           data_date,
           diccode)
          select a.zoneno,
                 a.brno,
                 a.bankflag,
                 a.subcode,
                 '992',
                 sum(a.ecost * b.uscvrate),
                 a.data_date,
                 a.diccode
            from stg_tmp_yhk a, PRM_CURRENCY_RATE b
           where a.currtype <> '001'
             and a.currtype = b.currency
           group by zoneno, brno, bankflag, subcode, data_date, diccode;
        ----------------开始本外币折人民币----------------
        insert into stg_tmp_yhk
          (zoneno,
           brno,
           bankflag,
           subcode,
           currtype,
           ecost,
           data_date,
           diccode)
          select a.zoneno,
                 a.brno,
                 a.bankflag,
                 a.subcode,
                 '994',
                 sum(decode(a.currtype, '001', a.ecost, a.ecost / b.uscvrate)),
                 a.data_date,
                 a.diccode
            from stg_tmp_yhk a, PRM_CURRENCY_RATE b
           where a.currtype in ('001', '992')
             and b.currency = '001'
           group by zoneno, brno, bankflag, subcode, data_date, diccode;
      -----------------------------


    ELSE

      SELECT MAX(QUOTIETY)
        INTO V_XS
        FROM PRM_XS081
       WHERE P_I_DATE >= START_DATE
         AND P_I_DATE < END_DATE;
      INSERT INTO STG_TMP_YHK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               DECODE(SUBSTR(A.SUBCODE, 1, 1),
                      8,
                      A.TDCRBAL * NVL(C.QUOTIETY, V_XS) * B.SUBJECT_APP,
                      2,
                      A.TDCRBAL * NVL(C.QUOTIETY, V_XS) * B.SUBJECT_APP,
                      4,
                      (A.TDDRBAL - A.TDCRBAL) * NVL(C.QUOTIETY, V_XS) *
                      B.SUBJECT_APP,
                      A.TDDRBAL * NVL(C.QUOTIETY, V_XS) * B.SUBJECT_APP),
               P_I_DATE,
               '102'
          FROM STG_DAT_NFGNLED A, PRM_CS081 B, PRM_XS081 C
         WHERE DECODE(B.SUBJECT_TYPE, 1, SUBSTR(A.SUBCODE, 1, 4), A.SUBCODE) =
               B.SUBJECT_CODE
           AND B.PRODUCT_ID = C.THPRODUCT(+)
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
           AND P_I_DATE >= C.START_DATE(+)
           AND P_I_DATE < C.END_DATE(+)
           AND A.CURRTYPE IN ('001', '992', '994');

           END IF;


      ---------------------结束银行卡汇总存储过程------------
      P_O_SUCCEED := '0';
      COMMIT;
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
    --------------
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_YHK;
  ---------------------------------------------------------------------
  PROCEDURE PROC_DEAL_FRDK --处理法人贷款经济资本
  (P_I_DATE    IN VARCHAR2, --输入日期
   P_O_SUCCEED OUT VARCHAR2 --输出标志
   ) IS
    V_FLAG       NUMBER(1) := 2; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_FRDK';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    V_STEP_NO := '2';

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      --EXECUTE IMMEDIATE 'truncate table stg_tmp_frdk';

      EXECUTE IMMEDIATE 'truncate table STG_TMP_FD';
      ----------------------
      INSERT INTO STG_TMP_FD
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT ZONENO,
               BRNO,
               '0',
               SUBCODE,
               CURRTYPE,
               SUM(ECOST),
               P_I_DATE,
               '103'
          FROM DW_MOD_FRDK DMF
         WHERE DMF.START_DATE=P_I_DATE
         GROUP BY ZONENO, BRNO, SUBCODE, CURRTYPE;
      ---------------------------------------------------
      FOR V_FLAG IN 2 .. 4 LOOP
        MERGE INTO STG_TMP_FD STG
        USING (SELECT PRM.BELONG_ZONENO ZONENO,
                      PRM.BELONG_BRNO BRNO,
                      PRM.BELONG_BANK_FLAG BANKFLAG,
                      STG.SUBCODE,
                      STG.CURRTYPE,
                      SUM(STG.ECOST) ECOST,
                      STG.DATA_DATE,
                      STG.DICCODE
                 FROM STG_TMP_FD STG, PRM_IRA_ORGAN PRM
                WHERE STG.ZONENO = PRM.ZONE_NO
                  AND STG.BRNO = PRM.BR_NO
                  AND STG.BANKFLAG = PRM.BANK_FLAG
                  AND PRM.BELONG_BANK_FLAG = V_FLAG
                  AND PRM.BANK_FLAG <> V_FLAG
                  AND P_I_DATE >= PRM.START_DATE
                  AND P_I_DATE < PRM.END_DATE
                GROUP BY PRM.BELONG_ZONENO,
                         PRM.BELONG_BRNO,
                         PRM.BELONG_BANK_FLAG,
                         STG.SUBCODE,
                         STG.CURRTYPE,
                         STG.DATA_DATE,
                         STG.DICCODE) TMP
        ON (STG.ZONENO = TMP.ZONENO AND STG.BRNO = TMP.BRNO AND STG.BANKFLAG = TMP.BANKFLAG AND STG.SUBCODE = TMP.SUBCODE AND STG.CURRTYPE = TMP.CURRTYPE AND STG.DATA_DATE = TMP.DATA_DATE AND STG.DICCODE = TMP.DICCODE)
        WHEN MATCHED THEN
          UPDATE SET STG.ECOST = STG.ECOST + TMP.ECOST
        WHEN NOT MATCHED THEN
          INSERT
            (STG.ZONENO,
             STG.BRNO,
             STG.BANKFLAG,
             STG.SUBCODE,
             STG.CURRTYPE,
             STG.ECOST,
             STG.DATA_DATE,
             STG.DICCODE)
          VALUES
            (TMP.ZONENO,
             TMP.BRNO,
             TMP.BANKFLAG,
             TMP.SUBCODE,
             TMP.CURRTYPE,
             TMP.ECOST,
             TMP.DATA_DATE,
             TMP.DICCODE);
      END LOOP;

      ---------------------开始外币折美元-----------------
      INSERT INTO STG_TMP_FD
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               '992',
               SUM(A.ECOST * B.USCVRATE),
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_FD A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE <> '001'
           AND A.ZONENO = B.ZONE_NO
           AND A.CURRTYPE = B.CURRENCY
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE, DATA_DATE, DICCODE;
      ----------------开始本外币折人民币----------------
      INSERT INTO STG_TMP_FD
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               '994',
               SUM(DECODE(A.CURRTYPE, '001', A.ECOST, A.ECOST / B.USCVRATE)),
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_FD A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE IN ('001', '992')
           AND A.ZONENO = B.ZONE_NO
           AND B.CURRENCY = '001'
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE, DATA_DATE, DICCODE;

      -----------------------------

      ---------------------结束法人贷款汇总存储过程------------
      P_O_SUCCEED := '0';
      COMMIT;
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    --------------
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_FRDK;
  ---------------------------------------------------------------------
  ---------------------------------------------------------------------
  PROCEDURE PROC_DEAL_GRDK --处理个人贷款经济资本
  (P_I_DATE    IN VARCHAR2, --输入日期
   P_O_SUCCEED OUT VARCHAR2 --输出标志
   ) IS
    V_FLAG       NUMBER(1) := 2; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    v_open_day dic_all_kind.KIND_ID%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_GRDK';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    V_STEP_NO := '2';

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_grdk';

       --徐敏10月版本修改 13年启用新接口表数据
    BEGIN
    SELECT t.KIND_ID INTO v_open_day  from dic_all_kind t WHERE t.OPERATION_KIND='ADJUST_DATE_UG';
    EXCEPTION
    WHEN OTHERS THEN
    v_open_day:='20130101';
    END ;

    IF P_I_DATE>=v_open_day
    THEN

     INSERT INTO STG_TMP_GRDK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT ZONENO,
               PHYBRNO,
               '0',
               SUBCODE,
               CURRTYPE,
               SUM(ECOST),
               P_I_DATE,
               '104'
          FROM DW_MOD_GRDK_UG
         WHERE DATA_DATE = P_I_DATE
         GROUP BY ZONENO, PHYBRNO, SUBCODE, CURRTYPE;

    ELSE


      ----------------------
      INSERT INTO STG_TMP_GRDK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT ZONENO,
               ACTBRNO,
               '0',
               SUBCODE,
               CURRTYPE,
               SUM(ECOST),
               P_I_DATE,
               '104'
          FROM DW_MOD_GRDK
         WHERE START_DATE = P_I_DATE
         GROUP BY ZONENO, ACTBRNO, SUBCODE, CURRTYPE;
      END IF;

      ----------------------------------------------------
      FOR V_FLAG IN 2 .. 4 LOOP
        MERGE INTO STG_TMP_GRDK STG
        USING (SELECT PRM.BELONG_ZONENO ZONENO,
                      PRM.BELONG_BRNO BRNO,
                      PRM.BELONG_BANK_FLAG BANKFLAG,
                      STG.SUBCODE,
                      STG.CURRTYPE,
                      SUM(STG.ECOST) ECOST,
                      STG.DATA_DATE,
                      STG.DICCODE
                 FROM STG_TMP_GRDK STG, PRM_IRA_ORGAN PRM
                WHERE STG.ZONENO = PRM.ZONE_NO
                  AND STG.BRNO = PRM.BR_NO
                  AND STG.BANKFLAG = PRM.BANK_FLAG
                  AND PRM.BELONG_BANK_FLAG = V_FLAG
                  AND PRM.BANK_FLAG <> V_FLAG
                  AND P_I_DATE >= PRM.START_DATE
                  AND P_I_DATE < PRM.END_DATE
                GROUP BY PRM.BELONG_ZONENO,
                         PRM.BELONG_BRNO,
                         PRM.BELONG_BANK_FLAG,
                         STG.SUBCODE,
                         STG.CURRTYPE,
                         STG.DATA_DATE,
                         STG.DICCODE) TMP
        ON (STG.ZONENO = TMP.ZONENO AND STG.BRNO = TMP.BRNO AND STG.BANKFLAG = TMP.BANKFLAG AND STG.SUBCODE = TMP.SUBCODE AND STG.CURRTYPE = TMP.CURRTYPE AND STG.DATA_DATE = TMP.DATA_DATE AND STG.DICCODE = TMP.DICCODE)
        WHEN MATCHED THEN
          UPDATE SET STG.ECOST = STG.ECOST + TMP.ECOST
        WHEN NOT MATCHED THEN
          INSERT
            (STG.ZONENO,
             STG.BRNO,
             STG.BANKFLAG,
             STG.SUBCODE,
             STG.CURRTYPE,
             STG.ECOST,
             STG.DATA_DATE,
             STG.DICCODE)
          VALUES
            (TMP.ZONENO,
             TMP.BRNO,
             TMP.BANKFLAG,
             TMP.SUBCODE,
             TMP.CURRTYPE,
             TMP.ECOST,
             TMP.DATA_DATE,
             TMP.DICCODE);
      END LOOP;

      ---------------------开始外币折美元-----------------
      INSERT INTO STG_TMP_GRDK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               '992',
               SUM(A.ECOST * B.USCVRATE),
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_GRDK A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE <> '001'
           AND A.ZONENO = B.ZONE_NO
           AND A.CURRTYPE = B.CURRENCY
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE, DATA_DATE, DICCODE;
      ----------------开始本外币折人民币----------------
      INSERT INTO STG_TMP_GRDK
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               '994',
               SUM(DECODE(A.CURRTYPE, '001', A.ECOST, A.ECOST / B.USCVRATE)),
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_GRDK A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE IN ('001', '992')
           AND A.ZONENO = B.ZONE_NO
           AND B.CURRENCY = '001'
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE, DATA_DATE, DICCODE;
      -----------------------------

      ---------------------结束个人贷款汇总存储过程------------
      P_O_SUCCEED := '0';
      COMMIT;
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    --------------
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_GRDK;
