  --处理无息资产经济资本
  PROCEDURE PROC_DEAL_WXZC(P_I_DATE    IN VARCHAR2, --输入日期
                           P_O_SUCCEED OUT VARCHAR2 --输出标志
                           ) IS
    -- v_flag       number(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    V_FXXS     PRM_XS053.FXXS%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_WXZC';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_wxzc';
      SELECT MAX(FXXS)
        INTO V_FXXS
        FROM PRM_XS053
       WHERE P_I_DATE >= START_DATE
         AND P_I_DATE < END_DATE;

      V_STEP_NO := '2';

      ----------------------

      INSERT INTO STG_TMP_WXZC
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               DECODE(SUBSTR(A.SUBCODE, 1, 1),
                      8,
                      A.TDCRBAL * NVL(C.FXXS, V_FXXS) * B.SUBJECT_APP,
                      2,
                      A.TDCRBAL * NVL(C.FXXS, V_FXXS) * B.SUBJECT_APP,
                      4,
                      (A.TDDRBAL - A.TDCRBAL) * NVL(C.FXXS, V_FXXS) *
                      B.SUBJECT_APP,
                      A.TDDRBAL * NVL(C.FXXS, V_FXXS) * B.SUBJECT_APP),
               P_I_DATE,
               '108'
          FROM STG_DAT_NFGNLED A, PRM_CS05B B, PRM_XS053 C
         WHERE DECODE(B.SUBJECT_TYPE, 1, SUBSTR(A.SUBCODE, 1, 4), A.SUBCODE) =
               B.SUBJECT_CODE
           AND B.PRODUCT_ID = C.PRODUCT_ID(+)
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
           AND P_I_DATE >= C.START_DATE(+)
           AND P_I_DATE < C.END_DATE(+)
           AND A.CURRTYPE IN ('001', '992', '994')
        -- and substr(a.subcode,1,4) in (select substr(b.subject_code,1,4)
        -- from prm_cs05b b)

        ;
      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;

    ------------
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_WXZC;
