           AND P_I_DATE < B.END_DATE
           AND P_I_DATE >= C.START_DATE(+)
           AND P_I_DATE < C.END_DATE(+)
              /*    and
                                                     b.data_type = '1'*/
           AND A.CURRTYPE IN ('001', '992', '994');
      --and substr(a.subcode,1,4) in
      --(select substr(subject_code,1,4) from prm_cs05c
      -- where data_type='1'));
      COMMIT;
      --------------开始对表外资产衍生产品和承诺类进行处理
      INSERT INTO STG_TMP_BWZC
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               DECODE(SUBSTR(A.SUBCODE, 1, 1),
                      8,
                      A.TDCRBAL * NVL(C.XS_VALUE, V_XS) * B.SUBJECT_APP,
                      2,
                      A.TDCRBAL * NVL(C.XS_VALUE, V_XS) * B.SUBJECT_APP,
                      4,

                      (A.TDDRBAL - A.TDCRBAL) * NVL(C.XS_VALUE, V_XS) *
                      B.SUBJECT_APP,
                      A.TDDRBAL * NVL(C.XS_VALUE, V_XS) * B.SUBJECT_APP),
               P_I_DATE,
               '107'
          FROM STG_DAT_NFGNLED A, PRM_CS05C B, PRM_XS051 C
         WHERE DECODE(B.SUBJECT_TYPE, 1, SUBSTR(A.SUBCODE, 1, 4), A.SUBCODE) =
               B.SUBJECT_CODE
           AND B.PRODUCT_ID = C.PRODUCT_NAME3(+)
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
           AND P_I_DATE >= C.START_DATE(+)
           AND P_I_DATE < C.END_DATE(+)
           AND B.DATA_TYPE = '2'
           AND A.CURRTYPE IN ('001', '992', '994');
      --and substr(a.subcode,1,4) in
      -- (select substr(subject_code,1,4) from prm_cs05c
      -- where data_type='2'));
      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_BWZC;

  -------------------------
  --处理其它风险经济资本
  PROCEDURE PROC_DEAL_QTFX(P_I_DATE    IN VARCHAR2, --输入日期
                           P_O_SUCCEED OUT VARCHAR2 --输出标志
                           ) IS
    V_FLAG       NUMBER(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    V_XS       PRM_XS10.QUOTIETY%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_QTFX';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_qtfx';
      -----------------
      SELECT MAX(QUOTIETY)
        INTO V_XS
        FROM PRM_XS10
       WHERE P_I_DATE >= START_DATE
         AND P_I_DATE < END_DATE;

      INSERT INTO STG_TMP_QTFX
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT DW.ZONENO,
               DW.BRNO,
               '0',
               DW.SUBCODE,
               DW.CURRTYPE,
               SUM(DW.EC),
               P_I_DATE,
               '200'
          FROM DW_MOD_QTFX DW
         WHERE DW.DATA_DATE = P_I_DATE
         GROUP BY DW.ZONENO, DW.BRNO, DW.SUBCODE, DW.CURRTYPE;
      COMMIT;
      ----------------------------------
      --开始汇总
      FOR V_FLAG IN 2 .. 4 LOOP
        MERGE INTO STG_TMP_QTFX STG
        USING (SELECT PRM.BELONG_ZONENO ZONENO,
                      PRM.BELONG_BRNO BRNO,
                      PRM.BELONG_BANK_FLAG BANKFLAG,
                      STG.SUBCODE,
                      STG.CURRTYPE,
                      SUM(STG.ECOST) VALUE01,
                      stg.data_date,
                      '200'
                 FROM STG_TMP_QTFX STG, PRM_IRA_ORGAN PRM
                WHERE STG.ZONENO = PRM.ZONE_NO
                  AND STG.BRNO = PRM.BR_NO
                  AND STG.BANKFLAG = PRM.BANK_FLAG
                  AND PRM.BELONG_BANK_FLAG = V_FLAG
                  AND PRM.BANK_FLAG <> V_FLAG
                  AND P_I_DATE >= PRM.START_DATE
                  AND P_I_DATE < PRM.END_DATE
                GROUP BY PRM.BELONG_ZONENO,
                         PRM.BELONG_BRNO,
                         PRM.BELONG_BANK_FLAG,
                         STG.SUBCODE,
                         STG.CURRTYPE,
                         stg.data_date
                        ) TMP
        ON (STG.ZONENO = TMP.ZONENO AND STG.BRNO = TMP.BRNO AND STG.BANKFLAG = TMP.BANKFLAG AND STG.SUBCODE = TMP.SUBCODE AND STG.CURRTYPE = TMP.CURRTYPE)
        WHEN MATCHED THEN
          UPDATE SET STG.ECOST = STG.ECOST + TMP.VALUE01
        WHEN NOT MATCHED THEN
          INSERT
            (STG.ZONENO,
             STG.BRNO,
             STG.BANKFLAG,
             STG.SUBCODE,
             STG.CURRTYPE,
             STG.ECOST,
             STG.DATA_DATE,
             STG.DICCODE)
          VALUES
            (TMP.ZONENO,
             TMP.BRNO,
             TMP.BANKFLAG,
             TMP.SUBCODE,
             TMP.CURRTYPE,
             TMP.VALUE01,
             P_I_DATE,
             '200');
      END LOOP;
      -------开始折币
      INSERT INTO STG_TMP_QTFX
        (ZONENO,
         BRNO,
         BANKFLAG,
         CURRTYPE,
         SUBCODE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               '992',
               A.SUBCODE,
               SUM(A.ECOST * B.USCVRATE),
               P_I_DATE,
              '200'
          FROM STG_TMP_QTFX A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE <> '001'
           AND A.ZONENO = B.ZONE_NO
           AND A.CURRTYPE = B.CURRENCY
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE;
      ----------------开始本外币折人民币----------------
      INSERT INTO STG_TMP_QTFX
        (ZONENO,
         BRNO,
         BANKFLAG,
         CURRTYPE,
         SUBCODE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               '994',
               A.SUBCODE,
               SUM(DECODE(A.CURRTYPE, '001', A.ECOST, A.ECOST / B.USCVRATE)),
               P_I_DATE,
               '200'
          FROM STG_TMP_QTFX A, PRM_EXCHANGE_RATE B
         WHERE A.CURRTYPE IN ('001', '992')
           AND A.ZONENO = B.ZONE_NO
           AND B.CURRENCY = '001'
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
         GROUP BY ZONENO, BRNO, BANKFLAG, SUBCODE;
      --------------
      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_QTFX;
  -------------------------
  --处理债券投资经济资本
  PROCEDURE PROC_DEAL_ZQTZ(P_I_DATE    IN VARCHAR2, --输入日期
                           P_O_SUCCEED OUT VARCHAR2 --输出标志
                           ) IS
    -- v_flag       number(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    V_XS       PRM_XS061.PZXS%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_ZQTZ';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_zqtz';
      EXECUTE IMMEDIATE 'truncate table stg_tmp_zqtz_tmp';
      SELECT MAX(PZXS)
        INTO V_XS
        FROM PRM_XS061
       WHERE P_I_DATE >= START_DATE
         AND P_I_DATE < END_DATE;
      ---------------------------------------------------------
      /*   --先插入中间表
      --先插入本币
      insert into STG_TMP_ZQTZ_tmp
        (zoneno,
         brno,
         bankflag,
         subcode,
         currtype,
         ecost,
         data_date,
         diccode)
        select substr(a.organ, 1, 4),
               '0000',
               '4',
               a.statcode,
               '001',
               decode(sign(a.balance), -1, 0, a.balance) *
               nvl(c.pzxs, v_xs),
               p_i_date,
               '105'

          from prm_sg_bond_rmb a,
               --prm_subcode_statcode b,
               prm_cs061 b,
               prm_xs061 c
         where a.statcode = b.subject_code
           and b.dmlx = '2'
           and a.datadate = p_i_date
           and p_i_date >= b.start_date
           and p_i_date < b.end_date
           and b.product_id = c.product_id(+)
           and p_i_date >= c.start_date(+)
           and p_i_date < c.end_date(+);
      --插入美元数据 ,因为只有美元数据，则把币种记为992
      insert into STG_TMP_ZQTZ_tmp
        (zoneno,
         brno,
         bankflag,
         subcode,
         currtype,
         ecost,
         data_date,
         diccode)
        select substr(a.organ, 1, 4),
               '0000',
               '4',
               a.statcode,
               '992',
               decode(sign(a.balance), -1, 0, a.balance) *
               nvl(c.pzxs, v_xs),
               p_i_date,
               '105'

          from prm_sg_bond_d a,
               --prm_subcode_statcode b,
               prm_cs061 b,
               prm_xs061 c
         where a.statcode = b.subject_code
           and b.dmlx = '2'
           and a.datadate = p_i_date
           and p_i_date >= b.start_date
           and p_i_date < b.end_date
           and b.product_id = c.product_id(+)
           and p_i_date >= c.start_date(+)
           and p_i_date < c.end_date(+);
      commit;
      ----重新放入stg_tmp_zqtz表中
      insert into stg_tmp_zqtz
        (zoneno,
         brno,
         bankflag,
         subcode,
         currtype,
         ecost,
         data_date,
         diccode)
        select a.zoneno,
               a.brno,
               a.bankflag,
               b.subcode,
               a.currtype,
               sum(a.ecost),
               a.data_date,
               a.diccode
          from STG_TMP_ZQTZ_tmp a, prm_subcode_statcode b
         where substr(a.subcode, 1, 3) || '00' = b.statcode
           and p_i_date >= b.start_date
           and p_i_date < b.end_date
         group by a.zoneno,
                  a.brno,
                  a.bankflag,
                  b.subcode,
                  a.currtype,
                  a.data_date,
                  a.diccode;
      --execute immediate 'truncate table dw_mod_pvmsdata';
      commit;*/
      /*   --------------------本外币折人民币------------------
      insert into stg_tmp_zqtz
        (zoneno,
         brno,
         bankflag,
         subcode,
         currtype,
         ecost,
         data_date,
         diccode)
        select a.zoneno,
               a.brno,
               a.bankflag,
               a.subcode,
               '994',
               sum(decode(a.currtype, '001', a.ecost, a.ecost / b.uscvrate)),
               a.data_date,
               a.diccode
          from stg_tmp_zqtz a, prm_exchange_rate b
         where a.currtype in ('001', '992')
           and a.zoneno = b.zone_no
           and b.currency = '001'
           and p_i_date >= b.start_date
           and p_i_date < b.end_date
         group by zoneno, brno, bankflag, subcode, data_date, diccode;*/
      -------------------插入总帐数据-------
      INSERT INTO STG_TMP_ZQTZ
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               DECODE(SUBSTR(A.SUBCODE, 1, 1),
                      8,
                      A.TDCRBAL * NVL(C.PZXS, V_XS) * B.SUBJECT_APP,
                      2,
                      A.TDCRBAL * NVL(C.PZXS, V_XS) * B.SUBJECT_APP,
                      4,

                      (A.TDDRBAL - A.TDCRBAL) * NVL(C.PZXS, V_XS) *
                      B.SUBJECT_APP,
                      A.TDDRBAL * NVL(C.PZXS, V_XS) * B.SUBJECT_APP),
               P_I_DATE,
               '105'
          FROM STG_DAT_NFGNLED A, PRM_CS061 B, PRM_XS061 C
         WHERE B.DMLX = '1'
           AND P_I_DATE >= B.START_DATE
           AND P_I_DATE < B.END_DATE
           AND DECODE(B.SUBJECT_TYPE, 1, SUBSTR(A.SUBCODE, 1, 4), A.SUBCODE) =
               B.SUBJECT_CODE
           AND B.PRODUCT_ID = C.PRODUCT_ID(+)
           AND P_I_DATE >= C.START_DATE
           AND P_I_DATE < C.END_DATE
           AND A.CURRTYPE IN ('001', '992', '994')
           AND A.BANKFLAG = '4'
        --and substr(a.subcode,1,4) in
        --(select substr(subject_code,1,4) from prm_cs061
        --where dmlx='1'
        ;

      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_ZQTZ;

  -------------------------
  PROCEDURE PROC_DEAL_TOTAL --处理汇总经济资本
  (P_I_DATE    IN VARCHAR2, --输入日期
   P_O_SUCCEED OUT VARCHAR2 --输出标志
   ) IS
    -- v_flag       number(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_TOTAL';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table dw_mod_pvmsdata';
      -----插入票据贴现本币数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_PJTXBB A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入银行卡数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_YHK A
        WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入法人贷款数据
       insert into dw_mod_pvmsdata
      (zoneno,
       brno,
       bankflag,
       subcode,
       currtype,
       ecost,
       data_date,
       diccode)
      select a.zoneno,
             a.brno,
             a.bankflag,
             a.subcode,
             a.currtype,
             a.ecost * 10000,
             a.data_date,
             a.diccode
        from stg_tmp_fd a
       where a.currtype in ('001', '992', '994');
      -----插入个人贷款数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_GRDK A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入票据贴现外币数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_PJTXWB A
        where a.currtype in ('001', '992', '994')
        ;
      -----插入无息资产数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_WXZC A
       where a.currtype in ('001', '992', '994')
        ;
      -----插入资金业务数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_ZJYW A
        where a.currtype in ('001', '992', '994')
        ;
      -----插入表外资产数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_BWZC A
        where a.currtype in ('001', '992', '994')
        ;
      -----插入债券投资数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_ZQTZ A
        where a.currtype in ('001', '992', '994')
        ;
      -----插入其它风险数据
      INSERT INTO DW_MOD_PVMSDATA
        (ZONENO,
         BRNO,
         BANKFLAG,
         SUBCODE,
         CURRTYPE,
         ECOST,
         DATA_DATE,
         DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.SUBCODE,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_QTFX A
        where a.currtype in ('001', '992', '994')
        ;
      -----把外币折美元改成pv需要的014
      UPDATE DW_MOD_PVMSDATA A
         SET A.CURRTYPE = '014'
       WHERE A.CURRTYPE = '992';
      ------把本外币折人民币改成pv需要的999
      UPDATE DW_MOD_PVMSDATA A
         SET A.CURRTYPE = '999'
       WHERE A.CURRTYPE = '994';
      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_TOTAL;
  
