CREATE OR REPLACE PACKAGE BODY      PACK_DEAL_PVMSDATA_11 is

  PROCEDURE PROC_DEAL_YHK(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS

    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
    v_open_day dic_all_kind.KIND_ID%TYPE;

  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_YHK_11';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    V_STEP_NO := '2';
    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table stg_tmp_yhk_11';
      ----------------------------------------------------------------------

       --徐敏10月版本修改 13年启用新接口表数据
    BEGIN
    SELECT t.KIND_ID INTO v_open_day  from dic_all_kind t WHERE t.OPERATION_KIND='ADJUST_DATE_UG';
    EXCEPTION
    WHEN OTHERS THEN
    v_open_day:='20130101';
    END ;

    IF P_I_DATE>=v_open_day
    THEN
    INSERT INTO STG_TMP_YHK_11
        SELECT T.ZONENO,
               T.BRNO,
               T.BANKFLAG,
               T.CURRTYPE,
               SUM(T.VALUE02),
               P_I_DATE,
               '102'
          FROM DM_CS_YHK_UG T
         GROUP BY T.ZONENO, T.BRNO, T.BANKFLAG, T.CURRTYPE;
    ELSE

      INSERT INTO STG_TMP_YHK_11
        SELECT T.ZONENO,
               T.BRNO,
               T.BANKFLAG,
               T.CURRTYPE,
               SUM(T.VALUE02),
               P_I_DATE,
               '102'
          FROM DM_CS_YHK T
         GROUP BY T.ZONENO, T.BRNO, T.BANKFLAG, T.CURRTYPE;
     END IF;
      COMMIT;

    ELSE
      P_O_SUCCEED := '0';
    END IF;
    P_O_SUCCEED := '0';
    COMMIT;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;

  END PROC_DEAL_YHK;

