  -------------------------
  PROCEDURE PROC_DEAL_TOTAL --处理汇总经济资本
  (P_I_DATE    IN VARCHAR2, --输入日期
   P_O_SUCCEED OUT VARCHAR2 --输出标志
   ) IS
    -- v_flag       number(1) := 3; --行级别
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_DEAL_TOTAL';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    --删除中间表中当日数据

    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'YYYY-MM-DD')), 'YYYYMMDD') THEN
      EXECUTE IMMEDIATE 'truncate table dw_mod_pvmsdata_11';
      EXECUTE IMMEDIATE 'truncate table dw_mod_pvmsdata_11_tmp';
      -----插入票据贴现本币数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_PJTXBB_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入银行卡数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_YHK_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入法人贷款数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_FRDK_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入个人贷款数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_GRDK_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入票据贴现外币数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_PJTXWB_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入无息资产数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_WXZC_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入资金业务数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_ZJYW_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入表外资产数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_BWZC_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----插入债券投资数据
      INSERT INTO DW_MOD_PVMSDATA_11_TMP
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_ZQTZ_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----所有的市场风险的资本求和
      INSERT INTO DW_MOD_PVMSDATA_11
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               SUM(A.ECOST),
               A.DATA_DATE,
               '1'
          FROM DW_MOD_PVMSDATA_11_TMP A
         GROUP BY ZONENO, BRNO, BANKFLAG, CURRTYPE, DATA_DATE;

      -----插入其它风险数据
      INSERT INTO DW_MOD_PVMSDATA_11
        (ZONENO, BRNO, BANKFLAG, CURRTYPE, ECOST, DATA_DATE, DICCODE)
        SELECT A.ZONENO,
               A.BRNO,
               A.BANKFLAG,
               A.CURRTYPE,
               A.ECOST * 10000,
               A.DATA_DATE,
               A.DICCODE
          FROM STG_TMP_QTFX_11 A
         WHERE A.CURRTYPE IN ('001', '992', '994');
      -----把外币折美元改成pv需要的014
      UPDATE DW_MOD_PVMSDATA_11 A
         SET A.CURRTYPE = '014'
       WHERE A.CURRTYPE = '992';
      ------把本外币折人民币改成pv需要的999
      UPDATE DW_MOD_PVMSDATA_11 A
         SET A.CURRTYPE = '999'
       WHERE A.CURRTYPE = '994';
      COMMIT;
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      V_SQL_TXT,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_DEAL_TOTAL;

  PROCEDURE PROC_PRODUCT_REF(P_I_DATE    IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS

    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;

    V_ERR_CODE L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT  L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO  L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT  L_GETDATA_ERR.SQL_TXT%TYPE;

  BEGIN
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PROC_product_ref';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    EXECUTE IMMEDIATE 'truncate table DM_CS_PRODUCT';

    V_STEP_NO := '2';
    INSERT INTO DM_CS_PRODUCT
      (SUBJECT_CODE, PRODUCT_ID, PRODUCT_NAME, START_DATE, END_DATE)
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS031 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS044 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS05A A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS05B A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS05C A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS061 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS071 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS081 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1
      UNION ALL
      SELECT A.SUBJECT_CODE,
             A.PRODUCT_ID,
             B.PRODUCT_NAME,
             A.START_DATE,
             A.END_DATE
        FROM PRM_CS10 A, PRM_PRODUCT B
       WHERE A.PRODUCT_ID = B.PRODUCT_ID
         AND A.START_DATE >= B.START_DATE
         AND A.END_DATE <= B.END_DATE
         AND A.SUBJECT_APP = 1;
    P_O_SUCCEED := '0';
    COMMIT;

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
