  --各位 确定信用风险产品 1法贷 2个贷 3票据 4表外 5债券 6银行卡 7资金 8无息 9其他

  PROCEDURE PROC_ECTOTAL_INIT(P_I_DATE    IN VARCHAR2,
                              P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
