    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')), 'yyyymmdd') THEN
      --------------------------------------------------------------------------------------------
      DELETE FROM CAP_ECTOTAL_DATA WHERE DATADATE = substr(P_I_DATE,1,6);
      EXECUTE IMMEDIATE 'TRUNCATE TABLE CAP_ECTOTAL_DATA_TMP ';
      -----------
      COMMIT;
      -----------------------
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
