                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
