  PROCEDURE PROC_ECTOTAL_TOTAL(P_I_DATE    IN VARCHAR2,
                               P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_ECTOTAL_DATA_1005.PROC_ECTOTAL_TOTAL';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    IF P_I_DATE =
       TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')), 'yyyymmdd') THEN
      --------------------------------------------------------------------------------------------
      DELETE FROM CAP_ECTOTAL_DATA WHERE DATADATE = P_I_DATE;
      -----------------------------------------
      --插入信用风险
      INSERT INTO CAP_ECTOTAL_DATA
        (DATADATE, ORGANCODE, EC, DICCODE) --0:信用风险 1:人民币信贷 2:操作风险
        SELECT substr(P_I_DATE,1,6), ZONENO || BRNO, SUM(VALUE), '0'
          FROM CAP_ECTOTAL_DATA_TMP
         WHERE SUBSTR(DICCODE, 2, 1) = '1'
         GROUP BY ZONENO, BRNO;
      -----------
      ----插入人民币信贷
      INSERT INTO CAP_ECTOTAL_DATA
        (DATADATE, ORGANCODE, EC, DICCODE) --0:信用风险 1:人民币信贷 2:操作风险
        SELECT substr(P_I_DATE,1,6), ZONENO || BRNO, SUM(VALUE), '1'
          FROM CAP_ECTOTAL_DATA_TMP
         WHERE SUBSTR(DICCODE, 2, 1) = '2'
         GROUP BY ZONENO, BRNO;
      ----插入操作风险
      INSERT INTO CAP_ECTOTAL_DATA
        (DATADATE, ORGANCODE, EC, DICCODE) --0:信用风险 1:人民币信贷 2:操作风险
        SELECT substr(P_I_DATE,1,6), ZONENO || BRNO, SUM(VALUE), '2'
          FROM CAP_ECTOTAL_DATA_TMP
         WHERE SUBSTR(DICCODE, 1, 1) = '1'
         GROUP BY ZONENO, BRNO;
      COMMIT;
      -----------------------
      P_O_SUCCEED := '0';
    ELSE
      P_O_SUCCEED := '0';
    END IF;
    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_ECTOTAL_TOTAL;
