  --以下过程为汇总 CAP_EC_DATA_TMP
  PROCEDURE PROC_ECDATA_FRDK(P_I_DATE    IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS

    V_FLAG NUMBER(1) := 2; --行级别
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_ECTOTAL_DATA_1005.PROC_ECDATA_FRDK';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    ----法人贷款数据
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             DW.ZONENO,
             DW.BRNO,
             '0',
             DW.CURRTYPE,
             DECODE(PRM.PRODUCT_LEVEL, '3', PRM.PARENT_ID, PRM.PRODUCT_ID),
             SUM(DW.ECOST),
             0,
             SUM(DW.BALANCE),
             0
        FROM DW_MOD_FRDK DW, PRM_PRODUCT PRM
       WHERE DW.PRODUCT_ID3 = PRM.PRODUCT_ID
         AND DW.START_DATE <= P_I_DATE
         AND DW.END_DATE > P_I_DATE
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
       GROUP BY DW.ZONENO,
                DW.BRNO,
                DW.CURRTYPE,
                DECODE(PRM.PRODUCT_LEVEL,
                       '3',
                       PRM.PARENT_ID,
                       PRM.PRODUCT_ID);
    ---插入月末到期的数据
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             DW.ZONENO,
             DW.BRNO,
             '0',
             DW.CURRTYPE,
             DECODE(PRM.PRODUCT_LEVEL, '3', PRM.PARENT_ID, PRM.PRODUCT_ID),
             0,
             SUM(DW.ECOST),
             0,
             SUM(DW.BALANCE)
        FROM DW_MOD_FRDK DW, PRM_PRODUCT PRM
       WHERE DW.PRODUCT_ID3 = PRM.PRODUCT_ID
         AND DW.START_DATE <= P_I_DATE
         AND DW.END_DATE > P_I_DATE
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
         AND DW.EXHMATUD <=
             TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')), 'yyyymmdd')
       GROUP BY DW.ZONENO,
                DW.BRNO,
                DW.CURRTYPE,
                DECODE(PRM.PRODUCT_LEVEL,
                       '3',
                       PRM.PARENT_ID,
                       PRM.PRODUCT_ID);
    -------------------------

    --------------------------------------------------------------------------------------------
    /* --把信贷类产品汇总到一级产品
    INSERT INTO CAP_EC_DATA_TMP2
      (DATA_DATE,
       ZONENO,
       BRNO,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS,
       BANKFLAG)
      SELECT TMP.DATA_DATE,
             TMP.ZONENO,
             TMP.BRNO,
             TMP.CURRTYPE,
             PRM.PARENT_ID,
             SUM(TMP.EC),
             SUM(EC_MINUS),
             SUM(BALANCE),
             SUM(BALANCE_MINUS),
             BANKFLAG
        FROM CAP_EC_DATA_TMP2 TMP, PRM_PRODUCT PRM
       WHERE TMP.DICCODE = PRM.PRODUCT_ID
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
       GROUP BY TMP.DATA_DATE,
                TMP.ZONENO,
                TMP.BRNO,
                TMP.CURRTYPE,
                PRM.PARENT_ID,
                TMP.BANKFLAG;*/
    ---进行折币，汇总
    --汇总

    ------------
    COMMIT;
    P_O_SUCCEED := '0';

    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_ECDATA_FRDK;
