    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_ECTOTAL_DATA_1005.PROC_ECDATA_GRDK';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    --------个人贷款
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             DW.ZONENO,
             DW.ACTBRNO,
             '0',
             DW.CURRTYPE,
             DECODE(PRM.PRODUCT_LEVEL, '3', PRM.PARENT_ID, PRM.PRODUCT_ID),
             SUM(DW.ECOST),
             0,
             SUM(DW.BALANCE),
             0
        FROM DW_MOD_GRDK DW, PRM_PRODUCT PRM
       WHERE DW.PRODUCT_ID3 = PRM.PRODUCT_ID
         AND DW.START_DATE <= P_I_DATE
         AND DW.END_DATE > P_I_DATE
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
        -- AND DW.CURRTYPE = '001'
       GROUP BY DW.ZONENO,
                DW.ACTBRNO,
                DW.CURRTYPE,
                DECODE(PRM.PRODUCT_LEVEL,
                       '3',
                       PRM.PARENT_ID,
                       PRM.PRODUCT_ID);
    ---插入月末到齐的数据
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             DW.ZONENO,
             DW.ACTBRNO,
             '0',
             DW.CURRTYPE,
             DECODE(PRM.PRODUCT_LEVEL, '3', PRM.PARENT_ID, PRM.PRODUCT_ID),
             0,
             SUM(DW.ECOST),
             0,
             SUM(DW.BALANCE)
        FROM DW_MOD_GRDK DW, PRM_PRODUCT PRM
       WHERE DW.PRODUCT_ID3 = PRM.PRODUCT_ID
         AND DW.START_DATE <= P_I_DATE
         AND DW.END_DATE > P_I_DATE
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
        -- AND DW.CURRTYPE = '001'
         AND DW.TA500261016 <=
             TO_CHAR(LAST_DAY(TO_DATE(P_I_DATE, 'yyyymmdd')), 'yyyymmdd')
       GROUP BY DW.ZONENO,
                DW.ACTBRNO,
                DW.CURRTYPE,
                DECODE(PRM.PRODUCT_LEVEL,
                       '3',
                       PRM.PARENT_ID,
                       PRM.PRODUCT_ID);

    ------------
    COMMIT;
    P_O_SUCCEED := '0';
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
