  PROCEDURE PROC_ECDATA_XDFX(P_I_DATE    IN VARCHAR2,
                             P_O_SUCCEED OUT VARCHAR2) IS

    V_FLAG NUMBER(1) := 2; --行级别
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_ECTOTAL_DATA_1005.PROC_ECDATA_XDFX';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    FOR V_FLAG IN 2 .. 4 LOOP
      MERGE INTO CAP_EC_DATA_TMP CAP
      USING (SELECT PRM.BELONG_ZONENO ZONENO,
                    PRM.BELONG_BRNO BRNO,
                    PRM.BELONG_BANK_FLAG BANKFLAG,
                    CAP.DICCODE,
                    CAP.CURRTYPE,
                    SUM(CAP.EC) VALUE01,
                    SUM(CAP.EC_MINUS) VALUE02,
                    SUM(CAP.BALANCE) VALUE03,
                    SUM(CAP.BALANCE_MINUS) VALUE04,
                    CAP.DATA_DATE
               FROM CAP_EC_DATA_TMP CAP, PRM_IRA_ORGAN PRM
              WHERE CAP.ZONENO = PRM.ZONE_NO
                AND CAP.BRNO = PRM.BR_NO
                AND CAP.BANKFLAG = PRM.BANK_FLAG
                AND PRM.BELONG_BANK_FLAG = V_FLAG
                AND PRM.BANK_FLAG <> V_FLAG
                AND P_I_DATE >= PRM.START_DATE
                AND P_I_DATE < PRM.END_DATE
              GROUP BY PRM.BELONG_ZONENO,
                       PRM.BELONG_BRNO,
                       PRM.BELONG_BANK_FLAG,
                       CAP.DICCODE,
                       CAP.CURRTYPE,
                       CAP.DATA_DATE) TMP
      ON (CAP.ZONENO = TMP.ZONENO AND CAP.BRNO = TMP.BRNO AND CAP.BANKFLAG = TMP.BANKFLAG AND CAP.DICCODE = TMP.DICCODE AND CAP.CURRTYPE = TMP.CURRTYPE)
      WHEN MATCHED THEN
        UPDATE
           SET CAP.EC            = CAP.EC + TMP.VALUE01,
               CAP.EC_MINUS      = CAP.EC_MINUS + TMP.VALUE02,
               CAP.BALANCE       = CAP.BALANCE + TMP.VALUE03,
               CAP.BALANCE_MINUS = CAP.BALANCE_MINUS + TMP.VALUE04
      WHEN NOT MATCHED THEN
        INSERT
          (DATA_DATE,
           ZONENO,
           BRNO,
           CURRTYPE,
           DICCODE,
           EC,
           EC_MINUS,
           BALANCE,
           BALANCE_MINUS,
           BANKFLAG)
        VALUES
          (TMP.DATA_DATE,
           TMP.ZONENO,
           TMP.BRNO,
           TMP.CURRTYPE,
           TMP.DICCODE,
           TMP.VALUE01,
           TMP.VALUE02,
           TMP.VALUE03,
           TMP.VALUE04,
           TMP.BANKFLAG);
    END LOOP;
    ---------
    --折币
    --外币折美元
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             A.ZONENO,
             A.BRNO,
             A.BANKFLAG,
             '992',
             A.DICCODE,
             SUM(A.EC * B.USCVRATE),
             SUM(A.EC_MINUS * B.USCVRATE),
             SUM(A.BALANCE * B.USCVRATE),
             SUM(A.BALANCE_MINUS * B.USCVRATE)
        FROM CAP_EC_DATA_TMP A, PRM_EXCHANGE_RATE B
       WHERE A.CURRTYPE <> '001'
         AND A.ZONENO = B.ZONE_NO
         AND A.CURRTYPE = B.CURRENCY
         AND P_I_DATE >= B.START_DATE
         AND P_I_DATE < B.END_DATE
       GROUP BY ZONENO, BRNO, BANKFLAG, DICCODE;
    ------本外币折人民币
    INSERT INTO CAP_EC_DATA_TMP
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             A.ZONENO,
             A.BRNO,
             A.BANKFLAG,
             '994',
             A.DICCODE,
             SUM(DECODE(A.CURRTYPE, '001', A.EC, A.EC / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.EC_MINUS,
                        A.EC_MINUS / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.BALANCE,
                        A.BALANCE / B.USCVRATE)),
             SUM(DECODE(A.CURRTYPE,
                        '001',
                        A.BALANCE_MINUS,
                        A.BALANCE_MINUS / B.USCVRATE))
        FROM CAP_EC_DATA_TMP A, PRM_EXCHANGE_RATE B
       WHERE A.CURRTYPE IN ('001', '992')
         AND A.ZONENO = B.ZONE_NO
         AND B.CURRENCY = '001'
         AND P_I_DATE >= B.START_DATE
         AND P_I_DATE < B.END_DATE
       GROUP BY ZONENO, BRNO, BANKFLAG, DICCODE;
    --------
    --插入到tmp2表中
    INSERT INTO CAP_EC_DATA_TMP2
      (DATA_DATE,
       ZONENO,
       BRNO,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS,
       BANKFLAG)
      SELECT DATA_DATE,
             ZONENO,
             BRNO,
             CURRTYPE,
             DICCODE,
             SUM(EC),
             SUM(EC_MINUS),
             SUM(BALANCE),
             SUM(BALANCE_MINUS),
             BANKFLAG
        FROM CAP_EC_DATA_TMP
       WHERE BANKFLAG IN ('3', '4')
         AND CURRTYPE IN ('001', '994')
       GROUP BY DATA_DATE, ZONENO, BRNO, CURRTYPE, DICCODE, BANKFLAG;
    ------------
    --插入人民币信贷风险合计
    INSERT INTO CAP_EC_DATA_TMP2
      (DATA_DATE,
       ZONENO,
       BRNO,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS,
       BANKFLAG)
      SELECT DATA_DATE,
             ZONENO,
             BRNO,
             '001',
             '999',
             SUM(EC),
             SUM(EC_MINUS),
             SUM(BALANCE),
             SUM(BALANCE_MINUS),
             BANKFLAG
        FROM CAP_EC_DATA_TMP
       WHERE BANKFLAG IN ('3', '4')
         AND CURRTYPE = '001'
       GROUP BY DATA_DATE, ZONENO, BRNO, BANKFLAG;
    ------------
    COMMIT;
    P_O_SUCCEED := '0';
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_ECDATA_XDFX;
