  PROCEDURE PROC_ECDATA_TOTAL(P_I_DATE    IN VARCHAR2,
                              P_O_SUCCEED OUT VARCHAR2) IS

    V_FLAG NUMBER(1) := 2; --行级别
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_ECTOTAL_DATA_1005.PROC_ECDATA_TOTAL';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';
    --------------------------------------------------------------------------------------------
    --------
    INSERT INTO CAP_EC_DATA_TMP2
      (DATA_DATE,
       ZONENO,
       BRNO,
       BANKFLAG,
       CURRTYPE,
       DICCODE,
       EC,
       EC_MINUS,
       BALANCE,
       BALANCE_MINUS)
      SELECT P_I_DATE,
             CAP.ZONENO,
             CAP.BRNO,
             CAP.BANKFLAG,
             CAP.CURRTYPE,
             PRM.PARENT_ID,
             SUM(CAP.EC),
             SUM(CAP.EC_MINUS),
             SUM(CAP.BALANCE),
             SUM(CAP.BALANCE_MINUS)
        FROM CAP_EC_DATA_TMP2 CAP, PRM_PRODUCT PRM
       WHERE CAP.DICCODE = PRM.PRODUCT_ID
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
       GROUP BY CAP.ZONENO,
                CAP.BRNO,
                CAP.BANKFLAG,
                CAP.CURRTYPE,
                PRM.PARENT_ID;
    -----插入CAP_EC_DATA表
    INSERT INTO CAP_EC_DATA
      (DATADATE,
       ORGANCODE,
       CURRENCY,
       ITEMCODE,
       KCDQVALUE,
       XSVALUE,
       ZCYEVALUE)
      SELECT CAP.DATA_DATE,
             CAP.ZONENO || CAP.BRNO,
             CAP.CURRTYPE,
             CAP.DICCODE,
             CAP.EC - CAP.EC_MINUS,
             DECODE(CAP.BALANCE, 0, 0, CAP.EC / CAP.BALANCE),
             CAP.BALANCE_MINUS
        FROM CAP_EC_DATA_TMP2 CAP;
    ------------
    --汇总信用风险本外币数据
    INSERT INTO CAP_EC_DATA
      (DATADATE,
       ORGANCODE,
       CURRENCY,
       ITEMCODE,
       KCDQVALUE,
       XSVALUE,
       ZCYEVALUE)
      SELECT CAP.DATADATE,
             CAP.ORGANCODE,
             '994',
             '000',
             SUM(CAP.KCDQVALUE),
             SUM(CAP.XSVALUE),
             SUM(CAP.ZCYEVALUE)
        FROM CAP_EC_DATA CAP,prm_product prm
       WHERE CAP.ITEMCODE <> '999'
         AND CAP.CURRENCY = '994'
         AND PRM.START_DATE <= P_I_DATE
         AND PRM.END_DATE > P_I_DATE
         AND prm.product_level='1'
         AND cap.itemcode=prm.product_id
       GROUP BY CAP.DATADATE, CAP.ORGANCODE;

    ---插入操作风险数据
    INSERT INTO CAP_EC_DATA
      (DATADATE,
       ORGANCODE,
       CURRENCY,
       ITEMCODE,
       KCDQVALUE,
       XSVALUE,
       ZCYEVALUE)
      SELECT P_I_DATE,
             DM.ZONENO || DM.BRNO,
             DM.CURRTYPE,
             '100',
             sum(DM.EC),
             0,
             0
        FROM DM_CS_CZFX DM
       WHERE DM.BANKFLAG IN ('3', '4')
       GROUP BY dm.zoneno,dm.brno,dm.bankflag,dm.currtype;
    --汇总经济资本占用总量
    INSERT INTO CAP_EC_DATA
      (DATADATE,
       ORGANCODE,
       CURRENCY,
       ITEMCODE,
       KCDQVALUE,
       XSVALUE,
       ZCYEVALUE)
      SELECT CAP.DATADATE,
             CAP.ORGANCODE,
             '994',
             '999',
             SUM(CAP.KCDQVALUE),
             SUM(CAP.XSVALUE),
             SUM(CAP.ZCYEVALUE)
        FROM CAP_EC_DATA CAP
       WHERE CAP.ITEMCODE <> '999'
         AND CAP.ITEMCODE IN ( '000','100')
         AND CAP.CURRENCY = '994'
       GROUP BY CAP.DATADATE, CAP.ORGANCODE;


    --结束，填写日志
    COMMIT;
    P_O_SUCCEED := '0';

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_ECDATA_TOTAL;

END PACK_ECTOTAL_DATA_1005;
//
CREATE OR REPLACE PACKAGE      PACK_EXP_USER_OPER_INFO AS
  PROCEDURE PROC_EXP_CAP_ASA_A0001(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   );
  PROCEDURE PROC_EXP_CAP_ASA_A0002(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   );
  PROCEDURE PROC_EXP_CAP_ASA_A0003(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   );
END PACK_EXP_USER_OPER_INFO;
//
CREATE OR REPLACE PACKAGE BODY      PACK_EXP_USER_OPER_INFO AS
  PROCEDURE PROC_EXP_CAP_ASA_A0001(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   ) IS
    V_PROC_NAME  CPMG.L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  CPMG.L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME CPMG.L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   CPMG.L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   CPMG.L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    CPMG.L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    CPMG.L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    CPMG.L_GETDATA_ERR.SQL_TXT%TYPE;

    V_RI_FLAG   VARCHAR2(1) := '1'; --'0'为运行
    V_FREQUENCE VARCHAR2(10);
    --v_succeed           VARCHAR2(1);
  BEGIN
    --数据校验,变量初始化-----------------------------------------------------------------------------------------------------------
    --记载数据处理日志
    V_STEP_NO   := '1';
    V_PROC_NAME := 'PACK_EXP_USER_OPER_INFO.PROC_EXP_CAP_ASA_A0001';
    V_LOG_LEVEL := '2';

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    COMMIT;
    --------------------------------------------------------------------------------------------------------------------------------
    --判断是否能运行


    -------------------------------------------------------------------------------------------------------------------------------
    IF p_i_date =
       TO_CHAR(LAST_DAY(TO_DATE(p_i_date, 'yyyymmdd')), 'yyyymmdd') THEN
      --如果运行，执行存储过程主体部分
      -------------------------------------------------------------------------------------------------------------------------------
      EXECUTE IMMEDIATE 'TRUNCATE TABLE EXP_CAP_ASA_A0001'; --清空表

      V_STEP_NO := '2'; --按地区号，网点号，模块号统计每月的交易数量
      INSERT INTO EXP_CAP_ASA_A0001
        (ZONENO, BRNO, MODULE_ID, CNT, DATADATE)
        SELECT SUBSTR(BRANCH_ID, 1, 4),
               SUBSTR(BRANCH_ID, 5, 4),
               FUNCMODULE_ID,
               COUNT(1),
               SUBSTR(P_I_DATE, 1, 6)
          FROM CPMG.LOG_USERLOG
         WHERE LOGDATE BETWEEN SUBSTR(P_I_DATE, 1, 4) || '0101' AND
               P_I_DATE
         GROUP BY SUBSTR(BRANCH_ID, 1, 4),
                  SUBSTR(BRANCH_ID, 5, 4),
                  FUNCMODULE_ID;

      --使用户在前台操作该表时，能选到该批量日期------------------------------------------------------------------------
      --Proc_Log_Record (P_I_DATE,'DM_D_CASH_RESULT_D',v_frequence,v_succeed);
      -------------------------------------------------------------------------------------------------------------------------------
    END IF; --存储过程主体部分结束
    -------------------------------------------------------------------------------------------------------------------------------
    --数据处理成功
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
    CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                         V_LOG_LEVEL,
                                         V_BEGIN_TIME,
                                         V_END_TIME,
                                         'SUCCESS',
                                         V_STEP_NO,
                                         V_SQL_TXT);
    P_O_SUCCEED := 0;
    COMMIT;

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                             V_LOG_LEVEL,
                                             V_BEGIN_TIME,
                                             V_END_TIME,
                                             'FAILED',
                                             V_STEP_NO,
                                             V_SQL_TXT,
                                             V_ERR_CODE,
                                             V_ERR_TXT);
        RAISE;
      END;
  END PROC_EXP_CAP_ASA_A0001;

  PROCEDURE PROC_EXP_CAP_ASA_A0002(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   ) IS
    V_PROC_NAME  CPMG.L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  CPMG.L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME CPMG.L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   CPMG.L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   CPMG.L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    CPMG.L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    CPMG.L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    CPMG.L_GETDATA_ERR.SQL_TXT%TYPE;

    V_RI_FLAG   VARCHAR2(1) := '1'; --'0'为运行
    V_FREQUENCE VARCHAR2(10);
    --v_succeed           VARCHAR2(1);
  BEGIN
    --数据校验,变量初始化-----------------------------------------------------------------------------------------------------------
    --记载数据处理日志
    V_STEP_NO   := '1';
    V_PROC_NAME := 'PACK_EXP_USER_OPER_INFO.PROC_EXP_CAP_ASA_A0002';
    V_LOG_LEVEL := '2';

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    COMMIT;
    --------------------------------------------------------------------------------------------------------------------------------
    --判断是否能运行


    -------------------------------------------------------------------------------------------------------------------------------
    IF p_i_date =
       TO_CHAR(LAST_DAY(TO_DATE(p_i_date, 'yyyymmdd')), 'yyyymmdd') THEN
      --如果运行，执行存储过程主体部分
      -------------------------------------------------------------------------------------------------------------------------------
      EXECUTE IMMEDIATE 'TRUNCATE TABLE EXP_CAP_ASA_A0002'; --清空表

      V_STEP_NO := '2'; --按地区号，网点号，行级别统计每月的交易数量
      INSERT INTO EXP_CAP_ASA_A0002
        (ZONENO, BRNO, USER_LEVEL, CNT,CNT_TOTAL, DATADATE)
        SELECT SUBSTR(BRANCH_ID, 1, 4),
               SUBSTR(BRANCH_ID, 5, 4),
               SUBSTR(BRANCH_ID, 9, 1),
               COUNT(1),
               3,
               SUBSTR(P_I_DATE, 1, 6) --P_I_DATE
          FROM (SELECT DISTINCT A.LOGDATE, A.USER_ID, A.BRANCH_ID
                  FROM CPMG.LOG_USERLOG A,cpmg.CTP_USER b
                 WHERE A.LOGDATE BETWEEN SUBSTR(P_I_DATE, 1, 4) || '0101' AND
                       P_I_DATE
                      )
         GROUP BY SUBSTR(BRANCH_ID, 1, 4),
                  SUBSTR(BRANCH_ID, 5, 4),
                  SUBSTR(BRANCH_ID, 9, 1);

      -------------------------------------------------------------------------------------------------------------------------------
    END IF; --存储过程主体部分结束
    -------------------------------------------------------------------------------------------------------------------------------
    --数据处理成功
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
    CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                         V_LOG_LEVEL,
                                         V_BEGIN_TIME,
                                         V_END_TIME,
                                         'SUCCESS',
                                         V_STEP_NO,
                                         V_SQL_TXT);
    P_O_SUCCEED := 0;
    COMMIT;

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                             V_LOG_LEVEL,
                                             V_BEGIN_TIME,
                                             V_END_TIME,
                                             'FAILED',
                                             V_STEP_NO,
                                             V_SQL_TXT,
                                             V_ERR_CODE,
                                             V_ERR_TXT);
        RAISE;
      END;
  END PROC_EXP_CAP_ASA_A0002;

  PROCEDURE PROC_EXP_CAP_ASA_A0003(P_I_DATE    IN VARCHAR2, --数据日期
                                   P_O_SUCCEED OUT VARCHAR2 --成功标志
                                   ) IS
    V_PROC_NAME  CPMG.L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  CPMG.L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME CPMG.L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   CPMG.L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   CPMG.L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    CPMG.L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    CPMG.L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    CPMG.L_GETDATA_ERR.SQL_TXT%TYPE;

    V_RI_FLAG   VARCHAR2(1) := '1'; --'0'为运行
    V_FREQUENCE VARCHAR2(10);
    --v_succeed           VARCHAR2(1);
  BEGIN
    --数据校验,变量初始化-----------------------------------------------------------------------------------------------------------
    --记载数据处理日志
    V_STEP_NO   := '1';
    V_PROC_NAME := 'PACK_EXP_USER_OPER_INFO.PROC_EXP_CAP_ASA_A0003';
    V_LOG_LEVEL := '2';

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    COMMIT;
    --------------------------------------------------------------------------------------------------------------------------------
    --判断是否能运行

    -------------------------------------------------------------------------------------------------------------------------------
   IF p_i_date =
       TO_CHAR(LAST_DAY(TO_DATE(p_i_date, 'yyyymmdd')), 'yyyymmdd') THEN
      --如果运行，执行存储过程主体部分
      -------------------------------------------------------------------------------------------------------------------------------
      EXECUTE IMMEDIATE 'TRUNCATE TABLE EXP_CAP_ASA_A0003'; --清空表

      V_STEP_NO := '2'; --统计单个模块的交易数量，本月为空的填0
      INSERT INTO EXP_CAP_ASA_A0003
        (MODULE_ID, MODULE_NAME, CNT, DATADATE)
        SELECT C.ID,
              c.name,
               NVL(CNT, 0),
               SUBSTR(P_I_DATE, 1, 6)
          FROM (SELECT A.FUNCMODULE_ID, COUNT(1) CNT
                  FROM CPMG.LOG_USERLOG A
                 WHERE A.LOGDATE BETWEEN SUBSTR(P_I_DATE, 1, 4) || '0101' AND
                       P_I_DATE
                 GROUP BY A.FUNCMODULE_ID) B,
               CPMG.ctp_item C
         WHERE B.FUNCMODULE_ID(+) = C.id;

      -------------------------------------------------------------------------------------------------------------------------------
    END IF; --存储过程主体部分结束
    -------------------------------------------------------------------------------------------------------------------------------
    --数据处理成功
    V_END_TIME := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
    CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                         V_LOG_LEVEL,
                                         V_BEGIN_TIME,
                                         V_END_TIME,
                                         'SUCCESS',
                                         V_STEP_NO,
                                         V_SQL_TXT);
    P_O_SUCCEED := 0;
    COMMIT;

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        CPMG.PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                             V_LOG_LEVEL,
                                             V_BEGIN_TIME,
                                             V_END_TIME,
                                             'FAILED',
                                             V_STEP_NO,
                                             V_SQL_TXT,
                                             V_ERR_CODE,
                                             V_ERR_TXT);
        RAISE;
      END;
  END PROC_EXP_CAP_ASA_A0003;
END PACK_EXP_USER_OPER_INFO;
