CREATE OR REPLACE package body      PACK_INSERT_EDW_01 is
  PROCEDURE PROC_MAIN(P_I_DATE    IN VARCHAR2, --数据日期
                      P_O_SUCCEED OUT VARCHAR2) IS
    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;
    --v_deal_flag           L_GETDATA_CALL.DEAL_FLAG%TYPE    ;

    v_err_code L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt  L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no  L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt  L_GETDATA_ERR.SQL_TXT%TYPE;

  BEGIN
    --记载数据处理日志
    v_step_no    := '1';
    v_proc_name  := 'PACK_INSERT_EDW_01';
    v_log_level  := '1';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    v_step_no := '2';

    PROC_DEAL_NFGNLED(P_I_DATE, --数据日期
                      P_O_SUCCEED); --成功标志
    PROC_DEAL_NFPABRP(P_I_DATE, --数据日期
                      P_O_SUCCEED); --成功标志

    PROC_DEAL_NFWKPRF(P_I_DATE, --数据日期
                      P_O_SUCCEED); --成功标志
    PROC_DEAL_HFCAEXOA(P_I_DATE, --数据日期
                       P_O_SUCCEED); --成功标志
/*    PROC_DEAL_HNPASBJ(P_I_DATE, --数据日期
                      P_O_SUCCEED); --成功标志
*/  --改为时间压缩处理

    --数据处理成功
    P_O_SUCCEED := '0';
    COMMIT;

    --记载数据处理日志
    v_end_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);

  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        v_end_time  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        v_err_code  := SQLCODE;
        v_err_txt   := SUBSTR(SQLERRM, 1, 4000);
        Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                      v_log_level,
                                      v_begin_time,
                                      v_end_time,
                                      'FAILED',
                                      v_step_no,
                                      v_sql_txt,
                                      v_err_code,
                                      v_err_txt);
        RAISE;
      END;

  END PROC_MAIN;

  PROCEDURE PROC_DEAL_NFGNLED(P_I_DATE    IN VARCHAR2, --数据日期
                              P_O_SUCCEED OUT VARCHAR2) --成功标志
    /******************************************************************************************************************/
    --WORD存储过程名称  PROC_DEAL_NFGNLED
    --WORD存储过程描述  PROC_DEAL_NFGNLED
    --使用模型名        NFGNLED
    --WORD作者          崔瑜
    --WORD日期          2007-08-28 18:26:02
    --WORD功能          批量 总帐文件批量过程
    --WORD用途          新增
    --WORD参数说明      P_I_DATE           IN   VARCHAR2 ,
    --WORD参数说明      P_O_SUCCEED        OUT  VARCHAR2
    /******************************************************************************************************************/
   IS

    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;
    v_count      NUMBER;
    v_count_all  NUMBER;
    v_load_time  VARCHAR2(20);

    v_err_code L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt  L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no  L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt  L_GETDATA_ERR.SQL_TXT%TYPE;

  BEGIN
    --==============================================================================================================
    --STEP STEP1.日志变量赋值
    --==============================================================================================================
    v_step_no    := '1';
    v_proc_name  := 'PROC_DEAL_NFGNLED';
    v_log_level  := '3';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');

    --==============================================================================================================
    --STEP STEP2.NFGNLED   列抽取转换和维度转换 总帐文件批量过程
    --==============================================================================================================
    v_step_no := '2.1';
    --*************************************************************
    delete from DW_DAT_NFGNLED where DATA_DATE = P_I_DATE;
    --删除当日统计数
    DELETE dw_dat_data_load
     WHERE TABLE_ID = 'DW_DAT_NFGNLED'
       AND DATA_DATE = P_I_DATE;
    COMMIT;
    --STEP STEP 2.1
    v_step_no := '2.2';
    --*************************************************************
    --STEP STEP 2.2         插入数据到目标表中
    INSERT INTO DW_DAT_NFGNLED
      (ZONENO,
       BRNO,
       CURRTYPE,
       SUBCODE,
       SUBCLASS,
       SUBNATUE,
       LYDRBAL,
       LYCRBAL,
       TYDRAMT,
       TYCRAMT,
       TYDRINO,
       TYCRINO,
       LMDRBAL,
       LMCRBAL,
       TMDRAMT,
       TMCRAMT,
       TMDRINO,
       TMCRINO,
       LDDRBAL,
       LDCRBAL,
       TDDRAMT,
       TDCRAMT,
       TDDRBAL,
       TDCRBAL,
       TDDRINO,
       TDCRINO,
       DRACM,
       CRACM,
       ACCCONT,
       DATA_DATE)
      SELECT ODS_TMP_NFGNLED.ZONENO,
             ODS_TMP_NFGNLED.BRNO,
             ODS_TMP_NFGNLED.CURRTYPE,
             ODS_TMP_NFGNLED.SUBCODE,
             ODS_TMP_NFGNLED.SUBCLASS,
             ODS_TMP_NFGNLED.SUBNATUE,
             ODS_TMP_NFGNLED.LYDRBAL,
             ODS_TMP_NFGNLED.LYCRBAL,
             ODS_TMP_NFGNLED.TYDRAMT,
             ODS_TMP_NFGNLED.TYCRAMT,
             ODS_TMP_NFGNLED.TYDRINO,
             ODS_TMP_NFGNLED.TYCRINO,
             ODS_TMP_NFGNLED.LMDRBAL,
             ODS_TMP_NFGNLED.LMCRBAL,
             ODS_TMP_NFGNLED.TMDRAMT,
             ODS_TMP_NFGNLED.TMCRAMT,
             ODS_TMP_NFGNLED.TMDRINO,
             ODS_TMP_NFGNLED.TMCRINO,
             ODS_TMP_NFGNLED.LDDRBAL,
             ODS_TMP_NFGNLED.LDCRBAL,
             ODS_TMP_NFGNLED.TDDRAMT,
             ODS_TMP_NFGNLED.TDCRAMT,
             ODS_TMP_NFGNLED.TDDRBAL,
             ODS_TMP_NFGNLED.TDCRBAL,
             ODS_TMP_NFGNLED.TDDRINO,
             ODS_TMP_NFGNLED.TDCRINO,
             ODS_TMP_NFGNLED.DRACM,
             ODS_TMP_NFGNLED.CRACM,
             ODS_TMP_NFGNLED.ACCCONT,
             P_I_DATE
        FROM ODS_TMP_NFGNLED;

    COMMIT;

    SELECT MAX(DATA_DATE)
      INTO v_load_time
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'DW_DAT_NFGNLED';

    SELECT NVL(MAX(DATA_CONT), 0)
      INTO v_count_all
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'DW_DAT_NFGNLED'
       AND DATA_DATE = v_load_time;

    SELECT COUNT(*) INTO v_count FROM ODS_TMP_NFGNLED;

    INSERT INTO dw_dat_data_load
      (TABLE_ID, DATA_DATE, LOAD_TIME, DATA_CONT, INSERT_CONT)
    VALUES
      ('DW_DAT_NFGNLED',
       P_I_DATE,
       TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MM:SS'),
       v_count_all + v_count,
       v_count);

    v_end_time := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
    Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);

    P_O_SUCCEED := '0';
    COMMIT;
    --------------------------------------------------------------------------------------------------------------
    --意外处理
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        v_end_time  := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');
        P_O_SUCCEED := '1';
        v_err_code  := SQLCODE;
        v_err_txt   := SUBSTR(SQLERRM, 1, 4000);
        Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                      v_log_level,
                                      v_begin_time,
                                      v_end_time,
                                      'FAILED',
                                      v_step_no,
                                      v_sql_txt,
                                      v_err_code,
                                      v_err_txt);
        RAISE;
      END;

  END PROC_DEAL_NFGNLED;

  PROCEDURE PROC_DEAL_NFPABRP(P_I_DATE    IN VARCHAR2, --数据日期
                              P_O_SUCCEED OUT VARCHAR2) --成功标志
    /******************************************************************************************************************/
    --WORD存储过程名称  PROC_DEAL_NFPABRP
    --WORD存储过程描述  PROC_DEAL_NFPABRP
    --使用模型名        NFPABRP
    --WORD作者          崔瑜
    --WORD日期          2007-08-28 18:26:02
    --WORD功能          批量 网点参数表文件批量过程
    --WORD用途          新增
    --WORD参数说明      P_I_DATE           IN   VARCHAR2 ,
    --WORD参数说明      P_O_SUCCEED        OUT  VARCHAR2
    /******************************************************************************************************************/
   IS

    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;

    v_count     NUMBER;
    v_count_all NUMBER;
    v_load_time VARCHAR2(20);

    v_err_code L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt  L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no  L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt  L_GETDATA_ERR.SQL_TXT%TYPE;

  BEGIN
    --==============================================================================================================
    --STEP STEP1.日志变量赋值
    --==============================================================================================================
    v_step_no    := '1';
    v_proc_name  := 'PROC_DEAL_NFPABRP';
    v_log_level  := '3';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS');

    --==============================================================================================================
    --STEP STEP2.NFPABRP   列抽取转换和维度转换 网点参数表文件批量过程
    --==============================================================================================================
    v_step_no := '2.1';
    --*************************************************************
    --STEP STEP 2.1
    delete from DW_DAT_NFPABRP where DATA_DATE = P_I_DATE;
    --删除当日统计数
    DELETE dw_dat_data_load
     WHERE TABLE_ID = 'DW_DAT_NFPABRP'
