CREATE OR REPLACE package body PACK_INSERT_EDW_04 is

  PROCEDURE PROC_UPDATE_PRM_EXCHANGE_RATE(P_I_DATE    IN VARCHAR2, --输入日期
                                          P_O_SUCCEED OUT VARCHAR2 --成功标志
                                          ) IS
    v_insert_count  NUMBER;
    v_update_count1 NUMBER;
    v_update_count2 NUMBER;
    v_data          dw_dat_data_load.DATA_DATE%TYPE;
    v_tol_count     NUMBER;
    --Add 2010-08-23 11:16
    v_rec_cnt NUMBER;
    --End Add
    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;
    --v_deal_flag           L_GETDATA_CALL.DEAL_FLAG%TYPE    ;
    v_err_code  L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt   L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no   L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt   L_GETDATA_ERR.SQL_TXT%TYPE;
    V_1318count NUMBER;
    V_2321count NUMBER;
  BEGIN
    v_insert_count  := 0;
    v_update_count1 := 0;
    v_update_count2 := 0;
    v_tol_count     := 0;
    V_1318count     := 0;
    V_2321count     := 0;
    --记载数据处理日志
    v_step_no    := '1';
    v_proc_name  := 'PACK_INSERT_EDW_04.UPDATE_PRM_EXCHANGE_RATE';
    v_log_level  := '2';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    
    EXECUTE IMMEDIATE 'TRUNCATE TABLE cpmg.PRM_EXCHANGE_RATE';
    INSERT INTO PRM_EXCHANGE_RATE D
      (ZONE_NO, CURRENCY, USCVRATE, START_DATE, END_DATE, CURRSMBL)
      SELECT O.ZONENO,
             O.CURRTYPE,
             O.USCVRATE / 1000000000,
             P_I_DATE,
             '99991231',
             O.CURRSMBL
        FROM ODS_TMP_HFCAEXOA O;
    insert into PRM_EXCHANGE_RATE
      (ZONE_NO, CURRENCY, USCVRATE, START_DATE, END_DATE, CURRSMBL)
      select distinct b.zone_no,
                      a.CURRENCY,
                      a.USCVRATE,
                      a.START_DATE,
                      a.END_DATE,
                      a.CURRSMBL
        from PRM_EXCHANGE_RATE a, prm_ira_organ b
       where a.zone_no = '0000'
         and b.start_date <= p_i_date
         and b.end_date > p_i_date
         and b.bank_flag IN ('3', '4')
         and b.zone_no not in
             (select distinct zone_no from PRM_EXCHANGE_RATE c);
    ------------开始对特殊的地区号进行处理--20080916新增
    SELECT COUNT(*)
      INTO V_1318count
      FROM PRM_exchange_rate
     WHERE ZONE_NO = '1318';
    SELECT COUNT(*)
      INTO V_2321count
      FROM PRM_exchange_rate
     WHERE ZONE_NO = '2321';
    IF V_1318count = 0 THEN
      insert into prm_exchange_rate
        (zone_no, currency, uscvrate, start_date, end_date, currsmbl)
        select '1318',
               b.currency,
               b.uscvrate,
               b.start_date,
               b.end_date,
               b.currsmbl
          from prm_exchange_rate b
         where b.zone_no = '1311';
    END IF;
    IF V_2321count = 0 THEN
      insert into prm_exchange_rate
        (zone_no, currency, uscvrate, start_date, end_date, currsmbl)
        select '2321',
               b.currency,
               b.uscvrate,
               b.start_date,
               b.end_date,
               b.currsmbl
          from prm_exchange_rate b
         where b.zone_no = '2307';
    END IF;
    --Add 2010-08-23 11:16
    SELECT COUNT(*)
      INTO v_rec_cnt
      FROM PRM_EXCHANGE_RATE
     WHERE START_DATE = p_i_date
       AND ROWNUM = 1;
    IF v_rec_cnt > 0 THEN
      EXECUTE IMMEDIATE 'TRUNCATE TABLE CPMG.PRM_CURRENCY_RATE';
      INSERT INTO PRM_CURRENCY_RATE
        SELECT DISTINCT T1.CURRENCY, T1.USCVRATE
          FROM PRM_EXCHANGE_RATE T1
         WHERE T1.ROWID = (SELECT MAX(T2.ROWID)
                             FROM PRM_EXCHANGE_RATE T2
                            WHERE T2.CURRENCY = T1.CURRENCY
                              AND T2.START_DATE = p_i_date)
           AND T1.START_DATE = p_i_date;
      --ADD 2014-03-12 BY JIANGDQ
      IF SUBSTR(p_i_date, 5) IN ('0331', '0630', '0930', '1231') THEN
        DELETE FROM RMB_CURRENCY_RATE WHERE DATA_DATE = p_i_date;
        INSERT INTO RMB_CURRENCY_RATE
          (CURRENCY, RMBCVRATE, DATA_DATE)
          SELECT CURRENCY,
                 USCVRATE / (SELECT T.USCVRATE
                               FROM CPMG.PRM_CURRENCY_RATE T
                              WHERE T.CURRENCY = '001'),
                 p_i_date
            FROM CPMG.PRM_CURRENCY_RATE;
      END IF;
    END IF;
    --End Add
    /*    v_step_no := '2.6';
    --统计记录数
    --取出最后一次处理该表的总记录数
    SELECT DISTINCT MAX(DATA_DATE)
      INTO v_data
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'PRM_EXCHANGE_RATE';
    SELECT DISTINCT NVL(MAX(DATA_CONT), 0)
      INTO v_tol_count
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'PRM_EXCHANGE_RATE'
       AND DATA_DATE = v_data;
     SELECT COUNT(*)
      INTO v_insert_count
      FROM PRM_EXCHANGE_RATE
     WHERE START_DATE = P_I_DATE;
     INSERT INTO dw_dat_data_load
      (TABLE_ID, DATA_DATE, LOAD_TIME, DATA_CONT, MODI_CONT, INSERT_CONT)
    VALUES
      ('PRM_EXCHANGE_RATE',
       P_I_DATE,
       TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS'),
       v_tol_count + v_insert_count,
       v_update_count1 + v_update_count2,
       v_insert_count);*/
    --数据处理成功
    P_O_SUCCEED := '0';
    COMMIT;
    --记载数据处理日志
    v_end_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        v_end_time  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        v_err_code  := SQLCODE;
        v_err_txt   := SUBSTR(SQLERRM, 1, 4000);
        Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                      v_log_level,
                                      v_begin_time,
                                      v_end_time,
                                      'FAILED',
                                      v_step_no,
                                      v_sql_txt,
                                      v_err_code,
                                      v_err_txt);
        RAISE;
      END;
  END PROC_UPDATE_PRM_EXCHANGE_RATE;
  PROCEDURE PROC_UPDATE_PRM_SUBJECT(P_I_DATE    IN VARCHAR2, --输入日期
                                    P_O_SUCCEED OUT VARCHAR2 --成功标志
                                    ) IS
    v_insert_count  NUMBER;
    v_update_count1 NUMBER;
    v_update_count2 NUMBER;
    v_data          dw_dat_data_load.DATA_DATE%TYPE;
    v_tol_count     NUMBER;
    v_proc_name     L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level     L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time    L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time      L_GETDATA_CALL.END_TIME%TYPE;
    --v_deal_flag           L_GETDATA_CALL.DEAL_FLAG%TYPE    ;
    v_err_code L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt  L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no  L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt  L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    v_insert_count  := 0;
    v_update_count1 := 0;
    v_update_count2 := 0;
    v_tol_count     := 0;
    --记载数据处理日志
    v_step_no    := '1';
    v_proc_name  := 'PACK_INSERT_EDW_04.UPDATE_PRM_SUBJECT';
    v_log_level  := '2';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    v_step_no    := '2.1';
    --删除表中开始日期=P_I_DATE的记录
    DELETE PRM_SUBJECT DW
     WHERE DW.START_DATE >= P_I_DATE
       AND LENGTH(DW.SUBCODE) = 6;
    COMMIT;
    --结束日期为P_I_DATE-1的，置成99991231
    UPDATE PRM_SUBJECT DW
       SET DW.END_DATE = '99991231'
     WHERE DW.END_DATE >=
           TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD')
       AND LENGTH(DW.SUBCODE) = 6;
    COMMIT;
    --删除当日统计数
    DELETE dw_dat_data_load
     WHERE TABLE_ID = 'PRM_SUBJECT'
       AND DATA_DATE >= P_I_DATE;
    COMMIT;
    v_step_no := '2.2';
    --按字段比对，DW中有（有效）ODS中也有的记录，比对字段不一致，置DW结束日期为P_I_DATE-1
    UPDATE PRM_SUBJECT D
       SET D.END_DATE = TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1,
                                'YYYYMMDD')
     WHERE EXISTS (SELECT 1
              FROM ODS_TMP_HNFPASBJ O
             WHERE ((NVL(TO_CHAR(O.SUBNATUE), 'EMPTY') !=
                   NVL(TO_CHAR(D.SUBNATUE), 'EMPTY')) OR
                   (NVL(TO_CHAR(O.SUBCLASS), 'EMPTY') !=
                   NVL(TO_CHAR(D.SUBCLASS), 'EMPTY')) OR
                   (NVL(TO_CHAR(O.SUBNO), 'EMPTY') !=
                   NVL(TO_CHAR(D.SUBNO), 'EMPTY')) OR
                   (NVL(TO_CHAR(O.NOTES), 'EMPTY') !=
                   NVL(TO_CHAR(D.NOTES), 'EMPTY')) OR
                   (NVL(TO_CHAR(O.INTDIFF), 'EMPTY') !=
                   NVL(TO_CHAR(D.INTDIFF), 'EMPTY')) OR
                   (NVL(TO_CHAR(O.APPNO), 'EMPTY') !=
                   NVL(TO_CHAR(D.APPNO), 'EMPTY')))
               AND O.ZONENO = D.ZONENO
               AND O.SUBCODE = D.SUBCODE
               AND LENGTH(O.SUBCODE) = 6)
       AND D.END_DATE = '99991231'
    RETURNING COUNT(ROWID) INTO v_update_count1;
    COMMIT;
    v_step_no := '2.3';
    --重新插入有效的记录 从ODS插入DW
    INSERT INTO PRM_SUBJECT D
      (ZONENO,
       SUBCODE,
       SUBNATUE,
       SUBCLASS,
       SUBNO,
       NOTES,
       INTDIFF,
       APPNO,
       START_DATE,
       END_DATE)
      SELECT O.ZONENO,
             O.SUBCODE,
             O.SUBNATUE,
             O.SUBCLASS,
             O.SUBNO,
             O.NOTES,
             O.INTDIFF,
             O.APPNO,
             P_I_DATE,
             '99991231'
        FROM ODS_TMP_HNFPASBJ O, PRM_SUBJECT D
       WHERE O.ZONENO = D.ZONENO
         AND O.SUBCODE = D.SUBCODE
         AND D.END_DATE =
             TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD')
         AND LENGTH(O.SUBCODE) = 6;
    COMMIT;
    v_step_no := '2.4';
    --以主键查找，DW表中有（有效）ODS表中没有的记录，置结束日期为P_I_DATE-1
    UPDATE PRM_SUBJECT DW
       SET DW.END_DATE = TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1,
                                 'YYYYMMDD')
     WHERE NOT EXISTS (SELECT 1
              FROM ODS_TMP_HNFPASBJ ODS
             WHERE ODS.ZONENO = DW.ZONENO
               AND ODS.SUBCODE = DW.SUBCODE)
       AND DW.END_DATE = '99991231'
       AND LENGTH(DW.SUBCODE) = 6
    RETURNING COUNT(ROWID) INTO v_update_count2;
    COMMIT;
    v_step_no := '2.5';
    --以主键查找，DW表中没有（有效）ODS表中有的记录，插入DW表
    INSERT INTO PRM_SUBJECT
      (ZONENO,
       SUBCODE,
       SUBNATUE,
       SUBCLASS,
       SUBNO,
       NOTES,
       INTDIFF,
       APPNO,
       START_DATE,
       END_DATE)
      SELECT ODS.ZONENO,
             ODS.SUBCODE,
             ODS.SUBNATUE,
             ODS.SUBCLASS,
             ODS.SUBNO,
             ODS.NOTES,
             ODS.INTDIFF,
             ODS.APPNO,
             P_I_DATE,
             '99991231'
        FROM ODS_TMP_HNFPASBJ ODS
       WHERE NOT EXISTS (SELECT 1
                FROM PRM_SUBJECT DW
               WHERE DW.ZONENO = ODS.ZONENO
                 AND DW.SUBCODE = ODS.SUBCODE
                 AND DW.END_DATE = '99991231')
         AND LENGTH(ODS.SUBCODE) = 6;
    v_step_no := '2.6';
    --统计记录数
    --取出最后一次处理该表的总记录数
    SELECT DISTINCT MAX(DATA_DATE)
      INTO v_data
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'PRM_SUBJECT';
    SELECT DISTINCT NVL(MAX(DATA_CONT), 0)
      INTO v_tol_count
      FROM dw_dat_data_load
     WHERE TABLE_ID = 'PRM_SUBJECT'
       AND DATA_DATE = v_data;
    SELECT COUNT(*)
      INTO v_insert_count
      FROM PRM_SUBJECT
     WHERE START_DATE = P_I_DATE;
    INSERT INTO dw_dat_data_load
      (TABLE_ID, DATA_DATE, LOAD_TIME, DATA_CONT, MODI_CONT, INSERT_CONT)
    VALUES
      ('PRM_SUBJECT',
       P_I_DATE,
       TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS'),
       v_tol_count + v_insert_count,
       v_update_count1 + v_update_count2,
       v_insert_count);
    --数据处理成功
    P_O_SUCCEED := '0';
    COMMIT;
    --记载数据处理日志
    v_end_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        v_end_time  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        v_err_code  := SQLCODE;
        v_err_txt   := SUBSTR(SQLERRM, 1, 4000);
        Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                      v_log_level,
                                      v_begin_time,
                                      v_end_time,
                                      'FAILED',
                                      v_step_no,
                                      v_sql_txt,
                                      v_err_code,
                                      v_err_txt);
        RAISE;
      END;
  END PROC_UPDATE_PRM_SUBJECT;
  PROCEDURE PROC_RECOVERY_PRM --恢复
  (P_I_DATE    IN VARCHAR2, --输入日期
   P_O_SUCCEED OUT VARCHAR2 --成功标志
   ) IS
    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;
    --v_deal_flag           L_GETDATA_CALL.DEAL_FLAG%TYPE    ;
    v_err_code L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt  L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no  L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt  L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    --记载数据处理日志
    v_step_no    := '1';
    v_proc_name  := 'PACK_INSERT_EDW_04.PROC_RECOVERY_PRM';
    v_log_level  := '1';
    v_begin_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    v_step_no    := '2.1';
    --删除表中开始日期=P_I_DATE的记录
    DELETE PRM_EXCHANGE_RATE DW --对攻汇率表
     WHERE DW.START_DATE >= P_I_DATE;
    COMMIT;
    --结束日期为P_I_DATE-1的，置成99991231
    UPDATE PRM_EXCHANGE_RATE DW
       SET DW.END_DATE = '99991231'
     WHERE DW.END_DATE >=
           TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD');
    COMMIT;
    --删除当日统计数
    DELETE dw_dat_data_load
     WHERE TABLE_ID = 'PRM_EXCHANGE_RATE'
       AND DATA_DATE >= P_I_DATE;
    COMMIT;
    v_step_no := '2.2';
    --删除表中开始日期=P_I_DATE的记录
    DELETE PRM_SUBJECT DW --科目表
     WHERE DW.START_DATE >= P_I_DATE
       AND LENGTH(SUBCODE) = 6;
    COMMIT;
    --结束日期为P_I_DATE-1的，置成99991231
    UPDATE PRM_SUBJECT DW
       SET DW.END_DATE = '99991231'
     WHERE DW.END_DATE >=
           TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD');
    COMMIT;
    --删除当日统计数
    DELETE dw_dat_data_load
     WHERE TABLE_ID = 'PRM_SUBJECT'
       AND DATA_DATE >= P_I_DATE;
    COMMIT;
    --数据处理成功
    P_O_SUCCEED := '0';
    COMMIT;
    --记载数据处理日志
    v_end_time := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        v_end_time  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        v_err_code  := SQLCODE;
        v_err_txt   := SUBSTR(SQLERRM, 1, 4000);
        Pack_Getdata_Log.PR_LOG_WRITE(v_proc_name,
                                      v_log_level,
                                      v_begin_time,
                                      v_end_time,
                                      'FAILED',
                                      v_step_no,
                                      v_sql_txt,
                                      v_err_code,
                                      v_err_txt);
        RAISE;
      END;
  END PROC_RECOVERY_PRM;
end PACK_INSERT_EDW_04;
//
CREATE OR REPLACE PACKAGE PACK_INSERT_OLAP IS

  PROCEDURE PROC_OLAP_FADAI(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);

  PROCEDURE PROC_OLAP_ALL(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);

  PROCEDURE PROC_OLAP_DIM(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);

 
  FUNCTION FUNC_GET_ZJDBCODE(DB_CODE IN VARCHAR2) RETURN VARCHAR2;
END PACK_INSERT_OLAP;
//
CREATE OR REPLACE PACKAGE BODY PACK_INSERT_OLAP IS
  PROCEDURE PROC_OLAP_FADAI(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_FLAG       NUMBER(1) := 3; --行级别

  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_INSERT_OLAP.PROC_OLAP_FADAI';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';



IF p_I_DATE =  to_char(last_day(to_date(P_I_DATE,'YYYYMMDD')),'YYYYMMDD') THEN
    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;

    --开始删除fact表中数据
    DELETE FROM olap_fact_faren
           WHERE DATA_DATE = P_I_DATE;

    COMMIT;
    DELETE FROM olap_fact_faren
      WHERE DATA_DATE <= to_char(add_months(to_date(P_I_DATE,'YYYYMMDD'),-13),'YYYYMMDD');

    COMMIT;
  --把法人贷款数据插入dm表
   INSERT INTO olap_fact_faren
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       deadline,
       business,
       product1,
       product2,
       product3,
       pd,
       lgd,
       is_small,
       balance,
       ec)
      SELECT P_I_DATE,
                '0'  ,              --一级分行
             dw.zoneno||dw.brno,
             DW.CURRTYPE,
             DW.XYVALUE,
             '00000'||substr(DW.DBFS_ID,1,5),
             decode(DW.TA200261037,
                     '10','1','20','1','21','1','22','1',
                     '30','2','31','2','32','2',
                     '40','3','41','3',
                     '42','4','50','4',
                     '60','5','0'),                   --资产质量
             DW.QXDC_ID2,                  --期限
             dw.TA200011014,    --行业
             '1'     ,         --一级产品
             '1'  ,          --二级级产品
             DW.PRODUCT_ID3,     --三级产品
             substr(DW.TA200261037,1,1),            --PD
             NVL2(dw.lgd,LGD.lgd_level,0),             --LDG
             DW.SMALL_CORP,     --小企业
             SUM(DW.BALANCE),
             SUM(DW.ECOST)
        FROM DW_MOD_FRDK DW,

             (SELECT t.seg_seq lgd_level,
                     t.LOWER lower_limit,
                     NVL(LEAD(LOWER) OVER(ORDER BY TO_NUMBER(t.seg_seq)), 999) upper_limit
                FROM cpmg.prm_csfr5 t
               WHERE t.start_date <= P_I_DATE
                 AND t.end_date > P_I_DATE) LGD

       WHERE DW.START_DATE = P_I_DATE


          AND NVL(dw.lgd,0) >= lgd.lower_limit
          AND NVL(dw.lgd,0) < lgd.upper_limit

       GROUP BY dw.zoneno||dw.brno,
             DW.CURRTYPE,
             DW.XYVALUE,
             DW.DBFS_ID,
             DW.TA200261037,
                                       --资产质量
             DW.QXDC_ID2 ,                  --期限
             dw.TA200011014,
             DW.PRODUCT_ID3,     --三级产品
             NVL2(dw.lgd,LGD.lgd_level,0),           --LDG
             DW.SMALL_CORP ;     --小企业
  COMMIT;
    ---开始折币
    ---------------------开始外币折美元-----------------
    INSERT INTO olap_fact_faren
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       deadline,
       business,
       product1,
       product2,
       product3,
       pd,
       lgd,
       is_small,
       balance,
       ec)
      SELECT A.data_date,
             A.branch1,
             A.branch2,
             '992',
             A.credit_lvl,
             A.assurance,
             A.asset_quality,
             A.deadline,
             A.business,
             A.product1,
             A.product2,
             A.product3,
             A.pd,
             A.lgd,
             A.is_small,
             SUM(A.balance * B.USCVRATE),
             SUM(A.ec * B.USCVRATE)
        FROM olap_fact_faren A, PRM_EXCHANGE_RATE B
       WHERE A.currency <> '001'
         AND substr(A.branch2,1,4) = B.ZONE_NO
         AND A.currency = B.CURRENCY
         AND A.DATA_DATE=P_I_DATE

       GROUP BY A.data_date,
               A.branch1,
               A.branch2,
               A.currency,
               A.credit_lvl,
               A.assurance,
               A.asset_quality,
               A.deadline,
               A.business,
               A.product1,
               A.product2,
               A.product3,
               A.pd,
               A.lgd,
               A.is_small;

    COMMIT;
    ----------------开始本外币折人民币----------------
    INSERT INTO olap_fact_faren
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       deadline,
       business,
       product1,
       product2,
       product3,
       pd,
       lgd,
       is_small,
       balance,
       ec)
      SELECT A.data_date,
             A.branch1,
             A.branch2,
             '994',
             A.credit_lvl,
             A.assurance,
             A.asset_quality,
             A.deadline,
             A.business,
             A.product1,
             A.product2,
             A.product3,
             A.pd,
             A.lgd,
             A.is_small,
             SUM(DECODE(A.currency,
                        '001',
                        A.balance,
                        A.balance / B.USCVRATE)),

             SUM(DECODE(A.currency,
                        '001',
                        A.ec,
                        A.ec / B.USCVRATE))
        FROM olap_fact_faren A, PRM_EXCHANGE_RATE B
       WHERE A.CURRENCY IN ('001', '992')
         AND substr(A.branch2,1,4) = B.ZONE_NO
         AND B.CURRENCY = '001'
         AND A.DATA_DATE=P_I_DATE

       GROUP BY A.data_date,
                 A.branch1,
                 A.branch2,
                 A.currency,
                 A.credit_lvl,
                 A.assurance,
                 A.asset_quality,
                 A.deadline,
                 A.business,
                 A.product1,
                 A.product2,
                 A.product3,
                 A.pd,
                 A.lgd,
                 A.is_small;
COMMIT;
DELETE OLAP_FACT_FAREN t WHERE t.currency NOT IN

(SELECT dic.kind_id FROM dic_all_kind dic WHERE dic.operation_kind='CURRENCY')
AND t.DATA_DATE=P_I_DATE;

COMMIT;

    --开始汇总
    FOR V_FLAG IN 0 .. 4 LOOP
      MERGE INTO olap_fact_faren t
      USING (SELECT t.data_date,
                    PRM.BELONG_BANK_FLAG branch1,
                    PRM.BELONG_ZONENO||PRM.BELONG_BRNO branch2,
                    t.currency,
                     t.credit_lvl,
                     t.assurance,
                     t.asset_quality,
                     t.deadline,
                     t.business,
                     t.product1,
                     t.product2,
                     t.product3,
                     t.pd,
                     t.lgd,
                     t.is_small,
                    SUM(t.balance) balance,
                    SUM(t.ec) ec
               FROM olap_fact_faren t, PRM_IRA_ORGAN PRM
              WHERE substr(t.branch2,1,4) = PRM.ZONE_NO
                AND substr(t.branch2,5,4) = PRM.BR_NO
                AND t.branch1 = PRM.BANK_FLAG
                AND PRM.BELONG_BANK_FLAG = V_FLAG
                AND PRM.BANK_FLAG <> V_FLAG
                AND P_I_DATE >= PRM.START_DATE
                AND P_I_DATE < PRM.END_DATE
                AND t.data_date=P_I_DATE
              GROUP BY PRM.BELONG_BANK_FLAG,
                       PRM.BELONG_ZONENO||PRM.BELONG_BRNO,
                       t.data_date,
                       t.currency,
                       t.credit_lvl,
                       t.assurance,
                       t.asset_quality,
                       t.deadline,
                       t.business,
                       t.product1,
                       t.product2,
                       t.product3,
                       t.pd,
                       t.lgd,
                       t.is_small) TMP
      ON (t.data_date=TMP.data_date
       AND t.branch1=TMP.branch1
       AND t.branch2=TMP.branch2
       AND t.currency=TMP.currency
       AND  t.credit_lvl=TMP.credit_lvl
       AND t.assurance=TMP.assurance
       AND t.asset_quality=TMP.asset_quality
       AND t.deadline=TMP.deadline
       AND  t.business=TMP.business
       AND t.product1=TMP.product1
       AND t.product2=TMP.product2
       AND t.product3=TMP.product3
       AND t.pd=TMP.pd
       AND t.lgd=TMP.lgd
       AND t.is_small=TMP.is_small )
      WHEN MATCHED THEN
        UPDATE
           SET t.balance  = t.balance + TMP.balance,
               t.ec  = t.ec + TMP.ec
      WHEN NOT MATCHED THEN
        INSERT
          (data_date,
           branch1,
           branch2,
           currency,
           credit_lvl,
           assurance,
           asset_quality,
           deadline,
           business,
           product1,
           product2,
           product3,
           pd,
           lgd,
           is_small,
           balance,
           ec)
        VALUES
          (TMP.data_date,
           TMP.branch1,
           TMP.branch2,
           TMP.currency,
           TMP.credit_lvl,
           TMP.assurance,
           TMP.asset_quality,
           TMP.deadline,
           TMP.business,
           TMP.product1,
           TMP.product2,
           TMP.product3,
           TMP.pd,
           TMP.lgd,
           TMP.is_small,
           TMP.balance,
           TMP.ec);
    END LOOP;

    -----------
    COMMIT;

  DELETE olap_fact_faren WHERE branch1 NOT IN ('2','3') AND DATA_DATE=P_I_DATE;
  COMMIT;

DELETE olap_fact_faren t
 WHERE t.branch1 = '2'
   AND NOT exists (select 1
          from (SELECT DISTINCT t.belong_zoneno Bzone
                    FROM prm_ira_organ t
                   WHERE t.bank_flag = 2
                     AND t.belong_bank_flag = 4) A
         where substr(t.branch2, 1, 4) = A.bzone)
   AND t.DATA_DATE = P_I_DATE;
  COMMIT;
--添加产品代码
  INSERT INTO olap_fact_faren
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       deadline,
       business,
       product1,
       product2,
       product3,
       pd,
       lgd,
       is_small,
       balance,
       ec)
   SELECT  t.data_date,
           po.belong_zoneno||po.belong_brno,
           t.branch2,
           t.currency,
           t.credit_lvl,
           t.assurance,
           t.asset_quality,
           t.deadline,
           t.business,
           NVL(prod.p1,0),
           NVL(prod.p2,0),
           t.product3,
           t.pd,
           t.lgd,
           t.is_small,
           t.balance,
           t.ec
     FROM olap_fact_faren t,
          prm_ira_organ po,
          (SELECT t1.product_id p3, t1.parent_id p2, t2.parent_id p1
  FROM prm_product t2,
       (select t.product_id, t.parent_id
          from prm_product t
         where t.start_date <= P_I_DATE
           and t.end_date > P_I_DATE) t1
 WHERE t1.parent_id = t2.product_id
   AND t2.parent_id IS NOT NULL
   and t2.start_date <= P_I_DATE
   and t2.end_date > P_I_DATE
UNION ALL
SELECT t.product_id, t.product_id, t.parent_id
  FROM prm_product t

 WHERE t.product_level = 2
   and t.start_date <= P_I_DATE
   and t.end_date > P_I_DATE
   AND t.product_id NOT IN
       (SELECT t.parent_id
          FROM prm_product t
         WHERE t.product_level = 3
           and t.start_date <= P_I_DATE
           and t.end_date > P_I_DATE)) prod
    WHERE t.branch2=po.zone_no||po.br_no
      AND t.product3=prod.p3(+)
      AND t.data_date=P_I_DATE
      AND po.bank_flag IN (2,3);

    DELETE olap_fact_faren WHERE length(branch1)=1 AND DATA_DATE=P_I_DATE;

    COMMIT;


    P_O_SUCCEED := '0';
 END IF;
    P_O_SUCCEED := '0';
    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_OLAP_FADAI;


  PROCEDURE PROC_OLAP_All(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_FLAG       NUMBER(1) := 3; --行级别

  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_INSERT_OLAP.PROC_OLAP_All';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';

    --读取系统时间记载开始处理时间

IF p_I_DATE =  to_char(last_day(to_date(P_I_DATE,'YYYYMMDD')),'YYYYMMDD') THEN
    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;


    --开始删除DM表中数据
   DELETE FROM olap_fact_all
           WHERE DATA_DATE = P_I_DATE;

    COMMIT;
    DELETE FROM olap_fact_all
      WHERE DATA_DATE <= to_char(add_months(to_date(P_I_DATE,'YYYYMMDD'),-13),'YYYYMMDD');

    COMMIT;
    --插入票据数据
    INSERT INTO olap_fact_all
      (data_date, branch1, branch2, currency, credit_lvl, assurance, asset_quality, business, product1, product2, product3, balance, ec)

    SELECT P_I_DATE,
                '0'  ,              --一级分行
             dw.zoneno||dw.ACTBRNO,
             '001',                           --币种
             DW.CREDITLEVEL,
             NULL,                            --担保方式
             dw.LEVELFIVE ,                 --资产质量
             NULL,    --行业
             '1'     ,         --一级产品
             '1'  ,          --二级级产品
             DW.PRODUCT,     --三级产品
             SUM(DW.BILLAMT),
             SUM(DW.EC)
      FROM   Dw_Mod_Pjtx DW
     WHERE DW.START_DATE = P_I_DATE
       GROUP BY dw.zoneno||dw.ACTBRNO,
            DW.CREDITLEVEL,
            dw.LEVELFIVE,
            DW.PRODUCT ;
    COMMIT;
    --插入个贷数据

    INSERT INTO olap_fact_all
      (data_date, branch1, branch2, currency, credit_lvl, assurance, asset_quality, business, product1, product2, product3, balance, ec)
    SELECT P_I_DATE,
                '0'  ,              --一级分行
             dw.zoneno||dw.ACTBRNO,
             dw.CURRTYPE,                           --币种
             DW.TA290008004,                 --信用等级
             SUBSTR(FUNC_GET_ZJDBCODE(DW.TA500251018), 1, 6), --substr(dw.TA500251018,1,6),                            --担保方式
             dw.TA500261018  ,                 --资产质量
             NULL,    --行业
             '1'     ,         --一级产品
             '1'  ,          --二级级产品
             DW.PRODUCT_ID3,     --三级产品
             SUM(DW.BALANCE),
             SUM(DW.ECOST)
      FROM   Dw_Mod_GRDK DW
     WHERE DW.START_DATE = P_I_DATE
       GROUP BY dw.zoneno||dw.ACTBRNO,
            dw.CURRTYPE,
            DW.TA290008004,
            dw.TA500261018,
            dw.TA500251018,
            DW.PRODUCT_ID3 ;
    COMMIT;
    --外币折美元
    INSERT INTO olap_fact_all
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       business,
       product1,
       product2,
       product3,
       balance,
       ec)
      SELECT A.data_date,
             A.branch1,
             A.branch2,
             '992',
             A.credit_lvl,
             A.assurance,
             A.asset_quality,
             A.business,
             A.product1,
             A.product2,
             A.product3,
             SUM(A.balance * B.USCVRATE),
             SUM(A.ec * B.USCVRATE)
        FROM olap_fact_all A, PRM_EXCHANGE_RATE B
       WHERE A.currency <> '001'
         AND substr(A.branch2,1,4) = B.ZONE_NO
         AND A.currency = B.CURRENCY
         AND A.DATA_DATE=P_I_DATE

       GROUP BY A.data_date,
               A.branch1,
               A.branch2,
               A.currency,
               A.credit_lvl,
               A.assurance,
               A.asset_quality,
               A.business,
               A.product1,
               A.product2,
               A.product3;

    COMMIT;
    ----------------开始本外币折人民币----------------
    INSERT INTO olap_fact_all
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       business,
       product1,
       product2,
       product3,
       balance,
       ec)
      SELECT A.data_date,
             A.branch1,
             A.branch2,
             '994',
             A.credit_lvl,
             A.assurance,
             A.asset_quality,
             A.business,
             A.product1,
             A.product2,
             A.product3,
             SUM(DECODE(A.currency,
                        '001',
                        A.balance,
                        A.balance / B.USCVRATE)),

             SUM(DECODE(A.currency,
                        '001',
                        A.ec,
                        A.ec / B.USCVRATE))
        FROM olap_fact_all A, PRM_EXCHANGE_RATE B
       WHERE A.CURRENCY IN ('001', '992')
         AND substr(A.branch2,1,4) = B.ZONE_NO
         AND B.CURRENCY = '001'
         AND A.DATA_DATE=P_I_DATE

       GROUP BY A.data_date,
                 A.branch1,
                 A.branch2,
                 A.currency,
                 A.credit_lvl,
                 A.assurance,
                 A.asset_quality,
                 A.business,
                 A.product1,
                 A.product2,
                 A.product3;

COMMIT;
DELETE OLAP_FACT_FAREN t WHERE t.currency NOT IN
(SELECT dic.kind_id FROM dic_all_kind dic WHERE dic.operation_kind='CURRENCY')
AND t.DATA_DATE=P_I_DATE;

COMMIT;

    --开始汇总
    FOR V_FLAG IN 0 .. 4 LOOP
      MERGE INTO olap_fact_all t
      USING (SELECT t.data_date,
                    PRM.BELONG_BANK_FLAG branch1,
                    PRM.BELONG_ZONENO||PRM.BELONG_BRNO branch2,
                    t.currency,
                     t.credit_lvl,
                     t.assurance,
                     t.asset_quality,
                     t.business,
                     t.product1,
                     t.product2,
                     t.product3,
                    SUM(t.balance) balance,
                    SUM(t.ec) ec
               FROM olap_fact_all t, PRM_IRA_ORGAN PRM
              WHERE substr(t.branch2,1,4) = PRM.ZONE_NO
                AND substr(t.branch2,5,4) = PRM.BR_NO
                AND t.branch1 = PRM.BANK_FLAG
                AND PRM.BELONG_BANK_FLAG = V_FLAG
                AND PRM.BANK_FLAG <> V_FLAG
                AND P_I_DATE >= PRM.START_DATE
                AND P_I_DATE < PRM.END_DATE
                AND t.data_date=P_I_DATE
              GROUP BY PRM.BELONG_BANK_FLAG,
                       PRM.BELONG_ZONENO||PRM.BELONG_BRNO,
                       t.data_date,
                       t.currency,
                       t.credit_lvl,
                       t.assurance,
                       t.asset_quality,
                       t.business,
                       t.product1,
                       t.product2,
                       t.product3) TMP
      ON (t.data_date=TMP.data_date
       AND t.branch1=TMP.branch1
       AND t.branch2=TMP.branch2
       AND t.currency=TMP.currency
       AND  t.credit_lvl=TMP.credit_lvl
       AND t.assurance=TMP.assurance
       AND t.asset_quality=TMP.asset_quality
       AND  t.business=TMP.business
       AND t.product1=TMP.product1
       AND t.product2=TMP.product2
       AND t.product3=TMP.product3 )
      WHEN MATCHED THEN
        UPDATE
           SET t.balance  = t.balance + TMP.balance,
               t.ec  = t.ec + TMP.ec
      WHEN NOT MATCHED THEN
        INSERT
          (data_date,
           branch1,
           branch2,
           currency,
           credit_lvl,
           assurance,
           asset_quality,
           business,
           product1,
           product2,
           product3,
           balance,
           ec)
        VALUES
          (TMP.data_date,
           TMP.branch1,
           TMP.branch2,
           TMP.currency,
           TMP.credit_lvl,
           TMP.assurance,
           TMP.asset_quality,
           TMP.business,
           TMP.product1,
           TMP.product2,
           TMP.product3,
           TMP.balance,
           TMP.ec);
    END LOOP;

    -----------
    COMMIT;

  DELETE olap_fact_all WHERE branch1 NOT IN ('2','3') AND DATA_DATE =P_I_DATE;
  COMMIT;

DELETE olap_fact_all t
 WHERE t.branch1 = '2'
   AND NOT exists (select 1
          from (SELECT DISTINCT t.belong_zoneno Bzone
                    FROM prm_ira_organ t
                   WHERE t.bank_flag = 2
                     AND t.belong_bank_flag = 4) A
         where substr(t.branch2, 1, 4) = A.bzone)
   AND t.DATA_DATE = P_I_DATE;
  COMMIT;
--添加产品代码
  INSERT INTO olap_fact_all
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       business,
       product1,
       product2,
       product3,
       balance,
       ec)
   SELECT  t.data_date,
           po.belong_zoneno||po.belong_brno,
           t.branch2,
           t.currency,
           t.credit_lvl,
           t.assurance,
           t.asset_quality,
           t.business,
           NVL(prod.p1,0),
           NVL(prod.p2,0),
           t.product3,
           t.balance,
           t.ec
     FROM olap_fact_all t,
          prm_ira_organ po,
          (SELECT t1.product_id p3, t1.parent_id p2, t2.parent_id p1
  FROM prm_product t2,
       (select t.product_id, t.parent_id
          from prm_product t
         where t.start_date <= P_I_DATE
           and t.end_date > P_I_DATE) t1
 WHERE t1.parent_id = t2.product_id
   AND t2.parent_id IS NOT NULL
   and t2.start_date <= P_I_DATE
   and t2.end_date > P_I_DATE
UNION ALL
SELECT t.product_id, t.product_id, t.parent_id
  FROM prm_product t

 WHERE t.product_level = 2
   and t.start_date <= P_I_DATE
   and t.end_date > P_I_DATE
   AND t.product_id NOT IN
       (SELECT t.parent_id
          FROM prm_product t
         WHERE t.product_level = 3
           and t.start_date <= P_I_DATE
           and t.end_date > P_I_DATE)) prod
    WHERE t.branch2=po.zone_no||po.br_no
      AND t.product3=prod.p3(+)
      AND t.data_date=P_I_DATE
      AND po.bank_flag IN (2,3);

    DELETE olap_fact_all WHERE length(branch1)=1 AND DATA_DATE=P_I_DATE;

    COMMIT;


    --插入法人贷款数据
    INSERT INTO olap_fact_all
      (data_date,
       branch1,
       branch2,
       currency,
       credit_lvl,
       assurance,
       asset_quality,
       business,
       product1,
       product2,
       product3,
       balance,
       ec)
      SELECT data_date,
             branch1,
             branch2,
             currency,
             credit_lvl,
             assurance,
             asset_quality,
             business,
             product1,
             product2,
             product3,
             sum(balance),
             sum(ec)
        FROM olap_fact_faren
       WHERE data_date=P_I_DATE
    GROUP BY data_date,
             branch1,
             branch2,
             currency,
             credit_lvl,
             assurance,
             asset_quality,
             business,
             product1,
             product2,
             product3;
      -----------
    COMMIT;

    P_O_SUCCEED := '0';
   END IF;

    P_O_SUCCEED := '0';
    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;
  END PROC_OLAP_ALL;

PROCEDURE PROC_OLAP_DIM(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2)  IS
    --以下变量为记录日志时使用的。
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    i            NUMBER(2);

  BEGIN

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PACK_INSERT_OLAP.PROC_OLAP_FADAI';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
