COMMIT;
FOR i IN 1..63
LOOP
INSERT INTO olap_dim_assurance
(assurance_id, assurance_name, start_date, end_date)
SELECT floor(i/32)|| floor(mod(i,32)/16)|| floor(mod(i,16)/8)|| floor(mod(i,8)/4)|| floor(mod(i,4)/2)|| mod(i,2),

decode(floor(i/32),1,'抵押 ',NULL)||
