decode(floor(mod(i,16)/8),1,'保证 ',NULL)||
decode(floor(mod(i,8)/4),1,'信用 ',NULL)||
decode(floor(mod(i,4)/2),1,'其他 ',NULL)||
decode(MOD(i,2),1,'保单',NULL),
'19000101',
'99991231'
FROM dual
WHERE decode(floor(i/32),1,'抵押 ',NULL)||
decode(floor(mod(i,32)/16),1,'质押 ',NULL)||
decode(floor(mod(i,16)/8),1,'保证 ',NULL)||
decode(floor(mod(i,8)/4),1,'信用 ',NULL)||
decode(floor(mod(i,4)/2),1,'其他 ',NULL)||
decode(MOD(i,2),1,'保单',NULL) IS NOT NULL;
END LOOP;

--更新 行业
DELETE olap_dim_business;
