SELECT dict_code, dict_name, '19000101', '99991231' FROM prm_da200011040;
COMMIT;
--更新 期限
DELETE olap_dim_deadline;
COMMIT;
INSERT INTO olap_dim_deadline
  (deadline_id, deadline_name, start_date, end_date)
SELECT qxdc_id, qxdc_name, start_date, end_date FROM prm_cs036;
COMMIT;
--更新 LGD
DELETE olap_dim_lgd;
COMMIT;
INSERT INTO olap_dim_lgd
  (lgd_id, lgd_name, start_date, end_date)
SELECT seg_seq, seg_name ,  start_date, end_date FROM prm_csfr5;
COMMIT;

--更新 PD
DELETE olap_dim_pd;
COMMIT;
insert into olap_dim_pd (PD_ID, PD_NAME, START_DATE, END_DATE)
values ('1', '等级1', '19000101', '99991231');

insert into olap_dim_pd (PD_ID, PD_NAME, START_DATE, END_DATE)
values ('2', '等级2', '19000101', '99991231');

insert into olap_dim_pd (PD_ID, PD_NAME, START_DATE, END_DATE)
values ('3', '等级3', '19000101', '99991231');

insert into olap_dim_pd (PD_ID, PD_NAME, START_DATE, END_DATE)
values ('4', '等级4', '19000101', '99991231');

insert into olap_dim_pd (PD_ID, PD_NAME, START_DATE, END_DATE)
values ('5', '等级5', '19000101', '99991231');
COMMIT;


--更新 是否小企业
DELETE olap_dim_is_small;
COMMIT;
insert into olap_dim_is_small (IS_SMALL_ID, IS_SMALL_NAME, START_DATE, END_DATE)
values ('1', '是', '19000101', '99991231');

insert into olap_dim_is_small (IS_SMALL_ID, IS_SMALL_NAME, START_DATE, END_DATE)
values ('0', '否', '19000101', '99991231');
COMMIT;

--更新 OLAP批量控制表

INSERT INTO olap_control
  (data_date)
values
  (P_I_DATE);
COMMIT;

   P_O_SUCCEED := '0';
END IF;

   P_O_SUCCEED := '0';
    --------------------------------------------------------------------------------------------
    --结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_SUCCEED := '1';
      V_ERR_CODE  := SQLCODE;
      V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;

END PROC_OLAP_DIM;

  /****************************************************************
  --  程序名:     FUNC_GET_ZJDBCODE
  --  功能:       将GCMS担保方式代码转换为主机代码
  --  版本号信息: <# V1.0#>
  --  作者：      KFZX-CAOZB
  ***************************************************************/
  FUNCTION FUNC_GET_ZJDBCODE(DB_CODE IN VARCHAR2) RETURN VARCHAR2
  IS
    ZJ_CODE VARCHAR2(50);
    TMP_DB_CODE VARCHAR2(50);
  BEGIN
    TMP_DB_CODE := REGEXP_REPLACE(DB_CODE, ',', '');
    ZJ_CODE := '00000000';

    FOR I IN 1..LENGTH(TMP_DB_CODE)
    LOOP
      IF SUBSTR(TMP_DB_CODE, I, 1) = '4' THEN
        ZJ_CODE := SUBSTR(ZJ_CODE, 1, 1) || '1' || SUBSTR(ZJ_CODE, 3);
      ELSIF SUBSTR(TMP_DB_CODE, I, 1) = '3' THEN
        ZJ_CODE := '1' || SUBSTR(ZJ_CODE, 2);
      ELSIF SUBSTR(TMP_DB_CODE, I, 1) = '2' THEN
        ZJ_CODE := SUBSTR(ZJ_CODE, 1, 2) || '1' || SUBSTR(ZJ_CODE, 4);
      ELSIF SUBSTR(TMP_DB_CODE, I, 1) = '1' THEN
        ZJ_CODE := SUBSTR(ZJ_CODE, 1, 3) || '1' || SUBSTR(ZJ_CODE, 5);
      END IF;
    END LOOP;

    RETURN ZJ_CODE;
  EXCEPTION
    WHEN OTHERS THEN
      RETURN DB_CODE;
  END FUNC_GET_ZJDBCODE;
END PACK_INSERT_OLAP;
//
CREATE OR REPLACE PACKAGE PACK_PUBLIC_PARA IS

  PROCEDURE PR_DEAL_ORGAN(P_I_DATE IN VARCHAR2, P_O_RESULT OUT VARCHAR2);

END PACK_PUBLIC_PARA;
//

CREATE OR REPLACE PACKAGE BODY PACK_PUBLIC_PARA AS

  PROCEDURE PR_DEAL_ORGAN(P_I_DATE IN VARCHAR2, P_O_RESULT OUT VARCHAR2) IS
    --通用变量

    V_P_RESULT VARCHAR2(10);
    V_COUNT    NUMBER;
    V_COUNT1   NUMBER;
    V_COUNT1318 NUMBER;
    --以下变量为记录日志时使用的。

    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
    V_DATE       VARCHAR2(10);

  BEGIN
    --------------------------------------------------------------------------------------------
    --1.填写相关日志参数

    --记载数据处理日志
    V_STEP_NO    := '1';
    V_PROC_NAME  := 'PR_DEAL_ORGAN';
    V_LOG_LEVEL  := '3'; --需要商定
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    V_STEP_NO    := '2.1';

    --------------------------------------------------------------------------------------------
    --2.调用应用结构预处理子存储过程

    --读取系统时间记载开始处理时间

    SELECT TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
      INTO V_BEGIN_TIME
      FROM DUAL;
    SELECT COUNT(*) INTO V_COUNT FROM ODS_TMP_NFPABRP;

    V_DATE := TO_CHAR(TO_DATE(P_I_DATE, 'YYYYMMDD') - 1, 'YYYYMMDD'); --昨天

    IF V_COUNT <> 0 THEN

      DELETE FROM PRM_IRA_ORGAN WHERE START_DATE = P_I_DATE;

      UPDATE PRM_IRA_ORGAN A
         SET END_DATE = '99991231'
       WHERE END_DATE = P_I_DATE;

      V_STEP_NO := 1;
      --更新PRM_IRA_ORGAN表，将ODS_DAT_NTHPABRP表中没有的记录置为无效

--      SELECT COUNT(1) INTO V_COUNT1318 FROM ODS_TMP_NFDLZON T
--      WHERE t.ZONENO IN ( '2321');

--      IF V_COUNT1318 <> 0

--      THEN

--      UPDATE PRM_IRA_ORGAN A
--         SET A.END_DATE = P_I_DATE
--       WHERE NOT EXISTS (SELECT 1
--                FROM ODS_TMP_NFPABRP B
--               WHERE B.ZONENO = A.ZONE_NO
--                 AND B.BRNO = A.BR_NO)
--         AND A.START_DATE <= P_I_DATE
--         AND A.END_DATE > P_I_DATE
--         AND A.BANK_FLAG = '0';
--         --AND A.ZONE_NO NOT IN ('1318', '2321');

--      SELECT COUNT(*) INTO V_COUNT1 FROM ODS_TMP_NFDLZON;

--      IF V_COUNT1 <> 0 THEN
--        UPDATE PRM_IRA_ORGAN A
--           SET A.END_DATE = P_I_DATE
--         WHERE NOT EXISTS
--         (SELECT 1 FROM ODS_TMP_NFDLZON B WHERE B.ZONENO = A.ZONE_NO)
--           AND A.START_DATE <= P_I_DATE
--           AND A.END_DATE > P_I_DATE
--           AND A.BANK_FLAG = '3';
--           --AND A.ZONE_NO NOT IN ('1318', '2321');
--      END IF;

--      V_STEP_NO := 2;
--      --更新PRM_IRA_ORGAN表，将机构归属变更的置为无效

--      UPDATE PRM_IRA_ORGAN A
--         SET A.END_DATE = P_I_DATE
--       WHERE EXISTS (SELECT 1
--                FROM ODS_TMP_NFPABRP B
--               WHERE B.ZONENO = A.ZONE_NO
--                 AND B.BRNO = A.BR_NO
--                 AND B.MBRNO <> A.BELONG_BRNO)
--         AND A.START_DATE <= P_I_DATE
--         AND A.END_DATE > P_I_DATE
--         AND A.BANK_FLAG = '0';
--         --AND A.ZONE_NO NOT IN ('1318', '2321');

--      /*UPDATE ODS_TMP_NFPABRP A
--         SET A.ZONENO = '1318'
--       WHERE A.ZONENO = '1311'
--         AND A.BRNO IN ('0400', '0380', '0430', '3228');*/

--      /*UPDATE ODS_TMP_NFPABRP A
--         SET A.ZONENO = '2321'
--       WHERE A.ZONENO = '2307'
--         AND A.BRNO IN ('4881', '4921', '4931', '4891');*/


--      ELSE


      UPDATE PRM_IRA_ORGAN A
         SET A.END_DATE = P_I_DATE
       WHERE NOT EXISTS (SELECT 1
                FROM ODS_TMP_NFPABRP B
               WHERE B.ZONENO = A.ZONE_NO
                 AND B.BRNO = A.BR_NO)
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND A.BANK_FLAG = '0';
         --AND A.ZONE_NO NOT IN ( '2321');

      SELECT COUNT(*) INTO V_COUNT1 FROM ODS_TMP_NFDLZON;

      IF V_COUNT1 <> 0 THEN
        UPDATE PRM_IRA_ORGAN A
           SET A.END_DATE = P_I_DATE
         WHERE NOT EXISTS
         (SELECT 1 FROM ODS_TMP_NFDLZON B WHERE B.ZONENO = A.ZONE_NO)
           AND A.START_DATE <= P_I_DATE
           AND A.END_DATE > P_I_DATE
           AND A.BANK_FLAG = '3';
           --AND A.ZONE_NO NOT IN ('2321');
      END IF;

      V_STEP_NO := 2;
      --更新PRM_IRA_ORGAN表，将机构归属变更的置为无效

      UPDATE PRM_IRA_ORGAN A
         SET A.END_DATE = P_I_DATE
       WHERE EXISTS (SELECT 1
                FROM ODS_TMP_NFPABRP B
               WHERE B.ZONENO = A.ZONE_NO
                 AND B.BRNO = A.BR_NO
                 AND B.MBRNO <> A.BELONG_BRNO)
         AND A.START_DATE <= P_I_DATE
         AND A.END_DATE > P_I_DATE
         AND A.BANK_FLAG = '0';
         --AND A.ZONE_NO NOT IN ( '2321');

/*      UPDATE ODS_TMP_NFPABRP A
         SET A.ZONENO = '1318'
       WHERE A.ZONENO = '1311'
         AND A.BRNO IN ('0400', '0380', '0430', '3228');
*/
--      UPDATE ODS_TMP_NFPABRP A
--         SET A.ZONENO = '2321'
--       WHERE A.ZONENO = '2307'
--         AND A.BRNO IN ('4881', '4921', '4931', '4891');


--      END IF;






      --插入二级分行的记录
      INSERT INTO PRM_IRA_ORGAN
        (ZONE_NO,
         BR_NO,
         BANK_FLAG,
         ORGAN_NAME,
         BELONG_ZONENO,
         BELONG_BRNO,
         BELONG_BANK_FLAG,
         BR_TYPE,
         START_DATE,
         END_DATE)
        SELECT DISTINCT ZONENO,
                        '0000',
                        '3',
                        'B',
                        'A',
                        '0000',
                        '4',
                        '',
                        P_I_DATE,
                        '99991231'
          FROM ODS_TMP_NFPABRP A
         WHERE NOT EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE A.ZONENO = B.ZONE_NO
                   AND B.BR_NO = '0000'
                   AND B.BANK_FLAG IN ('3', '4')
                   AND B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE)
                   AND BRSTATUS='1';

      UPDATE PRM_IRA_ORGAN A
         SET ORGAN_NAME = (SELECT NOTES
                             FROM ODS_TMP_NFDLZON B
                            WHERE A.ZONE_NO = B.ZONENO
                              AND A.BR_NO = '0000'
                              AND status='1'
                              AND A.BANK_FLAG IN ('3', '4'))
       WHERE A.ORGAN_NAME = 'B';

      V_STEP_NO := 3;
      --插入新网点到PRM_IRA_ORGAN表，0级
      INSERT INTO PRM_IRA_ORGAN
        (ZONE_NO,
         BR_NO,
         BANK_FLAG,
         ORGAN_NAME,
         BELONG_ZONENO,
         BELONG_BRNO,
         BELONG_BANK_FLAG,
         BR_TYPE,
         START_DATE,
         END_DATE)
        SELECT A.ZONENO,
               A.BRNO,
               '0',
               A.NOTES,
               A.ZONENO,
               A.MBRNO,
               '2',
               A.BRTYPE,
               P_I_DATE,
               '99991231'
          FROM ODS_TMP_NFPABRP A
         WHERE NOT EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE
                   AND B.BANK_FLAG = '0'
                   AND A.ZONENO = B.ZONE_NO
                   AND A.BRNO = B.BR_NO)
                   AND a.BRSTATUS='1';

      V_STEP_NO := 4;

      --插入新网点到PRM_IRA_ORGAN表，2级,并且该机构的地区存在于机构表里

      INSERT INTO PRM_IRA_ORGAN
        (ZONE_NO,
         BR_NO,
         BANK_FLAG,
         ORGAN_NAME,
         BELONG_ZONENO,
         BELONG_BRNO,
         BELONG_BANK_FLAG,
         BR_TYPE,
         START_DATE,
         END_DATE)
        SELECT A.ZONENO,
               A.MBRNO,
               '2',
               '*',
               A.ZONENO,
               '0000',
               '3',
               A.BRTYPE,
               P_I_DATE,
               '99991231'
          FROM ODS_TMP_NFPABRP A
         WHERE NOT EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE
                   AND B.BANK_FLAG <> '0'
                   AND A.ZONENO = B.ZONE_NO
                   AND A.MBRNO = B.BR_NO
                   AND B.BANK_FLAG = '2'
                  )
           AND A.BRNO = A.MBRNO
            AND a.BRSTATUS='1'
           AND EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE
                   AND A.ZONENO = B.ZONE_NO
                   AND B.BANK_FLAG = '3')
         GROUP BY A.ZONENO, A.MBRNO, A.BRTYPE;

      --插入新网点到PRM_IRA_ORGAN表，2级,并且该机构的地区不存在于机构表里
      INSERT INTO PRM_IRA_ORGAN
        (ZONE_NO,
         BR_NO,
         BANK_FLAG,
         ORGAN_NAME,
         BELONG_ZONENO,
         BELONG_BRNO,
         BELONG_BANK_FLAG,
         BR_TYPE,
         START_DATE,
         END_DATE)
        SELECT A.ZONENO,
               A.MBRNO,
               '2',
               A.NOTES,
               A.ZONENO,
               '0000',
               '4',
               A.BRTYPE,
               P_I_DATE,
               '99991231'
          FROM ODS_TMP_NFPABRP A
         WHERE NOT EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE
                   AND B.BANK_FLAG <> '0'
                   AND A.ZONENO = B.ZONE_NO
                   AND A.MBRNO = B.BR_NO)
           AND A.BRNO = A.MBRNO
            AND a.BRSTATUS='1'
           AND EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN B
                 WHERE B.START_DATE <= P_I_DATE
                   AND B.END_DATE > P_I_DATE
                   AND A.ZONENO = B.ZONE_NO
                   AND B.BANK_FLAG = '4');

      /*UPDATE PRM_IRA_ORGAN a
      SET a.belong_zoneno=(select b.zone_no from PRM_IRA_ORGAN b
                            where b.start_date<=p_i_date
                              and b.end_date>p_i_date
                              and b.zone_no=a.belong_zoneno
                              and b.br_no=a.)
      WHERE a.belong_zoneno='A'
        AND a.start_date<=P_I_DATE
       AND  a.end_date>P_I_DATE;*/

      --把这些新增地区的机构加一个父节点，归属为总行
      /*
      INSERT INTO PRM_IRA_ORGAN(zone_no,br_no,bank_flag,organ_name,
                            belong_zoneno,belong_brno,belong_bank_flag,
                           br_type,start_date,end_date)
      SELECT a.belong_zoneno,a.belong_brno,a.belong_bank_flag,a.organ_name,
             '0100','0000','5',
             '1',P_I_DATE,'99991231'
      FROM   PRM_IRA_ORGAN a
      WHERE  NOT EXISTS (SELECT 1 FROM PRM_IRA_ORGAN b
                         WHERE b.zone_no=a.belong_zoneno
                         AND   b.br_no=a.belong_brno
                         AND   b.bank_flag=a.belong_bank_flag)
      AND a.belong_bank_flag='4';*/

      V_STEP_NO := 5;
      --更新MAG_ORGAN表，更新名称、行级别
      UPDATE PRM_IRA_ORGAN A
         SET ORGAN_NAME = (SELECT DISTINCT NOTES
                             FROM ODS_TMP_NFPABRP
                            WHERE ZONENO = A.ZONE_NO
                              AND BRNO = A.BR_NO)
       WHERE ORGAN_NAME = '*';
      COMMIT;
      /*UPDATE PRM_IRA_ORGAN a
      SET    a.belong_bank_flag=
             (SELECT b.bank_flag
              FROM   PRM_IRA_ORGAN b
              WHERE  b.start_date<=P_I_DATE
              AND    b.end_date>P_I_DATE
              AND    b.zone_no=a.belong_zoneno
              AND    b.br_no=a.belong_brno)
      WHERE  a.start_date<=P_I_DATE
      AND    a.end_date>P_I_DATE
      AND    a.belong_brno='0000'
      AND    a.belong_bank_flag='A';*/

      --如果发现2级网点没有下属网点补上0层网点

      INSERT INTO PRM_IRA_ORGAN
        (ZONE_NO,
         BR_NO,
         BANK_FLAG,
         ORGAN_NAME,
         BELONG_ZONENO,
         BELONG_BRNO,
         BELONG_BANK_FLAG,
         BR_TYPE,
         START_DATE,
         END_DATE)
        SELECT ZONE_NO,
               BR_NO,
               '0',
               ORGAN_NAME,
               ZONE_NO,
               BR_NO,
               BANK_FLAG,
               BR_TYPE,
               START_DATE,
               END_DATE
          FROM PRM_IRA_ORGAN B
         WHERE NOT EXISTS (SELECT 1
                  FROM PRM_IRA_ORGAN A
                 WHERE B.ZONE_NO = A.BELONG_ZONENO
                   AND B.BR_NO = A.BELONG_BRNO
                   AND B.BANK_FLAG = A.BELONG_BANK_FLAG
                   AND B.BANK_FLAG = '2')
           AND B.BANK_FLAG = '2';

      --更新核算网点字段，只更新行级别小于3的
      V_STEP_NO := 6;
      UPDATE PRM_IRA_ORGAN A
         SET ACT_BR_NO = (SELECT ACTBRNO
                            FROM ODS_TMP_NFPABRP
                           WHERE ZONENO = A.ZONE_NO
                             AND BRNO = A.BR_NO
                              AND BRSTATUS='1')
       WHERE A.BANK_FLAG < 3;

      --更新网点名称
      UPDATE PRM_IRA_ORGAN A
         SET ORGAN_NAME = (SELECT NOTES
                             FROM ODS_TMP_NFPABRP
                            WHERE ZONENO = A.ZONE_NO
                              AND BRNO = A.BR_NO
                               AND BRSTATUS='1')
       WHERE A.BANK_FLAG < 3
         AND START_DATE <= P_I_DATE
         AND END_DATE > P_I_DATE;

      --更新空网点名称
      UPDATE PRM_IRA_ORGAN A
         SET ORGAN_NAME = '未知机构'
       WHERE ORGAN_NAME IS NULL;

      COMMIT;
      --20100311新增，汇总数据到ctp_branch表
      DELETE FROM CTP_BRANCH;
      INSERT INTO CTP_BRANCH
        (ID,
         BRANCH_LEVEL,
         NAME,
         REGION_ID,
         NET_TERMINAL,
         PARENT_ID,
         STATUS)
        SELECT ZONE_NO || BR_NO,
               6 - DECODE(BANK_FLAG, '2', '3', BANK_FLAG),
               trim(ORGAN_NAME),
               ZONE_NO,
               BR_NO,
               DECODE(BANK_FLAG, '5', '', BELONG_ZONENO || BELONG_BRNO),
               '1'
          FROM PRM_IRA_ORGAN
         WHERE BELONG_BANK_FLAG IN ('5', '4')
           AND END_DATE = '99991231';



      UPDATE PRM_IRA_ORGAN T
         SET T.IS_SALES = '0'
       WHERE T.END_DATE = '99991231';
      /******************* ORACLE 11g 下不支持 bypass_ujvc *************************/
      --UPDATE /*+bypass_ujvc*/ (SELECT A.IS_SALES
      --        FROM PRM_IRA_ORGAN A, PRM_SALE B
      --       WHERE A.ZONE_NO = B.ZONE_NO
      --        AND A.BR_NO = B.BR_NO
      --         AND A.BANK_FLAG = B.BANK_FLAG
      --         AND A.END_DATE = '99991231')
      --   SET IS_SALES = '1';
      /******************************************************************************/
      --ORACLE 11g升级，代码变更
      MERGE INTO PRM_IRA_ORGAN A USING PRM_SALE B
      ON(A.ZONE_NO = B.ZONE_NO
         AND A.BR_NO = B.BR_NO
         AND A.BANK_FLAG = B.BANK_FLAG
         AND A.END_DATE = '99991231')
      WHEN MATCHED THEN UPDATE SET IS_SALES = '1';



      COMMIT;

         COMMIT;

      --dbms_mview.refresh('PRM_ZONENO', '?');
    END IF;

    P_O_RESULT := '0';

    --------------------------------------------------------------------------------------------
    --6.结束，填写日志

    V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      V_END_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
      P_O_RESULT := '1';
      V_ERR_CODE := SQLCODE;
      V_ERR_TXT  := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                    V_LOG_LEVEL,
                                    V_BEGIN_TIME,
                                    V_END_TIME,
                                    'FAILED',
                                    V_STEP_NO,
                                    V_SQL_TXT,
                                    V_ERR_CODE,
                                    V_ERR_TXT);
      RAISE;

  END PR_DEAL_ORGAN;

END PACK_PUBLIC_PARA;
