CREATE OR REPLACE package PCKG_ALM_FTP is
  
  PROCEDURE PROC_DEAL_ALM_ZJYEFQX(P_I_DATE    IN VARCHAR2,
                                  P_O_SUCCEED OUT VARCHAR2);

  
  PROCEDURE PROC_DEAL_ALM_FTPSHIBOER(P_I_DATE    IN VARCHAR2,
                                     P_O_SUCCEED OUT VARCHAR2);
 
  PROCEDURE PROC_MAIN(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2);

end PCKG_ALM_FTP;
//

CREATE OR REPLACE package body PCKG_ALM_FTP is
  /****************************************************************
   --  程序名:PROC_DEAL_ALM_ZJYEFQX
   --  功能:ods进dw
   --  版本号信息: <# V1.0#>
   --2015.12.7
  ***************************************************************/
  PROCEDURE PROC_DEAL_ALM_ZJYEFQX(P_I_DATE    IN VARCHAR2,
                                  P_O_SUCCEED OUT VARCHAR2) IS
  
  BEGIN
    P_O_SUCCEED := '0';
    DELETE FROM DW_ZJZJRJYE T WHERE T.DATA_DATE = P_I_DATE;
    INSERT INTO DW_ZJZJRJYE
      SELECT E.DATA_DATE,
             E.ZONENO,
             E.BRNO,
             E.BRANCH_LEVEL,
             E.CURRENCY,
             E.TERM,
             E.AD_BALANCE
        FROM ODS_TMP_ZJZJRJYE E
       WHERE E.DATA_DATE = P_I_DATE;
    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      P_O_SUCCEED := '1';
      RAISE;
  END PROC_DEAL_ALM_ZJYEFQX;
  /****************************************************************
   --  程序名:PROC_DEAL_ALM_FTPSHIBOER
   --  功能:ods进dw
   --  版本号信息: <# V1.0#>
   --2015.12.7
  ***************************************************************/
  PROCEDURE PROC_DEAL_ALM_FTPSHIBOER(P_I_DATE    IN VARCHAR2,
                                     P_O_SUCCEED OUT VARCHAR2) IS
  BEGIN
    P_O_SUCCEED := '0';
    DELETE FROM PRM_FTPSHIBOR T;
    INSERT INTO PRM_FTPSHIBOR
      SELECT E.DIC_CODE,
             E.DIC_DESC,
             E.DIC_SUBCODE,
             E.DIC_SUBDESC,
             E.DIC_COMMENT
        FROM ODS_TMP_FTPSHIBOR E;
    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      P_O_SUCCEED := '1';
      RAISE;
  END PROC_DEAL_ALM_FTPSHIBOER;
  /****************************************************************
   --  程序名:PROC_MAIN
   --  功能:主调程序
   --  版本号信息: <# V1.0#>
   --2015.12.7
  ***************************************************************/
  PROCEDURE PROC_MAIN(P_I_DATE IN VARCHAR2, P_O_SUCCEED OUT VARCHAR2) IS
  BEGIN
    P_O_SUCCEED := '0';
    PROC_DEAL_ALM_ZJYEFQX(P_I_DATE, P_O_SUCCEED);
    PROC_DEAL_ALM_FTPSHIBOER(P_I_DATE, P_O_SUCCEED);
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      P_O_SUCCEED := '1';
      RAISE;
  END PROC_MAIN;
end PCKG_ALM_FTP;
//

