CREATE OR REPLACE PACKAGE BODY      PCKG_JW_G4A_REPORT IS
  --报表格式及特殊符号处理函数
  /****************************************************************
  --  程序名:     ITEM_TO_FMNUM
  --  功能:       报表格式及特殊符号处理
  --  版本号信息: <# V1.0#>
  --  作者：      KFZX-JIANGWEI
  ***************************************************************/
  FUNCTION ITEM_TO_FMNUM(I_CHS IN VARCHAR2, I_FLG IN VARCHAR2)
    RETURN VARCHAR2 IS
    RST VARCHAR2(200);
  BEGIN
    RST := I_CHS;

    IF I_FLG = '%' THEN
      RST := '0.00%';
    END IF;

    IF I_FLG = '1' THEN
      RST := TO_CHAR(TO_NUMBER(RST), 'FM999999999999999990.00');
    END IF;

    RETURN RST;
  EXCEPTION
    WHEN OTHERS THEN
      RETURN I_CHS;
  END ITEM_TO_FMNUM;

  --G4A指标临时表到报表数据临时表数据入库(G4A)
  /****************************************************************
  --  程序名:     PROC_G4A_TO_REPORTDATA_BYRID
  --  功能:       G4A指标临时表到报表数据临时表数据入库(G4A)计算逻辑
  --  版本号信息: <# V1.0#>
