              ITEM_TO_FMNUM(MAX(DECODE(D.FIELD_NAME, 'VALUE50', I.VALUE)),
                            MAX(DECODE(D.FIELD_NAME, 'VALUE50', D2.ISVALUE))) VALUE50
         FROM DIC_INDEX_RELATION_G4A D, DW_G4A_ITEM I, DIC_G4A_ITEM D2
        WHERE D.ITEM_ID = I.ITEM_ID
          AND I.ITEM_ID = D2.ITEM_ID
          AND D.RID = P_I_RID
          AND I.DATA_DATE = P_I_DATE
        GROUP BY I.DATA_DATE, D.RID, I.SCALE, D.ITEM_CODE, I.ORG);

    COMMIT;

    P_O_SUCCEED := '0';
    V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      P_I_RID,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_ITEM_TO_REPORTDATA;

  --G4A临时指标表到指标表(G4A)
  /****************************************************************
  --  程序名:     PROC_TMP_TO_ITEM
  --  功能:       G4A临时指标表到指标表(G4A)计算逻辑
  --  版本号信息: <# V1.0#>
  --  作者：      KFZX-JIANGWEI
  ***************************************************************/
  PROCEDURE PROC_TMP_TO_ITEM(P_I_CHECK_SEQ IN VARCHAR2,
                             P_O_SUCCEED   OUT VARCHAR2) IS
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    V_PROC_NAME  := 'PROC_TMP_TO_ITEM';
    V_STEP_NO    := '1';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    V_STEP_NO := '2';

    --根据批号从 DW_G4A_ITEM_TMP 将数据MERGE到 DW_G4A_ITEM
    MERGE INTO DW_G4A_ITEM O
    USING (SELECT DATA_DATE, ITEM_ID, VALUE, SCALE, ORG
             FROM DW_G4A_ITEM_TMP T
            WHERE T.CHECK_SEQ = P_I_CHECK_SEQ) T1
    ON (O.SCALE = T1.SCALE AND O.DATA_DATE = T1.DATA_DATE AND O.ITEM_ID = T1.ITEM_ID AND O.ORG = T1.ORG)
    WHEN MATCHED THEN
      UPDATE SET O.VALUE = T1.VALUE
    WHEN NOT MATCHED THEN
      INSERT
        (DATA_DATE, ITEM_ID, VALUE, SCALE, ORG)
      VALUES
        (T1.DATA_DATE, T1.ITEM_ID, T1.VALUE, T1.SCALE, T1.ORG);

    COMMIT;

    P_O_SUCCEED := '0';
    V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      P_I_CHECK_SEQ,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_TMP_TO_ITEM;

