  --生成正式G4A报表(G4A)
  /****************************************************************
  --  程序名:     PROC_REPORTDATA_TO_G4A
  --  功能:       生成正式G4A报表(G4A)
  --  版本号信息: <# V1.0#>
  --  作者：      KFZX-JIANGWEI
  ***************************************************************/
  PROCEDURE PROC_REPORTDATA_TO_G4A(P_I_DATE    IN VARCHAR2,
                                   P_O_SUCCEED OUT VARCHAR2) IS
    V_PROC_NAME  L_GETDATA_CALL.PROC_NAME%TYPE;
    V_LOG_LEVEL  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    V_BEGIN_TIME L_GETDATA_CALL.BEGIN_TIME%TYPE;
    V_END_TIME   L_GETDATA_CALL.END_TIME%TYPE;
    V_ERR_CODE   L_GETDATA_ERR.ERR_CODE%TYPE;
    V_ERR_TXT    L_GETDATA_ERR.ERR_TXT%TYPE;
    V_STEP_NO    L_GETDATA_ERR.STEP_NO%TYPE;
    V_SQL_TXT    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    V_PROC_NAME  := 'PROC_REPORTDATA_TO_G4A';
    V_STEP_NO    := '1';
    V_LOG_LEVEL  := '3';
    V_BEGIN_TIME := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');

    V_STEP_NO := '2';

    --清空正式报表内容
    --变更内容：根据日期清空正式报表内容
    --变更时间：2013-1-17
    DELETE FROM DW_G4A_REPORT_DATA
     WHERE RID = 'D1.1'
       AND DATA_DATE = P_I_DATE;

    COMMIT;

    --将手工填报表中相关部分填入正式报表
    INSERT INTO DW_G4A_REPORT_DATA
      (DATA_DATE, RID, SCALE, ITEM_CODE, ORG, VALUE1)
      SELECT DATA_DATE, 'D1.1' RID, SCALE, ITEM_CODE, ORG, NVL(VALUE1, 0)
        FROM DW_G4A_REPORT_DATA T
       WHERE T.RID = 'M1.5'
         AND T.DATA_DATE = P_I_DATE;

    COMMIT;

    --将83，84两行（手工报表冗余的内容）删除
    DELETE FROM DW_G4A_REPORT_DATA
     WHERE ITEM_CODE IN ('0083', '0084')
       AND RID = 'D1.1'
       AND DATA_DATE = P_I_DATE;

    COMMIT;

    V_STEP_NO := '3';

    --将相关表中部分填入正式报表
    INSERT INTO DW_G4A_REPORT_DATA(DATA_DATE,
                                   RID,
                                   SCALE,
                                   ITEM_CODE,
                                   ORG,
                                   VALUE1)
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0002' ITEM_CODE,
             D.ORG,
             NVL(D.VALUE, 0)
        FROM DW_G4A_ITEM D
       WHERE D.ITEM_ID = '100G4A00530002' AND D.DATA_DATE = P_I_DATE
      --1.1实收资本可计入部分-股本
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0003' ITEM_CODE,
             D.ORG,
             NVL(D.VALUE, 0)
        FROM DW_G4A_ITEM D
       WHERE D.ITEM_ID = '100G4A00540002' AND D.DATA_DATE = P_I_DATE
      --1.2资本公积可计入部分-资本公积
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0004' ITEM_CODE,
             D.ORG,
             NVL(D.VALUE, 0)
        FROM DW_G4A_ITEM D
       WHERE D.ITEM_ID = '100G4A00560002' AND D.DATA_DATE = P_I_DATE
      --1.3盈余公积-盈余公积
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0005' ITEM_CODE,
             D.ORG,
             NVL(D.VALUE, 0)
        FROM DW_G4A_ITEM D
       WHERE D.ITEM_ID = '100G4A00570002' AND D.DATA_DATE = P_I_DATE
      --1.4一般风险准备-一般风险准备
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0006' ITEM_CODE,
             D.ORG,
             NVL(D.VALUE, 0)
        FROM DW_G4A_ITEM D
       WHERE D.ITEM_ID = '100G4A00580002' AND D.DATA_DATE = P_I_DATE
      --1.5未分配利润-未分配利润
      UNION ALL
      SELECT O1.DATA_DATE,
             'D1.1' RID,
             O1.SCALE,
             '0007' ITEM_CODE,
             O1.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(TO_NUMBER(NVL(O1.VALUE, 0)) * TO_NUMBER (NVL (O2.VALUE, 0)), '1')
        FROM (SELECT D.DATA_DATE,
                     D.SCALE,
                     D.ORG,
                     REGEXP_REPLACE(D.VALUE, ',', '') VALUE
                FROM DW_G4A_ITEM D
               WHERE D.ITEM_ID = '120G4A00250001' AND D.DATA_DATE = P_I_DATE) O1,
             (SELECT D.DATA_DATE,
                     D.SCALE,
                     D.ORG,
                     REGEXP_REPLACE(D.VALUE, ',', '') VALUE
                FROM DW_G4A_ITEM D
               WHERE D.ITEM_ID = '150G4A00830001' AND D.DATA_DATE = P_I_DATE) O2
       WHERE O1.SCALE = O2.SCALE AND O1.ORG = O2.ORG
      --1.5.1未分配利润中应分未分部分-利润表中归属于母公司净利润*预计分红比例
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0012' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE3, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.4'
         AND D.VALUE1 = '1702'
         AND D.DATA_DATE = P_I_DATE
      --2.1.1商誉扣减与之相关的递延税负债后的净额-二级科目表1702
      UNION ALL
      --2.1.2其他无形资产(不含土地使用权) 扣减与之相关的递延税负债后的净利润
      --二级科目表1910无形资产借方科目余额-191001土地使用权借方科目
      SELECT O1.DATA_DATE,
             'D1.1' RID,
             O1.SCALE,
             '0013' ITEM_CODE,
             O1.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(TO_NUMBER(NVL(O1.VALUE3, 0)) -
                                              TO_NUMBER(NVL(O2.VALUE3, 0)),
                                              '1')
        FROM (SELECT D.DATA_DATE,
                     D.SCALE,
                     D.ORG,
                     REGEXP_REPLACE(D.VALUE3, ',', '') VALUE3
                FROM DW_G4A_REPORT_DATA D
               WHERE D.RID = 'M1.4'
                 AND D.VALUE1 = '1910'
                 AND D.DATA_DATE = P_I_DATE) O1,
             (SELECT D.DATA_DATE,
                     D.SCALE,
                     D.ORG,
                     REGEXP_REPLACE(D.VALUE3, ',', '') VALUE3
                FROM DW_G4A_REPORT_DATA D
               WHERE D.RID = 'M1.4'
                 AND D.VALUE1 = '191001'
                 AND D.DATA_DATE = P_I_DATE) O2
       WHERE O1.SCALE = O2.SCALE AND O1.ORG = O2.ORG
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0021' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE4, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.4'
         AND D.VALUE1 = '302009'
         AND D.DATA_DATE = P_I_DATE
      --2.1.8 未按公允价值计量的项目进行现金流套期形成的储备
      --二级科目余额表中的“302009 现金流量套期”贷方科目余额
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0024' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE3, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.3.1'
         AND D.ITEM_CODE = '0001'
         AND D.DATA_DATE = P_I_DATE
      --2.1.11 对有控制权但不并表的金融机构的核心一级资本投资
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0025' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE3, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.3.2'
         AND D.ITEM_CODE = '0001'
         AND D.DATA_DATE = P_I_DATE
      --2.1.12 对有控制权但不并表的金融机构的核心一级资本投资缺口
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0027' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE3, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.3.3'
         AND D.ITEM_CODE = '0001'
         AND D.DATA_DATE = P_I_DATE
      --2.2.1 对未并表金融机构小额少数资本投资中的核心一级资本
      UNION ALL
      SELECT D.DATA_DATE,
             'D1.1' RID,
             D.SCALE,
             '0029' ITEM_CODE,
             D.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(NVL(D.VALUE3, 0), '1')
        FROM DW_G4A_REPORT_DATA D
       WHERE D.RID = 'M1.3.5'
         AND D.ITEM_CODE = '0001'
         AND D.DATA_DATE = P_I_DATE
      --2.2.2 对未并表金融机构大额少数资本投资中的核心一级资本
      UNION ALL
      SELECT O1.DATA_DATE,
             'D1.1' RID,
             O1.SCALE,
             '0031' ITEM_CODE,
             O1.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(TO_NUMBER(NVL(O1.VALUE, 0)) -
                                              TO_NUMBER(NVL(O2.VALUE, 0)),
                                              '1')
        FROM (SELECT D.DATA_DATE, D.SCALE, D.ORG, REGEXP_REPLACE(D.VALUE, ',', '') VALUE
                FROM DW_G4A_ITEM D
               WHERE D.ITEM_ID = '100G4A00270002'
                 AND D.DATA_DATE = P_I_DATE) O1,
             (SELECT D.DATA_DATE, D.SCALE, D.ORG, REGEXP_REPLACE(D.VALUE, ',', '') VALUE
                FROM DW_G4A_ITEM D
               WHERE D.ITEM_ID = '100G4A00490002'
                 AND D.DATA_DATE = P_I_DATE) O2
       WHERE O1.SCALE = O2.SCALE AND O1.ORG = O2.ORG
      --2.2.3 其他依赖于银行未来盈利的净递延税资产
      --资产负债表中的递延税资产-资产负债表中的递延税负债
      UNION ALL
      SELECT O1.DATA_DATE,
             'D1.1' RID,
             O1.SCALE,
             '0058' ITEM_CODE,
             O1.ORG,
             PCKG_JW_G4A_REPORT.ITEM_TO_FMNUM(TO_NUMBER(NVL(O1.VALUE4, 0)) +
                                              TO_NUMBER(NVL(O2.VALUE, 0)),
                                              '1')
        FROM (SELECT D.DATA_DATE,
                     D.SCALE,
                     D.ORG,
                     REGEXP_REPLACE(D.VALUE4, ',', '') VALUE4
                FROM DW_G4A_REPORT_DATA D
               WHERE D.RID = 'M1.4'
                 AND D.VALUE1 = '2600'
                 AND D.DATA_DATE = P_I_DATE) O1,
             (SELECT D.DATA_DATE, D.SCALE, D.ORG, REGEXP_REPLACE(D.VALUE, ',', '') VALUE
                FROM DW_G4A_ITEM D
               WHERE D.ITEM_ID = '150G4A00840001'
                 AND D.DATA_DATE = P_I_DATE) O2
       WHERE O1.SCALE = O2.SCALE AND O1.ORG = O2.ORG;

    --5.1 二级资本工具及其溢价可计入金额
    --二级科目余额表中2600 发行次级债贷方科目余额+可转债

    COMMIT;

    P_O_SUCCEED := '0';
    V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
    PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                  V_LOG_LEVEL,
                                  V_BEGIN_TIME,
                                  V_END_TIME,
                                  'SUCCESS',
                                  V_STEP_NO,
                                  V_SQL_TXT);
  EXCEPTION
    WHEN OTHERS THEN
      BEGIN
        ROLLBACK;
        V_END_TIME  := TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS');
        P_O_SUCCEED := '1';
        V_ERR_CODE  := SQLCODE;
        V_ERR_TXT   := SUBSTR(SQLERRM, 1, 4000);
        PACK_GETDATA_LOG.PR_LOG_WRITE(V_PROC_NAME,
                                      V_LOG_LEVEL,
                                      V_BEGIN_TIME,
                                      V_END_TIME,
                                      'FAILED',
                                      V_STEP_NO,
                                      P_I_DATE,
                                      V_ERR_CODE,
                                      V_ERR_TXT);
        RAISE;
      END;
  END PROC_REPORTDATA_TO_G4A;
END PCKG_JW_G4A_REPORT;
//

CREATE OR REPLACE FUNCTION FUNC_GET_BRANCHNAME(BRANCHID IN VARCHAR2)
  RETURN VARCHAR2 IS
  RETVALUE CTP_BRANCH.NAME%TYPE;
BEGIN
  --20160121 总行下的一级分行及一级分行营业部的名字另初始化
  SELECT max(C.TRANS_BRANCH_NAME) INTO RETVALUE
  FROM CAP_TRANS_BRANCH_SORT C
  WHERE C.TRANS_BRANCH_ID = BRANCHID;

  if retVALUE is null then
    SELECT MAX(B.NAME) INTO RETVALUE FROM CTP_BRANCH B WHERE B.ID = BRANCHID;
    if retVALUE is null then
      SELECT max(ORGAN_NAME) into RETVALUE
                           FROM PRM_IRA_ORGAN
                          WHERE (ZONE_NO || BR_NO) = BRANCHID
                          and END_DATE = '99991231';
    end if;
  end if;
  RETURN RETVALUE;

EXCEPTION
  WHEN OTHERS THEN

    RETURN RETVALUE;
END;
//


