CREATE OR REPLACE PACKAGE BODY      PCKG_LIMIT_TRADE_RPT IS
--create by liukan
  --交易明细历史
  --modify 20160119
  --修改前只查询：交易状态为3-已签批的交易
  --修改后查询：交易状态为3-已签批的交易 或 交易状态为2-待签批 且 本级行审批通过时间<=交易结束时间 的交易
  PROCEDURE PROC_TRD_HISRPT(I_YEAR     IN VARCHAR2, --交易年份
                           I_USER_BR IN VARCHAR2, --用户机构  接收机构
                           I_BR_ID    IN VARCHAR2, --交易机构
                           I_BEG_NUM    IN VARCHAR2,
                           I_FETCH_NUM  IN VARCHAR2,
                           O_RETCODE  OUT VARCHAR2,
                           O_totalNum   OUT number,
                           O_RETLIST  OUT REFCUR,
                           O_RETMSG OUT VARCHAR2
                           ) IS
                                 
   v_level                 ctp_branch.branch_level%type;
   
   BEGIN
      
      select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
     if I_BR_ID is not null then
     
        OPEN O_RETLIST for with rs as(
            select     func_get_branchname(O.TRANS_INITIATE) initiate_name,
                       func_get_branchname(O.TRANS_ACCEPT_BRANCH) accept_branch_name,
                       decode(o.s, '1','一季度','2','半年','3','前三季度','全年') s,
                       O.b1,
                       O.s1,
                       O.b2,
                       O.s2,
                       O.b3,
                       O.s3,
                       O.b4,
                       O.s4
             from (
                SELECT A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '1' s,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s4
                  FROM CAP_TRANS_APPLY A
                 WHERE (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                   and A.TRANS_YEAR = I_YEAR
                   and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                 GROUP BY TRANS_INITIATE, TRANS_ACCEPT_BRANCH
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '2' S,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '3' s,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '4' S,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch) O
                where TRANS_INITIATE = I_BR_ID
                order by decode(i_user_br ,'01000000',
                                  (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.TRANS_INITIATE),
                                 o.TRANS_INITIATE),--TRANS_INITIATE, 20160125 modify
                      o.TRANS_ACCEPT_BRANCH, 
                      o.S)                
                   /*select * from (select rs.*, rownum row_num from rs)*/
                   select *
                     from (select rs.initiate_name,
                                  rs.accept_branch_name,
                                  rs.s,
                                  rs.b1,
                                  rs.s1,
                                  rs.b2,
                                  rs.s2,
                                  rs.b3,
                                  rs.s3,
                                  rs.b4,
                                  rs.s4, rownum row_num
                             from rs)
                  where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;
                 
                
       select count(1) * 4 into o_totalNum from (
          SELECT distinct A.TRANS_INITIATE, A.TRANS_ACCEPT_BRANCH
              FROM CAP_TRANS_APPLY A
             WHERE (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
             and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
             AND A.TRANS_YEAR = I_YEAR) where TRANS_INITIATE = I_BR_ID;
    else 
       
         OPEN O_RETLIST for with rs as(
           select      func_get_branchname(O.TRANS_INITIATE) initiate_name,
                       func_get_branchname(O.TRANS_ACCEPT_BRANCH) accept_branch_name,
                       decode(o.s, '1','一季度','2','半年','3','前三季度','全年') s,
                       O.b1,
                       O.s1,
                       O.b2,
                       O.s2,
                       O.b3,
                       O.s3,
                       O.b4,
                       O.s4,
                       O.TRANS_INITIATE
              from (
                SELECT A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '1' s,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s4
                  FROM CAP_TRANS_APPLY A
                 WHERE (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                   and A.TRANS_YEAR = I_YEAR
                   and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                 GROUP BY TRANS_INITIATE, TRANS_ACCEPT_BRANCH
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '2' S,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '3' S,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '4' S,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))  
                and A.TRANS_YEAR = I_YEAR
                and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                group by TRANS_INITIATE, trans_accept_branch) O 
                where TRANS_INITIATE in 
                (SELECT B.id FROM CTP_BRANCH B
                         WHERE B.BRANCH_LEVEL = v_level + 1
                          START WITH B.ID =  i_user_br
                          CONNECT BY B.PARENT_ID = PRIOR ID
                  union all
                  SELECT (ZONE_NO || BR_NO) ID
                             FROM PRM_IRA_ORGAN
                            WHERE BANK_FLAG = '3'
                              AND IS_SALES = '1'
                              and v_level = 1 
                              and end_date = '99991231')
                order by decode(i_user_br ,'01000000',
                                  (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.TRANS_INITIATE),
                                 o.TRANS_INITIATE),--TRANS_INITIATE, 20160125 modify
                      o.TRANS_ACCEPT_BRANCH, 
                      o.S)
                select * from (select rs.initiate_name,
                                  rs.accept_branch_name,
                                  rs.s,
                                  rs.b1,
                                  rs.s1,
                                  rs.b2,
                                  rs.s2,
                                  rs.b3,
                                  rs.s3,
                                  rs.b4,
                                  rs.s4, rs.TRANS_INITIATE, rownum row_num from rs)
                  where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;
                                                
           select count(1) * 4 into o_totalNum from (
              SELECT distinct A.TRANS_INITIATE, A.TRANS_ACCEPT_BRANCH
                  FROM CAP_TRANS_APPLY A
                 WHERE (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                 and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                 AND A.TRANS_YEAR = I_YEAR) 
                 where TRANS_INITIATE in 
                    (SELECT B.id FROM CTP_BRANCH B
                             WHERE B.BRANCH_LEVEL = v_level + 1
                              START WITH B.ID =  i_user_br
                              CONNECT BY B.PARENT_ID = PRIOR ID
                     union all
                      SELECT (ZONE_NO || BR_NO) ID
                                 FROM PRM_IRA_ORGAN
                                WHERE BANK_FLAG = '3'
                                  AND IS_SALES = '1'
                                  and v_level = 1
                                  and end_date = '99991231' );
                               
         end if;   
        
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
   PROCEDURE PROC_TRD_HISRPT_GETALLDATA(I_YEAR     IN VARCHAR2, --交易年份
                                 I_USER_BR IN VARCHAR2, --用户机构
                                 I_BR_ID    IN VARCHAR2, --交易机构
                                 O_RETCODE  OUT VARCHAR2,
                                 O_totalNum   OUT number,
                                 O_RETLIST  OUT REFCUR,
                                 O_RETMSG OUT VARCHAR2
                                 ) IS
                                 
   v_level                     ctp_branch.branch_level%type;
   
   BEGIN
      select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
      if I_BR_ID is not null then
     
        OPEN O_RETLIST FOR
            select     func_get_branchname(O.TRANS_INITIATE),
                       func_get_branchname(O.TRANS_ACCEPT_BRANCH),
                       decode(o.s, '1','一季度','2','半年','3','前三季度','全年'),
                       O.b1,
                       O.s1,
                       O.b2,
                       O.s2,
                       O.b3,
                       O.s3,
                       O.b4,
                       O.s4
             from (
                SELECT A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '1' s,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s4
                  FROM CAP_TRANS_APPLY A
                 WHERE (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                   and A.TRANS_YEAR = I_YEAR
                   and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                 GROUP BY TRANS_INITIATE, TRANS_ACCEPT_BRANCH
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '2' S,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '3' s,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch
                union all
                select A.TRANS_INITIATE,
                       A.TRANS_ACCEPT_BRANCH,
                       '4' S,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 1 then a.trans_count else 0 end) b1,
                       SUM(case when a.trans_variety= '1' and a.trans_type = 0 then a.trans_count else 0 end) s1,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 1 then a.trans_count else 0 end) b2,
                       SUM(case when a.trans_variety= '2' and a.trans_type = 0 then a.trans_count else 0 end) s2,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 1 then a.trans_count else 0 end) b3,
                       SUM(case when a.trans_variety= '3' and a.trans_type = 0 then a.trans_count else 0 end) s3,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 1 then a.trans_count else 0 end) b4,
                       SUM(case when a.trans_variety= '4' and a.trans_type = 0 then a.trans_count else 0 end) s4
                from CAP_TRANS_APPLY a 
                where (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate))) 
                and A.TRANS_YEAR = I_YEAR
                and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
                group by TRANS_INITIATE, trans_accept_branch) O
                where TRANS_INITIATE = I_BR_ID
                --order by TRANS_INITIATE, TRANS_ACCEPT_BRANCH, S;
                order by decode(i_user_br ,'01000000',
                                  (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.TRANS_INITIATE),
                                 o.TRANS_INITIATE),--TRANS_INITIATE, 20160125 modify
                      o.TRANS_ACCEPT_BRANCH, 
                      o.S;
                
         select count(1) * 4 into o_totalNum from (
          SELECT distinct A.TRANS_INITIATE, A.TRANS_ACCEPT_BRANCH
              FROM CAP_TRANS_APPLY A
             WHERE (A.TRANS_STATUS = '3' 
                       or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
             and (A.TRANS_ACCEPT_BRANCH = I_USER_BR or I_USER_BR = I_BR_ID)
             AND A.TRANS_YEAR = I_YEAR) where TRANS_INITIATE = I_BR_ID;
         else 
           
               OPEN O_RETLIST FOR
                         select      func_get_branchname(O.TRANS_INITIATE),
                           func_get_branchname(O.TRANS_ACCEPT_BRANCH),
                           decode(o.s, '1','一季度','2','半年','3','前三季度','全年'),
                           O.b1,
                           O.s1,
                           O.b2,
                           O.s2,
                           O.b3,
                           O.s3,
                           O.b4,
                           O.s4
                  from (
                    SELECT A.TRANS_INITIATE,
                           A.TRANS_ACCEPT_BRANCH,
                           '1' s,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1') and a.trans_type = 0 then a.trans_count else 0 end) s4
                      FROM CAP_TRANS_APPLY A
                     WHERE (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                       and A.TRANS_YEAR = I_YEAR
                       and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                     GROUP BY TRANS_INITIATE, TRANS_ACCEPT_BRANCH
                    union all
                    select A.TRANS_INITIATE,
                           A.TRANS_ACCEPT_BRANCH,
                           '2' S,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2') and a.trans_type = 0 then a.trans_count else 0 end) s4
                    from CAP_TRANS_APPLY a 
                    where (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))  
                    and A.TRANS_YEAR = I_YEAR
                    and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                    group by TRANS_INITIATE, trans_accept_branch
                    union all
                    select A.TRANS_INITIATE,
                           A.TRANS_ACCEPT_BRANCH,
                           '3' S,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b1,
                           SUM(case when a.trans_variety= '1' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s1,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b2,
                           SUM(case when a.trans_variety= '2' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s2,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b3,
                           SUM(case when a.trans_variety= '3' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s3,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 1 then a.trans_count else 0 end) b4,
                           SUM(case when a.trans_variety= '4' and a.TRANS_QUARTER in ('1', '2', '3') and a.trans_type = 0 then a.trans_count else 0 end) s4
                    from CAP_TRANS_APPLY a 
                    where (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))  
                    and A.TRANS_YEAR = I_YEAR
                    and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                    group by TRANS_INITIATE, trans_accept_branch
                    union all
                    select A.TRANS_INITIATE,
                           A.TRANS_ACCEPT_BRANCH,
                           '4' S,
                           SUM(case when a.trans_variety= '1' and a.trans_type = 1 then a.trans_count else 0 end) b1,
                           SUM(case when a.trans_variety= '1' and a.trans_type = 0 then a.trans_count else 0 end) s1,
                           SUM(case when a.trans_variety= '2' and a.trans_type = 1 then a.trans_count else 0 end) b2,
                           SUM(case when a.trans_variety= '2' and a.trans_type = 0 then a.trans_count else 0 end) s2,
                           SUM(case when a.trans_variety= '3' and a.trans_type = 1 then a.trans_count else 0 end) b3,
                           SUM(case when a.trans_variety= '3' and a.trans_type = 0 then a.trans_count else 0 end) s3,
                           SUM(case when a.trans_variety= '4' and a.trans_type = 1 then a.trans_count else 0 end) b4,
                           SUM(case when a.trans_variety= '4' and a.trans_type = 0 then a.trans_count else 0 end) s4
                    from CAP_TRANS_APPLY a 
                    where (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))  
                    and A.TRANS_YEAR = I_YEAR
                    and A.TRANS_ACCEPT_BRANCH = I_USER_BR
                    group by TRANS_INITIATE, trans_accept_branch) O 
                    where TRANS_INITIATE in 
                    (SELECT B.id FROM CTP_BRANCH B
                             WHERE B.BRANCH_LEVEL = v_level + 1
                              START WITH B.ID =  i_user_br
                              CONNECT BY B.PARENT_ID = PRIOR ID
                      union all
                      SELECT (ZONE_NO || BR_NO) ID
                                 FROM PRM_IRA_ORGAN
                                WHERE BANK_FLAG = '3'
                                  AND IS_SALES = '1'
                                  and v_level = 1
                                  and end_date = '99991231' )
                     --order by TRANS_INITIATE, TRANS_ACCEPT_BRANCH, S;             
                    
                order by decode(i_user_br ,'01000000',
                                  (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.TRANS_INITIATE),
                                 o.TRANS_INITIATE),--TRANS_INITIATE, 20160125 modify
                      o.TRANS_ACCEPT_BRANCH, 
                      o.S;
                    
           select count(1) * 4 into o_totalNum from (
              SELECT distinct A.TRANS_INITIATE, A.TRANS_ACCEPT_BRANCH
                  FROM CAP_TRANS_APPLY A
                 WHERE (A.TRANS_STATUS = '3' 
                           or(A.TRANS_STATUS = '2' and func_get_transendtime(A.trans_id) >= func_get_passtime(A.trans_id,A.trans_initiate)))
                 AND A.TRANS_YEAR = I_YEAR) 
                 where TRANS_INITIATE in 
                    (SELECT B.id FROM CTP_BRANCH B
                             WHERE B.BRANCH_LEVEL = v_level + 1
                              START WITH B.ID =  i_user_br
                              CONNECT BY B.PARENT_ID = PRIOR ID
                      union all
                      SELECT (ZONE_NO || BR_NO) ID
                                 FROM PRM_IRA_ORGAN
                                WHERE BANK_FLAG = '3'
                                  AND IS_SALES = '1'
                                  and v_level = 1
                                  and end_date = '99991231' );
                              
         end if;   
        
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
   --报价情况汇总
    PROCEDURE PROC_CALLPRICE_LIST (I_YEAR     IN VARCHAR2, --交易年份
                                  I_USER_BR IN VARCHAR2, --用户机构
                              --    I_BR_ID    IN VARCHAR2, --交易机构
                                  I_SEASON   IN VARCHAR2, --交易季度
                                  I_BEG_NUM    IN VARCHAR2,
                                  I_FETCH_NUM  IN VARCHAR2,
                                  O_RETCODE  OUT VARCHAR2,
                                  O_totalNum   OUT number,
                                  O_RETLIST  OUT REFCUR,
                                  O_RETMSG OUT VARCHAR2) IS
     v_query_sql  VARCHAR2(30000) := '';
     v_count_sql  VARCHAR2(30000) := '';
     v_where_sql  VARCHAR2(30000) := '';                             
     v_level      ctp_branch.branch_level%type;                             
   BEGIN
      o_retCode := '0';
      select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
       
      select decode(count(1), 0, 3, count(1) + 3) into O_totalNum from  (select distinct OFFER_BRANCH FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = I_YEAR
                             AND O.OFFER_QUARTER = I_SEASON
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231'));
       
      open O_RETLIST for with rs as( 
          SELECT  func_get_branchname(TT.OFFER_BRANCH) branch_name,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = I_SEASON
                              and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1                    
                   order by decode(i_user_br ,'01000000',
                                    (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = t.OFFER_BRANCH),
                                   t.OFFER_BRANCH)) TT 
                   GROUP BY TT.OFFER_BRANCH
         union all   
         SELECT '最小值' branch_name,
                min((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                min((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                min((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                min((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                min((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                min((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                min((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                min((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = I_SEASON
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')
                             ) T
                   WHERE RN = 1) TT  
            union all   
           SELECT '最大值' branch_name,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'  
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1) TT   
           union all   
           SELECT '平均值' branch_name,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1) TT )
                select *
                  from (select /*rs.**/
                         rs.branch_name,
                         rs.b1,
                         rs.s1,
                         rs.b2,
                         rs.s2,
                         rs.b3,
                         rs.s3,
                         rs.b4,
                         rs.s4,
                         rownum row_num
                          from rs)
                 where row_num >= I_BEG_NUM
                   and row_num < I_BEG_NUM + I_FETCH_NUM;
     
        O_RETCODE := '0';
        O_RETMSG := '获取机构数据成功';
        RETURN;
     EXCEPTION
        WHEN OTHERS
        THEN
           O_RETCODE := '1';
           O_RETMSG := '获取机构数据失败';
           dbms_output.put_line(O_RETMSG);  
           RETURN;
     END;
   
  --报价情况汇总
  PROCEDURE PROC_CALLPRICE_LIST_GETALLDATA(I_YEAR     IN VARCHAR2, --交易年份
                                I_USER_BR IN VARCHAR2, --用户机构
                             --   I_BR_ID    IN VARCHAR2, --交易机构
                                I_SEASON   IN VARCHAR2, --交易季度
                                O_RETCODE  OUT VARCHAR2,
                                O_totalNum   OUT number,
                                O_RETLIST  OUT REFCUR,
                                O_RETMSG OUT VARCHAR2) IS
     v_query_sql  VARCHAR2(30000) := '';
     v_count_sql  VARCHAR2(30000) := '';
     v_where_sql  VARCHAR2(30000) := '';                             
     v_level      ctp_branch.branch_level%type;                             
     BEGIN
       o_retCode := '0';
           select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
       
    select decode(count(1), 0, 3, count(1) + 3) into O_totalNum from  (select distinct OFFER_BRANCH FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231'));
       
      open O_RETLIST for with rs as( 
      SELECT  func_get_branchname(TT.OFFER_BRANCH) branch_name,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                              and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1 
                   order by decode(i_user_br ,'01000000',
                                    (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = t.OFFER_BRANCH),
                                   t.OFFER_BRANCH)) TT 
                   GROUP BY TT.OFFER_BRANCH
         union all   
         SELECT '最小值' branch_name,
                min((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                min((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                min((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                min((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                min((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                min((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                min((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                min((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')
                             ) T
                   WHERE RN = 1) TT  
            union all   
           SELECT '最大值' branch_name,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  max((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1) TT   
           union all   
           SELECT '平均值' branch_name,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.BUY_PRICE ELSE null END)) b1,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 1 THEN TT.SELL_PRICE ELSE null END)) s1,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.BUY_PRICE ELSE null END)) b2,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 2 THEN TT.SELL_PRICE ELSE null END)) s2,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.BUY_PRICE ELSE null END)) b3,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 3 THEN TT.SELL_PRICE ELSE null END)) s3,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.BUY_PRICE ELSE null END)) b4,
                  avg((CASE WHEN TT.OFFER_VARIETIES = 4 THEN TT.SELL_PRICE ELSE null END)) s4
            FROM (SELECT /***/T.OFFER_BRANCH,T.OFFER_VARIETIES,T.BUY_PRICE,T.SELL_PRICE
                    FROM (SELECT /*O.*,*/O.OFFER_BRANCH,O.OFFER_VARIETIES,O.BUY_PRICE,O.SELL_PRICE,
                                 ROW_NUMBER() OVER(PARTITION BY O.OFFER_BRANCH, O.OFFER_YEAR, O.OFFER_QUARTER, O.OFFER_VARIETIES ORDER BY O.Create_Time DESC) RN
                            FROM CAP_BRANCHS_TRANS_OFFER O
                           WHERE O.OFFER_YEAR = i_year
                             AND O.OFFER_QUARTER = i_season
                             and O.OFFER_BRANCH in (SELECT B.ID
                            FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level + 1
                           START WITH B.ID = I_USER_BR
                          CONNECT BY B.PARENT_ID = PRIOR ID
                          union all 
                          SELECT (ZONE_NO || BR_NO) id
                                           FROM PRM_IRA_ORGAN
                                          WHERE BANK_FLAG = '3'
                                            AND IS_SALES = '1'
                                            and v_level = 1
                                            and end_date = '99991231')) T
                   WHERE RN = 1) TT )
                select *
                 
                  from (select /*rs.**/
                         rs.branch_name,
                         rs.b1,
                         rs.s1,
                         rs.b2,
                         rs.s2,
                         rs.b3,
                         rs.s3,
                         rs.b4,
                         rs.s4,
                         rownum row_num
                          from rs);
                

      O_RETCODE := '0';
      O_RETMSG := '获取机构数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取机构数据失败';
         RETURN;
   END;
  --交易价格查询
  PROCEDURE PROC_TRDPRICE_RPT(I_YEAR     IN VARCHAR2, --交易年份
                              I_USER_BR IN VARCHAR2, --用户机构
                              I_BR_ID    IN VARCHAR2, --交易机构
                              I_SEASON   IN VARCHAR2, --交易季度
                              I_BEG_NUM    IN VARCHAR2,
                              I_FETCH_NUM  IN VARCHAR2,
                              O_RETCODE  OUT VARCHAR2,
                              O_totalNum   OUT number,
                              O_RETLIST  OUT REFCUR,
                              O_RETMSG OUT VARCHAR2)IS
   v_query_sql  VARCHAR2(30000) := '';
   v_count_sql  VARCHAR2(30000) := '';
   v_where_sql  VARCHAR2(30000) := '';
   v_level      ctp_branch.branch_level%type;
   
   BEGIN
     
     o_retCode := '0';
     select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;
     --modify 20160119
     --修改前只查询：交易状态为3-已签批的交易
     --修改后查询：交易状态为3-已签批的交易 或 交易状态为2-待签批 且 本级行审批通过时间<=交易结束时间 的交易
     --v_where_sql := 'where a.trans_status = 3 and a.trans_year = ''' || I_YEAR ||''' and a.TRANS_QUARTER = ''' || I_SEASON || '''';
     v_where_sql := 'where (A.TRANS_STATUS = ''3'' or(A.TRANS_STATUS = ''2'' and pckg_limit_trade_rpt.func_get_transendtime(A.trans_id) >= pckg_limit_trade_rpt.func_get_passtime(A.trans_id,A.trans_initiate))) and a.trans_year = ''' || I_YEAR ||''' and a.TRANS_QUARTER = ''' || I_SEASON || '''';
     
     if I_BR_ID is null and v_level <> 2 then --全部机构
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                            FROM CTP_BRANCH B
                                           WHERE B.BRANCH_LEVEL = ' || v_level ||
                                           ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                           ' CONNECT BY B.PARENT_ID = PRIOR ID ) ';

     elsif I_BR_ID is null and v_level = 2 then --全部机构
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                            FROM CTP_BRANCH B
                                           WHERE B.BRANCH_LEVEL = ' || v_level ||
                                           ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                           ' CONNECT BY B.PARENT_ID = PRIOR ID ' ||
                                           ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''
                                                        and end_date = ''99991231'' ) ';
     elsif I_BR_ID = I_USER_BR then
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
     else 
           v_where_sql := v_where_sql || ' and A.TRANS_ACCEPT_BRANCH = ''' || I_USER_BR || '''' || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
        
     end if;
       
     v_count_sql := 'SELECT COUNT(1) FROM (select 1 from CAP_TRANS_APPLY a ' || v_where_sql || ' ) ';
    
     v_query_sql := 'select func_get_branchname(a.trans_initiate),
                     decode(a.trans_quarter, ''1'', ''第一季度'', ''2'', ''第二季度'', ''3'', ''第三季度'',''第四季度''), 
                      to_char(a.TRANS_TIME, ''yyyy-mm-dd hh24:mi:ss''),
                      (case when a.trans_variety= 1 and a.trans_type = 1 then a.trans_price else 0 end) b1,
                      (case when a.trans_variety= 1 and a.trans_type = 0 then a.trans_price else 0 end) s1,
                      (case when a.trans_variety= 2 and a.trans_type = 1 then a.trans_price else 0 end) b2,
                      (case when a.trans_variety= 2 and a.trans_type = 0 then a.trans_price else 0 end) s2,
                      (case when a.trans_variety= 3 and a.trans_type = 1 then a.trans_price else 0 end) b3,
                      (case when a.trans_variety= 3 and a.trans_type = 0 then a.trans_price else 0 end) s3,
                      (case when a.trans_variety= 4 and a.trans_type = 1 then a.trans_price else 0 end) b4,
                      (case when a.trans_variety= 4 and a.trans_type = 0 then a.trans_price else 0 end) s4,                     
                     row_number() over (order by decode(''' || i_user_br || '''' ||',''01000000'',
                                                   (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = a.trans_initiate),
                                                  a.trans_initiate),a.trans_quarter,a.TRANS_TIME) rn
              from CAP_TRANS_APPLY a ' || v_where_sql ; --被修改的原来逻辑：row_number() over (order by a.trans_initiate,a.trans_quarter) rn
     
                
       EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;

       v_query_sql := 'SELECT *
          FROM (' || v_query_sql  || ')
          WHERE rn BETWEEN :i_beg AND :i_end';
        
       OPEN o_retList FOR v_query_sql
           USING i_beg_num, i_beg_num + i_fetch_num - 1;
           
       /*OPEN O_RETLIST FOR
           select a.trans_initiate, a.trans_quarter, to_char(a.TRANS_TIME, 'yyyymmdd hh24:mi:ss'),
              (case when a.trans_variety= '1' and a.trans_type = 1 then a.trans_price else 0 end),
              (case when a.trans_variety= '1' and a.trans_type = 0 then a.trans_price else 0 end),
              (case when a.trans_variety= '2' and a.trans_type = 1 then a.trans_price else 0 end),
              (case when a.trans_variety= '2' and a.trans_type = 0 then a.trans_price else 0 end),
              (case when a.trans_variety= '3' and a.trans_type = 1 then a.trans_price else 0 end),
              (case when a.trans_variety= '3' and a.trans_type = 0 then a.trans_price else 0 end),
              (case when a.trans_variety= '4' and a.trans_type = 1 then a.trans_price else 0 end),
              (case when a.trans_variety= '4' and a.trans_type = 0 then a.trans_price else 0 end)
      from CAP_TRANS_APPLY a where a.trans_status = '3' and a.trans_year = I_YEAR  
      order by a.trans_initiate,a.trans_quarter;*/

      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
   --交易价格查询
  PROCEDURE PROC_TRDPRICE_RPT_GETALLDATA(I_YEAR     IN VARCHAR2, --交易年份
                                  I_USER_BR IN VARCHAR2, --用户机构
                                  I_BR_ID    IN VARCHAR2, --交易机构
                                  I_SEASON   IN VARCHAR2, --交易季度
                                  O_RETCODE  OUT VARCHAR2,
                                  O_totalNum   OUT number,
                                  O_RETLIST  OUT REFCUR,
                                  O_RETMSG OUT VARCHAR2)IS
    v_query_sql  VARCHAR2(30000) := '';
   v_count_sql  VARCHAR2(30000) := '';
   v_where_sql  VARCHAR2(30000) := '';
   v_level      ctp_branch.branch_level%type;
   
   BEGIN
     
     o_retCode := '0';
     select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;
     
     --v_where_sql := 'where a.trans_status = 3 and a.trans_year = ''' || I_YEAR ||''' and a.TRANS_QUARTER = ''' || I_SEASON || '''';
     v_where_sql := 'where (A.TRANS_STATUS = ''3'' or(A.TRANS_STATUS = ''2'' and pckg_limit_trade_rpt.func_get_transendtime(A.trans_id) >= pckg_limit_trade_rpt.func_get_passtime(A.trans_id,A.trans_initiate))) and a.trans_year = ''' || I_YEAR ||''' and a.TRANS_QUARTER = ''' || I_SEASON || '''';
     if I_BR_ID is null and v_level <> 2 then --全部机构
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                            FROM CTP_BRANCH B
                                           WHERE B.BRANCH_LEVEL = ' || v_level ||
                                           ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                           ' CONNECT BY B.PARENT_ID = PRIOR ID ) ';

     elsif I_BR_ID is null and v_level = 2 then --全部机构
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                            FROM CTP_BRANCH B
                                           WHERE B.BRANCH_LEVEL = ' || v_level ||
                                           ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                           ' CONNECT BY B.PARENT_ID = PRIOR ID ' ||
                                           ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''
                                                        and end_date = ''99991231'' ) ';
     elsif I_BR_ID = I_USER_BR then
           v_where_sql := v_where_sql || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
     else 
           v_where_sql := v_where_sql || ' and A.TRANS_ACCEPT_BRANCH = ''' || I_USER_BR || '''' || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
        
     end if;
       
     v_count_sql := 'SELECT COUNT(1) FROM (select 1 from CAP_TRANS_APPLY a ' || v_where_sql || ' ) ';
    
     v_query_sql := 'select func_get_branchname(a.trans_initiate),
                     decode(a.trans_quarter, ''1'', ''第一季度'', ''2'', ''第二季度'', ''3'', ''第三季度'',''第四季度''), 
                            to_char(a.TRANS_TIME, ''yyyy-mm-dd hh24:mi:ss''),
                      (case when a.trans_variety= 1 and a.trans_type = 1 then a.trans_price else 0 end) b1,
                      (case when a.trans_variety= 1 and a.trans_type = 0 then a.trans_price else 0 end) s1,
                      (case when a.trans_variety= 2 and a.trans_type = 1 then a.trans_price else 0 end) b2,
                      (case when a.trans_variety= 2 and a.trans_type = 0 then a.trans_price else 0 end) s2,
                      (case when a.trans_variety= 3 and a.trans_type = 1 then a.trans_price else 0 end) b3,
                      (case when a.trans_variety= 3 and a.trans_type = 0 then a.trans_price else 0 end) s3,
                      (case when a.trans_variety= 4 and a.trans_type = 1 then a.trans_price else 0 end) b4,
                      (case when a.trans_variety= 4 and a.trans_type = 0 then a.trans_price else 0 end) s4                      
              from CAP_TRANS_APPLY a ' || v_where_sql ||'order by decode(''' || i_user_br || '''' ||',''01000000'',
                                                                         (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = a.trans_initiate),
                                                                        a.trans_initiate),
                                                                  a.trans_quarter,a.TRANS_TIME'
              ;--增加排序row_number()
     
                
       EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;

       v_query_sql := 'SELECT *
          FROM (' || v_query_sql  || ')';

       OPEN o_retList FOR v_query_sql;

      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
  --交易日志查询
  PROCEDURE PROC_TRDLOG_RPT(I_BEGDATE   IN VARCHAR2, --交易开始时间
                            I_ENDDATE   IN VARCHAR2, --交易结束时间
                            I_TRADEVAR  IN VARCHAR2, --交易品种
                            I_TRADETYPE IN VARCHAR2, --交易类型
                            I_USER_BR  IN VARCHAR2, --用户机构
                            I_BR_ID     IN VARCHAR2, --交易机构
                            I_BEG_NUM    IN VARCHAR2,
                            I_FETCH_NUM  IN VARCHAR2,
                            O_RETCODE   OUT VARCHAR2,
                            O_totalNum   OUT number,
                            O_RETLIST  OUT REFCUR,
                            O_RETMSG OUT VARCHAR2)IS
   v_query_sql  VARCHAR2(30000) := '';
   v_count_sql  VARCHAR2(30000) := '';
   v_where_sql  VARCHAR2(30000) := '';
   v_level      ctp_branch.branch_level%type;
   BEGIN
     
     o_retCode := '0';
     select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;
     --modify 20160119
     --修改前只查询：交易状态为3-已签批的交易
     --修改后查询：交易状态为3-已签批的交易 或 交易状态为2-待签批 且 本级行审批通过时间<=交易结束时间 的交易
     --v_where_sql := 'where A.TRANS_STATUS = ''3'' and TO_CHAR(A.TRANS_TIME, ''yyyymmdd'') BETWEEN ''' || I_BEGDATE || ''' and ''' || I_ENDDATE || '''';
     v_where_sql := 'where (A.TRANS_STATUS = ''3'' or(A.TRANS_STATUS = ''2'' and pckg_limit_trade_rpt.func_get_transendtime(A.trans_id) >= pckg_limit_trade_rpt.func_get_passtime(A.trans_id,A.trans_initiate))) and TO_CHAR(A.TRANS_TIME, ''yyyymmdd'') BETWEEN ''' || I_BEGDATE || ''' and ''' || I_ENDDATE || '''';
     
     if I_TRADEVAR is not null then 
        v_where_sql := v_where_sql || ' and a.TRANS_VARIETY = ' || I_TRADEVAR;
     end if;
        
     if I_TRADETYPE is not null then 
       v_where_sql := v_where_sql || ' and a.TRANS_TYPE = ' || I_TRADETYPE;
     end if;
     
     if I_BR_ID is null and v_level <> 2 then --全部机构
         v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                          FROM CTP_BRANCH B
                                         WHERE B.BRANCH_LEVEL = ' || v_level ||
                                         ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                         ' CONNECT BY B.PARENT_ID = PRIOR ID ) and a.TRANS_ACCEPT_BRANCH = '''||I_USER_BR||'''';
     
     elsif I_BR_ID is null and v_level = 2 then --全部机构
         v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                          FROM CTP_BRANCH B
                                         WHERE B.BRANCH_LEVEL = ' || v_level ||
                                         ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                         ' CONNECT BY B.PARENT_ID = PRIOR ID ' ||
                                         ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''
                                                        and end_date = ''99991231'' ) and a.TRANS_ACCEPT_BRANCH = '''||I_USER_BR||'''';
     elsif I_BR_ID = I_USER_BR then
        v_where_sql := v_where_sql || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
        
     else
        v_where_sql := v_where_sql || ' and A.TRANS_ACCEPT_BRANCH = ''' || I_USER_BR || '''' || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
     end if;
     
     v_count_sql := 'select count(1) from CAP_TRANS_APPLY a ' || v_where_sql ;
     
     v_query_sql := 'SELECT A.TRANS_ID,
                           func_get_branchname(A.TRANS_INITIATE),
                           func_get_branchname(A.TRANS_ACCEPT_BRANCH),
                           decode(A.TRANS_TYPE, ''0'', ''卖出'', ''买入''),
                           decode(A.TRANS_VARIETY, ''1'',''Q1'',''2'',''Q2'',''3'',''Q3'',''Q4'' ),
                           A.TRANS_PRICE,
                           A.TRANS_COUNT,
                           TO_CHAR(A.TRANS_TIME, ''yyyy-mm-dd hh24:mi:ss''),                           
                           row_number() over (order by (select nvl(sort_no,a.trans_initiate) from cap_trans_branch_sort where trans_branch_id(+) = a.trans_initiate), A.TRANS_ID) rn
                    FROM CAP_TRANS_APPLY A ' || v_where_sql ; --20160125被修改的原来逻辑为：row_number() over (order by A.TRANS_INITIATE, A.TRANS_ID) rn
                
       EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;

       v_query_sql := 'SELECT *
          FROM (' || v_query_sql  || ')
          WHERE rn BETWEEN :i_beg AND :i_end';
        
       OPEN o_retList FOR v_query_sql
           USING i_beg_num, i_beg_num + i_fetch_num - 1;
     
     /* OPEN O_RETLIST FOR
           SELECT A.TRANS_ID,
               A.TRANS_INITIATE,
               A.TRANS_ACCEPT_BRANCH,
               A.TRANS_TYPE,
               A.TRANS_VARIETY,
               A.TRANS_PRICE,
               A.TRANS_COUNT,
               TO_CHAR(A.TRANS_TIME, 'yyyy-mm-dd hh24:mi:ss')
        FROM CAP_TRANS_APPLY A
 WHERE TO_CHAR(A.TRANS_TIME, 'yyyymmdd') BETWEEN '' AND ''
   AND A.TRANS_VARIETY = ''
   AND A.TRANS_TYPE = ''
   AND A.TRANS_INITIATE = '';*/

      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
    --交易日志查询
  PROCEDURE PROC_TRDLOG_RPT_GETALLDATA(I_BEGDATE   IN VARCHAR2, --交易开始时间
                                I_ENDDATE   IN VARCHAR2, --交易结束时间
                                I_TRADEVAR  IN VARCHAR2, --交易品种
                                I_TRADETYPE IN VARCHAR2, --交易类型
                                I_USER_BR  IN VARCHAR2, --用户机构
                                I_BR_ID     IN VARCHAR2, --交易机构
                                O_RETCODE   OUT VARCHAR2,
                                O_totalNum   OUT number,
                                O_RETLIST  OUT REFCUR,
                                O_RETMSG OUT VARCHAR2)IS
   v_query_sql  VARCHAR2(30000) := '';
   v_count_sql  VARCHAR2(30000) := '';
   v_where_sql  VARCHAR2(30000) := '';
   v_level      ctp_branch.branch_level%type;
   BEGIN
   o_retCode := '0';
     select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;
     
     --v_where_sql := 'where A.TRANS_STATUS = ''3'' and TO_CHAR(A.TRANS_TIME, ''yyyymmdd'') BETWEEN ''' || I_BEGDATE || ''' and ''' || I_ENDDATE || '''';
     v_where_sql := 'where (A.TRANS_STATUS = ''3'' or(A.TRANS_STATUS = ''2'' and pckg_limit_trade_rpt.func_get_transendtime(A.trans_id) >= pckg_limit_trade_rpt.func_get_passtime(A.trans_id,A.trans_initiate))) and TO_CHAR(A.TRANS_TIME, ''yyyymmdd'') BETWEEN ''' || I_BEGDATE || ''' and ''' || I_ENDDATE || '''';
     if I_TRADEVAR is not null then 
        v_where_sql := v_where_sql || ' and a.TRANS_VARIETY = ' || I_TRADEVAR;
     end if;
        
     if I_TRADETYPE is not null then 
       v_where_sql := v_where_sql || ' and a.TRANS_TYPE = ' || I_TRADETYPE;
     end if;
     
     if I_BR_ID is null and v_level <> 2 then --全部机构
         v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                          FROM CTP_BRANCH B
                                         WHERE B.BRANCH_LEVEL = ' || v_level ||
                                         ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                         ' CONNECT BY B.PARENT_ID = PRIOR ID ) and a.TRANS_ACCEPT_BRANCH = '''||I_USER_BR||'''';
     
     elsif I_BR_ID is null and v_level = 2 then --全部机构
         v_where_sql := v_where_sql || ' and a.TRANS_INITIATE in (SELECT B.id
                                          FROM CTP_BRANCH B
                                         WHERE B.BRANCH_LEVEL = ' || v_level ||
                                         ' START WITH B.ID = ''' || I_USER_BR || '''' ||
                                         ' CONNECT BY B.PARENT_ID = PRIOR ID ' ||
                                         ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''
                                                        and end_date = ''99991231'' ) and a.TRANS_ACCEPT_BRANCH = '''||I_USER_BR||'''';
     elsif I_BR_ID = I_USER_BR then
        v_where_sql := v_where_sql || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
        
     else
        v_where_sql := v_where_sql || ' and A.TRANS_ACCEPT_BRANCH = ''' || I_USER_BR || '''' || ' and a.TRANS_INITIATE = ''' || I_BR_ID || '''';
     end if;
     
     v_count_sql := 'select count(1) from CAP_TRANS_APPLY a ' || v_where_sql ;
     
     v_query_sql := 'SELECT A.TRANS_ID,
                           func_get_branchname(A.TRANS_INITIATE),
                           func_get_branchname(A.TRANS_ACCEPT_BRANCH),
                           decode(A.TRANS_TYPE, ''0'', ''卖出'', ''买入''),
                           decode(A.TRANS_VARIETY, ''1'',''Q1'',''2'',''Q2'',''3'',''Q3'',''Q4'' ),
                           A.TRANS_PRICE,
                           A.TRANS_COUNT,
                           TO_CHAR(A.TRANS_TIME, ''yyyy-mm-dd hh24:mi:ss'')                          
                    FROM CAP_TRANS_APPLY A ' || v_where_sql
 || ' order by (select nvl(sort_no,a.trans_initiate) 
      from cap_trans_branch_sort where trans_branch_id(+) = a.trans_initiate), A.TRANS_ID';--20160125被修改的原来逻辑order by A.TRANS_INITIATE
 
                
       EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;
        
       OPEN o_retList FOR v_query_sql;
       O_RETMSG := '获取统计数据成功';
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
 --柜员可选的机构
  PROCEDURE PROC_GETBRANCH_LIST(I_USER_BR IN VARCHAR2, --用户机构
                                O_RETCODE   OUT VARCHAR2,
                                O_RETMSG    OUT VARCHAR2,
                                O_RETLIST   OUT REFCUR)IS
   
   BEGIN
      OPEN O_RETLIST FOR
         SELECT *
           FROM (SELECT ID, NAME, BRANCH_LEVEL
                   FROM CTP_BRANCH
                 WHERE PARENT_ID = I_USER_BR
                 UNION ALL
                 SELECT ID, NAME, BRANCH_LEVEL
                   FROM CTP_BRANCH
                  WHERE PARENT_ID = I_USER_BR)
          ORDER BY BRANCH_LEVEL, ID;

      O_RETCODE := '0';
      O_RETMSG := '获取机构数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取机构数据失败';
         RETURN;
   END;
   
     --限额核定结果汇总
  PROCEDURE PROC_LIMAUTH_RPT(I_YEAR     IN VARCHAR2, --交易年份
                             I_BR_ID    IN VARCHAR2, --交易机构
                             I_VARIETY   IN VARCHAR2, --交易品种
                             I_USERBR IN VARCHAR2, --本机构
                             I_BEG_NUM    IN VARCHAR2,
                             I_FETCH_NUM  IN VARCHAR2,
                             O_RETCODE  OUT VARCHAR2,
                             O_totalNum   OUT number,
                             O_RETLIST  OUT REFCUR,
                             O_RETMSG OUT VARCHAR2)IS
   v_br_level                ctp_branch.branch_level%type;
   v_usrbr_level             ctp_branch.branch_level%type;
   BEGIN
     
     select max(b.branch_level) into v_br_level from ctp_branch b where b.id = I_BR_ID;
     select max(b.branch_level) into v_usrbr_level from ctp_branch b where b.id = I_USERBR;

     select decode(count(1), 0, 0, count(1) + 1) into O_totalNum from (select distinct A.TRANS_INITIATE  FROM CAP_TRANS_APPLY A, CAP_TRANS_LIMIT L
          WHERE A.TRANS_INITIATE = L.LIMIT_BRANCH
            AND A.TRANS_YEAR = L.LIMIT_YEAR
            and L.LIMIT_TYPE = I_VARIETY
            AND A.trans_accept_branch = I_USERBR
            AND L.CREATE_BRANCH = I_USERBR
            AND A.TRANS_VARIETY <= I_VARIETY
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS in ('2', '3')            
            and (A.TRANS_INITIATE = I_BR_ID or I_BR_ID = I_USERBR));  --modify 20160216                   
                          
      OPEN O_RETLIST for with rs as(
          select nvl(T.BRID, '合计') total,
                 T.INITLIM,
                 T.MINLIM,
                 T.LIM,
                 T.TB,
                 T.TS,
                 T.RLIM    
              from (    
              SELECT func_get_branchname(A.BRID) BRID,
                        SUM(A.INITLIM) INITLIM,
                        SUM(A.MINLIM) MINLIM,
                        SUM(LIM) LIM,
                        SUM(B.TB) TB,
                        SUM(B.TS) TS,
                        (SUM(LIM) + SUM(B.TB) - SUM(B.TS)) RLIM
              FROM (SELECT L.LIMIT_BRANCH BRID,
                           L.LIMIT_INIT INITLIM,
                           L.LIMIT_MIN MINLIM,
                           (CASE
                             WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                              L.LIMIT_INIT
                             ELSE
                              L.LIMIT_MIN
                           END) LIM
                      FROM CAP_TRANS_LIMIT L
                     WHERE L.LIMIT_YEAR = I_YEAR
                       AND L.LIMIT_TYPE = I_VARIETY
                       AND L.CREATE_BRANCH = I_USERBR                       
                        and (L.LIMIT_BRANCH = I_BR_ID or I_BR_ID = I_USERBR)  --modify 20160216                 
                       ) A,
                   (SELECT A.TRANS_INITIATE BRID,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '0', A.TRANS_COUNT, 0)), 0) TS,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '1', A.TRANS_COUNT, 0)), 0) TB
                      FROM CAP_TRANS_APPLY A
                     WHERE A.TRANS_YEAR = I_YEAR
                       AND A.TRANS_VARIETY <= I_VARIETY
                       AND A.trans_accept_branch = I_USERBR  
                       AND A.TRANS_STATUS in ('2', '3')
                       and (A.TRANS_INITIATE = I_BR_ID or I_BR_ID = I_USERBR)  --modify 20160216    
                     GROUP BY A.TRANS_INITIATE) B
             WHERE A.BRID = B.BRID
             GROUP BY ROLLUP(A.BRID) --order by A.BRID  20160125 modify by zhaoxm
             order by decode(I_USERBR,'01000000',
                             (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = A.BRID),
                             A.BRID)
             ) T)               
            select * from (select /*rs.*,*/rs.total, rs.INITLIM,rs.MINLIM,rs.LIM,rs.TB,rs.TS,rs.RLIM, rownum row_num from rs)
                 where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;               
                           
  /* OPEN O_RETLIST for with rs as(
        select nvl(T.TRANS_INITIATE, '合计'),
               T.LIMIT_INIT,
               T.LIMIT_MIN,
               T.CUR_LIMIT,
               T.BAMT,
               T.SAMT,
               T.REALLIMIT
         from (
        SELECT func_get_branchname(A.TRANS_INITIATE) TRANS_INITIATE,
                sum(L.LIMIT_INIT) LIMIT_INIT,
                sum(L.LIMIT_MIN) LIMIT_MIN,
                sum(CASE
                  WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                   L.LIMIT_INIT
                  ELSE
                   L.LIMIT_MIN
                END) CUR_LIMIT,
                sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0)) BAMT,
                sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0)) SAMT,
                (max(CASE
                  WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                   L.LIMIT_INIT
                  ELSE
                   L.LIMIT_MIN
                END) + sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0)) + sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0))) REALLIMIT
        FROM CAP_TRANS_APPLY A, CAP_TRANS_LIMIT L
          WHERE A.TRANS_INITIATE = L.LIMIT_BRANCH
            AND A.TRANS_YEAR = L.LIMIT_YEAR
            and L.LIMIT_TYPE = I_VARIETY
            AND A.TRANS_VARIETY <= I_VARIETY
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS = '3'
            and A.TRANS_INITIATE in 
             (SELECT B.id FROM CTP_BRANCH B
                         WHERE B.BRANCH_LEVEL = I_USERBR_LVL + 1
                          START WITH B.ID =  I_BR_ID
                          CONNECT BY B.PARENT_ID = PRIOR ID 
              union all
              SELECT (ZONE_NO || BR_NO) ID
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_USERBR_LVL = 1
                          and v_br_level = I_USERBR_LVL
                          and end_date = '99991231' )
          GROUP BY rollup(A.TRANS_INITIATE) order by A.TRANS_INITIATE) t)
          select * from (select rs.*, rownum row_num from rs)
                 where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;*/
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
  --限额核定结果汇总
  PROCEDURE PROC_LIMAUTH_RPT_GETALLDATA(I_YEAR     IN VARCHAR2, --交易年份
                              I_BR_ID    IN VARCHAR2, --交易机构
                              I_VARIETY   IN VARCHAR2, --交易品种
                              I_USERBR IN VARCHAR2,                     
                              O_RETCODE  OUT VARCHAR2,
                              O_totalNum   OUT number,
                              O_RETLIST  OUT REFCUR,
                              O_RETMSG OUT VARCHAR2)IS
   v_br_level                ctp_branch.branch_level%type;
   v_usrbr_level             ctp_branch.branch_level%type;
   BEGIN
     
     select max(b.branch_level) into v_br_level from ctp_branch b where b.id = I_BR_ID;
     select max(b.branch_level) into v_usrbr_level from ctp_branch b where b.id = I_USERBR;

     select decode(count(1), 0, 0, count(1) + 1) into O_totalNum from (select distinct A.TRANS_INITIATE  FROM CAP_TRANS_APPLY A, CAP_TRANS_LIMIT L
          WHERE A.TRANS_INITIATE = L.LIMIT_BRANCH
            AND A.TRANS_YEAR = L.LIMIT_YEAR
            and L.LIMIT_TYPE = I_VARIETY
            AND A.TRANS_VARIETY <= I_VARIETY
            AND A.trans_accept_branch = I_USERBR
            AND L.CREATE_BRANCH = I_USERBR
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS in ('2', '3')            
            and (A.TRANS_INITIATE = I_BR_ID or I_BR_ID = I_USERBR));  --modify 20160216                   
                          
      OPEN O_RETLIST for with rs as(
          select nvl(T.BRID, '合计') total,
                 T.INITLIM,
                 T.MINLIM,
                 T.LIM,
                 T.TB,
                 T.TS,
                 T.RLIM    
              from (    
              SELECT func_get_branchname(A.BRID) BRID,
                        SUM(A.INITLIM) INITLIM,
                        SUM(A.MINLIM) MINLIM,
                        SUM(LIM) LIM,
                        SUM(B.TB) TB,
                        SUM(B.TS) TS,
                        (SUM(LIM) + SUM(B.TB) - SUM(B.TS)) RLIM
              FROM (SELECT L.LIMIT_BRANCH BRID,
                           L.LIMIT_INIT INITLIM,
                           L.LIMIT_MIN MINLIM,
                           (CASE
                             WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                              L.LIMIT_INIT
                             ELSE
                              L.LIMIT_MIN
                           END) LIM
                      FROM CAP_TRANS_LIMIT L
                     WHERE L.LIMIT_YEAR = I_YEAR
                       AND L.LIMIT_TYPE = I_VARIETY
                       AND L.CREATE_BRANCH = I_USERBR                       
                        and (L.LIMIT_BRANCH = I_BR_ID or I_BR_ID = I_USERBR)  --modify 20160216                    
                       ) A,
                   (SELECT A.TRANS_INITIATE BRID,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '0', A.TRANS_COUNT, 0)), 0) TS,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '1', A.TRANS_COUNT, 0)), 0) TB
                      FROM CAP_TRANS_APPLY A
                     WHERE A.TRANS_YEAR = I_YEAR
                       AND A.TRANS_VARIETY <= I_VARIETY
                       AND A.trans_accept_branch = I_USERBR  
                       AND A.TRANS_STATUS in ('2', '3')
                       and (A.TRANS_INITIATE = I_BR_ID or I_BR_ID = I_USERBR)  --modify 20160216  
                     GROUP BY A.TRANS_INITIATE) B
             WHERE A.BRID = B.BRID
             GROUP BY ROLLUP(A.BRID) --order by A.BRID  20160125
             order by decode(I_USERBR,'01000000',
                             (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = A.BRID),
                             A.BRID)
             ) T)               
            select * from (select /*rs.**/rs.total, rs.INITLIM,rs.MINLIM,rs.LIM,rs.TB,rs.TS,rs.RLIM from rs);
                
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
  --限额计价情况汇总
  PROCEDURE PROC_LIMPRICE_RPT(I_YEAR     IN VARCHAR2, --交易年份
                             I_BR_ID    IN VARCHAR2, --交易机构
                             I_VARIETY   IN VARCHAR2, --交易品种
                             I_USERBR IN VARCHAR2,            
                             I_BEG_NUM    IN VARCHAR2,
                             I_FETCH_NUM  IN VARCHAR2,
                             O_RETCODE  OUT VARCHAR2,
                             O_totalNum   OUT number,
                             O_RETLIST  OUT REFCUR,
                             O_RETMSG OUT VARCHAR2) IS
   V_PRM_UPLIMINC            varchar2(20); --限额增计倍数 参数表
   V_PRM_CAPCOST             varchar2(20); --资本成本率
   v_br_level                ctp_branch.branch_level%type;
   v_usrbr_level             ctp_branch.branch_level%type;
   v_level                   ctp_branch.branch_level%type;
   v_br_id                   ctp_branch.id%type;
   v_bvariety                 varchar(2);
   v_evariety                 varchar(2);
   BEGIN
      O_totalNum := 0;
      O_RETCODE := '0';
     
      SELECT nvl(max(T.PAR_COEF), 0.1) into V_PRM_CAPCOST
       FROM PRM_XSXJ1 T
       WHERE T.END_DATE = '99991231';
      
      SELECT nvl(max(T.PAR_COEF), 1) into V_PRM_UPLIMINC
       FROM PRM_XSXJ2 T
       WHERE T.END_DATE = '99991231';
       
      select max(b.branch_level) into v_br_level from ctp_branch b where b.id = I_BR_ID;
      select max(b.branch_level) into v_usrbr_level from ctp_branch b where b.id = I_USERBR;
      
      if I_BR_ID is null then
        v_level := v_usrbr_level + 1;
        v_br_id := I_USERBR;
      elsif I_USERBR = I_BR_ID then 
        v_level := v_usrbr_level;
        v_br_id := I_BR_ID; 
      else 
        v_level := v_br_level;
        v_br_id := I_BR_ID; 
      end if;
      
      if i_variety is null then
        v_bvariety := 1;
        v_evariety := 4;
      else 
        v_bvariety := I_VARIETY;
        v_evariety := I_VARIETY;
      end if;
      --实际限额
      delete CAP_TRANSLIMIT_STAT_TMP;
      --总行选择本级行则导出为空
      if I_USERBR = I_BR_ID and I_BR_ID = '01000000'then
        v_bvariety := 5;
      end if;
      
      FOR i_v IN v_bvariety .. v_evariety LOOP
      insert into CAP_TRANSLIMIT_STAT_TMP (BRANCHID, YEAR, QUARTER) 
            SELECT B.ID,
                    I_YEAR,
                    i_v
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level
               and B.id not in ('01010000','01010011','01020000','01770000',
                            '01780000','45000000','46990000')
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
            union all
              SELECT (ZONE_NO || BR_NO) ID,
                    I_YEAR,
                    i_v
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231';
              
        merge into CAP_TRANSLIMIT_STAT_TMP A using (
        select A.BRID,
               I_YEAR c_year,
               i_v c_quar,      
               (SUM(LIM) + SUM(B.TB) - SUM(B.TS)) RLIM
              FROM (SELECT L.LIMIT_BRANCH BRID,
                           L.LIMIT_INIT INITLIM,
                           L.LIMIT_MIN MINLIM,
                           (CASE
                             WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                              L.LIMIT_INIT
                             ELSE
                              L.LIMIT_MIN
                           END) LIM
                      FROM CAP_TRANS_LIMIT L
                     WHERE L.LIMIT_YEAR = I_YEAR
                       AND L.LIMIT_TYPE = i_v
                       AND L.CREATE_BRANCH = I_USERBR
                       AND L.LIMIT_BRANCH in (
                         SELECT B.id FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level
                            START WITH B.ID =  v_br_id
                            CONNECT BY B.PARENT_ID = PRIOR ID 
                            union all
                            SELECT (ZONE_NO || BR_NO) ID
                                       FROM PRM_IRA_ORGAN
                                      WHERE BANK_FLAG = '3'
                                        AND IS_SALES = '1'
                                        and I_BR_ID is null
                                        and v_usrbr_level = 1
                                        and end_date = '99991231')
                       ) A,
                   (SELECT A.TRANS_INITIATE BRID,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '0', A.TRANS_COUNT, 0)), 0) TS,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '1', A.TRANS_COUNT, 0)), 0) TB
                      FROM CAP_TRANS_APPLY A
                     WHERE A.TRANS_YEAR = I_YEAR
                       AND A.TRANS_QUARTER <= i_v
                       AND A.TRANS_VARIETY = i_v
                       AND A.trans_accept_branch = I_USERBR  
                       AND A.TRANS_STATUS IN ('2','3')
                       AND A.TRANS_INITIATE in (
                         SELECT B.id FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level
                            START WITH B.ID =  v_br_id
                            CONNECT BY B.PARENT_ID = PRIOR ID 
                            union all
                            SELECT (ZONE_NO || BR_NO) ID
                                       FROM PRM_IRA_ORGAN
                                      WHERE BANK_FLAG = '3'
                                        AND IS_SALES = '1'
                                        and I_BR_ID is null
                                        and v_usrbr_level = 1
                                        and end_date = '99991231')
                     GROUP BY A.TRANS_INITIATE) B
             WHERE A.BRID = B.BRID
             GROUP BY ROLLUP(A.BRID) ) T 
              on (T.BRID = A.BRANCHID and T.c_year = A.YEAR and T.c_quar = A.QUARTER)
              when matched then
                update set REALLIMT = T.RLIM;
         --超限额度 实际增量-实际限额
         merge into CAP_TRANSLIMIT_STAT_TMP T using (SELECT I.INC_BRANCH, I.INC_TYPE, I.INC_COUNT
                FROM CAP_REAL_INCREMENT I
               WHERE I.INC_YEAR = I_YEAR
                 AND I.INC_TYPE = i_v
                 and I.CREATE_BRANCH = I_USERBR
                 and I.INC_BRANCH in  (SELECT B.ID
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level --统计所有下级行
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
              union all
              SELECT (ZONE_NO || BR_NO) ID
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231') ) C on (T.BRANCHID = C.INC_BRANCH and T.QUARTER = C.INC_TYPE)
          when matched then
            update set T.REALINC = C.INC_COUNT,
                       T.UPLIMIT = (case when C.INC_COUNT - T.REALLIMT < 0 then 0 else C.INC_COUNT - T.REALLIMT end);  
        
       --超限额增计     
       update CAP_TRANSLIMIT_STAT_TMP t set t.uplimitinc = t.uplimit * V_PRM_UPLIMINC;
 
            
       --买入额度	买入计价	卖出额度	卖出计价 影响EVA(年化)
       --影响EVA(年化）= ∑卖出额度*卖出价格*资本成本率*（买入当期至月末月份数/12）-∑买入额度*买入价格*资本成本率*（买入当期至月末月份数/12）
       merge into CAP_TRANSLIMIT_STAT_TMP T using( select A.TRANS_INITIATE, A.TRANS_VARIETY,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0)) BUYCNT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0)) SELLCNT,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price) BUYCALAMT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price) SELLCALAMT
            FROM CAP_TRANS_APPLY A
              WHERE  A.TRANS_VARIETY = i_v
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS in ('2', '3')
            and A.TRANS_INITIATE  IN
             (SELECT B.ID
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
              union all
              SELECT (ZONE_NO || BR_NO) ID
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231'
                          ) group by TRANS_INITIATE, A.TRANS_VARIETY) V 
              on(T.BRANCHID = V.trans_initiate and T.QUARTER = V.TRANS_VARIETY)
             when matched then
               update set T.BUYCNT = V.BUYCNT,
                          T.SELLCNT = V.SELLCNT,
                          T.BUYCALAMT = V.BUYCALAMT,
                          T.SELLCALAMT = V.SELLCALAMT;
                    
        --保底额度 初始额度 
        merge into CAP_TRANSLIMIT_STAT_TMP T using( select L.LIMIT_BRANCH, L.LIMIT_TYPE,
            L.LIMIT_INIT,
            L.LIMIT_MIN
            FROM CAP_TRANS_LIMIT L
              WHERE  L.LIMIT_TYPE = i_v
            AND L.LIMIT_YEAR = I_YEAR
           -- and L.LIMIT_BRANCH = I_BR_ID
            and L.CREATE_BRANCH = I_USERBR) V 
              on(T.BRANCHID = V.LIMIT_BRANCH and T.QUARTER = V.LIMIT_TYPE)            
             when matched then
               update set T.LIMIT_MIN = V.LIMIT_MIN,
                          T.LIMIT_INIT = V.LIMIT_INIT;
       
       --交易计价小计    买入计价-卖出计价               
       update CAP_TRANSLIMIT_STAT_TMP t set t.TRANSTOLAMT = func_get_buyselltol(t.branchid, I_USERBR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt);
 
       --买入计价 卖出计价 影响EVA(年化）
       update CAP_TRANSLIMIT_STAT_TMP t 
       set t.quartereva = func_get_QUARTEREVA(t.branchid, I_USERBR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt,V_PRM_CAPCOST );
             
       --超限额增计与交易计价小计
       update CAP_TRANSLIMIT_STAT_TMP t set t.UPLIMITINCAMT = t.uplimitinc + t.transtolamt;
        
        end loop;
        
           --输出统计信息
        select decode(count(1), 0, 0, count(1) + 1) into O_totalNum from CAP_TRANSLIMIT_STAT_TMP T where T.QUARTER = I_VARIETY or i_variety is null;
        
        OPEN O_RETLIST for with rs as(
          select nvl(TT.BRANCH, '合计') total,
                 decode(TT.QUARTER, '1', '一季度',2,'上半年', 3,'前三季度', 4, '全年' ) QUARTER,
                 TT.UPLIMIT,
                 TT.UPLIMITINC,
                 TT.BUYCNT,
                 TT.BUYCALAMT,
                 TT.SELLCNT,
                 TT.SELLCALAMT,
                 TT.TRANSTOLAMT,
                 TT.QUARTEREVA,
                 TT.UPLIMITINCAMT
          from (
               select func_get_branchname(T.BRANCHID) BRANCH,
                      T.QUARTER,
                      sum(T.UPLIMIT) UPLIMIT,
                      sum(T.UPLIMITINC) UPLIMITINC,
                      sum(T.BUYCNT) BUYCNT,
                      sum(T.BUYCALAMT) BUYCALAMT,
                      sum(T.SELLCNT) SELLCNT,
                      sum(T.SELLCALAMT) SELLCALAMT,
                      sum(T.TRANSTOLAMT) TRANSTOLAMT,
                      sum(T.QUARTEREVA) QUARTEREVA,
                      sum(T.UPLIMITINCAMT) UPLIMITINCAMT
                 from CAP_TRANSLIMIT_STAT_TMP T where (T.QUARTER = I_VARIETY or i_variety is null)
                 group by rollup(T.BRANCHID, T.QUARTER) 
                 --order by T.BRANCHID, 20160125
                 order by decode(I_USERBR,'01000000',
                             (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = T.BRANCHID),
                             T.BRANCHID), 
                 T.QUARTER) TT where 
                 (TT.QUARTER is null and TT.BRANCH is null) or TT.QUARTER is not null
          ) select * from (select /*rs.*,*/rs.total, rs.QUARTER,rs.UPLIMIT,rs.UPLIMITINC,rs.BUYCNT,rs.BUYCALAMT,rs.SELLCNT,rs.SELLCALAMT,rs.TRANSTOLAMT,rs.QUARTEREVA,rs.UPLIMITINCAMT, rownum row_num from rs)
                    where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;
      --  end if;
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败' || SQLCODE || ' ' || SQLERRM;
         RETURN;
   END;
   
  --限额计价情况汇总
  PROCEDURE PROC_LIMPRICE_RPT_GETALLDATA(I_YEAR     IN VARCHAR2, --交易年份
                              I_BR_ID    IN VARCHAR2, --交易机构
                              I_VARIETY   IN VARCHAR2, --交易品种
                              I_USERBR IN VARCHAR2,
                              O_RETCODE  OUT VARCHAR2,
                              O_totalNum   OUT number,
                              O_RETLIST  OUT REFCUR,
                              O_RETMSG OUT VARCHAR2) IS
   
   V_PRM_UPLIMINC            varchar2(20); --限额增计倍数 参数表
   V_PRM_CAPCOST             varchar2(20); --资本成本率
   v_br_level                ctp_branch.branch_level%type;
   v_usrbr_level             ctp_branch.branch_level%type;
   v_level                   ctp_branch.branch_level%type;
   v_br_id                   ctp_branch.id%type;
   v_bvariety                 varchar(2);
   v_evariety                 varchar(2);
   BEGIN
      O_totalNum := 0;
      O_RETCODE := 0;
      
      SELECT nvl(max(T.PAR_COEF), 0.1) into V_PRM_CAPCOST
       FROM PRM_XSXJ1 T
       WHERE T.END_DATE = '99991231';
      
      SELECT nvl(max(T.PAR_COEF), 1) into V_PRM_UPLIMINC
       FROM PRM_XSXJ2 T
       WHERE T.END_DATE = '99991231';
       
      select max(b.branch_level) into v_br_level from ctp_branch b where b.id = I_BR_ID;
      select max(b.branch_level) into v_usrbr_level from ctp_branch b where b.id = I_USERBR;
      
      if I_BR_ID is null then
        v_level := v_usrbr_level + 1;
        v_br_id := I_USERBR;
      elsif I_USERBR = I_BR_ID then 
        v_level := v_usrbr_level;
        v_br_id := I_BR_ID; 
      else 
        v_level := v_br_level;
        v_br_id := I_BR_ID; 
      end if;
      
      if i_variety is null then
        v_bvariety := 1;
        v_evariety := 4;
      else 
        v_bvariety := I_VARIETY;
        v_evariety := I_VARIETY;
      end if;
      
      --实际限额
      delete CAP_TRANSLIMIT_STAT_TMP;
      --总行选择本级行则导出为空
      if I_USERBR = I_BR_ID and I_BR_ID = '01000000'then
        v_bvariety := 5;
      end if;
      FOR i_v IN v_bvariety .. v_evariety LOOP
      insert into CAP_TRANSLIMIT_STAT_TMP (BRANCHID, YEAR, QUARTER) 
            SELECT B.ID,
                    I_YEAR,
                    i_v
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level
               and B.id not in ('01010000','01010011','01020000','01770000',
                            '01780000','45000000','46990000')
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
            union all
              SELECT (ZONE_NO || BR_NO) ID,
                    I_YEAR,
                    i_v
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231';
              
        merge into CAP_TRANSLIMIT_STAT_TMP A using (
        select A.BRID,
               I_YEAR c_year,
               i_v c_quar,      
               (SUM(LIM) + SUM(B.TB) - SUM(B.TS)) RLIM
              FROM (SELECT L.LIMIT_BRANCH BRID,
                           L.LIMIT_INIT INITLIM,
                           L.LIMIT_MIN MINLIM,
                           (CASE
                             WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                              L.LIMIT_INIT
                             ELSE
                              L.LIMIT_MIN
                           END) LIM
                      FROM CAP_TRANS_LIMIT L
                     WHERE L.LIMIT_YEAR = I_YEAR
                       AND L.LIMIT_TYPE = i_v
                       AND L.CREATE_BRANCH = I_USERBR
                       AND L.LIMIT_BRANCH in (
                         SELECT B.id FROM CTP_BRANCH B
                          WHERE B.BRANCH_LEVEL = v_level
                           START WITH B.ID = v_br_id
                            CONNECT BY B.PARENT_ID = PRIOR ID 
                            union all
                            SELECT (ZONE_NO || BR_NO) ID
                                       FROM PRM_IRA_ORGAN
                                      WHERE BANK_FLAG = '3'
                                        AND IS_SALES = '1'
                                        and I_BR_ID is null
                                        and v_usrbr_level = 1
                                        and end_date = '99991231')
                       ) A,
                   (SELECT A.TRANS_INITIATE BRID,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '0', A.TRANS_COUNT, 0)), 0) TS,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '1', A.TRANS_COUNT, 0)), 0) TB
                      FROM CAP_TRANS_APPLY A
                     WHERE A.TRANS_YEAR = I_YEAR
                       AND A.TRANS_VARIETY <= i_v
                       AND A.TRANS_VARIETY = i_v
                       AND A.trans_accept_branch = I_USERBR  
                       AND A.TRANS_STATUS in ('2','3')
                       AND A.TRANS_INITIATE in (
                         SELECT B.id FROM CTP_BRANCH B
                           WHERE B.BRANCH_LEVEL = v_level
                           START WITH B.ID = v_br_id
                            CONNECT BY B.PARENT_ID = PRIOR ID 
                union all
                SELECT (ZONE_NO || BR_NO) ID
                           FROM PRM_IRA_ORGAN
                          WHERE BANK_FLAG = '3'
                            AND IS_SALES = '1'
                            and I_BR_ID is null
                            and v_usrbr_level = 1
                            and end_date = '99991231')
                     GROUP BY A.TRANS_INITIATE) B
             WHERE A.BRID = B.BRID
             GROUP BY ROLLUP(A.BRID) ) T 
              on (T.BRID = A.BRANCHID and T.c_year = A.YEAR and T.c_quar = A.QUARTER)
              when matched then
                update set REALLIMT = T.RLIM;
         --超限额度 实际增量-实际限额
         merge into CAP_TRANSLIMIT_STAT_TMP T using (SELECT I.INC_BRANCH, I.INC_TYPE, I.INC_COUNT
                FROM CAP_REAL_INCREMENT I
               WHERE I.INC_YEAR = I_YEAR
                 AND I.INC_TYPE = i_v
                 and I.CREATE_BRANCH = I_USERBR
                 and I.INC_BRANCH in  (SELECT B.ID
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
              union all
              SELECT (ZONE_NO || BR_NO) ID
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231') ) C on (T.BRANCHID = C.INC_BRANCH and T.QUARTER = C.INC_TYPE)
          when matched then
            update set T.REALINC = C.INC_COUNT,
                       T.UPLIMIT = (case when C.INC_COUNT - T.REALLIMT < 0 then 0 else C.INC_COUNT - T.REALLIMT end);  
        
       --超限额增计     
       update CAP_TRANSLIMIT_STAT_TMP t set t.uplimitinc = t.uplimit * V_PRM_UPLIMINC;
     
       --买入额度	买入计价	卖出额度	卖出计价 影响EVA(年化)
       --影响EVA(年化）= ∑卖出额度*卖出价格*资本成本率*（买入当期至月末月份数/12）-∑买入额度*买入价格*资本成本率*（买入当期至月末月份数/12）
       merge into CAP_TRANSLIMIT_STAT_TMP T using( select A.TRANS_INITIATE, A.TRANS_VARIETY,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0)) BUYCNT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0)) SELLCNT,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price) BUYCALAMT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price) SELLCALAMT
            FROM CAP_TRANS_APPLY A
              WHERE  A.TRANS_VARIETY = i_v
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS IN ('2', '3')
            and A.TRANS_INITIATE  IN
             (SELECT B.ID
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = v_level
               START WITH B.ID = v_br_id
              CONNECT BY B.PARENT_ID = PRIOR ID
              union all
              SELECT (ZONE_NO || BR_NO) ID
                         FROM PRM_IRA_ORGAN
                        WHERE BANK_FLAG = '3'
                          AND IS_SALES = '1'
                          and I_BR_ID is null
                          and v_usrbr_level = 1
                          and end_date = '99991231'
                          ) group by TRANS_INITIATE, A.TRANS_VARIETY) V 
              on(T.BRANCHID = V.trans_initiate and T.QUARTER = V.TRANS_VARIETY)
              
             when matched then
               update set T.BUYCNT = V.BUYCNT,
                          T.SELLCNT = V.SELLCNT,
                          T.BUYCALAMT = V.BUYCALAMT,
                          T.SELLCALAMT = V.SELLCALAMT;
        --保底额度 初始额度 
        merge into CAP_TRANSLIMIT_STAT_TMP T using( select L.LIMIT_BRANCH, L.LIMIT_TYPE,
            L.LIMIT_INIT,
            L.LIMIT_MIN
            FROM CAP_TRANS_LIMIT L
              WHERE  L.LIMIT_TYPE = i_v
            AND L.LIMIT_YEAR = I_YEAR
       --     and L.LIMIT_BRANCH = I_BR_ID
            and L.CREATE_BRANCH = I_USERBR) V 
              on(T.BRANCHID = V.LIMIT_BRANCH and T.QUARTER = V.LIMIT_TYPE)            
             when matched then
               update set T.LIMIT_MIN = V.LIMIT_MIN,
                          T.LIMIT_INIT = V.LIMIT_INIT;
        
       --交易计价小计    买入计价-卖出计价               
       update CAP_TRANSLIMIT_STAT_TMP t set t.TRANSTOLAMT = func_get_buyselltol(t.branchid, I_USERBR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt);
 
       --买入计价 卖出计价 影响EVA(年化）
       update CAP_TRANSLIMIT_STAT_TMP t 
       set t.quartereva = func_get_QUARTEREVA(t.branchid, I_USERBR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt,V_PRM_CAPCOST );
                       
        --超限额增计与交易计价小计
        update CAP_TRANSLIMIT_STAT_TMP t set t.UPLIMITINCAMT = t.uplimitinc + t.transtolamt;
        
        end loop;
        --输出统计信息
        select decode(count(1), 0, 0, count(1) + 1) into O_totalNum from CAP_TRANSLIMIT_STAT_TMP T where (T.QUARTER = I_VARIETY or i_variety is null);
        
        OPEN O_RETLIST for with rs as(
          select nvl(TT.BRANCH, '合计') total,
                 decode(TT.QUARTER, '1', '一季度',2,'上半年', 3,'前三季度', 4, '全年' ) QUARTER,
                 TT.UPLIMIT,
                 TT.UPLIMITINC,
                 TT.BUYCNT,
                 TT.BUYCALAMT,
                 TT.SELLCNT,
                 TT.SELLCALAMT,
                 TT.TRANSTOLAMT,
                 TT.QUARTEREVA,
                 TT.UPLIMITINCAMT
          from (
               select func_get_branchname(T.BRANCHID) BRANCH,
                      T.QUARTER,
                      sum(T.UPLIMIT) UPLIMIT,
                      sum(T.UPLIMITINC) UPLIMITINC,
                      sum(T.BUYCNT) BUYCNT,
                      sum(T.BUYCALAMT) BUYCALAMT,
                      sum(T.SELLCNT) SELLCNT,
                      sum(T.SELLCALAMT) SELLCALAMT,
                      sum(T.TRANSTOLAMT) TRANSTOLAMT,
                      sum(T.QUARTEREVA) QUARTEREVA,
                      sum(T.UPLIMITINCAMT) UPLIMITINCAMT
                 from CAP_TRANSLIMIT_STAT_TMP T where (T.QUARTER = I_VARIETY or i_variety is null) 
                 group by rollup(T.BRANCHID, T.QUARTER) 
                 --order by T.BRANCHID,
                 order by decode(I_USERBR,'01000000',
                             (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = T.BRANCHID),
                             T.BRANCHID), 
                  T.QUARTER) TT where 
                 (TT.QUARTER is null and TT.BRANCH is null) or TT.QUARTER is not null
          ) select * from (select /*rs.**/rs.total, rs.QUARTER,rs.UPLIMIT,rs.UPLIMITINC,rs.BUYCNT,rs.BUYCALAMT,rs.SELLCNT,rs.SELLCALAMT,rs.TRANSTOLAMT,rs.QUARTEREVA,rs.UPLIMITINCAMT  from rs);
      --  end if;

      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
   
  --单机构限额计价情况
  PROCEDURE PROC_LIMITPRICE_DETAIL(I_YEAR     IN VARCHAR2, --交易年份
                             I_BR_ID    IN VARCHAR2, --交易机构
                             I_VARIETY   IN VARCHAR2, --交易品种
                             I_RCV_BR    IN VARCHAR2, --交易接收机构
                             O_RETCODE  OUT VARCHAR2,
                             O_RETLIST  OUT REFCUR,
                             O_RETMSG OUT VARCHAR2) IS
   V_PRM_UPLIMINC            varchar2(20); --限额增计倍数 参数表
   V_PRM_CAPCOST             varchar2(20); --资本成本率
   v_br_level             ctp_branch.branch_level%type;
   BEGIN
     
      SELECT nvl(max(T.PAR_COEF), 0.1) into V_PRM_CAPCOST
       FROM PRM_XSXJ1 T
       WHERE T.END_DATE = '99991231';
      
      SELECT nvl(max(T.PAR_COEF), 1) into V_PRM_UPLIMINC
       FROM PRM_XSXJ2 T
       WHERE T.END_DATE = '99991231';
      
      select max(branch_level) into v_br_level from ctp_branch b where b.id = I_BR_ID;
      --实际限额
      delete CAP_TRANSLIMIT_STAT_TMP;
      
      FOR i IN 1 .. I_VARIETY LOOP
        insert into CAP_TRANSLIMIT_STAT_TMP (BRANCHID, YEAR, QUARTER)  values (I_BR_ID, I_YEAR, i);
            
        merge into CAP_TRANSLIMIT_STAT_TMP A using (
       select A.BRID,
               I_YEAR c_year,
               i c_quar,      
               (SUM(LIM) + SUM(B.TB) - SUM(B.TS)) RLIM
              FROM (SELECT L.LIMIT_BRANCH BRID,
                           L.LIMIT_INIT INITLIM,
                           L.LIMIT_MIN MINLIM,
                           (CASE
                             WHEN L.LIMIT_INIT > L.LIMIT_MIN THEN
                              L.LIMIT_INIT
                             ELSE
                              L.LIMIT_MIN
                           END) LIM
                      FROM CAP_TRANS_LIMIT L
                     WHERE L.LIMIT_YEAR = I_YEAR
                       AND L.LIMIT_TYPE = i
                       AND L.CREATE_BRANCH = I_RCV_BR
                       AND L.LIMIT_BRANCH = I_BR_ID
                       ) A,
                   (SELECT A.TRANS_INITIATE BRID,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '0', A.TRANS_COUNT, 0)), 0) TS,
                           NVL(SUM(DECODE(A.TRANS_TYPE, '1', A.TRANS_COUNT, 0)), 0) TB
                      FROM CAP_TRANS_APPLY A
                     WHERE A.TRANS_YEAR = I_YEAR
                       AND A.TRANS_VARIETY <= i
                       AND A.trans_accept_branch = I_RCV_BR  
                       AND A.TRANS_STATUS in ('2', '3')
                       AND A.TRANS_INITIATE = I_BR_ID
                     GROUP BY A.TRANS_INITIATE) B
             WHERE A.BRID = B.BRID
             GROUP BY ROLLUP(A.BRID) ) T 
              on (T.BRID = A.BRANCHID and T.c_year = A.YEAR and T.c_quar = A.QUARTER)
              when matched then
                update set REALLIMT = T.RLIM;
         --超限额度 实际增量-实际限额
         merge into CAP_TRANSLIMIT_STAT_TMP T using (SELECT I.INC_BRANCH, I.INC_TYPE, I.INC_COUNT
                FROM CAP_REAL_INCREMENT I
               WHERE I.INC_YEAR = I_YEAR
                 AND I.INC_TYPE = i
                 and I.INC_BRANCH = I_BR_ID
                 and I.CREATE_BRANCH = I_RCV_BR ) C on (T.BRANCHID = C.INC_BRANCH and T.QUARTER = C.INC_TYPE)
          when matched then
            update set T.REALINC = C.INC_COUNT,
                       T.UPLIMIT = (case when C.INC_COUNT - T.REALLIMT < 0 then 0 else C.INC_COUNT - T.REALLIMT end);
                       
       --超限额增计     
       update CAP_TRANSLIMIT_STAT_TMP t set t.uplimitinc = t.uplimit * V_PRM_UPLIMINC;

       --买入额度	买入计价	卖出额度	卖出计价 影响EVA(年化)
       --影响EVA(年化）= ∑卖出额度*卖出价格*资本成本率*（买入当期至月末月份数/12）-∑买入额度*买入价格*资本成本率*（买入当期至月末月份数/12）
       merge into CAP_TRANSLIMIT_STAT_TMP T using( select A.TRANS_INITIATE, A.TRANS_VARIETY,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0)) BUYCNT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0)) SELLCNT,
            sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price) BUYCALAMT,
            sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price) SELLCALAMT/*,
            (sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price) 
               - sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price)) TRANSTOLAMT,
            sum(case when A.TRANS_QUARTER = 1 
                then decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 12/12 -
                     decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 12/12
                when A.TRANS_QUARTER = 2 
                then decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 9/12 -
                     decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 9/12
                when A.TRANS_QUARTER = 3 
                then decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 6/12 -
                     decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 6/12 
                when A.TRANS_QUARTER = 4 
                then decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 3/12 -
                     decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price * V_PRM_CAPCOST * 3/12
                end
            ) QUARTEREVA*/
            FROM CAP_TRANS_APPLY A
              WHERE  A.TRANS_VARIETY = i
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS IN ('2', '3')
            and A.TRANS_INITIATE = I_BR_ID
            and A.TRANS_ACCEPT_BRANCH = I_RCV_BR
             group by TRANS_INITIATE, A.TRANS_VARIETY) V 
              on(T.BRANCHID = V.trans_initiate and T.QUARTER = V.TRANS_VARIETY)            
             when matched then
               update set T.BUYCNT = V.BUYCNT,
                          T.SELLCNT = V.SELLCNT,
                          T.BUYCALAMT = V.BUYCALAMT,
                          T.SELLCALAMT = V.SELLCALAMT;
        --保底额度 初始额度 
        merge into CAP_TRANSLIMIT_STAT_TMP T using( select L.LIMIT_BRANCH, L.LIMIT_TYPE,
            L.LIMIT_INIT,
            L.LIMIT_MIN
            FROM CAP_TRANS_LIMIT L
              WHERE  L.LIMIT_TYPE = i
            AND L.LIMIT_YEAR = I_YEAR
           -- and L.LIMIT_BRANCH = I_BR_ID
            and L.CREATE_BRANCH = I_RCV_BR) V 
              on(T.BRANCHID = V.LIMIT_BRANCH and T.QUARTER = V.LIMIT_TYPE)            
             when matched then
               update set T.LIMIT_MIN = V.LIMIT_MIN,
                          T.LIMIT_INIT = V.LIMIT_INIT;
        
        
       --交易计价小计    买入计价-卖出计价               
       update CAP_TRANSLIMIT_STAT_TMP t set t.TRANSTOLAMT = func_get_buyselltol(t.branchid, I_RCV_BR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt);
        
        --买入计价 卖出计价 影响EVA(年化）
       update CAP_TRANSLIMIT_STAT_TMP t set t.quartereva = func_get_QUARTEREVA(t.branchid, I_RCV_BR, t.year, t.quarter, t.limit_min, t.limit_init, t.buycnt, t.sellcnt,V_PRM_CAPCOST );

       --超限额增计与交易计价小计
        update CAP_TRANSLIMIT_STAT_TMP t set t.UPLIMITINCAMT = t.uplimitinc + t.transtolamt;
        
       end loop;

        --输出统计信息

        OPEN O_RETLIST for with rs as(
         SELECT TT.REALLIMT,
                TT.REALINC,
                 TT.UPLIMITINC,
                  TT.BUYCNT,
                  TT.BUYCALAMT,
                  TT.SELLCNT,
                  TT.SELLCALAMT,
                  TT.TRANSTOLAMT,
                  TT.QUARTEREVA,
                  TT.UPLIMITINCAMT
             FROM CAP_TRANSLIMIT_STAT_TMP TT
            WHERE TT.QUARTER = I_VARIETY
              AND TT.BRANCHID = I_BR_ID
           UNION ALL
           SELECT sum(TT.REALLIMT),
                  sum(TT.REALINC),
                  sum(TT.UPLIMITINC),
                  SUM(TT.BUYCNT),
                  SUM(TT.BUYCALAMT),
                  SUM(TT.SELLCNT),
                  SUM(TT.SELLCALAMT),
                  SUM(TT.TRANSTOLAMT),
                  SUM(TT.QUARTEREVA),
                  sum(TT.UPLIMITINCAMT)
             FROM CAP_TRANSLIMIT_STAT_TMP TT
            WHERE TT.QUARTER <= I_VARIETY
            GROUP BY TT.BRANCHID
          ) select * from (select /*rs.*,*/rs.REALLIMT,rs.REALINC,rs.UPLIMITINC,rs.BUYCNT,rs.BUYCALAMT,rs.SELLCNT,rs.SELLCALAMT,rs.TRANSTOLAMT,rs.QUARTEREVA,rs.UPLIMITINCAMT, rownum row_num from rs);
        
      O_RETCODE := '0';
      O_RETMSG := '获取统计数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         O_RETCODE := '1';
         O_RETMSG := '获取统计数据失败';
         RETURN;
   END;
  
  FUNCTION func_get_buyselltol(i_br_id        IN VARCHAR2, --用户
                            i_rcvbr_id     IN VARCHAR2,
                            i_year         in varchar2,
                            i_var          in varchar2,
                            i_limit_min    in varchar2,
                            i_limit_init   in varchar2,
                            i_buycnt      in varchar2,
                            i_sellcnt      in varchar2) RETURN number IS
  v_val                               number(22,2);                                   
  BEGIN
    v_val := 0;
    
    --情景模拟：A分行三季度保底限额为10亿元，初始限额为8亿元，两者差额为2亿元，限额卖出价格为0.3。由于保底限额＞初始限额，A分行启用保底限额作为三季度限额。
    --①A分行向总行出售限额2亿元，出售数量未超过保底限额与初始限额的差额，因此总行不予计价；
    --②A分行向总行出售限额3亿元，总行对超出差额部分的1亿元进行考核计价，即扣减考核口径经济资本0.3亿元（1亿元x0.3=0.3亿元）。
    if i_limit_min - i_limit_init > 0 and i_sellcnt - i_buycnt > 0  then --启动保底限额
      if (i_sellcnt - i_buycnt) > (i_limit_min - i_limit_init) then
        
      select nvl(t.trans_price * (i_sellcnt - i_buycnt - (i_limit_min - i_limit_init)), 0) into v_val from (
         select a.trans_price, row_number() over (order by a.trans_time desc ) rn from cap_trans_apply a WHERE  A.TRANS_VARIETY = i_var
            AND A.TRANS_YEAR = I_YEAR
            and A.Trans_Type = 0
            AND A.TRANS_STATUS IN ('2', '3')
            and A.TRANS_INITIATE = i_br_id
            and A.TRANS_ACCEPT_BRANCH = i_rcvbr_id ) t where t.rn = 1;
      else 
         v_val := 0;
      end if;   
    else
      select 
       nvl(sum(decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price) 
               - sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price), 0) into v_val
       from cap_trans_apply a WHERE  A.TRANS_VARIETY = i_var
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS in ('2', '3')
            and A.TRANS_INITIATE = i_br_id
            and A.TRANS_ACCEPT_BRANCH = i_rcvbr_id;
    end if;
    return v_val;
  end;
  
    FUNCTION func_get_QUARTEREVA(i_br_id        IN VARCHAR2, 
                                i_rcvbr_id     IN VARCHAR2,
                                i_year         in varchar2,
                                i_var          in varchar2,
                                i_limit_min    in varchar2,
                                i_limit_init   in varchar2,
                                i_buycnt      in varchar2,
                                i_sellcnt      in varchar2,
                                i_prmcost      in varchar2
                            ) RETURN number IS
  v_val                               number(22,2);  
  v_retmsg                            varchar2(1000);                                 
  BEGIN
    v_val := 0;
    
    --情景模拟：A分行三季度保底限额为10亿元，初始限额为8亿元，两者差额为2亿元，限额卖出价格为0.3。由于保底限额＞初始限额，A分行启用保底限额作为三季度限额。
    --①A分行向总行出售限额2亿元，出售数量未超过保底限额与初始限额的差额，因此总行不予计价；
    --②A分行向总行出售限额3亿元，总行对超出差额部分的1亿元进行考核计价，即扣减考核口径经济资本0.3亿元（1亿元x0.3=0.3亿元）。
    if i_limit_min - i_limit_init > 0 and i_sellcnt - i_buycnt > 0  then --启动保底限额
      if (i_sellcnt - i_buycnt) > (i_limit_min - i_limit_init) then
        
      select t.trans_price * (i_sellcnt - i_buycnt - (i_limit_min - i_limit_init)) * i_prmcost * (12- (i_var - 1)* 3)/12 into v_val from (
         select a.trans_price, row_number() over (order by a.trans_time desc ) rn from cap_trans_apply a 
         WHERE  A.TRANS_VARIETY = i_var
            AND A.TRANS_YEAR = I_YEAR
            and A.Trans_Type = 0
            AND A.TRANS_STATUS IN ('2', '3')
            and A.TRANS_INITIATE = i_br_id
            and A.TRANS_ACCEPT_BRANCH = i_rcvbr_id ) t where t.rn = 1;
      else 
         v_val := 0;
      end if;   
    else
      select 
       nvl(sum(decode(A.TRANS_TYPE, 0, A.TRANS_COUNT, 0) * A.Trans_Price * i_prmcost * (12- (i_var - 1)* 3)/12 -
       decode(A.TRANS_TYPE, 1, A.TRANS_COUNT, 0) * A.Trans_Price * i_prmcost * (12- (i_var - 1)* 3)/12), 0)
        into v_val
       from cap_trans_apply a WHERE  A.TRANS_VARIETY = i_var
            AND A.TRANS_YEAR = I_YEAR
            AND A.TRANS_STATUS IN ('2', '3')
            and A.TRANS_INITIATE = i_br_id
            and A.TRANS_ACCEPT_BRANCH = i_rcvbr_id;
    end if;
    return v_val;
    EXCEPTION
      WHEN OTHERS
      THEN
           return 0;
  end;
  
   --获取交易结束时间
  FUNCTION func_get_transendtime( i_trans_id      IN VARCHAR2 --交易编号
                                  ) RETURN varchar2 is 
  
  v_endtime                       CAP_TRANS_OFFER.trans_end_time%type;--交易结束时间 
         
  BEGIN
    
    SELECT A.TRANS_END_TIME into v_endtime      
      FROM CAP_TRANS_OFFER A, CAP_TRANS_APPLY P
     WHERE A.TRANS_YEAR = P.TRANS_YEAR
       AND A.TRANS_VARIETIES = P.TRANS_VARIETY
       AND A.TRANS_BRANCH = P.TRANS_INITIATE
       AND A.TRANS_QUARTER = P.TRANS_QUARTER
       and a.trans_offer_seq = p.trans_offer_seq
       AND A.TRANS_LEVEL =
           (SELECT MAX(BRANCH_LEVEL)
                 FROM CTP_BRANCH
                WHERE ID = P.TRANS_ACCEPT_BRANCH)
       AND P.TRANS_ID = i_trans_id;
           
    return v_endtime;
    
    EXCEPTION
      WHEN OTHERS
      THEN
           return '';
  END;
  
   --20160120 add by zhaoxm 获取本级行审批通过时间
  FUNCTION func_get_passtime( i_trans_id      IN VARCHAR2, --交易编号
                              i_branch_id     IN VARCHAR2  --交易机构          
                                  ) RETURN varchar2 is 
  
  v_passtime                      CAP_TRANS_OFFER.trans_end_time%type;--交易结束时间   
  v_apprType                      CAP_APPROVE_TYPE.appr_type%type;--交易审批层级  
  v_accept_branch                 CAP_TRANS_APPLY.TRANS_ACCEPT_BRANCH%type;  
  v_count     number; 
  BEGIN
    select t.trans_accept_branch into v_accept_branch from CAP_TRANS_APPLY t where t.trans_id = i_trans_id;
    
    --查询审批层级 add20160217
    SELECT count(*) INTO V_COUNT
      FROM CAP_APPROVE_TYPE T
     WHERE T.BRANCH_ID = v_accept_branch
            AND T.END_DATE = '99991231';
           
    if V_COUNT > 0 then
        SELECT t.appr_type INTO v_apprType
          FROM CAP_APPROVE_TYPE T
         WHERE T.BRANCH_ID = v_accept_branch
                AND T.END_DATE = '99991231'; 
    else
        v_apprType :='2';
    end if ; 
    -----------------------------    
    --交易日志表里操作类型为1-审批确认（2级审批）或5-审批核定（3级审批） 的交易的审批通过时间          
    SELECT to_char(t.oper_time,'yyyymmdd') into v_passtime      
      FROM cap_trans_log t
     WHERE t.TRANS_ID = i_trans_id
      and ((v_apprType = '2' and t.oper_type = '1')
          or (v_apprType = '3' and t.oper_type = '5')); 
          
    return v_passtime;
    
    EXCEPTION
      WHEN OTHERS
      THEN
           return '';
  END;
    
END PCKG_LIMIT_TRADE_RPT;
