CREATE OR REPLACE package body PCKG_LOG is
  /*********************************************************************/
  --存储过程名称： RECORD_LOG
  --作者：         wanghb01
  --时间：         2014-7-25 10:00:05
  --功能：         记录应用日志
  --版本号：       1.0
  /*********************************************************************/
  PROCEDURE RECORD_LOG(i_op_type    IN VARCHAR2, --日志类型
                       i_userId     IN VARCHAR2, --用户ID
                       i_op_time    IN TIMESTAMP, --操作时间
                       i_op_target  IN VARCHAR2, --操作目标
                       i_extra_info IN VARCHAR2 --扩展信息
                       ) IS
    v_retcode varchar2(10);
    v_msg     varchar2(2000);
  BEGIN
    RECORD_LOG_F(i_op_type,
                 i_userId,
                 i_op_time,
                 i_op_target,
                 i_extra_info,
                 v_retcode,
                 v_msg);
  END;
  /*********************************************************************/
  --存储过程名称： RECORD_LOG
  --作者：         wanghb01
  --时间：         2014-7-25 10:00:05
  --功能：         记录应用日志
  --版本号：       1.0
  /*********************************************************************/
  PROCEDURE RECORD_LOG_F(i_op_type    IN VARCHAR2, --日志类型
                         i_userId     IN VARCHAR2, --用户ID
                         i_op_time    IN TIMESTAMP, --操作时间
                         i_op_target  IN VARCHAR2, --操作目标
                         i_extra_info IN VARCHAR2, --扩展信息
                         o_retcode    OUT VARCHAR2, --0  成功  1 失败
                         o_msg        OUT VARCHAR2) IS
    v_proc_name  L_GETDATA_CALL.PROC_NAME%TYPE;
    v_log_level  L_GETDATA_CALL.LOG_LEVEL%TYPE;
    v_begin_time L_GETDATA_CALL.BEGIN_TIME%TYPE;
    v_end_time   L_GETDATA_CALL.END_TIME%TYPE;
    v_err_code   L_GETDATA_ERR.ERR_CODE%TYPE;
    v_err_txt    L_GETDATA_ERR.ERR_TXT%TYPE;
    v_step_no    L_GETDATA_ERR.STEP_NO%TYPE;
    v_sql_txt    L_GETDATA_ERR.SQL_TXT%TYPE;
  BEGIN
    o_retcode    := '0';
    v_proc_name  := 'RECORD_LOG_F';
    v_step_no    := '1';
    v_log_level  := '1';
    v_begin_time := to_char(SYSDATE, 'yyyy-mm-dd hh24:mi:ss');
  
    insert into LOG_APP_OPERATION
      (op_type, user_id, op_time, op_target, extra_info)
      select i_op_type, i_userId, i_op_time, i_op_target, i_extra_info
        from dual;
  
    v_end_time := to_char(SYSDATE, 'yyyy-mm-dd hh24:mi:ss');
    PACK_GETDATA_LOG.PR_LOG_WRITE(v_proc_name,
                                  v_log_level,
                                  v_begin_time,
                                  v_end_time,
                                  'SUCCESS',
                                  v_step_no,
                                  v_sql_txt);
  
  EXCEPTION
    WHEN OTHERS THEN
      o_retcode  := '1';
      o_msg      := o_msg || '记录日志失败:' || SQLCODE || ' ' || SQLERRM;
      v_end_time := to_char(SYSDATE, 'yyyy-mm-dd hh24:mi:ss');
      v_err_code := SQLCODE;
      v_err_txt  := SUBSTR(SQLERRM, 1, 4000);
      PACK_GETDATA_LOG.PR_LOG_WRITE(v_proc_name,
                                    v_log_level,
                                    v_begin_time,
                                    v_end_time,
                                    'FAILED',
                                    v_step_no,
                                    null,
                                    v_err_code,
                                    v_err_txt);
  END;

end PCKG_LOG;
