CREATE OR REPLACE package      PCKG_QUARTZ_UTIL is

  
  PROCEDURE PROC_LOG_ADD(
    i_EXECTOR  IN VARCHAR2,
    i_JOBNAME IN VARCHAR2,
    i_JOBGROUP IN VARCHAR2,
    i_TRIGGERNAME IN VARCHAR2,
    i_TRIGGERGROUP IN VARCHAR2,
    i_PREVIOUSFIREDTIME IN VARCHAR2,
    i_NEXTFIREDTIME IN VARCHAR2,
    i_ACTION IN VARCHAR2,
    i_MESSAGE IN VARCHAR2,
    o_retCode OUT VARCHAR2,
    o_retMsg OUT varchar2
    );
end PCKG_QUARTZ_UTIL;
//

CREATE OR REPLACE package body      PCKG_QUARTZ_UTIL is


  PROCEDURE PROC_LOG_ADD(
    i_EXECTOR  IN VARCHAR2,
    i_JOBNAME IN VARCHAR2,
    i_JOBGROUP IN VARCHAR2,
    i_TRIGGERNAME IN VARCHAR2,
    i_TRIGGERGROUP IN VARCHAR2,
    i_PREVIOUSFIREDTIME IN VARCHAR2,
    i_NEXTFIREDTIME IN VARCHAR2,
    i_ACTION IN VARCHAR2,
    i_MESSAGE IN VARCHAR2,
    o_retCode OUT VARCHAR2,
    o_retMsg OUT VARCHAR2
    ) IS

  BEGIN
    o_retCode := '0';
    insert into cpmg.CPMG_QRTZ_HISTORY
    (seq_no,EXECTOR,LOGDATE,DATATIME,JOBNAME,JOBGROUP,TRIGGERNAME,TRIGGERGROUP,
    PREVIOUSFIREDTIME,NEXTFIREDTIME,ACTION,MESSAGE)
    values
    (
           cpmg.SEQ_LOG_QUARTZ_NO.Nextval,
           i_EXECTOR,
           to_char(sysdate,'yyyymmdd'),
           to_char(sysdate,'hh24miss'),
           i_JOBNAME,
           i_JOBGROUP,
           i_TRIGGERNAME,
           i_TRIGGERGROUP,
           i_PREVIOUSFIREDTIME,
           i_NEXTFIREDTIME,
           i_ACTION,
           substr(i_MESSAGE,1,4000)    
    );
    commit;
    RETURN;
  EXCEPTION
    WHEN OTHERS THEN
    	rollback;
      o_retCode :=SQLCODE;
      o_retMsg := SQLERRM(SQLCODE);
      RETURN;
  END;
end PCKG_QUARTZ_UTIL;
