CREATE OR REPLACE PACKAGE      pkg_amc_serverenv_init AS

  TYPE ARRYTYPE IS TABLE OF VARCHAR2(2000);

  FUNCTION GETARRAY(TMPSTR IN VARCHAR2, PARAM IN VARCHAR2) RETURN ARRYTYPE;

  PROCEDURE prc_amc_serverenv_init( p_o_flag        OUT INTEGER,
                                   p_o_msg         OUT VARCHAR2);

END pkg_amc_serverenv_init;
//
CREATE OR REPLACE PACKAGE BODY      pkg_amc_serverenv_init AS

  FUNCTION GETARRAY(TMPSTR IN VARCHAR2, PARAM IN VARCHAR2) RETURN ARRYTYPE IS
      I       INTEGER;
      POS     INTEGER;
      K       INTEGER;
      V_COUNT INTEGER := 0;
      OBJDATA ARRYTYPE;
    BEGIN
      K       := 1;
      POS     := 1;
      OBJDATA := ARRYTYPE();
      I       := INSTR(TMPSTR, PARAM, POS);

      WHILE K <> 0 LOOP
        K       := INSTR(TMPSTR, PARAM, POS);
        POS     := K + LENGTH(PARAM);
        V_COUNT := V_COUNT + 1;
      END LOOP;

      IF I <= 0 THEN
        OBJDATA.EXTEND();
        OBJDATA(1) := TMPSTR;
        RETURN OBJDATA;
      END IF;

      POS := 1;

      FOR J IN 1 .. V_COUNT - 1 LOOP
        OBJDATA.EXTEND();
        I := INSTR(TMPSTR, PARAM, POS);
        OBJDATA(J) := SUBSTR(TMPSTR, POS, I - 1 - POS + 1);
        POS := I + LENGTH(PARAM);
      END LOOP;

      OBJDATA.EXTEND();
      OBJDATA(V_COUNT) := SUBSTR(TMPSTR, POS, LENGTH(TMPSTR) - POS + 1);
      RETURN OBJDATA;

    EXCEPTION
      WHEN OTHERS THEN
        RETURN NULL;
    END;

  /*******************************************************************************
   程序名：prc_amc_serverenv_init
   功能描述：初始化AMC的IP和port
   版本号：1.0
   作者：hejian
   时间：2020-03-25
  ******************************************************************************/
  PROCEDURE prc_amc_serverenv_init( p_o_flag        OUT INTEGER,
                                   p_o_msg         OUT VARCHAR2) AS

    --v_monitor_hostname    VARCHAR2(4000) := '$#{ENV_CPMG_MONITOR_HOSTNAME_LIST}';
    --v_webserver_ip        VARCHAR2(4000) := '$#{ENV_CAP_WEBSERVER_IP_LIST}';
    --v_server_port       	VARCHAR2(20) := '$#{ENV_CPMG_serverport}';
    v_monitor_hostname    VARCHAR2(4000) := 'CPMG_SERVER1,CPMG_SERVER2';
    v_webserver_ip        VARCHAR2(4000) := '84.33.46.47,84.33.46.48';
    v_server_port       	VARCHAR2(20) := '9080';
    v_hostname_array			pkg_amc_serverenv_init.arrytype;
    v_ip_array     				pkg_amc_serverenv_init.arrytype;
    channeltypes					int := 4;
    switchtypes           int := 2;
  BEGIN

    p_o_flag := 0;
    p_o_msg  := '初始化AMC的IP和port成功';

		v_hostname_array := cpmg.pkg_amc_serverenv_init.getarray(v_monitor_hostname, ',');
		v_ip_array			 := cpmg.pkg_amc_serverenv_init.getarray(v_webserver_ip, ',');

		if v_hostname_array.count=v_ip_array.count then

			delete from cpmg.ctp_mx_server_ip where 1=1;
			delete from cpmg.ctp_mx_server_port where 1=1;
			delete from cpmg.ctp_mx_monitor_flag where 1=1;

			FOR arr_index IN 1..v_hostname_array.count LOOP
				insert into cpmg.ctp_mx_server_ip(hostname,ip) values(v_hostname_array(arr_index),v_ip_array(arr_index));
				insert into cpmg.ctp_mx_server_port(hostname,port) values(v_hostname_array(arr_index),v_server_port);

        for switch_index in 1..switchtypes loop
          for chanel_index in 1..channeltypes loop
            insert into cpmg.ctp_mx_monitor_flag(HOSTNAME,SWITCHTYPE,CHANNELTYPE,ACTION)values(v_hostname_array(arr_index),switch_index,chanel_index,'1');
          end loop;
				end loop;

			END LOOP;
		else
			p_o_flag := 1;
    	p_o_msg  := '初始化AMC的IP和port失败，hostname和ip个数不匹配';
		end if;
    commit;

  EXCEPTION
    WHEN OTHERS THEN
    	rollback;
      p_o_flag := 1;
      p_o_msg  := '初始化AMC的IP和port失败' || SQLERRM;
  END prc_amc_serverenv_init;

END pkg_amc_serverenv_init;
