CREATE OR REPLACE PACKAGE      pkg_common_strutils AS

  TYPE ARRYTYPE IS TABLE OF VARCHAR2(2000);
  
  FUNCTION GETARRAY(TMPSTR IN VARCHAR2, PARAM IN VARCHAR2) RETURN ARRYTYPE;
                                   
END pkg_common_strutils;
//
CREATE OR REPLACE PACKAGE BODY      pkg_common_strutils AS


  FUNCTION GETARRAY(TMPSTR IN VARCHAR2, PARAM IN VARCHAR2) RETURN ARRYTYPE IS
      I       INTEGER;
      POS     INTEGER;
      K       INTEGER;
      V_COUNT INTEGER := 0;
      OBJDATA ARRYTYPE;
    BEGIN
      K       := 1;
      POS     := 1;
      OBJDATA := ARRYTYPE();
      I       := INSTR(TMPSTR, PARAM, POS);

      WHILE K <> 0 LOOP
        K       := INSTR(TMPSTR, PARAM, POS);
        POS     := K + LENGTH(PARAM);
        V_COUNT := V_COUNT + 1;
      END LOOP;

      IF I <= 0 THEN
        OBJDATA.EXTEND();
        OBJDATA(1) := TMPSTR;
        RETURN OBJDATA;
      END IF;

      POS := 1;

      FOR J IN 1 .. V_COUNT - 1 LOOP
        OBJDATA.EXTEND();
        I := INSTR(TMPSTR, PARAM, POS);
        OBJDATA(J) := SUBSTR(TMPSTR, POS, I - 1 - POS + 1);
        POS := I + LENGTH(PARAM);
      END LOOP;

      OBJDATA.EXTEND();
      OBJDATA(V_COUNT) := SUBSTR(TMPSTR, POS, LENGTH(TMPSTR) - POS + 1);
      RETURN OBJDATA;

    EXCEPTION
      WHEN OTHERS THEN
        RETURN NULL;
    END;
                  
END pkg_common_strutils;
//

create or replace function CTP_FUNC_BANKLEVEL2(ZONENO IN VARCHAR2,
                                               BRNO   IN VARCHAR2)
  RETURN VARCHAR2 IS
  ora_name   VARCHAR2(20) := null;
  P_ZONEBRNO VARCHAR2(10) := null;
BEGIN
  SELECT p.organ_name
    into ora_name
    FROM prm_ira_organ p
   where ((p.zone_no = zoneno and p.belong_bank_flag = '4' and
         p.bank_flag = '3')
      or (p.zone_no || p.br_no = zoneno || brno And
         p.belong_bank_flag = '4' and p.bank_flag = '2'))
         and p.end_date=to_char(to_date('99991231','YYYYMMDD'),'YYYYMMDD');
  return ora_name;
EXCEPTION
  WHEN OTHERS THEN
    select p.belong_zoneno || p.belong_brno
      into P_ZONEBRNO
      from prm_ira_organ p
     where p.zone_no || p.br_no = zoneno || brno
       And p.belong_bank_flag = '2'
       and p.bank_flag = '0'
       and p.end_date=to_char(to_date('99991231','YYYYMMDD'),'YYYYMMDD');
    select p.organ_name
      INTO ora_name
      FROM prm_ira_organ p
     where p.zone_no || p.br_no = P_ZONEBRNO
       and p.belong_bank_flag = '4'
       and p.bank_flag = '2'
        and p.end_date=to_char(to_date('99991231','YYYYMMDD'),'YYYYMMDD');
    return ora_name;
end;
