                         ta200011070,
                         ta200011005,
                         ta200011016,
                         ta200011034,
                         ta340362013,
                         ta200268004,
                         rzzd_fl,
                         product_id3,
                         product_name3,
                         xyvalue,
                         xyname,
                         dbdc_id,
                         dbdc_name,
                         dbfs_id,
                         dbfs_lb,
                         qxdc_id1,
                         qxdc_name1,
                         qxdc_id2,
                         qxdc_name2,
                         xs031,
                         xs034,
                         xs033,
                         xs032,
                         xs035,
                         xs036,
                         gjrz_xs,
                         jjzb_xs,
                         ytbbbl,
                         ytbbj,
                         dkamount,
                         A.ecost * B.USCVRATE *
                         c.daoshu ecost,
                         A.start_date,
                         A.end_date,
                         xs_product,
                         ywzl,
                         htsfsr,
                         rate_today,
                         cust_exe_rate,
                         pd,
                         lgd,
                         
                         ta490461016_cm,
                         ytbbj_cm,
                         
                         rate_base,
                         small_corp,
                         dubil_std_rate,
                         rate_chg_mode,
                         corp_name,
                         croup_name,
                         BNKRATE
                    FROM DW_MOD_FRDK A,
                         PRM_CURRENCY_RATE B,
                         (SELECT DISTINCT 1 /
                                          USCVRATE daoshu
                            FROM PRM_CURRENCY_RATE b1
                           WHERE b1.currency = '001') C
                   WHERE A.CURRTYPE <> '001'
                     AND A.CURRTYPE = B.CURRENCY
                     and A.start_date =
                         to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')) dw,
                 (select distinct org.ZONE_NO ||
                                  org.br_no zbid
                    from prm_ira_organ org
                   where org.start_date <=
                         to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                     and org.end_date >
                         to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                     and org.belong_zoneno ||
                         org.belong_brno =
                         i_branchid) AA
           where AA.zbid = dw.zoneno || dw.brno;
        o_flag := '0';
        o_msg  := '获取机构数据成功';
        RETURN;
      end if;
    end if;
  EXCEPTION
    WHEN OTHERS THEN
      o_flag := '1';
      o_msg  := '获取机构数据失败';
      RETURN;
  END;
  
  PROCEDURE do_exportpj(i_branchid IN VARCHAR2,
                        i_currency IN VARCHAR2,
                        i_date     IN VARCHAR2,
                        o_flag     OUT VARCHAR2,
                        o_msg      OUT VARCHAR2,
                        o_ret      OUT ref_cursor) IS
  BEGIN
    if substr(i_branchid, 3, 6) = '000000' then
      OPEN o_ret FOR
        SELECT ROWNUM,
               '''' || zoneno,
               '''' || actbrno,
               '''' || innerno,
               '''' || billno,
               '''' || subcode,
               billamt,
               billamt_cm,
               '''' || billtype,
               '''' || buytype,
               '''' || firsttype,
               '''' || drawerbank,
               '''' || holder,
               '''' || holdertype,
               '''' || creditlevel,
               '''' || managerno,
               '''' || levelfive,
               '''' || discountdate,
               '''' || realmaturity,
               '''' || retmaturity,
               capcost,
               intincome,
               '''' || product,
               '''' || qx,
               xspj1,
               xspj2,
               xspj3,
               xs,
               ec,
               ec_cm,
               '''' || start_date,
               '''' || end_date,
               '''' || bearer_name,
               '''' || croup_num,
               '''' || croup_name
          FROM (select *
                  from DW_MOD_PJTX
                 WHERE i_currency IN ('994', '001')
                   AND start_date =
                      to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')) dw
         where EXISTS
         (SELECT zone_no
                  FROM prm_ira_organ d
                 WHERE d.start_date <=
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                   and d.end_date >
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                   and d.belong_zoneno ||
                       d.belong_brno = i_branchid
                   AND d.zone_no = dw.zoneno);
      o_flag := '0';
      o_msg  := '获取机构数据成功';
      RETURN;
    elsif substr(i_branchid, 5, 4) = '0000' then
      OPEN o_ret FOR
        SELECT ROWNUM,
               '''' || zoneno,
               '''' || actbrno,
               '''' || innerno,
               '''' || billno,
               '''' || subcode,
               billamt,
               billamt_cm,
               '''' || billtype,
               '''' || buytype,
               '''' || firsttype,
               '''' || drawerbank,
               '''' || holder,
               '''' || holdertype,
               '''' || creditlevel,
               '''' || managerno,
               '''' || levelfive,
               '''' || discountdate,
               '''' || realmaturity,
               '''' || retmaturity,
               capcost,
               intincome,
               '''' || product,
               '''' || qx,
               xspj1,
               xspj2,
               xspj3,
               xs,
               ec,
               ec_cm,
               '''' || start_date,
               '''' || end_date,
               '''' || bearer_name,
               '''' || croup_num,
               '''' || croup_name
          FROM (select *
                  from DW_MOD_PJTX
                 WHERE i_currency IN ('994', '001')
                   AND start_date =
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')) dw
         where dw.ZONENO = substr(i_branchid, 1, 4);
      o_flag := '0';
      o_msg  := '获取机构数据成功';
      RETURN;
    else
      OPEN o_ret FOR
        SELECT ROWNUM,
               '''' || zoneno,
               '''' || actbrno,
               '''' || innerno,
               '''' || billno,
               '''' || subcode,
               billamt,
               billamt_cm,
               '''' || billtype,
               '''' || buytype,
               '''' || firsttype,
               '''' || drawerbank,
               '''' || holder,
               '''' || holdertype,
               '''' || creditlevel,
               '''' || managerno,
               '''' || levelfive,
               '''' || discountdate,
               '''' || realmaturity,
               '''' || retmaturity,
               capcost,
               intincome,
               '''' || product,
               '''' || qx,
               xspj1,
               xspj2,
               xspj3,
               xs,
               ec,
               ec_cm,
               '''' || start_date,
               '''' || end_date,
               '''' || bearer_name,
               '''' || croup_num,
               '''' || croup_name
          FROM (select *
                  from DW_MOD_PJTX
                 WHERE i_currency IN ('994', '001')
                   AND start_date =
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')) dw,
               (select distinct org.ZONE_NO ||
                                org.br_no zbid
                  from prm_ira_organ org
                 where org.start_date <=
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                   and org.end_date >
                       to_char(to_date(i_date,
                                                  'YYYYMMDD'),
                                 'YYYYMMDD')
                   and org.belong_zoneno ||
                       org.belong_brno = i_branchid) AA
         where AA.zbid = dw.zoneno || dw.actbrno;
      o_flag := '0';
      o_msg  := '获取机构数据成功';
      RETURN;
    end if;
  EXCEPTION
    WHEN OTHERS THEN
      o_flag := '1';
      o_msg  := '获取机构数据失败';
      RETURN;
  END;
  /*******************************************************************************
  --过程名称：      LOANDATAEXPORT
  --作者：          wangj
  --时间：          2019.7.30
  --使用目标表名称：DW_GCMS_ZTM280362，PRM_IRA_ORGAN
  --功能：          贷款承诺明细表导出
  --版本号：        1.0
  *******************************************************************************/
  PROCEDURE LOANDATAEXPORT(I_BRANCHID IN VARCHAR2,
                           I_CURRENCY IN VARCHAR2,
                           I_DATE     IN VARCHAR2,
                           I_IDENTY   IN VARCHAR2,
                           I_LEVEL    IN VARCHAR2,
                           O_FLAG     OUT VARCHAR2,
                           O_MSG      OUT VARCHAR2,
                           O_RET      OUT REF_CURSOR) IS
    O_LEVEL VARCHAR2(2) := NULL;
  BEGIN
    IF I_LEVEL = '1' THEN
      O_LEVEL := '5';
    ELSIF I_LEVEL = '2' THEN
      O_LEVEL := '4';
    ELSE
      SELECT
       O.BANK_FLAG
        INTO O_LEVEL
        FROM PRM_IRA_ORGAN O
       WHERE O.ZONE_NO = SUBSTR(I_BRANCHID, 1, 4)
         AND O.BR_NO = SUBSTR(I_BRANCHID, 5, 4)
         AND O.BELONG_BANK_FLAG = '4';
    END IF;
  
    IF I_IDENTY = '5' THEN
      OPEN O_RET FOR
        SELECT '''' || M.ORGANIZATION_ID,
               '''' || N.ORGAN_NAME,
               '''' || N.BELONG_ORG,
               '''' || M.CUST_ID,
               '''' || M.CUST_NAME,
               '''' || M.CONTRACT_ID,
               '''' || M.LOAN_KIND,
               '''' || M.BUSINESS_KIND,
               '''' || TO_CHAR(M.APPROVE_AMT / 100000000,
                               'fm999,999,999,999,999,990.0000'),
               '''' || TO_CHAR(M.PROMISS_AMT / 100000000,
                               'fm999,999,999,999,999,990.0000'),
               '''' || DECODE(M.CURRENCY,
                              '001',
                              '人民币',
                              '992',
                              '外币折美元',
                              '994',
                              '本外币合计'),
               '''' || M.INDUSTRY,
               '''' || M.SUBJECT,
               '''' || DECODE(M.PROMISS_FLAG,
                              1,
                              '可随时无条件撤销',
                              2,
                              '可有条件撤销',
                              3,
                              '不可撤销',
                              4,
                              '其他')
          FROM DW_GCMS_ZTM280362 M,
               (SELECT DISTINCT B.ZONE_NO, B.BR_NO, B.ORGAN_NAME,
                    CASE  WHEN ORG1.BANK_FLAG=4 THEN ORG1.ORGAN_NAME 
                          WHEN ORG2.BANK_FLAG=4 THEN ORG2.ORGAN_NAME 
                          WHEN ORG3.BANK_FLAG=4 THEN ORG3.ORGAN_NAME 
                          ELSE '未知'   END AS BELONG_ORG
                  FROM (SELECT A.ZONE_NO,
                               A.BR_NO,
                               A.BANK_FLAG,
                               A.ORGAN_NAME,
                               A.START_DATE,
                               A.END_DATE,
                               A.BELONG_ZONENO,A.BELONG_BRNO,A.BELONG_BANK_FLAG
                          FROM PRM_IRA_ORGAN A
                         START WITH A.ZONE_NO = SUBSTR(I_BRANCHID, 1, 4)
                                AND A.BR_NO = SUBSTR(I_BRANCHID, 5, 4)
                                AND A.BANK_FLAG = O_LEVEL
                        CONNECT BY NOCYCLE
                         PRIOR A.ZONE_NO = A.BELONG_ZONENO
                               AND PRIOR A.BR_NO = A.BELONG_BRNO
                               AND PRIOR A.BANK_FLAG = A.BELONG_BANK_FLAG) B
                 left join CPMG.PRM_IRA_ORGAN org1 on B.BELONG_ZONENO=org1.zone_no and B.BELONG_BRNO=org1.br_no and B.BELONG_BANK_FLAG = org1.bank_flag  AND org1.START_DATE <= I_DATE AND org1.END_DATE >= I_DATE 
                 left join CPMG.PRM_IRA_ORGAN org2 on org1.BELONG_ZONENO=org2.zone_no and org1.BELONG_BRNO=org2.br_no and org1.BELONG_BANK_FLAG = org2.bank_flag  AND org2.START_DATE <= I_DATE AND org2.END_DATE >= I_DATE 
                 left join CPMG.PRM_IRA_ORGAN org3 on org2.BELONG_ZONENO=org3.zone_no and org2.BELONG_BRNO=org3.br_no and org2.BELONG_BANK_FLAG = org3.bank_flag  AND org3.START_DATE <= I_DATE AND org3.END_DATE >= I_DATE 

                 WHERE B.ORGAN_NAME <> '未知机构'
                   AND B.BANK_FLAG = '0'
                   AND B.START_DATE <= I_DATE
                   AND B.END_DATE >= I_DATE) N
         WHERE M.ZONENO = N.ZONE_NO
           AND M.BRANCHNO = N.BR_NO
           AND M.DATA_DATE = I_DATE
           AND M.CURRENCY = I_CURRENCY
         ORDER BY N.ZONE_NO, N.BR_NO, M.PROMISS_FLAG;
    ELSE
      OPEN O_RET FOR
        SELECT '''' || M.ORGANIZATION_ID,
               '''' || N.ORGAN_NAME,
               '''' || N.BELONG_ORG,
               '''' || M.CUST_ID,
               '''' || M.CUST_NAME,
               '''' || M.CONTRACT_ID,
               '''' || M.LOAN_KIND,
               '''' || M.BUSINESS_KIND,
               '''' || TO_CHAR(M.APPROVE_AMT / 100000000,
                               'fm999,999,999,999,999,990.0000'),
               '''' || TO_CHAR(M.PROMISS_AMT / 100000000,
                               'fm999,999,999,999,999,990.0000'),
               '''' || DECODE(M.CURRENCY,
                              '001',
                              '人民币',
                              '992',
                              '外币折美元',
                              '994',
                              '本外币合计'),
               '''' || M.INDUSTRY,
               '''' || M.SUBJECT,
               '''' || DECODE(M.PROMISS_FLAG,
                              1,
                              '可随时无条件撤销',
                              2,
                              '可有条件撤销',
                              3,
                              '不可撤销',
                              4,
                              '其他')
          FROM DW_GCMS_ZTM280362 M,
               (SELECT DISTINCT B.ZONE_NO, B.BR_NO, B.ORGAN_NAME,
                    CASE  WHEN ORG1.BANK_FLAG=4 THEN ORG1.ORGAN_NAME 
                          WHEN ORG2.BANK_FLAG=4 THEN ORG2.ORGAN_NAME 
                          WHEN ORG3.BANK_FLAG=4 THEN ORG3.ORGAN_NAME 
                          ELSE '未知'   END AS BELONG_ORG
                  FROM (SELECT A.ZONE_NO,
                               A.BR_NO,
                               A.BANK_FLAG,
                               A.ORGAN_NAME,
                               A.START_DATE,
                               A.END_DATE,
                               A.BELONG_ZONENO,A.BELONG_BRNO,A.BELONG_BANK_FLAG
                          FROM PRM_IRA_ORGAN A
                         START WITH A.ZONE_NO = SUBSTR(I_BRANCHID, 1, 4)
                                AND A.BR_NO = SUBSTR(I_BRANCHID, 5, 4)
                                AND A.BANK_FLAG = O_LEVEL
                        CONNECT BY NOCYCLE
                         PRIOR A.ZONE_NO = A.BELONG_ZONENO
                               AND PRIOR A.BR_NO = A.BELONG_BRNO
                               AND PRIOR A.BANK_FLAG = A.BELONG_BANK_FLAG) B
                 left join CPMG.PRM_IRA_ORGAN org1 on B.BELONG_ZONENO=org1.zone_no and B.BELONG_BRNO=org1.br_no and B.BELONG_BANK_FLAG = org1.bank_flag  AND org1.START_DATE <= I_DATE AND org1.END_DATE >= I_DATE 
                 left join CPMG.PRM_IRA_ORGAN org2 on org1.BELONG_ZONENO=org2.zone_no and org1.BELONG_BRNO=org2.br_no and org1.BELONG_BANK_FLAG = org2.bank_flag  AND org2.START_DATE <= I_DATE AND org2.END_DATE >= I_DATE 
                 left join CPMG.PRM_IRA_ORGAN org3 on org2.BELONG_ZONENO=org3.zone_no and org2.BELONG_BRNO=org3.br_no and org2.BELONG_BANK_FLAG = org3.bank_flag  AND org3.START_DATE <= I_DATE AND org3.END_DATE >= I_DATE 

                 WHERE B.ORGAN_NAME <> '未知机构'
                   AND B.BANK_FLAG = '0'
                   AND B.START_DATE <= I_DATE
                   AND B.END_DATE >= I_DATE) N
         WHERE M.ZONENO = N.ZONE_NO
           AND M.BRANCHNO = N.BR_NO
           AND M.DATA_DATE = I_DATE
           AND M.CURRENCY = I_CURRENCY
           AND M.PROMISS_FLAG = I_IDENTY
         ORDER BY N.ZONE_NO, N.BR_NO, M.PROMISS_FLAG;
    END IF;
    O_FLAG := '0';
    O_MSG  := '获取机构数据成功';
    RETURN;
  EXCEPTION
    WHEN OTHERS THEN
      IF O_RET%ISOPEN THEN
        CLOSE O_RET;
      END IF;
      O_FLAG := '1';
      O_MSG  := '获取机构数据失败';
      RETURN;
  END;
END pkg_corpdata_export;
