CREATE OR REPLACE PACKAGE      pkg_data_management

IS
   TYPE ref_cursor IS REF CURSOR;

   PROCEDURE get_template (i_userbranchid   IN     VARCHAR2,
                           o_flag              OUT VARCHAR2,
                           o_msg               OUT VARCHAR2,
                           o_ret               OUT ref_cursor);

   PROCEDURE data_check (i_seq            IN     VARCHAR2,
                         i_userbranchid   IN     VARCHAR2,
                         o_successflag       OUT VARCHAR2,
                         o_errordesc         OUT VARCHAR2);

   PROCEDURE data_insert (i_seq            IN     VARCHAR2,
                          i_year           IN     VARCHAR2,
                          i_userbranchid   IN     VARCHAR2,
                          i_userid         IN     VARCHAR2,
                          o_successflag       OUT VARCHAR2,
                          o_errordesc         OUT VARCHAR2);

   PROCEDURE forecast_result (i_date          IN     VARCHAR2,
                             i_organcode     IN     VARCHAR2,
                             o_successflag      OUT VARCHAR2,
                             o_errordesc        OUT VARCHAR2);
END pkg_data_management;
//

CREATE OR REPLACE PACKAGE BODY      pkg_data_management
--create by panxl
IS
   PROCEDURE get_template (i_userbranchid   IN     VARCHAR2,
                           o_flag              OUT VARCHAR2,
                           o_msg               OUT VARCHAR2,
                           o_ret               OUT ref_cursor)
   IS
   BEGIN
      OPEN o_ret FOR
           SELECT id, name
             FROM ctp_branch
            WHERE parent_id = i_userbranchid
         ORDER BY id;

      o_flag := '0';
      o_msg := '获取机构数据成功';
      RETURN;
   EXCEPTION
      WHEN OTHERS
      THEN
         o_flag := '1';
         o_msg := '获取机构数据失败';
         RETURN;
   END;


   PROCEDURE data_check (                                                 --校验
                         i_seq            IN     VARCHAR2,
                         i_userbranchid   IN     VARCHAR2,
                         o_successflag       OUT VARCHAR2,
                         o_errordesc         OUT VARCHAR2)
   AS
      v_organ       VARCHAR2 (10);
      v_branchnum   NUMBER;
      v_modelnum    NUMBER;
   BEGIN
      o_errordesc := '';
      o_successflag := '0';

      SELECT COUNT (*)
        INTO v_branchnum
        FROM ctp_branch
       WHERE parent_id = i_userbranchid;

      SELECT COUNT (*)
        INTO v_modelnum
        FROM cap_plan_data_tmp
       WHERE seq = i_seq;

      IF v_branchnum <> v_modelnum
      THEN
         o_successflag := '1';
         o_errordesc := o_errordesc || '模版机构条数不正确。<br/>';
         RETURN;
      END IF;

      FOR i IN (  SELECT "ROWNUMS",
                         organcode,
                         xyfxlimit,
                         rmblimit,
                         czfxlimit
                    FROM cap_plan_data_tmp
                   WHERE seq = i_seq
                ORDER BY "ROWNUMS")
      LOOP
         SELECT MAX (aa.id)
           INTO v_organ
           FROM (  SELECT id, ROWNUM rn
                     FROM ctp_branch
                    WHERE parent_id = i_userbranchid
                 ORDER BY id) aa
          WHERE aa.rn = i."ROWNUMS" + 1;

         IF TO_NUMBER (i.organcode) <> TO_NUMBER (v_organ)
         THEN
            o_successflag := '1';
            o_errordesc :=
                  o_errordesc
               || '第'
               || (i."ROWNUMS" + 1)
               || '行记录，机构代码与模版不符。<br/>';
         END IF;

         IF i.xyfxlimit IS NULL
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，信用风险及其他增量限额为空。<br/>';
         ELSIF i.xyfxlimit > 99999999999.99
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，信用风险及其他增量限额超过11位整数2位小数上限。<br/>';
         ELSIF i.xyfxlimit < 0
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，信用风险及其他增量限额为负数。<br/>';
         END IF;

         IF i.rmblimit IS NULL
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，人民币信贷经济资本增量限额为空。<br/>';
         ELSIF i.rmblimit >= i.xyfxlimit
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，人民币信贷经济资本增量限额大于等于信用风险及其他增量限额。<br/>';
         ELSIF i.rmblimit < 0
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，人民币信贷经济资本增量限额为负数。<br/>';
         END IF;

         IF i.czfxlimit IS NULL
         THEN
            o_successflag := '1';
            o_errordesc :=
                  o_errordesc
               || '第'
               || (i."ROWNUMS" + 1)
               || '行记录，操作风险经济资本限额为空。<br/>';
         ELSIF i.czfxlimit > 99999999999.99
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，操作风险经济资本限额超过11位整数2位小数上限。<br/>';
         ELSIF i.czfxlimit < 0
         THEN
            o_successflag := '1';
            o_errordesc :=
               o_errordesc || '第' || (i."ROWNUMS" + 1)
               || '行记录，操作风险经济资本限额为负数。<br/>';
         END IF;
      END LOOP;
   EXCEPTION
      WHEN OTHERS
      THEN
         o_successflag := '1';
         o_errordesc := '校验出错。<br/>';
   END;

   PROCEDURE data_insert (i_seq            IN     VARCHAR2,
                          i_year           IN     VARCHAR2,
                          i_userbranchid   IN     VARCHAR2,
                          i_userid         IN     VARCHAR2,
                          o_successflag       OUT VARCHAR2,
                          o_errordesc         OUT VARCHAR2)
   AS
   BEGIN
      o_errordesc := '';
      o_successflag := '0';

      DELETE FROM cap_plan_data
            WHERE     year = i_year
                  AND startdate >= TO_CHAR (SYSDATE, 'yyyymmdd')
                  AND organcode IN (SELECT id
                                      FROM ctp_branch
                                     WHERE parent_id = i_userbranchid);

      UPDATE cap_plan_data
         SET enddate = TO_CHAR (SYSDATE, 'yyyymmdd')
       WHERE     year = i_year
             AND startdate < TO_CHAR (SYSDATE, 'yyyymmdd')
             AND organcode IN (SELECT id
                                 FROM ctp_branch
                                WHERE parent_id = i_userbranchid);

      INSERT INTO cap_plan_data (year,
                                 organcode,
                                 xyfxlimit,
                                 rmblimit,
                                 czfxlimit,
                                 startdate,
                                 enddate,
                                 userid)
         SELECT i_year,
                organcode,
                xyfxlimit * 10000,
                rmblimit * 10000,
                czfxlimit * 10000,
                TO_CHAR (SYSDATE, 'yyyymmdd'),
                '99991231',
                i_userid
           FROM cap_plan_data_tmp
          WHERE seq = i_seq;

      COMMIT;
   EXCEPTION
      WHEN OTHERS
      THEN
         ROLLBACK;
         o_successflag := '1';
         o_errordesc := '数据插入失败。<br/>';
   END;



   PROCEDURE forecast_result (i_date          IN     VARCHAR2,
                              i_organcode     IN     VARCHAR2,
                              o_successflag      OUT VARCHAR2,
                              o_errordesc        OUT VARCHAR2)
   AS
   BEGIN
      o_successflag := 0;

      DELETE FROM cap_ec_forecast
            WHERE plandate = i_date AND organcode = i_organcode;

      INSERT INTO cap_ec_forecast (plandate,
                                   organcode,
                                   currency,
                                   itemcode,
                                   kcdqvalue,
                                   xsvalue,
                                   zcyevalue,
                                   newzcvalue,
                                   zyzlvalue,
                                   zbzyvalue,
                                   zblimit,
                                   jdvalue)
         SELECT i_date,
                i_organcode,
                fore.currency,
                dic.kind_id,
                ec.kcdqvalue kcdq,
                ec.xsvalue xs,
                ec.zcyevalue zc,
                fore.yjxf yjxf,
                ec.xsvalue * fore.yjxf zyzl,
                ec.xsvalue * fore.yjxf + ec.kcdqvalue yjzy,
                total.eczy eczy,
                (ec.xsvalue * fore.yjxf + ec.kcdqvalue) / total.eczy zxjd
           FROM (SELECT currency, itemcode, VALUE yjxf
                   FROM cap_forecast_data
                  WHERE forecastdate = i_date AND organcode = i_organcode) fore,
                (SELECT currency,
                        itemcode,
                        kcdqvalue,
                        xsvalue,
                        zcyevalue
                   FROM cap_ec_data
                  WHERE organcode = i_organcode) ec,
                (SELECT 'RMB0999A' itemcode, rmblimit + ec eczy
                   FROM cap_plan_data aa, cap_ectotal_data bb
                  WHERE     aa.year = SUBSTR (i_date, 1, 4)
                        AND bb.datadate = aa.year - 1 || '12'
                        AND startdate <= i_date
                        AND enddate > i_date
                        AND aa.organcode = bb.organcode
                        AND aa.organcode = i_organcode
                        AND bb.diccode = '1'
                 UNION ALL
                 SELECT 'BWB0999A' itemcode, xyfxlimit + czfxlimit + ec eczy
                   FROM cap_plan_data aa, cap_ectotal_data bb
                  WHERE     aa.year = SUBSTR (i_date, 1, 4)
                        AND bb.datadate = aa.year - 1 || '12'
                        AND startdate <= i_date
                        AND enddate > i_date
                        AND aa.organcode = bb.organcode
                        AND aa.organcode = i_organcode
                        AND bb.diccode = '0') total,
                dic_all_kind dic
          WHERE fore.itemcode(+) = dic.kind_id
                AND ec.itemcode(+) =
                       RTRIM (RTRIM (SUBSTR (fore.itemcode, 5), 'T'), 'A')
                AND ec.currency(+) = fore.currency
                AND total.itemcode(+) = dic.kind_id
                AND dic.operation_kind IN
                       ('FORECAST_ITEM_BWB', 'FORECAST_ITEM_RMB');
   EXCEPTION
      WHEN OTHERS
      THEN
         ROLLBACK;
         o_successflag := '1';
         o_errordesc := SQLERRM;
         RETURN;
   END;
END pkg_data_management;
//

CREATE OR REPLACE function FUNC_CTP_LG_GETARRAY(TMPSTR IN VARCHAR2, PARAM IN VARCHAR2) RETURN ctp_type_arraytype IS
    I       INTEGER;
    POS     INTEGER;
    K       INTEGER;
    V_COUNT INTEGER := 0;
    OBJDATA ctp_type_arraytype;
  BEGIN
    K       := 1;
    POS     := 1;
    OBJDATA := ctp_type_arraytype();
    I       := INSTR(TMPSTR, PARAM, POS);

    WHILE K <> 0 LOOP
      K       := INSTR(TMPSTR, PARAM, POS);
      POS     := K + LENGTH(PARAM);
      V_COUNT := V_COUNT + 1;
    END LOOP;

    IF I <= 0 THEN
      OBJDATA.EXTEND();
      OBJDATA(1) := TMPSTR;
      RETURN OBJDATA;
    END IF;

    POS := 1;

    FOR J IN 1 .. V_COUNT - 1 LOOP
      OBJDATA.EXTEND();
      I := INSTR(TMPSTR, PARAM, POS);
      OBJDATA(J) := SUBSTR(TMPSTR, POS, I - 1 - POS + 1);
      POS := I + LENGTH(PARAM);
    END LOOP;

    OBJDATA.EXTEND();
    OBJDATA(V_COUNT) := SUBSTR(TMPSTR, POS, LENGTH(TMPSTR) - POS + 1);
    RETURN OBJDATA;

  EXCEPTION
    WHEN OTHERS THEN
      RETURN NULL;
  END;
  //

CREATE OR REPLACE PACKAGE BODY      PCKG_CAP_TRANS IS
    

  PROCEDURE PROC_TRANS_PRICE_IMP(i_year      in varchar2,
                                 i_quarter   in varchar2,
                                 i_branchId  IN VARCHAR2,
                                 i_seq       IN VARCHAR2, 
                                 i_varieties IN VARCHAR2, 
                                 i_userbr_id in varchar2,
                                 o_retCode   OUT VARCHAR2) IS
    v_arr1 ctp_type_arraytype;
    v_arr2 ctp_type_arraytype;
    v_seq  CAP_TRANS_OFFER.TRANS_OFFER_SEQ%type;
    v_level CAP_TRANS_OFFER.TRANS_LEVEL%type;
    v_cnt integer;

  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_userbr_id;
    
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_varieties, ',');

    v_seq := i_seq;
    
    delete CAP_TRANS_OFFER o where o.trans_offer_seq = v_seq and o.trans_branch = i_branchId;
    
    FOR i IN 1 .. v_arr1.count LOOP
      v_arr2 := FUNC_CTP_LG_GETARRAY(v_arr1(i), '@');  
      INSERT INTO CAP_TRANS_OFFER
        (TRANS_OFFER_SEQ,
         TRANS_BRANCH, --交易机构
         TRANS_YEAR, --年份
         TRANS_QUARTER, --交易季度（1：第一季度、2：第二季度、3：第三季度、4:第四季度）
         PRICE_RELEA_DATE, --价格发布日期
         TRANS_VARIETIES, --交易品种（1：q1、2：q2、3：q3、4：q4）
         BUY_PRICE, --买入价格
         SELL_PRICE, --卖出价格
         CONFIRM,--是否确认（1：已确认、2：未确认）
         IN_TRADING_VARIETIES, --是否当期交易品种（0：否、1：是）
         IN_TRADING, --是否开启交易（1：关闭、2：开启）
         HISTORY_RECORD, --是否历史记录（0：是，1：否） 
         CREATE_TIME, --创建时间
         TRANS_LEVEL
         )
      VALUES
        (v_seq,
         i_branchId,
         i_year,
         i_quarter,
         to_char(sysdate, 'yyyymmdd'),
         v_arr2(1),
         v_arr2(2),
         v_arr2(3),
         '2',
         '0',
         '1',
         '1',
         SYSDATE,
         v_level);
    END LOOP;
  
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  

  PROCEDURE PROC_TRANS_PRICE_UPDATE(i_branchId  IN VARCHAR2,
                                    i_offerseq   IN VARCHAR2,
                                    i_varieties IN VARCHAR2,
                                    i_userbr_id in varchar2,
                                    o_retCode   OUT VARCHAR2) IS
    v_arr1 ctp_type_arraytype;
    v_arr2 ctp_type_arraytype;
    v_level CAP_TRANS_OFFER.TRANS_LEVEL%type;
  BEGIN
    o_retCode := 0;
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_varieties, ',');
 
    
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_userbr_id;
    
    delete CAP_TRANS_OFFER o where o.trans_offer_seq = i_offerseq and o.trans_branch = i_branchId;

    
    FOR i IN 1 .. v_arr1.count LOOP
      v_arr2 := FUNC_CTP_LG_GETARRAY(v_arr1(i), '@');  
      INSERT INTO CAP_TRANS_OFFER
        (TRANS_OFFER_SEQ,
         TRANS_BRANCH, --交易机构
         TRANS_YEAR, --年份
         TRANS_QUARTER, --交易季度（1：第一季度、2：第二季度、3：第三季度、4:第四季度）
         PRICE_RELEA_DATE, --价格发布日期
         TRANS_VARIETIES, --交易品种（1：q1、2：q2、3：q3、4：q4）
         BUY_PRICE, --买入价格
         SELL_PRICE, --卖出价格
         CONFIRM,--是否确认（1：已确认、2：未确认）
         IN_TRADING_VARIETIES, --是否当期交易品种（0：否、1：是）
         IN_TRADING, --是否开启交易（1：关闭、2：开启）
         HISTORY_RECORD, --是否历史记录（0：是，1：否） 
         CREATE_TIME, --创建时间 
         TRANS_LEVEL
         )
      VALUES
        (i_offerseq,
         i_branchId,
         substr(i_offerseq, 9,4),
         substr(i_offerseq, 13,1),
         to_char(sysdate, 'yyyymmdd'),
         v_arr2(1),
         v_arr2(2),
         v_arr2(3),
         '2',
         '0',
         '1',
         '1',
         SYSDATE,
         v_level);
    END LOOP;
  
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;

  PROCEDURE PROC_TRANS_PRICE_LIST(  i_user_br   in varchar2, 
                                    i_branchId  IN VARCHAR2, 
                                    i_quarter   IN VARCHAR2,
                                    i_trans_seq IN VARCHAR2,
                                    i_beg_num in varchar2,
                                    i_fetch_num in varchar2,
                                    o_retCode   OUT VARCHAR2,
                                    o_totalNum  out number,
                                    o_retList   out ref_result_list) is
  v_query_sql  VARCHAR2(30000) := '';
  v_count_sql  VARCHAR2(30000) := '';
  v_where_sql  VARCHAR2(30000) := '';
  v_level      ctp_branch.branch_level%type;
  BEGIN
    o_retCode := '0';
    select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
   
    v_where_sql := 'where o.TRANS_LEVEL = '|| v_level ||' and o.TRANS_QUARTER = ' || i_quarter || ' and o.TRANS_OFFER_SEQ = ''' || i_trans_seq ||'''';
    
    v_level := v_level + 1;
    if i_branchId is null then 
       v_where_sql := v_where_sql || ' and o.TRANS_BRANCH in (SELECT B.id
                                        FROM CTP_BRANCH B
                                       WHERE B.BRANCH_LEVEL = ' || v_level ||
                                       ' START WITH B.ID = ''' || i_user_br || '''' ||
                                       ' CONNECT BY B.PARENT_ID = PRIOR ID ' ||
                                       ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''' || 
                                                      ' AND 1 = ''' || to_number(v_level - 1) || '''
                                                        and end_date = ''99991231'' ) ';
    else 
       v_where_sql := v_where_sql || ' and o.TRANS_BRANCH = ''' || i_branchId || '''';
    
    end if;
    
    v_count_sql := 'select count(1) from (select o.trans_offer_seq from CAP_TRANS_OFFER o ' || v_where_sql || ' group by o.trans_offer_seq, o.trans_branch)';
    
   
    v_query_sql :=  'select seq_branch, trans_offer_seq, branchname, decode(b1, 9999999999999999999999.99, '''', b1), decode(s1, 9999999999999999999999.99, '''', s1),
                  decode(b2, 9999999999999999999999.99, '''', b2), decode(s2, 9999999999999999999999.99, '''', s2),
                  decode(b3, 9999999999999999999999.99, '''', b3), decode(s3, 9999999999999999999999.99, '''', s3),
                  decode(b4, 9999999999999999999999.99, '''', b4), decode(s4, 9999999999999999999999.99, '''', s4),status,rn from 
    (select o.trans_offer_seq || ''$|$'' || o.trans_branch seq_branch,decode(length(o.trans_offer_seq),9, substr(o.trans_offer_seq,6),substr(o.trans_offer_seq,9)) trans_offer_seq, FUNC_GET_BRANCHNAME(o.trans_branch) branchname,o.TRANS_QUARTER,
            sum(case when o.trans_varieties = 1 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b1,
            sum(case when o.trans_varieties = 1 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s1,
            sum(case when o.trans_varieties = 2 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b2,
            sum(case when o.trans_varieties = 2 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s2,
            sum(case when o.trans_varieties = 3 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b3,
            sum(case when o.trans_varieties = 3 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s3,
            sum(case when o.trans_varieties = 4 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b4,
            sum(case when o.trans_varieties = 4 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s4,
            decode(max(o.confirm), 1, ''已确认'', ''未确认'' ) status,            
            row_number() over (order by o.trans_offer_seq, 
                                     decode(''' || i_user_br || '''' ||',''01000000'',
                                                (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.trans_branch),
                                                o.trans_branch)
                              ) rn
        from CAP_TRANS_OFFER  o ' || v_where_sql || ' group by o.trans_offer_seq, o.trans_branch,o.TRANS_QUARTER)';        
    EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;
          
    v_query_sql := 'SELECT *
        FROM (' || v_query_sql  || ')
        WHERE rn BETWEEN :i_beg AND :i_end';
        
    OPEN o_retList FOR v_query_sql
         USING i_beg_num, i_beg_num + i_fetch_num - 1;
         
  
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
                           
  PROCEDURE PROC_GET_BRANCH_TRANSPRICE(i_user_br   in varchar2, --用户机构
                                    i_branchId  IN VARCHAR2, --选择机构
                                    i_quarter   IN VARCHAR2,
                                    i_trans_seq IN VARCHAR2,    
                                     o_retCode   OUT VARCHAR2,
                                     o_resList out ref_result_list)is 
  v_level       ctp_branch.branch_level%type;
  v_count number;
  BEGIN
    o_retCode := 0;
    select b.branch_level into v_level from ctp_branch b where b.id = i_user_br;
    
    select count(*) into v_count from CAP_TRANS_OFFER o where o.TRANS_LEVEL =v_level  and o.TRANS_QUARTER =i_quarter  and o.TRANS_OFFER_SEQ =i_trans_seq  and o.TRANS_BRANCH = i_branchId;
    IF v_count > 0 THEN
    open o_resList for
    select decode(b1, 9999999999999999999999.99, '', b1), decode(s1, 9999999999999999999999.99, '', s1),
                  decode(b2, 9999999999999999999999.99, '', b2), decode(s2, 9999999999999999999999.99, '', s2),
                  decode(b3, 9999999999999999999999.99, '', b3), decode(s3, 9999999999999999999999.99, '', s3),
                  decode(b4, 9999999999999999999999.99, '', b4), decode(s4, 9999999999999999999999.99, '', s4) 
      from (select 
            sum(case when o.trans_varieties = 1 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b1,
            sum(case when o.trans_varieties = 1 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s1,
            sum(case when o.trans_varieties = 2 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b2,
            sum(case when o.trans_varieties = 2 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s2,
            sum(case when o.trans_varieties = 3 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b3,
            sum(case when o.trans_varieties = 3 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s3,
            sum(case when o.trans_varieties = 4 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b4,
            sum(case when o.trans_varieties = 4 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s4
        from CAP_TRANS_OFFER o where o.TRANS_LEVEL =v_level  and o.TRANS_QUARTER =i_quarter  and o.TRANS_OFFER_SEQ =i_trans_seq  and o.TRANS_BRANCH = i_branchId group by o.trans_offer_seq, o.trans_branch);
    ELSE
    open o_resList for  
      select '','','','','','','','' from dual;
    END IF;       

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;  
                                    

  PROCEDURE PROC_TRANS_PRICE_DEL(  i_trans_seq   in varchar2, --序列号
                                   i_branchids      in varchar2, --机构
                                   o_retCode   OUT VARCHAR2) is
  
  BEGIN
    DELETE CAP_TRANS_OFFER O WHERE O.TRANS_BRANCH 
    in (select column_value from table(FUNC_CTP_LG_GETARRAY(i_branchids, ',')))
    and O.TRANS_OFFER_SEQ in (select column_value from table(FUNC_CTP_LG_GETARRAY(I_TRANS_SEQ, ',')));
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                                   

  PROCEDURE PROC_TRANS_PRICE_CONFIRM(  i_trans_seq   in varchar2, --用户机构
                                   o_retCode   OUT VARCHAR2) is
  
  BEGIN
    UPDATE CAP_TRANS_OFFER
       SET CONFIRM = 1
     WHERE TRANS_OFFER_SEQ in (select column_value from table(FUNC_CTP_LG_GETARRAY(I_TRANS_SEQ, ',')));
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
  

  PROCEDURE PROC_TRANS_DATE_LIST(  i_branchid   in varchar2, 
                                   i_trans_seq  in varchar2,
                                   i_quarter    in varchar2,
                                   i_varieties  in varchar2,
                                   o_retCode   OUT VARCHAR2,
                                   o_retList   out ref_result_list) is
  v_level      ctp_branch.branch_level%type;

  BEGIN
    select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_branchid;

    open o_retList for
     SELECT TRANS_BRANCH,
            func_get_branchname(TRANS_BRANCH),
            TRANS_VARIETIES,
            BUY_PRICE,
            SELL_PRICE,
            TRANS_START_TIME,
            TRANS_END_TIME,
            decode(IN_TRADING, '2', '开启','关闭' )
       FROM CAP_TRANS_OFFER o
      WHERE TRANS_OFFER_SEQ = I_TRANS_SEQ
        and TRANS_QUARTER = i_quarter
        and confirm = '1'
        and TRANS_BRANCH in (SELECT B.id
                                        FROM CTP_BRANCH B
                                       WHERE B.BRANCH_LEVEL = v_level
                                        START WITH B.ID = i_branchid
                                        CONNECT BY B.PARENT_ID = PRIOR ID
                                        union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = '3'
                                                        AND IS_SALES = '1' 
                                                        AND  1 = to_number(v_level - 1) 
                                                        and end_date = '99991231' ) 
        AND TRANS_VARIETIES IN
            (SELECT COLUMN_VALUE
               FROM TABLE(FUNC_CTP_LG_GETARRAY(i_varieties, ','))) 
        order by decode(i_branchid,'01000000',(select sort_no
            from cap_trans_branch_sort
           where trans_branch_id(+) = o.trans_branch),o.trans_branch),o.TRANS_VARIETIES;

               
    o_retCode := '0';
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                                   

  PROCEDURE PROC_TRANS_CLOSE(  i_trans_seq   in varchar2, --用户机构
                               i_variety     in varchar2, --'1,2,3,4'
                               i_user_br   in varchar2,
                               i_userId    IN varchar2,
                               o_retCode   OUT VARCHAR2) is
  v_logseq                         CAP_TRANS_LOG.LOG_ID%type;                               
  
  BEGIN
    UPDATE CAP_TRANS_OFFER O
       SET O.IN_TRADING = '1'
     WHERE O.TRANS_OFFER_SEQ = I_TRANS_SEQ and O.TRANS_VARIETIES in
     (select column_value from table(FUNC_CTP_LG_GETARRAY(i_variety, ',')));
    

    
    for i in (
      SELECT t.trans_id FROM (select o.trans_branch,o.trans_year,o.trans_varieties,o.trans_quarter from CAP_TRANS_OFFER O where o.trans_offer_seq = I_TRANS_SEQ and O.TRANS_VARIETIES in
     (select column_value from table(FUNC_CTP_LG_GETARRAY(i_variety, ',')))) A, CAP_TRANS_APPLY T WHERE t.trans_initiate = a.trans_branch and t.trans_year = a.trans_year and t.trans_variety = a.trans_varieties and t.trans_quarter = a.trans_quarter
     
     and t.trans_status not in ('2', '3', '6') 
      
    ) loop 
    
    update cap_trans_apply t set t.trans_status = '6' where t.trans_id = i.trans_id;
     
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;

        
   INSERT into CAP_TRANS_LOG
        (LOG_ID,
         TRANS_ID,
         OPER_TYPE,
         OPER_MSG,
         OPERATER,
         OPER_TIME,
         OPER_DEPT,
         OPER_BRANCH)
      VALUES
        (v_logseq, i.trans_id, '7', '作废', i_userId, SYSDATE, '', I_USER_BR); 
        
    end loop;     
    
    o_retCode := '0';
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                                

  PROCEDURE PROC_TRANS_OPEN(i_trans_seq   in varchar2, --交易序列
                            i_branch_id   in varchar2, --用户机构
                            i_variety     in varchar2, --'Q1' 'Q2'
                            i_begin_date  in varchar2,
                            i_end_date  in varchar2,
                            o_retCode   OUT VARCHAR2) is
                       
  v_rec               CAP_TRANS_OFFER%rowtype;
  BEGIN
    
    select * into v_rec from CAP_TRANS_OFFER O where O.TRANS_OFFER_SEQ = I_TRANS_SEQ and  rownum = 1;
    
    UPDATE CAP_TRANS_OFFER O
       SET O.IN_TRADING       = '2',
           O.TRANS_START_TIME = I_BEGIN_DATE,
           O.TRANS_END_TIME   = I_END_DATE
     WHERE O.TRANS_OFFER_SEQ = I_TRANS_SEQ
       AND O.TRANS_BRANCH = i_branch_id
       AND O.TRANS_VARIETIES = decode(i_variety, 'Q1','1','Q2','2','Q3','3','4');

      
     UPDATE CAP_TRANS_OFFER O
       SET O.IN_TRADING  = '1'
     WHERE O.TRANS_BRANCH = i_branch_id
           AND O.TRANS_YEAR = v_rec.trans_year
           AND O.TRANS_QUARTER = v_rec.trans_quarter
           and O.Trans_Level = v_rec.trans_level
           AND O.TRANS_VARIETIES = decode(i_variety, 'Q1','1','Q2','2','Q3','3','4')
           AND O.TRANS_OFFER_SEQ <> I_TRANS_SEQ;
       
       o_retCode := '0';
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  

  PROCEDURE PROC_TRANS_BRPRICE_LIST(i_user_br   in varchar2, --年份
                                    i_branchId  IN VARCHAR2, --报价机构
                                    i_quarter   IN VARCHAR2, --报价季度
                                    i_year IN VARCHAR2,--报价年份
                                    i_beg_num in varchar2,
                                    i_fetch_num in varchar2,
                                    o_retCode   OUT VARCHAR2,
                                    o_totalNum  out number,
                                    o_retList   out ref_result_list) is
  
  v_query_sql  VARCHAR2(30000) := '';
  v_count_sql  VARCHAR2(30000) := '';
  v_where_sql  VARCHAR2(30000) := '';
  v_level      ctp_branch.branch_level%type;
  BEGIN
    o_retCode := '0';
    select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;
   
    v_where_sql := 'where o.offer_year = ' || i_year || ' and o.offer_quarter = ''' || i_quarter ||'''';
    if i_branchId is null then 
       v_where_sql := v_where_sql || ' and o.offer_BRANCH in (SELECT B.id
                                        FROM CTP_BRANCH B
                                       WHERE B.BRANCH_LEVEL = ' || v_level ||
                                       ' START WITH B.ID = ''' || i_user_br || '''' ||
                                       ' CONNECT BY B.PARENT_ID = PRIOR ID '||
                                       ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''' || 
                                                      ' AND 1 = ''' || to_number(v_level - 1) || '''
                                                        and end_date = ''99991231'' ) ';
    else 
       v_where_sql := v_where_sql || ' and o.offer_BRANCH = ''' || i_branchId || '''';
    
    end if;
    
    v_count_sql := 'select count(1) from (select o.OFFER_BRANCH, to_char(o.create_time,''yyyy-mm-dd hh24:mi:ss'')
        from CAP_BRANCHS_TRANS_OFFER o  ' || v_where_sql || ' group by o.offer_branch, to_char(o.create_time,''yyyy-mm-dd hh24:mi:ss''))';
    
   
   v_query_sql := 'select branch_name, create_time, decode(b1, 9999999999999999999999.99, '''', b1), decode(s1, 9999999999999999999999.99, '''', s1),
                  decode(b2, 9999999999999999999999.99, '''', b2), decode(s2, 9999999999999999999999.99, '''', s2),
                  decode(b3, 9999999999999999999999.99, '''', b3), decode(s3, 9999999999999999999999.99, '''', s3),
                  decode(b4, 9999999999999999999999.99, '''', b4), decode(s4, 9999999999999999999999.99, '''', s4), rn
                  from (select FUNC_GET_BRANCHNAME(o.OFFER_BRANCH) branch_name , to_char(o.create_time,''yyyy-mm-dd hh24:mi:ss'') create_time,
                        sum(case when o.OFFER_VARIETIES = 1 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b1,
                        sum(case when o.OFFER_VARIETIES = 1 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s1,
                        sum(case when o.OFFER_VARIETIES = 2 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b2,
                        sum(case when o.OFFER_VARIETIES = 2 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s2,
                        sum(case when o.OFFER_VARIETIES = 3 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b3,
                        sum(case when o.OFFER_VARIETIES = 3 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s3,
                        sum(case when o.OFFER_VARIETIES = 4 then decode(o.buy_price,null,9999999999999999999999.99,o.buy_price) else 0 end) b4,
                        sum(case when o.OFFER_VARIETIES = 4 then decode(o.sell_price,null,9999999999999999999999.99,o.sell_price) else 0 end) s4,
                        row_number() over (order by decode(''' || i_user_br || '''' ||',''01000000'',
                                                            (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.offer_branch),
                                                            o.offer_branch), 
                                                to_char(o.create_time,''yyyy-mm-dd hh24:mi:ss'')) rn
                        from CAP_BRANCHS_TRANS_OFFER o ' || v_where_sql || 'group by o.offer_branch, to_char(o.create_time,''yyyy-mm-dd hh24:mi:ss''))';
    EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;
          
    v_query_sql := 'SELECT *
        FROM (' || v_query_sql  || ')
        WHERE rn BETWEEN :i_beg AND :i_end';
        
    OPEN o_retList FOR v_query_sql
         USING i_beg_num, i_beg_num + i_fetch_num - 1;
  
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
 --分行交易报价新增
  PROCEDURE PROC_TRANS_BRPRICE_ADD (i_branchId  IN VARCHAR2,
                                    i_year     IN VARCHAR2,
                                    i_quarter   IN VARCHAR2,
                                    i_varieties IN VARCHAR2, --品种@买入价格@卖出价格,
                                    o_retCode   OUT VARCHAR2) IS
    v_arr1 ctp_type_arraytype;
    v_arr2 ctp_type_arraytype;
    v_date date;

  BEGIN
    o_retCode := 0;
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_varieties, ',');
    v_date    := sysdate;
    
    FOR i IN 1 .. v_arr1.count LOOP
      v_arr2 := FUNC_CTP_LG_GETARRAY(v_arr1(i), '@');  
      INSERT INTO CAP_BRANCHS_TRANS_OFFER
        (OFFER_BRANCH, --交易机构
         OFFER_YEAR, --年份
         OFFER_QUARTER, --交易季度（1：第一季度、2：第二季度、3：第三季度、4:第四季度）
         OFFER_VARIETIES, --交易品种（1：q1、2：q2、3：q3、4：q4）
         BUY_PRICE, --买入价格
         SELL_PRICE, --卖出价格
         CREATE_TIME,
         CREATE_BRANCH, --创建机构
         OFFER_DATE
         )
      VALUES
        (i_branchId,
         i_year,
         i_quarter,
         v_arr2(1),
         v_arr2(2),
         v_arr2(3),
         v_date,
         i_branchId,
         to_char(sysdate,'yyyymmdd'));
    END LOOP;
  
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
     --交易申请新增
  PROCEDURE PROC_TRANS_APPR_ADD(i_year      IN VARCHAR2,
                                i_quarter   IN VARCHAR2, --add by lish 20160201 根据选择季度获取价格               
                                i_varieties IN VARCHAR2,
                                i_oper      IN VARCHAR2,
                                i_price     in varchar2,
                                i_offer     in varchar2,
                                i_branchId  IN VARCHAR2,
                                i_rcvbrId   IN VARCHAR2,
                                i_userId    IN varchar2,
                                o_retCode   OUT VARCHAR2) is 
  v_level                       ctp_branch.branch_level%type;
  v_rec                         CAP_TRANS_OFFER%rowtype;
  v_season                      CAP_TRANS_OFFER.TRANS_QUARTER%type;--交易季度
  v_logseq                      CAP_TRANS_LOG.LOG_ID%type;
  v_transid                     CAP_TRANS_APPLY.TRANS_ID%type;
  BEGIN
    o_retCode := 0;
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
    
    select 'AP' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tansappr.Nextval,5,'0') into v_transid from dual;
    
    select b.branch_level into v_level from ctp_branch b where b.id = i_rcvbrId;

      
    SELECT *
      INTO V_REC
      FROM CAP_TRANS_OFFER A
     WHERE A.TRANS_YEAR = I_YEAR
       AND A.TRANS_VARIETIES = I_VARIETIES
       AND A.TRANS_BRANCH = I_BRANCHID
       AND A.IN_TRADING = '2'
       AND A.TRANS_LEVEL = V_LEVEL

       AND A.Trans_Quarter = i_quarter 
       AND TO_CHAR(SYSDATE, 'yyyymmdd') BETWEEN A.TRANS_START_TIME AND
           A.TRANS_END_TIME
           and rownum = 1;
    
    insert into CAP_TRANS_APPLY (trans_id, 
        trans_initiate, 
        trans_accept_branch, 
        trans_type, 
        trans_variety, 
        trans_price, 
        trans_count, 
        trans_status, 
        price_relea_date, 
        trans_time, 
        trans_quarter, 
        trans_year,
        trans_offer_seq
        ) values (v_transid,i_branchId, i_rcvbrId,i_oper,i_varieties,i_price,i_offer,'1', V_REC.PRICE_RELEA_DATE,
        sysdate,v_rec.trans_quarter,i_year,v_rec.trans_offer_seq);

    INSERT into CAP_TRANS_LOG
        (LOG_ID,
         TRANS_ID,
         OPER_TYPE,
         OPER_MSG,
         OPERATER,
         OPER_TIME,
         OPER_DEPT,
         OPER_BRANCH)
      VALUES
        (v_logseq, v_transid, '0', '交易申请提交', i_userId, SYSDATE, '', i_branchId);

      INSERT INTO CAP_LIMIT_APPRMAIL
        (DATA_DATE,
         RECEIVER_ID,
         RECEIVER_NAME,
         MAIL_TITLE,
         MAIL_ADDRESS,
         MAIL_CONTENT,
         RECEIVER_BRANCH,
         SEND_STATUS,
         LOG_ID)
        SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
               '限额交易待确认',
               u.email,
               '您有限额交易待确认记录需要处理。',
               u.branch_id,
               '0',
               v_logseq
          FROM CTP_USER U, CTP_ROLE_USER_REL R
         WHERE U.BRANCH_ID = I_BRANCHID
           AND U.ID = R.USER_ID
           and U.Email is not null
           AND R.ROLE_ID IN ('201', '301', '401', '601');
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END; 

  PROCEDURE PROC_GET_TRANS_PRICE( i_year      IN VARCHAR2,
                                  i_quarter   IN VARCHAR2, 
                                  i_varieties IN VARCHAR2,
                                  i_oper      IN VARCHAR2,
                                  i_branchId  IN VARCHAR2,
                                  i_rcvbrId   IN varchar2,
                                  o_retCode   OUT VARCHAR2,
                                  o_price     out varchar2) is 
  v_level                         ctp_branch.branch_level%type;
  v_season                        CAP_TRANS_OFFER.TRANS_QUARTER%type;
                   
  BEGIN
    o_retCode := 0;
    
    if i_rcvbrId is null then
       return;
    end if;
    
    select b.branch_level into v_level from ctp_branch b where b.id = i_rcvbrId;
    

    
    select max(branch_level) into v_level from ctp_branch where id = i_rcvbrId;
    
    SELECT max(decode(i_oper, '0', A.SELL_PRICE, A.Buy_Price)) into o_price
      FROM CAP_TRANS_OFFER A
     WHERE A.TRANS_YEAR = I_YEAR
       AND A.trans_varieties = I_VARIETIES
       AND A.Trans_Branch = I_BRANCHID

       AND A.Trans_Quarter = i_quarter 
       AND A.IN_TRADING = '2'
       and trans_level = v_level
       AND TO_CHAR(SYSDATE, 'yyyymmdd') BETWEEN TRANS_START_TIME AND
           TRANS_END_TIME;
           
    
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  

  PROCEDURE PROC_TRANS_APPR_LIST( i_year   in varchar2, --交易年份
                                  i_quarter  IN VARCHAR2, --交易季度
                                 -- i_transDay in varchar2,
                                  i_varieties   IN VARCHAR2, --交易品种
                                  i_oper IN VARCHAR2,--报价年份
                                  i_status in varchar2,
                                  i_branch_id in varchar2,
                                  i_user_br   in varchar2,
                                  i_beg_num in varchar2,
                                  i_fetch_num in varchar2,
                                  o_retCode   OUT VARCHAR2,
                                  o_totalNum  out number,
                                  o_retList   out ref_result_list) is
  v_query_sql  VARCHAR2(30000) := '';
  v_count_sql  VARCHAR2(30000) := '';
  v_where_sql  VARCHAR2(30000) := '';
  v_level      ctp_branch.branch_level%type;
  BEGIN
    o_retCode := 0;
    select b.branch_level + 1 into v_level from ctp_branch b where b.id = i_user_br;

    v_where_sql := ' where o.TRANS_QUARTER = ' || i_quarter
                   || ' and o.trans_year = ''' || i_year || '''';
                   
    if i_branch_id is null then 
       v_where_sql := v_where_sql || ' and o.TRANS_INITIATE in (SELECT B.id
                                        FROM CTP_BRANCH B
                                       WHERE B.BRANCH_LEVEL = ' || v_level ||
                                       ' START WITH B.ID = ''' || i_user_br || '''' ||
                                       ' CONNECT BY B.PARENT_ID = PRIOR ID '||
                                       ' union all
                                            SELECT (ZONE_NO || BR_NO) ID
                                                       FROM PRM_IRA_ORGAN
                                                      WHERE BANK_FLAG = ''3''
                                                        AND IS_SALES = ''1''' || 
                                                      ' AND 1 = ''' || to_number(v_level - 1) || '''
                                                        and end_date = ''99991231'' ) and o.trans_accept_branch = '''||i_user_br||'''';
    elsif i_branch_id = I_USER_BR then
       v_where_sql := v_where_sql || ' and o.TRANS_INITIATE = ''' || i_branch_id || '''';
    else 
       v_where_sql := v_where_sql || 'and o.TRANS_ACCEPT_BRANCH = ''' || i_user_br || ''' and o.TRANS_INITIATE = ''' || i_branch_id || '''';
    
    end if;
    
    if i_varieties is not null then
      v_where_sql := v_where_sql || ' and o.trans_variety = ''' || i_varieties || '''';
    end if;
    
    if i_oper is not null then
      v_where_sql := v_where_sql || ' and o.trans_type = ''' || i_oper || '''';
    end if;
    
    if i_status is not null then
      v_where_sql := v_where_sql || ' and o.trans_status = ''' || i_status || '''';
    end if;
    
    
    
    
    v_count_sql := 'select count(1) from CAP_TRANS_APPLY o ' || v_where_sql;
        
    EXECUTE IMMEDIATE v_count_sql
          INTO o_totalNum;
          
             
    v_where_sql := v_where_sql || ' and o.TRANS_INITIATE = T.TRANS_BRANCH(+)
                      AND o.branch_level = t.trans_level(+)
                      AND o.TRANS_YEAR = T.TRANS_YEAR(+)
                      AND o.TRANS_QUARTER = T.TRANS_QUARTER(+)
                      AND o.TRANS_VARIETY = T.trans_varieties(+)
                      AND T.CONFIRM (+)= 1
                      AND T.IN_TRADING (+) = 2 ';
                     
          
    v_query_sql :=  ' SELECT o.TRANS_ID || ''$|$'' || o.TRANS_INITIATE,
              func_get_branchname(o.TRANS_INITIATE),
              func_get_branchname(o.TRANS_ACCEPT_BRANCH),
              o.TRANS_QUARTER,
              o.TRANS_TYPE,
              o.TRANS_VARIETY,
              o.TRANS_PRICE,
              decode(o.Trans_Type, 0, T.SELL_PRICE,T.BUY_PRICE),
              o.TRANS_COUNT,
              to_char(o.TRANS_TIME, ''yyyy-mm-dd hh24:mi:ss''),
              o.TRANS_STATUS,
              row_number() over (order by decode(''' || i_user_br || '''' ||',''01000000'',
                                                   (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = o.trans_initiate),
                                                  o.trans_initiate)
                                 , to_char(o.TRANS_TIME, ''yyyymmdd hh24:mi:ss'')) rn
         FROM (select a.trans_id,
                      a.trans_initiate,
                      a.trans_accept_branch,
                      a.trans_year,
                      a.trans_quarter,
                      a.trans_type,
                      a.trans_variety,
                      a.trans_price,
                      a.trans_count,
                      a.trans_time,
                      a.trans_status,
                      b.branch_level branch_level 
                      from CAP_TRANS_APPLY a,ctp_branch b 
                      where a.trans_accept_branch = b.id) o, CAP_TRANS_OFFER T ' || v_where_sql;

          
    v_query_sql := 'SELECT *
        FROM (' || v_query_sql  || ')
        WHERE rn BETWEEN :i_beg AND :i_end';
        
    dbms_output.put_line(v_query_sql);    
        
    OPEN o_retList FOR v_query_sql
         USING i_beg_num, i_beg_num + i_fetch_num - 1;
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  

  PROCEDURE PROC_TRANS_APPRTODO_LIST( i_branch_id in varchar2,
                                      i_status in varchar2,
                                      i_beg_num in varchar2,
                                      i_fetch_num in varchar2,
                                      o_retCode   OUT VARCHAR2,
                                      o_totalNum  out number,
                                      o_retList   out ref_result_list) is 
  v_level                          ctp_branch.branch_level%type;   
  BEGIN
    o_retCode := 0;
    o_totalNum := 1;

    select b.branch_level into v_level from ctp_branch b where b.id = i_branch_id;
    if i_status = '2' then 
      v_level := v_level + 1;
    end if;
    
    open o_retList for with rs as(
        SELECT A.TRANS_ID,
            func_get_branchname(A.TRANS_INITIATE) initiate_name,
            func_get_branchname(A.TRANS_ACCEPT_BRANCH) accept_branch_name,
            A.TRANS_YEAR,
            A.TRANS_QUARTER,
            A.TRANS_VARIETY,
            A.TRANS_TYPE,
            A.TRANS_PRICE,
            decode(A.Trans_Type, 0, T.SELL_PRICE,T.BUY_PRICE) sell_buy_price,
            A.TRANS_COUNT,
            A.TRANS_STATUS
       FROM (select c.trans_id, 
                   c.trans_initiate, 
                   c.trans_accept_branch, 
                   c.trans_variety, 
                   c.trans_type, 
                   c.trans_price, 
                   c.trans_count,
                   c.trans_status,
                   c.trans_year, 
                   c.trans_quarter, 
                   d.branch_level 
                   from CAP_TRANS_APPLY c, ctp_branch d 
                   where c.trans_accept_branch = d.id) A, CAP_TRANS_OFFER T
      WHERE A.TRANS_INITIATE = T.TRANS_BRANCH(+)
        AND a.branch_level = t.trans_level(+)
        AND A.TRANS_YEAR = T.TRANS_YEAR(+)
        AND A.TRANS_QUARTER = T.TRANS_QUARTER(+)
        AND A.TRANS_VARIETY = T.TRANS_VARIETIES(+)
        AND T.CONFIRM (+)= '1'
        AND T.IN_TRADING (+) = '2'
        and A.TRANS_STATUS = i_status
        and ((i_status = '1' and A.TRANS_INITIATE = i_branch_id) 
            or (i_status = '7' and A.TRANS_INITIATE = i_branch_id) 
              or (i_status = '2' and A.TRANS_ACCEPT_BRANCH = i_branch_id))
      
        order by decode(i_branch_id ,'01000000',
                        (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = a.trans_initiate),
                       a.trans_initiate),
              a.trans_id, a.TRANS_VARIETY  
        )
       select *
         from (select 
                rs.TRANS_ID,
                rs.initiate_name,
                rs.accept_branch_name,
                rs.TRANS_YEAR,
                rs.TRANS_QUARTER,
                rs.TRANS_VARIETY,
                rs.TRANS_TYPE,
                rs.TRANS_PRICE,
                rs.sell_buy_price,
                rs.TRANS_COUNT,
                rs.TRANS_STATUS,
                rownum row_num
                 from rs)
        where row_num >= I_BEG_NUM
          and row_num < I_BEG_NUM + I_FETCH_NUM;
                                       
     SELECT COUNT(1)
       INTO O_TOTALNUM
       FROM CAP_TRANS_APPLY A
      WHERE A.TRANS_STATUS = I_STATUS
        and ((i_status = '1' and A.TRANS_INITIATE = i_branch_id) 
            or (i_status = '7' and A.TRANS_INITIATE = i_branch_id)
              or (i_status = '2' and A.TRANS_ACCEPT_BRANCH = i_branch_id));
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  

  PROCEDURE PROC_TRANS_APPR_LOG( i_trans_Id   in varchar2, 
                                  i_beg_num in varchar2,
                                  i_fetch_num in varchar2,
                                  o_retCode   OUT VARCHAR2,
                                  o_totalNum  out number,
                                  o_retList   out ref_result_list)is 
  
  BEGIN
    o_retCode := 0;
    
    OPEN O_RETLIST for with rs as(
      SELECT L.LOG_ID,
             L.OPER_TYPE,
             L.OPER_MSG,
             func_get_branchname(L.OPER_BRANCH) branch_name,

             L.OPERATER,
             TO_CHAR(L.OPER_TIME, 'yyyy-mm-dd hh24:mi:ss') oper_time
      from CAP_TRANS_LOG l where l.trans_id = i_trans_Id order by L.OPER_TIME
    )  select * from (select rs.LOG_ID,rs.OPER_TYPE,rs.OPER_MSG,rs.branch_name,rs.OPERATER,rs.oper_time, rownum row_num from rs)
                 where row_num >= I_BEG_NUM and row_num < I_BEG_NUM + I_FETCH_NUM;
                 
    SELECT count(1) into o_totalNum
      from CAP_TRANS_LOG l where l.trans_id = i_trans_Id;   
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                         
  PROCEDURE PROC_TRANS_APPR_UPDATE(i_trans_Id   in varchar2, --交易流水号
                                    i_quarter   IN VARCHAR2, --add by lish 20160201 根据选择季度获取价格      
                                    i_year   in varchar2,
                                    i_variety    in varchar2,
                                    i_type  in varchar2,
                                    i_price in varchar2,
                                    i_count in varchar2,
                                    i_user_br   in varchar2,
                                    i_userId    IN varchar2,
                                    o_retCode    OUT VARCHAR2)is 
  v_logseq                         CAP_TRANS_LOG.LOG_ID%type;
  BEGIN
    o_retCode := 0;
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
    UPDATE CAP_TRANS_APPLY A
       SET A.TRANS_YEAR    = I_YEAR,
           A.Trans_Quarter = i_quarter,
           A.TRANS_VARIETY = I_VARIETY,
           A.TRANS_TYPE    = I_TYPE,
           A.TRANS_PRICE   = I_PRICE,
           A.TRANS_COUNT   = I_COUNT,
           A.TRANS_STATUS = '1' --待确认
      where A.TRANS_ID = i_trans_Id;
    --日志

      INSERT into CAP_TRANS_LOG
        (LOG_ID,
         TRANS_ID,
         OPER_TYPE,
         OPER_MSG,
         OPERATER,
         OPER_TIME,
         OPER_DEPT,
         OPER_BRANCH)
      VALUES
        (v_logseq, I_TRANS_ID, '0', '修改后提交', i_userId, SYSDATE, '', I_USER_BR);
        
      --邮件待发送
      INSERT INTO CAP_LIMIT_APPRMAIL
        (DATA_DATE,
         RECEIVER_ID,
         RECEIVER_NAME,
         MAIL_TITLE,
         MAIL_ADDRESS,
         MAIL_CONTENT,
         RECEIVER_BRANCH,
         SEND_STATUS,
         LOG_ID)
        SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
               '限额交易待确认',
               u.email,
               '您有限额交易待确认记录需要处理。',
               u.branch_id,
               '0',
               v_logseq
          FROM CTP_USER U, CTP_ROLE_USER_REL R
         WHERE U.BRANCH_ID = i_user_br
           AND U.ID = R.USER_ID
           and U.Email is not null
           AND R.ROLE_ID IN ('201', '301', '401', '601');

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
                           
  PROCEDURE PROC_TRANS_APPR_DEL(i_trans_Id   in varchar2, --交易流水号
                                i_user_br   in varchar2,
                                i_userId    IN varchar2,
                                o_retCode    OUT VARCHAR2)is 
  v_logseq                         CAP_TRANS_LOG.LOG_ID%type;
  BEGIN
    o_retCode := 0;
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
    
    UPDATE CAP_TRANS_APPLY A
       SET A.trans_status = '6' --作废
      where A.TRANS_ID = i_trans_Id;
    
    INSERT into CAP_TRANS_LOG
        (LOG_ID,
         TRANS_ID,
         OPER_TYPE,
         OPER_MSG,
         OPERATER,
         OPER_TIME,
         OPER_DEPT,
         OPER_BRANCH)
      VALUES
        (v_logseq, I_TRANS_ID, '6', '作废', i_userId, SYSDATE, '', I_USER_BR);
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;                                
                                     
                           
  PROCEDURE PROC_TRANS_APPR_DETAIL(i_trans_Id   in varchar2, --交易流水号
                                   o_retCode    OUT VARCHAR2,
                                   o_retList   out ref_result_list)is 
  
  BEGIN
