      RAISE;
  END;     
  
    --审批确认                               
  PROCEDURE PROC_TRANS_APPR_CONFIRM( i_trans_Id   in varchar2, --交易流水号
                                     i_status     in varchar2, --1同意 2 退回
                                     i_apprNote   in varchar2,
                                     i_user_id    in varchar2,
                                     i_branch_id  in varchar2,
                                     o_retCode   OUT VARCHAR2) is 
  v_logseq          CAP_TRANS_LOG.LOG_ID%type;
  v_level           CTP_BRANCH.BRANCH_LEVEL%type;
  v_price           CAP_TRANS_APPLY.TRANS_PRICE%type;
  v_arr1 ctp_type_arraytype;
  v_apprType        CAP_APPROVE_TYPE.APPR_TYPE%type; 
  v_count     number;
  v_accept_branch   CAP_TRANS_APPLY.TRANS_ACCEPT_BRANCH%type;         
  BEGIN
    o_retCode := 0;
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_trans_Id, ',');
    select b.branch_level into v_level from ctp_branch b where b.id = i_branch_id;
    
                         
    
    FOR i IN 1 .. v_arr1.count - 1 LOOP
      
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
    
    select t.trans_accept_branch into v_accept_branch from CAP_TRANS_APPLY t where t.trans_id = v_arr1(i);
    
        --查询审批层级 add20160115
    SELECT count(*) INTO V_COUNT
      FROM CAP_APPROVE_TYPE T
     WHERE T.BRANCH_ID = v_accept_branch
            AND T.END_DATE = '99991231';
           
    if V_COUNT > 0 then
        SELECT t.appr_type INTO v_apprType
          FROM CAP_APPROVE_TYPE T
         WHERE T.BRANCH_ID = v_accept_branch
                AND T.END_DATE = '99991231'; 
    else
        v_apprType :='无';
    end if ;   
    
    --确认后使用的是最新的价格
    SELECT MAX(DECODE(P.TRANS_TYPE, '0', A.SELL_PRICE, A.BUY_PRICE))
      INTO V_PRICE
      FROM CAP_TRANS_OFFER A, CAP_TRANS_APPLY P
     WHERE A.TRANS_YEAR = P.TRANS_YEAR
       AND A.TRANS_VARIETIES = P.TRANS_VARIETY
       AND A.TRANS_BRANCH = P.TRANS_INITIATE
       AND A.TRANS_QUARTER = P.TRANS_QUARTER
       AND A.IN_TRADING = '2'
       AND A.TRANS_LEVEL =
           NVL((SELECT MAX(BRANCH_LEVEL)
                 FROM CTP_BRANCH
                WHERE ID = P.TRANS_ACCEPT_BRANCH), V_LEVEL - 1)
       AND P.TRANS_ID = v_arr1(i)
       AND TO_CHAR(SYSDATE, 'yyyymmdd') BETWEEN A.TRANS_START_TIME AND
           A.TRANS_END_TIME;
           
    if V_APPRTYPE ='无' or V_APPRTYPE = '2' then       
      if i_status = 1 then
         UPDATE CAP_TRANS_APPLY P
         SET TRANS_STATUS = DECODE(I_STATUS, '1', 2, '2', 4),
             TRANS_PRICE = nvl(v_price, P.Trans_Price)
         WHERE TRANS_ID = v_arr1(i);    
      else
         UPDATE CAP_TRANS_APPLY P
           SET TRANS_STATUS = DECODE(I_STATUS, '1', 2, '2', 4)
         WHERE TRANS_ID = v_arr1(i);
      end if;                             
     else
      if i_status = 1 then
         UPDATE CAP_TRANS_APPLY P
         SET TRANS_STATUS = DECODE(I_STATUS, '1', 7, '2', 4),
             TRANS_PRICE = nvl(v_price, P.Trans_Price)
         WHERE TRANS_ID = v_arr1(i); 
      else
         UPDATE CAP_TRANS_APPLY P
           SET TRANS_STATUS = DECODE(I_STATUS, '1', 7, '2', 4)
         WHERE TRANS_ID = v_arr1(i);
      end if;                 
     end if; 
     
     --记录交易日志
     INSERT INTO CAP_TRANS_LOG
       (LOG_ID,
        TRANS_ID,
        OPER_TYPE,
        OPER_MSG,
        OPERATER,
        OPER_TIME,
        OPER_DEPT,
        OPER_BRANCH)
     VALUES
       (v_logseq,
        v_arr1(i),
        DECODE(I_STATUS, '1', 1, '2', 3),
        I_APPRNOTE,
        I_USER_ID,
        sysdate,
        '',
        I_BRANCH_ID);
     
    --邮件待发送记录
     if i_status = '1' then
       if V_APPRTYPE ='无' or V_APPRTYPE = '2' then
        INSERT INTO CAP_LIMIT_APPRMAIL
          (DATA_DATE,
           RECEIVER_ID,
           RECEIVER_NAME,
           MAIL_TITLE,
           MAIL_ADDRESS,
           MAIL_CONTENT,
           RECEIVER_BRANCH,
           SEND_STATUS,
           LOG_ID)
          SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
                 '限额交易待签批',
                 u.email,
                 '您有限额交易待签批记录需要处理。',
                 u.branch_id,
                 '0',
                 v_logseq
            FROM CAP_TRANS_APPLY A, CTP_USER U, CTP_ROLE_USER_REL R
           WHERE A.TRANS_ACCEPT_BRANCH = u.branch_id
             and A.TRANS_ID = v_arr1(i)
             AND U.ID = R.USER_ID
             and U.Email is not null
             AND R.ROLE_ID IN ('201', '301', '401');         
       else  
        INSERT INTO CAP_LIMIT_APPRMAIL
          (DATA_DATE,
           RECEIVER_ID,
           RECEIVER_NAME,
           MAIL_TITLE,
           MAIL_ADDRESS,
           MAIL_CONTENT,
           RECEIVER_BRANCH,
           SEND_STATUS,
           LOG_ID)
          SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
                 '限额交易待核定',
                 u.email,
                 '您有限额交易待核定记录需要处理。',
                 u.branch_id,
                 '0',
                 v_logseq
            FROM CAP_TRANS_APPLY A, CTP_USER U, CTP_ROLE_USER_REL R
           WHERE A.TRANS_INITIATE= u.branch_id
             and A.TRANS_ID = v_arr1(i)
             AND U.ID = R.USER_ID
             and U.Email is not null
             /*AND R.ROLE_ID IN ('201', '301', '401', '601')*/AND R.ROLE_ID IN ('403');
        end if;     

       else
           
       INSERT INTO CAP_LIMIT_APPRMAIL
          (DATA_DATE,
           RECEIVER_ID,
           RECEIVER_NAME,
           MAIL_TITLE,
           MAIL_ADDRESS,
           MAIL_CONTENT,
           RECEIVER_BRANCH,
           SEND_STATUS,
           LOG_ID)
          SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
                 '限额交易退回待修改',
                 u.email,
                 '您有限额交易记录被退回需要处理。',
                 u.branch_id,
                 '0',
                 v_logseq
            FROM CAP_TRANS_APPLY A, CTP_USER U, CTP_ROLE_USER_REL R
           WHERE A.TRANS_INITIATE = u.branch_id
             and A.TRANS_ID = v_arr1(i)
             AND U.ID = R.USER_ID
             and U.Email is not null
             AND R.ROLE_ID IN ('202', '302', '402', '602');           
       end if;            
     
        
     end loop;
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
  PROCEDURE PROC_CHECK_TRANS_PRICE(i_trans_Id   in varchar2, --交易流水号
                                  i_price_list in varchar2, --交易价格列表
                                  i_branch_id  in varchar2,
                                  o_retCode    OUT VARCHAR2) is
  v_level           CTP_BRANCH.BRANCH_LEVEL%type;                                  
  v_price           CAP_TRANS_APPLY.TRANS_PRICE%type;                                  
  v_arr1 ctp_type_arraytype;
  v_arr2 ctp_type_arraytype;
  BEGIN
    o_retCode := 0;
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_trans_Id, ',');
    v_arr2    := FUNC_CTP_LG_GETARRAY(i_price_list, ',');
    select b.branch_level into v_level from ctp_branch b where b.id = i_branch_id;
     
    FOR i IN 1 .. v_arr1.count - 1 LOOP 
        
      --确认后使用的是最新的价格
      SELECT MAX(DECODE(P.TRANS_TYPE, '0', A.SELL_PRICE, A.BUY_PRICE))
        INTO V_PRICE
        FROM CAP_TRANS_OFFER A, CAP_TRANS_APPLY P
       WHERE A.TRANS_YEAR = P.TRANS_YEAR
         AND A.TRANS_VARIETIES = P.TRANS_VARIETY
         AND A.TRANS_BRANCH = P.TRANS_INITIATE
         AND A.TRANS_QUARTER = P.TRANS_QUARTER
         AND A.IN_TRADING = '2'
         AND A.TRANS_LEVEL =
             NVL((SELECT MAX(BRANCH_LEVEL)
                   FROM CTP_BRANCH
                  WHERE ID = P.TRANS_ACCEPT_BRANCH), V_LEVEL - 1)
         AND P.TRANS_ID = v_arr1(i)
         AND TO_CHAR(SYSDATE, 'yyyymmdd') BETWEEN A.TRANS_START_TIME AND
             A.TRANS_END_TIME;
             
      IF V_PRICE <> v_arr2(i) THEN
        o_retCode := -1;
        return;
      END IF;
    end loop;
                                            
    EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
