  PROCEDURE PROC_TRANS_APPR_SIGN( i_trans_Id   in varchar2, --交易流水号
                                  i_status     in varchar2, --1同意 2 退回
                                  i_apprNote   in varchar2,
                                  i_user_id    in varchar2,
                                  i_branch_id  in varchar2,
                                  o_retCode    OUT VARCHAR2) is 
  
   v_logseq          CAP_TRANS_LOG.LOG_ID%type;
   v_arr1 ctp_type_arraytype;
    v_apprType        CAP_APPROVE_TYPE.APPR_TYPE%type; 
    v_count     number;
    v_accept_branch   CAP_TRANS_APPLY.TRANS_ACCEPT_BRANCH%type;                     
  BEGIN
    o_retCode := 0;
    
    v_arr1    := FUNC_CTP_LG_GETARRAY(i_trans_Id, ',');
    FOR i IN 1 .. v_arr1.count - 1 LOOP
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
    
    select t.trans_accept_branch into v_accept_branch from CAP_TRANS_APPLY t where t.trans_id = v_arr1(i);
    
    --查询审批层级 add20160217
    SELECT count(*) INTO V_COUNT
      FROM CAP_APPROVE_TYPE T
     WHERE T.BRANCH_ID = v_accept_branch
            AND T.END_DATE = '99991231';
           
    if V_COUNT > 0 then
        SELECT t.appr_type INTO v_apprType
          FROM CAP_APPROVE_TYPE T
         WHERE T.BRANCH_ID = v_accept_branch
                AND T.END_DATE = '99991231'; 
    else
        v_apprType :='无';
    end if ; 
    
    UPDATE CAP_TRANS_APPLY
       SET TRANS_STATUS = DECODE(I_STATUS, '1', 3, '2', 5) 
     WHERE TRANS_ID = v_arr1(i);
     
     INSERT INTO CAP_TRANS_LOG
       (LOG_ID,
        TRANS_ID,
        OPER_TYPE,
        OPER_MSG,
        OPERATER,
        OPER_TIME,
        OPER_DEPT,
        OPER_BRANCH)
     VALUES
       (v_logseq,
