        I_USER_ID,
        sysdate,
        '',
        I_BRANCH_ID);
        
        if i_status = '2' then --退回发邮件给发起机构
          if V_APPRTYPE ='无' or V_APPRTYPE = '2' then
            INSERT INTO CAP_LIMIT_APPRMAIL
            (DATA_DATE,
             RECEIVER_ID,
             RECEIVER_NAME,
             MAIL_TITLE,
             MAIL_ADDRESS,
             MAIL_CONTENT,
             RECEIVER_BRANCH,
             SEND_STATUS,
             LOG_ID)
            SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
                   '限额交易退回待修改',
                   u.email,
                   '您有限额交易记录被退回需要处理。',
                   u.branch_id,
                   '0',
                   v_logseq
              FROM CAP_TRANS_APPLY A, CTP_USER U, CTP_ROLE_USER_REL R
             WHERE A.TRANS_INITIATE = u.branch_id
               and A.TRANS_ID = v_arr1(i)
               AND U.ID = R.USER_ID
               and U.Email is not null
               AND R.ROLE_ID IN ('301', '302', '401', '402', '601', '602');
           else
            INSERT INTO CAP_LIMIT_APPRMAIL
            (DATA_DATE,
             RECEIVER_ID,
             RECEIVER_NAME,
             MAIL_TITLE,
             MAIL_ADDRESS,
             MAIL_CONTENT,
             RECEIVER_BRANCH,
             SEND_STATUS,
             LOG_ID)
            SELECT distinct to_char(sysdate, 'yyyymmddhh24miss'), u.id, u.name,
                   '限额交易退回待修改',
                   u.email,
                   '您有限额交易记录被退回需要处理。',
                   u.branch_id,
                   '0',
                   v_logseq
              FROM CAP_TRANS_APPLY A, CTP_USER U, CTP_ROLE_USER_REL R
             WHERE A.TRANS_INITIATE = u.branch_id
               and A.TRANS_ID = v_arr1(i)
               AND U.ID = R.USER_ID
               and U.Email is not null
               AND R.ROLE_ID IN ('301', '302', '303', '401', '402', '403', '601', '602', '603');             
           end if;      
        end if;
     end loop;
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
    --交易机构选项获取  add by liukan                             
  PROCEDURE PROC_GET_BRANCH_LIST( i_branch_id   in varchar2, --本级机构号
                                  o_retCode   OUT VARCHAR2,
                                  o_resList out ref_result_list)is 
  v_level       ctp_branch.branch_level%type;
  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branch_id;
    
    open o_resList for 
      select T.id, func_get_branchname(T.id)--* 
      from
      (SELECT B.id, B.NAME
        FROM CTP_BRANCH B
       WHERE B.BRANCH_LEVEL = v_level + 1
       and B.id not in ('01010000','01010011','01020000','01770000',
                            '01780000','45000000','46990000')
       START WITH B.ID = i_branch_id
      CONNECT BY B.PARENT_ID = PRIOR ID 
      union all
       SELECT (ZONE_NO || BR_NO) ID,  ORGAN_NAME name
             FROM PRM_IRA_ORGAN
            WHERE BANK_FLAG = '3'
              AND IS_SALES = '1'
              and v_level = 1
              and end_date = '99991231') T
      --20160125 modify by zhaoxm 原逻辑：order by T.id;
     order by decode(i_branch_id,'01000000',(select sort_no
            from cap_trans_branch_sort
           where trans_branch_id(+) = t.id), t.id);
     
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                                  
  --交易批次获取  add by liukan                             
  PROCEDURE PROC_GET_TRANSDATE_LIST( i_branch_id   in varchar2, --本级机构号
                                     i_year        in varchar2, --年份
                                     i_quarter     in varchar2, --季度     
                                     o_retCode   OUT VARCHAR2,
                                     o_resList out ref_result_list)is 
  v_level       ctp_branch.branch_level%type;
  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branch_id;
    open o_resList for 
      SELECT distinct o.trans_offer_seq, decode(length(o.trans_offer_seq),9, substr(o.trans_offer_seq,6),substr(o.trans_offer_seq,9)) --o.trans_offer_seq  20160129
        FROM CAP_TRANS_OFFER O
       WHERE o.trans_year = i_year
             and o.trans_quarter = i_quarter
             and o.trans_level = v_level
             and O.TRANS_BRANCH IN
             (SELECT B.ID
                FROM CTP_BRANCH B
               WHERE B.BRANCH_LEVEL = V_LEVEL + 1
               START WITH B.ID = i_branch_id
              CONNECT BY B.PARENT_ID = PRIOR ID) order by to_number(o.trans_offer_seq) desc;

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
  --交易机构选项获取  add by liukan  上级行 总行                           
  PROCEDURE PROC_GET_RECVDATE_LIST( i_branch_id   in varchar2, --本级机构号
                                    o_retCode   OUT VARCHAR2,
                                    o_resList out ref_result_list)is 
  v_level       ctp_branch.branch_level%type;
  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branch_id;
     open o_resList for
      SELECT *
       FROM (SELECT '01000000' ID, '总行' NAME
               FROM DUAL
              WHERE i_branch_id IN (SELECT ZONE_NO || BR_NO
                                     FROM PRM_IRA_ORGAN
                                    WHERE BANK_FLAG = '3'
                                      AND IS_SALES = '1'
                                      and end_date = '99991231') --如果是营业厅可以同时与上级行和总行交易
             UNION ALL
             SELECT B.ID, func_get_branchname(B.id)--B.NAME
               FROM CTP_BRANCH B
              WHERE B.BRANCH_LEVEL = v_level - 1
              and B.id not in ('01010000','01010011','01020000','01770000',
                            '01780000','45000000','46990000')
              START WITH B.ID = i_branch_id
             CONNECT BY PRIOR B.PARENT_ID = ID) T
      ORDER BY T.ID;

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
   --价格导入模板导出 add by liukan                             
  PROCEDURE PROC_GET_PRICEIMP_TMP( i_branch_id   in varchar2, --本级机构号
                                   i_quarters   in varchar2, --季度
                                   O_FLAG   OUT VARCHAR2,
                                   o_TOTALNUM  out number,
                                   o_resList out ref_result_list) is 
  v_level       ctp_branch.branch_level%type;

  BEGIN
    O_FLAG := 0;
    o_TOTALNUM := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branch_id;
    
    SELECT count(1) into o_TOTALNUM
       from (select 1 FROM CTP_BRANCH B
       WHERE B.BRANCH_LEVEL = v_level + 1
       and B.id not in ('01010000','01010011','01020000','01770000',
                            '01780000','45000000','46990000')
       START WITH B.ID = i_branch_id
      CONNECT BY  B.PARENT_ID =  PRIOR ID 
      union all 
        SELECT 1
             FROM PRM_IRA_ORGAN
            WHERE BANK_FLAG = '3'
              AND IS_SALES = '1'
              and v_level = 1
              and end_date = '99991231');
              
