               FROM PRM_IRA_ORGAN
              WHERE BANK_FLAG = '3'
                AND IS_SALES = '1'
                and v_level = 1
                and end_date = '99991231') T 
           --20160125 modify by zhaoxm 原逻辑：order by T.id;
           order by decode(i_branch_id ,'01000000',
                        (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = t.id),
                       t.id);
     ELSIF i_quarters = '3' THEN
       open o_resList for 
       select func_get_branchname(t.id), t.id, t.a, t.b, t.c, t.d--T.* 
       from
        (SELECT B.NAME, B.id id, '' a, '' b, '' c, '' d
          FROM CTP_BRANCH B
         WHERE B.BRANCH_LEVEL = v_level + 1
         and B.id not in ('01010000','01010011','01020000','01770000',
                              '01780000','45000000','46990000')
         START WITH B.ID = i_branch_id
        CONNECT BY  B.PARENT_ID =  PRIOR ID 
        union all 
