  --限额列表 add by liukan
  PROCEDURE PROC_TRANS_LIMIT_LIST(  i_user_br   in varchar2, --用户机构
                                    i_year      in varchar2,
                                    i_quarter   IN VARCHAR2,
                                    o_retCode   OUT VARCHAR2,
                                    o_totalNum  out number,
                                    o_retList   out ref_result_list) is 
  BEGIN
    o_retCode := 0;
    
    SELECT COUNT(1)
      INTO O_TOTALNUM
      FROM CAP_TRANS_LIMIT L
     WHERE L.LIMIT_YEAR = I_YEAR
       AND L.LIMIT_TYPE = I_QUARTER
       AND L.CREATE_BRANCH = I_USER_BR;
    
     open o_retList for 
       SELECT func_get_branchname(L.LIMIT_BRANCH),
              L.LIMIT_INIT,
              L.LIMIT_MIN,
              L.LIMIT_TYPE,
              TO_CHAR(L.CREATE_TIME, 'yyyy-mm-dd hh24:mi:ss')
         FROM CAP_TRANS_LIMIT L
        WHERE L.LIMIT_YEAR = I_YEAR
          AND L.LIMIT_TYPE = I_QUARTER
          AND L.CREATE_BRANCH = I_USER_BR 
          --20160125 modify by zhaoxm 原逻辑：order by L.LIMIT_BRANCH;
          order by decode(i_user_br ,'01000000',
                        (select sort_no from cap_trans_branch_sort where trans_branch_id(+) = L.LIMIT_BRANCH),
                       L.LIMIT_BRANCH);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
                                    
   --限额导入
  PROCEDURE PROC_TRANS_LIMIT_IMP(i_branchId  IN VARCHAR2,
                                 i_userId    IN VARCHAR2,
                                 i_year       IN VARCHAR2,
                                 i_quarter   IN VARCHAR2,
                                 i_initlimit IN VARCHAR2,
                                 i_minlimit IN VARCHAR2, 
                                 o_retCode   OUT VARCHAR2) is 
  v_level       ctp_branch.branch_level%type;
  v_user_br     ctp_user.branch_id%type;
  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branchId;
    
    select max(c.branch_id) into v_user_br from ctp_user c where c.id = i_userId;
    
    delete CAP_TRANS_LIMIT L where L.LIMIT_BRANCH = i_branchId and L.LIMIT_YEAR = i_year and L.LIMIT_TYPE = i_quarter
           and L.CREATE_BRANCH = v_user_br;
    
    INSERT INTO CAP_TRANS_LIMIT
      (LIMIT_BRANCH,
       LIMIT_BRANCH_LV,
       LIMIT_YEAR,
       LIMIT_TYPE,
       LIMIT_MIN,
       CREATER,
       CREATE_TIME,
       CREATE_BRANCH,
       LIMIT_INIT)
    VALUES
      (I_BRANCHID,
       V_LEVEL,
       I_YEAR,
       I_QUARTER,
       I_MINLIMIT,
       I_USERID,
       SYSDATE,
       V_USER_BR,
       I_INITLIMIT);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
  --增量导入
  PROCEDURE PROC_TRANS_INC_IMP(i_branchId  IN VARCHAR2,
                               i_userId    IN VARCHAR2,
                               i_year       IN VARCHAR2,
                               i_quarter   IN VARCHAR2,
                               i_increment IN VARCHAR2,
                               o_retCode   OUT VARCHAR2)  is 
  v_level       ctp_branch.branch_level%type;
  v_user_br     ctp_user.branch_id%type;
  BEGIN
    o_retCode := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_branchId;
    
    select max(c.branch_id) into v_user_br from ctp_user c where c.id = i_userId;
    
    DELETE CAP_REAL_INCREMENT L
     WHERE L.INC_BRANCH = I_BRANCHID
       AND L.INC_YEAR = I_YEAR
       AND L.INC_TYPE = I_QUARTER
       and L.CREATE_BRANCH = v_user_br;
    
    INSERT INTO CAP_REAL_INCREMENT
      (INC_BRANCH,
       INC_BRANCH_LV,
       INC_YEAR,
       INC_TYPE,
       INC_COUNT,
       CREATER,
       CREATE_TIME,
       CREATE_BRANCH)
    VALUES
      (I_BRANCHID,
       V_LEVEL,
       I_YEAR,
       I_QUARTER,
       i_increment,
       I_USERID,
       SYSDATE,
       V_USER_BR);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
  
