  PROCEDURE PROC_VALIDATE_BRANCH(i_user_br   in varchar2,
                                 i_branch_id in varchar2, --本级机构号
                                 O_FLAG   OUT VARCHAR2) is 
  v_level       ctp_branch.branch_level%type;
  BEGIN
    O_FLAG := 0;
    select max(b.branch_level) into v_level from ctp_branch b where b.id = i_user_br;

      select count(1) into o_flag from dual where i_branch_id in(
              SELECT B.id FROM CTP_BRANCH B
                         WHERE B.BRANCH_LEVEL = v_level + 1
