                    SELECT (ZONE_NO || BR_NO) ID
                               FROM PRM_IRA_ORGAN
                              WHERE BANK_FLAG = '3'
                                AND IS_SALES = '1'
                                and v_level = 1
                                and end_date = '99991231');

  EXCEPTION
