  --生成交易价格导入所用的批次号
  ---20160115“交易价格设置”中的“新增批次导入” 是 覆盖 “未确认”的批次，若没有“未确认”的批次，则新增一个批次。序列号是每家分行连续。    
  FUNCTION FUNC_GENERATE_PRICE_IMPSEQ(i_year      in varchar2,
                                 i_quarter   in varchar2,
                                 i_userbr_id in varchar2 --登陆用户机构
                                 ) RETURN varchar2 IS
    v_seq  CAP_TRANS_OFFER.TRANS_OFFER_SEQ%type;
    v_cnt integer;

  BEGIN
    v_seq := 0;    
    
    --查找是否存在“未确认”批次
    select count(distinct o.trans_offer_seq) into v_cnt
      from CAP_TRANS_OFFER o
     where o.trans_year = i_year
       and o.trans_quarter = i_quarter
       and substr(o.trans_offer_seq,1,8) = i_userbr_id
       and o.confirm = '2';
    
    if v_cnt = 0 then --没有“未确认”的批次，则新增一个批次
      
       select i_userbr_id || i_year || i_quarter || lpad(nvl(max(substr(o.trans_offer_seq, 14, 4)),0)+1,4,'0') into v_seq
        from CAP_TRANS_OFFER o
       where substr(o.trans_offer_seq,1,8) = i_userbr_id
         and o.trans_year = i_year
         and o.trans_quarter = i_quarter;
      
    else  --有“未确认”批次，则覆盖批次号最大的一个
       select max(distinct o.trans_offer_seq) into v_seq
        from CAP_TRANS_OFFER o
       where o.trans_year = i_year
         and o.trans_quarter = i_quarter
         and substr(o.trans_offer_seq,1,8) = i_userbr_id
         and o.confirm = '2';
    end if;  
    
    return v_seq;
  
    EXCEPTION
      WHEN OTHERS
      THEN
           return 0;
  END;
 PROCEDURE PROC_TRANS_CLOSE_JOB(
                               o_retCode   OUT VARCHAR2)  is 
 v_logseq                         CAP_TRANS_LOG.LOG_ID%type;
  BEGIN
    o_retCode := 0;
                 
    for i in (
      SELECT t.trans_id FROM (select o.trans_branch,o.trans_year,o.trans_varieties,o.trans_quarter from CAP_TRANS_OFFER O where (o.TRANS_END_TIME < TO_CHAR(SYSDATE, 'yyyymmdd') 
                  OR o.TRANS_START_TIME > TO_CHAR(SYSDATE, 'yyyymmdd')) 
                  AND o.IN_TRADING = 2) A, CAP_TRANS_APPLY T WHERE t.trans_initiate = a.trans_branch and t.trans_year = a.trans_year and t.trans_variety = a.trans_varieties and t.trans_quarter = a.trans_quarter
     
     and t.trans_status not in ('2', '3', '6') 
      
    ) loop 
    
    update cap_trans_apply t set t.trans_status = '6' where t.trans_id = i.trans_id;
     
    select 'TL' || to_char(sysdate, 'yyyymmdd') || lpad(seq_tanslog.Nextval,5,'0') into v_logseq from dual;
         --记录交易日志
         
   INSERT into CAP_TRANS_LOG
        (LOG_ID,
         TRANS_ID,
         OPER_TYPE,
         OPER_MSG,
         OPERATER,
         OPER_TIME,
         OPER_DEPT,
         OPER_BRANCH)
      VALUES
        (v_logseq, i.trans_id, '7', '作废', '系统操作', SYSDATE, '', ''); 
        
    end loop;
    
    UPDATE CAP_TRANS_OFFER 
              SET IN_TRADING = '1' 
              WHERE (TRANS_END_TIME < TO_CHAR(SYSDATE, 'yyyymmdd') 
              OR TRANS_START_TIME > TO_CHAR(SYSDATE, 'yyyymmdd')) 
              AND IN_TRADING = '2';                  

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_retCode := SQLCODE;
      RAISE;
  END;
   
 END PCKG_CAP_TRANS;
