CREATE OR REPLACE PACKAGE PCKG_UTP_R_TOOLKIT AUTHID DEFINER IS
  /******************************************************************************
      程序包名称: PCKG_UTP_R_TOOLKIT
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      功能描述：提供各种常见案例功能模块的封装内容
  ******************************************************************************/

  /******************************************************************************
      程序名称: PROC_UTP_TAB_BACKUP
      模块名称: 数据准备--按后缀名备份多表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本前将原环境中表进行备份
      处理逻辑：根据配置表中配置的所有本次涉及的表，将数据表备份到指定后缀名标识的表中，
      当前默认后缀标识为 _B$
  ******************************************************************************/

  procedure PROC_UTP_TAB_BACKUP(TABLE_PRE IN VARCHAR2,
                                TABLE_FLG IN VARCHAR2 DEFAULT '_B$');
  /******************************************************************************
      程序名称: PROC_UTP_TAB_BACKUP_AS
      模块名称: 数据准备--按后缀名创建多表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本前将原环境中表进行加后缀创建临时表
      处理逻辑：按数据表加后缀创建相关表结构的空表，用于放期望值等，当前默认后缀标识为 _E$
  ******************************************************************************/

  PROCEDURE PROC_UTP_TAB_BACKUP_AS(TABLE_PRE  IN VARCHAR2,
                                   TABLE_AS   IN VARCHAR2);

  procedure PROC_UTP_TAB_CREATE(TABLE_PRE IN VARCHAR2,
                                TABLE_FLG IN VARCHAR2 DEFAULT '_E$');

  /******************************************************************************
      程序名称: PROC_UTP_TAB_CREATE_AS
      模块名称: 数据准备--按后缀名创建多表
      版本号：1.0.0
      创建日期：2016-12-08
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本前将原环境中表根据指定表名创建临时表
      处理逻辑：按数据表加后缀创建相关表结构的空表，用于放期望值等，当前默认后缀标识为 _E$
  ******************************************************************************/
  PROCEDURE PROC_UTP_TAB_CREATE_AS(TABLE_PRE  IN VARCHAR2,
                                   TABLE_AS   IN VARCHAR2);

  /******************************************************************************
      程序名称: PROC_UTP_TAB_RESTORE
      模块名称: 数据清理--按后缀名恢复多表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将原先备份的表进行恢复
      处理逻辑：根据配置表中配置的所有本次涉及的表，将备份的内容恢复到原表,
      当前默认原表加后缀名的备份表中恢复到原表中，后缀名默认为_B$
  ******************************************************************************/

  procedure PROC_UTP_TAB_RESTORE(TABLE_PRE IN VARCHAR2,
                                 TABLE_FLG IN VARCHAR2 DEFAULT '_B$');


  /******************************************************************************
      程序名称: PROC_UTP_TAB_RESTORE_FROM
      模块名称: 数据准备--恢复表
      版本号：1.0.0
      创建日期：2016-12-08
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将原先备份的表从指定备份表进行恢复
      处理逻辑：根据配置表中配置的所有本次涉及的表，将备份的内容恢复到原表
  ******************************************************************************/
  PROCEDURE PROC_UTP_TAB_RESTORE_FROM(TABLE_PRE  IN VARCHAR2,
                                      TABLE_AS   IN VARCHAR2);
  /******************************************************************************
      程序名称: PROC_UTP_TAB_DROP
