      处理逻辑：根据所有本次涉及的表，进行多表删除操作，期望临时表后缀名默认为_E$
  ******************************************************************************/
  PROCEDURE PROC_UTP_TAB_DROP_FROM(TABLE_PRE  IN VARCHAR2,
                                   TABLE_FROM IN VARCHAR2);

  /******************************************************************************
      程序名称: PROC_UTP_FILE_2TAB
      模块名称: 数据文件导入到数据库指定表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      发布类型：公开发布
      程序功能：执行自动测试脚本时将数据文件解析格式，导入到数据库表中
      处理逻辑：根据本次涉及的文件和表，将文件数据导入到指定表中
  ******************************************************************************/
  PROCEDURE PROC_UTP_FILE_2TAB(Psi_tableName     IN VARCHAR2, -- 将要load数据的表名
                               Psi_fileNames     IN VARCHAR2, -- 文件名，多文件以逗号分隔
                               Psi_filePath      IN VARCHAR2, -- 文件所在的逻辑目录
                               Pni_skipRecords   IN NUMBER DEFAULT 0, -- 忽略的记录数，默认全部导入
                               Psi_fieldTerminal IN VARCHAR2 DEFAULT ',', -- 文件中的字段分隔符,
                               Psi_enclosed      IN VARCHAR2 DEFAULT '', --字段引用符
                               Psi_tableOwner    IN VARCHAR2 DEFAULT '', --load表的所属用户，默认为当前用户
                               Psi_dataFormat    IN VARCHAR2 DEFAULT 'YYYY-MM-DD HH24:MI:SS' --日期格式
                               );

