      程序功能：执行自动测试脚本前将原环境中表进行备份
      处理逻辑：根据参数，通过重命名逻辑模拟表备份逻辑，提升大表处理效率
  ******************************************************************************/

  PROCEDURE PROC_BIG_TAB_BACKUP (TABLE_PRE IN VARCHAR2,
                                 TABLE_FLG IN VARCHAR2 DEFAULT '_B$');



  PROCEDURE PROC_BIG_TAB_RESTORE (TABLE_PRE IN VARCHAR2,
                                  TABLE_FLG IN VARCHAR2 DEFAULT '_B$');
END PCKG_UTP_R_TOOLKIT;
//

CREATE OR REPLACE PACKAGE BODY PCKG_UTP_R_TOOLKIT IS


  procedure PROC_UTP_TAB_BACKUP(TABLE_PRE IN VARCHAR2,
                                TABLE_FLG IN VARCHAR2 DEFAULT '_B$') is
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_exist EXCEPTION;
  BEGIN

    -----判断这些待备份的表是否有已存在备份表的情况,REPLACE(TABLE_PRE,' ','')进行去空格处理
      -----判断这些待备份的表是否有已存在备份表的情况,REPLACE(TABLE_PRE,' ','')进行去空格处理
    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(REPLACE(TABLE_PRE, ' ', ''),
                                              ',',
                                              '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE , ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(REPLACE(TABLE_PRE, ' ', ''), ',', '')) + 1));
    ------如果没有临时备份表存在的话，则进行逐个备份的操作，REPLACE(TABLE_PRE,' ','')去空格处理
    IF tab_count = 0 THEN
      FOR X IN (SELECT table_name AS table_name_A,
                       table_name || NVL(TABLE_FLG,'_B$') AS table_name_B
                  FROM (SELECT TRIM(SUBSTR(txt,
                                           INSTR(txt, ',', 1, LEVEL) + 1,
                                           INSTR(txt, ',', 1, LEVEL + 1) -
                                           INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                          FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                                  FROM DUAL)
                        CONNECT BY LEVEL <=
                                   LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                                   LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1)) LOOP
        vs_sql := 'CREATE /*+ PARALLEL */ TABLE ' || X.table_name_B || ' as select * from ' ||
                  X.table_name_A;
        EXECUTE IMMEDIATE vs_sql;
        vs_sql := 'TRUNCATE TABLE ' || X.table_name_A;
        EXECUTE IMMEDIATE vs_sql;
      END LOOP;
      NULL;
       --P_O_SUCCESS := '0';

    ELSE
      RAISE tab_exist;
    END IF;

  exception
    when tab_exist then
       --P_O_SUCCESS := '1';
      DBMS_OUTPUT.put_line('临时表名已存在于环境上,请检查!');
    when others then
      -- P_O_SUCCESS := '1';
      os_msg := '备份表' || TABLE_PRE || '出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);

  end;

   /******************************************************************************
      程序名称: PROC_UTP_TAB_BACKUP_AS
      模块名称: 数据准备--备份表
      版本号：1.0.0
      创建日期：2016-12-08
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本前将原环境中表根据指定备份表名进行备份
      处理逻辑：根据配置表中配置的所有本次涉及的表，将数据表备份到UT_开头的表中
  ******************************************************************************/

  PROCEDURE PROC_UTP_TAB_BACKUP_AS(TABLE_PRE  IN VARCHAR2,
