      DBMS_OUTPUT.put_line(os_msg);
  END;

  /******************************************************************************
      程序名称: PROC_UTP_TAB_CREATE
      模块名称: 数据准备--按后缀名创建多表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本前将原环境中表进行加后缀创建临时表
      处理逻辑：按数据表加后缀创建相关表结构的空表，用于放期望值等，当前默认后缀标识为 _E$
  ******************************************************************************/
  procedure PROC_UTP_TAB_CREATE(TABLE_PRE IN VARCHAR2,
                                TABLE_FLG IN VARCHAR2 DEFAULT '_E$') is
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_exist EXCEPTION;
  BEGIN

    -----判断这些待备份的表是否有已存在备份表的情况,REPLACE(TABLE_PRE,' ','')进行去空格处理
    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_E$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(REPLACE(TABLE_PRE, ' ', ''),
                                              ',',
                                              '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_E$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1));

    ------如果没有临时备份表存在的话，则进行逐个备份的操作，REPLACE(TABLE_PRE,' ','')去空格处理
    IF tab_count = 0 THEN
      FOR X IN (SELECT table_name AS table_name_A,
                       table_name || NVL(TABLE_FLG,'_E$') AS table_name_B
                  FROM (SELECT TRIM(SUBSTR(txt,
                                           INSTR(txt, ',', 1, LEVEL) + 1,
                                           INSTR(txt, ',', 1, LEVEL + 1) -
                                           INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                          FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                                  FROM DUAL)
                        CONNECT BY LEVEL <=
                                   LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                                   LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1)) LOOP
        vs_sql := 'CREATE /*+ PARALLEL */ TABLE ' || X.table_name_B || ' as select * from ' ||
                  X.table_name_A || ' WHERE 1=2 ';
        EXECUTE IMMEDIATE vs_sql;
        vs_sql := 'TRUNCATE TABLE ' || X.table_name_A;
        EXECUTE IMMEDIATE vs_sql;
      END LOOP;
      -- P_O_SUCCESS := '0';

    ELSE
      RAISE tab_exist;
    END IF;

  exception
    when tab_exist then
      -- P_O_SUCCESS := '1';
      DBMS_OUTPUT.put_line('临时创建表名已存在于环境上,请检查!');
    when others then
      -- P_O_SUCCESS := '1';
      os_msg := '对表' || TABLE_PRE || '创建后缀临时表出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);

  end;

