  /******************************************************************************
      程序名称: PROC_UTP_TAB_RESTORE
      模块名称: 数据准备--恢复表
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将原先备份的表进行恢复
      处理逻辑：根据配置表中配置的所有本次涉及的表，将备份的内容恢复到原表
  ******************************************************************************/

  procedure PROC_UTP_TAB_RESTORE(TABLE_PRE IN VARCHAR2,
                                 TABLE_FLG IN VARCHAR2 DEFAULT '_B$') is
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_noexist EXCEPTION;
    V_TABLE_PRE VARCHAR2(100);
  begin
    V_TABLE_PRE:=UPPER(TABLE_PRE);

    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(V_TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(V_TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(V_TABLE_PRE, ',', '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(V_TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(V_TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(V_TABLE_PRE, ',', '')) + 1));

    IF tab_count <> 0 THEN
      FOR X IN (SELECT table_name AS table_name_C, --还原表名，此表待还原
                       table_name || NVL(TABLE_FLG,'_B$') AS table_name_D --临时备份表名，此表待清除
                  FROM (SELECT TRIM(SUBSTR(txt,
                                           INSTR(txt, ',', 1, LEVEL) + 1,
                                           INSTR(txt, ',', 1, LEVEL + 1) -
                                           INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                          FROM (SELECT ',' || REPLACE(V_TABLE_PRE, ' ', '') || ',' txt
                                  FROM DUAL)
                        CONNECT BY LEVEL <=
                                   LENGTH(REPLACE(V_TABLE_PRE, ' ', '')) -
                                   LENGTH(REPLACE(V_TABLE_PRE, ',', '')) + 1)) LOOP

        vs_sql := 'TRUNCATE TABLE ' || X.table_name_C;
        EXECUTE IMMEDIATE vs_sql;
        vs_sql := 'INSERT /*+ PARALLEL */ INTO ' || X.table_name_C || ' SELECT * FROM ' ||
                  X.table_name_D;
        EXECUTE IMMEDIATE vs_sql;
        --删除临时备份表
        vs_sql := 'DROP TABLE ' || X.table_name_D || ' PURGE';
        EXECUTE IMMEDIATE vs_sql;

      END LOOP;

      --P_O_SUCCESS := '0';
    ELSE
      RAISE tab_noexist;
    END IF;

  exception
    when tab_noexist then
      --P_O_SUCCESS := '1';
      DBMS_OUTPUT.put_line('待清理的备份表名已不存在,请检查!');
    when others then
      --P_O_SUCCESS := '1';
      os_msg := '恢复表' || V_TABLE_PRE || '出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);
  end;

  /******************************************************************************
      程序名称: PROC_UTP_TAB_RESTORE
      模块名称: 数据准备--恢复表
      版本号：1.0.0
      创建日期：2016-12-08
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将原先备份的表从指定备份表进行恢复
      处理逻辑：根据配置表中配置的所有本次涉及的表，将备份的内容恢复到原表
  ******************************************************************************/
  PROCEDURE PROC_UTP_TAB_RESTORE_FROM(TABLE_PRE  IN VARCHAR2,
                                      TABLE_AS   IN VARCHAR2) IS
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_noexist EXCEPTION;
  BEGIN
   SELECT COUNT(1)
     INTO tab_count
     FROM all_tables at
    WHERE UPPER(at.table_name) = UPPER(TABLE_AS);

  IF tab_count <> 0 THEN
    vs_sql := 'TRUNCATE TABLE ' || UPPER(TABLE_PRE);
    EXECUTE IMMEDIATE vs_sql;
    vs_sql := ' INSERT /*+ PARALLEL */ INTO ' || UPPER(TABLE_PRE) || ' SELECT * FROM ' || UPPER(TABLE_AS);
    EXECUTE IMMEDIATE vs_sql;
    vs_sql := ' DROP TABLE ' || UPPER(TABLE_AS) || ' PURGE';
    EXECUTE IMMEDIATE vs_sql;
  ELSE
    RAISE tab_noexist;
  END IF;

  exception
    when tab_noexist then
      DBMS_OUTPUT.put_line('待清理的备份表名已不存在,请检查!');
    when others then
      os_msg := '恢复表' || TABLE_PRE || '出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);
  END;
  /******************************************************************************
      程序名称: PROC_UTP_TAB_DROP
      模块名称: 数据清理--多表删除
      版本号：1.0.0
      创建日期：2013-07-17
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将临时存放对应测试数据的期望临时表进行删除
      处理逻辑：根据所有本次涉及的表，进行多表删除操作，期望临时表后缀名默认为_E$
  ******************************************************************************/
  procedure PROC_UTP_TAB_DROP(TABLE_PRE IN VARCHAR2,
                              TABLE_FLG IN VARCHAR2 DEFAULT '_E$') is
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_noexist EXCEPTION;
  begin

    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_E$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_E$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                               LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1));

    IF tab_count <> 0 THEN
      FOR X IN (SELECT table_name || NVL(TABLE_FLG,'_E$') AS table_name_E --临时备份表名，此表待清除
                  FROM (SELECT TRIM(SUBSTR(txt,
                                           INSTR(txt, ',', 1, LEVEL) + 1,
                                           INSTR(txt, ',', 1, LEVEL + 1) -
                                           INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                          FROM (SELECT ',' || REPLACE(TABLE_PRE, ' ', '') || ',' txt
                                  FROM DUAL)
                        CONNECT BY LEVEL <=
                                   LENGTH(REPLACE(TABLE_PRE, ' ', '')) -
                                   LENGTH(REPLACE(TABLE_PRE, ',', '')) + 1)) LOOP

        --删除临时数据表
        vs_sql := 'DROP TABLE ' || X.table_name_E || ' PURGE';
        EXECUTE IMMEDIATE vs_sql;

      END LOOP;

      --P_O_SUCCESS := '0';
    ELSE
      RAISE tab_noexist;
    END IF;

  exception
    when tab_noexist then
      --P_O_SUCCESS := '1';
      DBMS_OUTPUT.put_line('待删除的后缀临时表名已不存在,请检查!');
    when others then
      --P_O_SUCCESS := '1';
      os_msg := '删除表' || TABLE_PRE || '加后缀名的表出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);
  end;

    /******************************************************************************
      程序名称: PROC_UTP_TAB_DROP_FROM
      模块名称: 数据清理--多表删除
      版本号：1.0.0
      创建日期：2016-12-08
      创建作者：持续集成研究小组 上海研发部
      程序功能：执行自动测试脚本后将临时存放对应测试数据的指定表名期望临时表进行删除
      处理逻辑：根据所有本次涉及的表，进行多表删除操作，期望临时表后缀名默认为_E$
  ******************************************************************************/
  PROCEDURE PROC_UTP_TAB_DROP_FROM(TABLE_PRE  IN VARCHAR2,
                                   TABLE_FROM IN VARCHAR2) IS
    vs_sql    varchar2(500);
    os_msg    varchar2(100);
    tab_count NUMBER(10);
    tab_noexist EXCEPTION;
  BEGIN
   SELECT COUNT(1)
     INTO tab_count
     FROM all_tables at
    WHERE UPPER(at.table_name) = UPPER(TABLE_FROM);

   IF tab_count <> 0 THEN
     vs_sql := ' DROP TABLE ' || UPPER(TABLE_FROM) || ' PURGE ';
     EXECUTE IMMEDIATE vs_sql;
   ELSE
     RAISE tab_noexist;
   END IF;

  exception
    when tab_noexist then
      DBMS_OUTPUT.put_line('待删除的后缀临时表名已不存在,请检查!');
    when others then
      os_msg := '删除表' || TABLE_PRE || '加后缀名的表出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);
  END;

  PROCEDURE PROC_UTP_FILE_2TAB(Psi_tableName     IN VARCHAR2, -- 将要load数据的表名
                               Psi_fileNames     IN VARCHAR2, -- 文件名，多文件以逗号分隔
                               Psi_filePath      IN VARCHAR2, -- 文件所在的目录K路径
                               Pni_skipRecords   IN NUMBER DEFAULT 0, -- 忽略的记录数，默认全部导入
                               Psi_fieldTerminal IN VARCHAR2 DEFAULT ',', -- 文件中的字段分隔符,可以使用CHR(27)等其他分隔符
                               Psi_enclosed      IN VARCHAR2 DEFAULT '', --字段引用符
                               Psi_tableOwner    IN VARCHAR2 DEFAULT '', --load表的所属用户，默认为当前用户
                               Psi_dataFormat    IN VARCHAR2 DEFAULT 'YYYY-MM-DD HH24:MI:SS' --日期格式
                               )
  /******************************************************************************
        程序名称: PROC_UTP_FILE_2TAB
        模块名称: 数据文件导入到数据库指定表
        版本号：1.0.0
        创建日期：2013-07-17
        创建作者：持续集成研究小组 上海研发部
        发布类型：公开发布
        程序功能：执行自动测试脚本时将数据文件解析格式，导入到数据库表中
        处理逻辑：根据本次涉及的文件和表，将文件数据导入到指定表中
    ******************************************************************************/
   IS

    ls_column_name varchar(500) := NULL;

    ls_table_name VARCHAR2(500) := upper(Psi_tableName);
    ls_file_name  VARCHAR2(500) := replace(replace(Psi_fileNames,
                                                  ',',
                                                  ''','''),
                                          ' ');
    ls_tableOwner VARCHAR2(300) := NULL;
    ls_dataFormat VARCHAR2(500) := NVL(Psi_dataFormat,
                                      'YYYY-MM-DD HH24:MI:SS');

    ls_enclosed VARCHAR2(2000) := NULL;
    ls_terminal VARCHAR2(2000) := NULL;

    ls_table_squence VARCHAR2(2000) := NULL;
    ls_ex_tablename  VARCHAR2(2000) := 'load_temp';

    ls_table_columns VARCHAR2(32767) := NULL;
    ls_table_col_ctl VARCHAR2(32767) := NULL; --FIELDS 里面文本数据格式化

    v_block          VARCHAR2(32767) := NULL;
    v_dot            NUMBER(3) := 0;
    --v_sql            VARCHAR2(2000) := NULL;
    --不再进行目录的每次创建，由数据库管理员统一创建完成20130927
    v_dir VARCHAR2(2000) :=  'LINK';
    --20130927 end

    CURSOR tab_col IS
      SELECT column_name,
             data_type,
             data_precision,
             data_scale,
             char_length
        FROM all_tab_columns
       WHERE (table_name = ls_table_name AND owner = ls_tableOwner)
          OR (OWNER || '.' || table_name = UPPER(ls_table_name))
       ORDER BY column_id;

  BEGIN
    SELECT INSTR(ls_table_name, '.') INTO v_dot FROM DUAL; ------20130722-----SH.SDC.ICBC.COM.CN
    ----CREATE OR REPLACE DIRECTORY MY_UT_DATA AS Psi_filePath---------20130726
    /*v_sql := ' GRANT READ, WRITE ON DIRECTORY MY_UT_DATA TO PUBLIC ';
      EXECUTE IMMEDIATE v_sql;
    */

    --不再进行目录的每次创建，由数据库管理员统一创建完成20130927
    --pckg_utp_r_directory_util.utp_create_directory(Psi_filePath, v_dir);
    --20130927 end

    IF Psi_tableOwner IS NULL THEN
      IF v_dot = 0 THEN
        ------20130722-----SH.SDC.ICBC.COM.CN -------START-----------
        SELECT SYS_CONTEXT('USERENV', 'SESSION_USER')
          INTO ls_tableOwner
          FROM DUAL;
      ELSE
        SELECT SUBSTR(upper(Psi_tableName), 1, v_dot - 1)
          INTO ls_tableOwner
          FROM DUAL;
      END IF; ------20130722-----SH.SDC.ICBC.COM.CN --------END-------------
    ELSE
      ls_tableOwner := Psi_tableOwner;
    END IF;
    -- 保证表名带有表用户前缀
    IF v_dot = 0 THEN
      ls_table_name := ls_tableOwner || '.' || ls_table_name;
    END IF;

    -----用于重建外部表字段 ls_table_columns--------------------------------------
    FOR cc IN tab_col LOOP
      SELECT '"' || cc.column_name || '"' INTO ls_column_name FROM dual;
      IF cc.data_type = 'NUMBER' THEN
        IF cc.data_precision IS NOT NULL THEN
          ls_table_columns := ls_table_columns || ls_column_name ||
                              ' NUMBER(' || cc.data_precision || ',' ||
                              cc.data_scale || '),' || CHR(10);
        ELSE
          ls_table_columns := ls_table_columns || ls_column_name ||
                              ' NUMBER,' || CHR(10);
        END IF;

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(10000),' ||
                            CHR(10);
      ELSIF cc.data_type in ('VARCHAR2', 'CHAR', 'NCHAR', 'NVARCHAR2') THEN
        ls_table_columns := ls_table_columns || ls_column_name || ' ' ||
                            cc.data_type || '(' || cc.char_length || '),' ||
                            CHR(10);

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(10000),' ||
                            CHR(10);
      ELSIF cc.data_type = 'DATE' THEN
        ls_table_columns := ls_table_columns || ls_column_name || ' DATE,' ||
                            CHR(10);

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name ||
                            ' CHAR date_format DATE mask "' ||
                            ls_dataFormat || '",' || CHR(10);
      ELSIF cc.data_type = 'TIMESTAMP(6)' THEN
        ls_table_columns := ls_table_columns || ls_column_name || ' TIMESTAMP,' ||
                            CHR(10);

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name ||
                            ' CHAR date_format TIMESTAMP mask "' ||
                            ls_dataFormat || '",' || CHR(10);
      ELSE
        ls_table_columns := ls_table_columns || ls_column_name || ' ' ||
                            cc.data_type || ',' || CHR(10);
        ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(10000),' ||
                            CHR(10);
      END IF;

    END LOOP;
    ls_table_columns := rtrim(rtrim(ls_table_columns, CHR(10)), ',');
    ls_table_col_ctl := rtrim(rtrim(ls_table_col_ctl, CHR(10)), ',');

    --配置外部表参数
    IF Psi_enclosed IS NULL THEN
      ls_enclosed := '';
    ELSIF Psi_enclosed = '''' THEN

      ls_enclosed := 'OPTIONALLY ENCLOSED BY "''"';
    ELSE
      ls_enclosed := 'OPTIONALLY ENCLOSED BY ''' || Psi_enclosed || '''';
    END IF;

    IF Psi_fieldTerminal IS NULL THEN
      ls_terminal := 'TERMINATED BY '',''';
    ELSIF Psi_fieldTerminal = '''' THEN

      ls_terminal := 'TERMINATED BY "''"';
    ELSE
      ls_terminal := 'TERMINATED BY ''' || Psi_fieldTerminal || '''';
    END IF;

    --获取系统时间戳，建立唯一临时外部表表名，用以多用户并发
    ls_table_squence := TO_CHAR(SYSTIMESTAMP, 'HH24MISSFF');
    --dbms_output.put_line(ls_table_squence);
    ls_ex_tablename := ls_ex_tablename || ls_table_squence;

    v_block := 'CREATE TABLE ' || ls_ex_tablename || CHR(10) || '(' ||
               ls_table_columns || '
       )
      ORGANIZATION EXTERNAL
     (
       TYPE ORACLE_LOADER
       DEFAULT DIRECTORY ' || v_dir || '
       ACCESS PARAMETERS
      (
        RECORDS DELIMITED BY ''\n''' || '
        SKIP ' || to_char(NVL(Pni_skipRecords, 0)) || ' ' || '
        DISABLE_DIRECTORY_LINK_CHECK' || '
        FIELDS ' || ls_terminal || ' ' || ls_enclosed ||
    -- added by huangxl, 20131026. Process when EXCEL CSV column-count not equal on all rows.
    ' MISSING FIELD VALUES ARE NULL' ||
    -- added by huangxl end.
               CHR(10) || '( ' || ls_table_col_ctl || CHR(10) || ')

      )
       LOCATION (''' || ls_file_name || ''')
     )reject limit unlimited';
    --------------------------MY_UT_DATA--------Psi_filePath-----------------20130726------------
    --dbms_output.put_line(v_block);
    EXECUTE IMMEDIATE v_block;

   -- EXECUTE IMMEDIATE 'DELETE FROM ' || ls_table_name;

    EXECUTE IMMEDIATE 'INSERT /*+ PARALLEL */ INTO ' || ls_table_name || ' SELECT * FROM ' || ' ' ||
                      ls_ex_tablename;

    EXECUTE IMMEDIATE 'DROP TABLE ' || ls_ex_tablename || ' PURGE';
    -- edit by huangxl, 20131012. 不再使用目录的动态创建和删除，由数据库管理员在最初时建立完成
    --pckg_utp_r_directory_util.utp_drop_directory(v_dir);
    -- edit by huangxl, 20131012.
  EXCEPTION
    WHEN OTHERS THEN
    -- edit by huangxl, 20131012. 异常情况下可能表并没有建立，此情况下不应异常。原先异常处理异常直接吃掉了，应该往外抛出。
      BEGIN
        EXECUTE IMMEDIATE 'DROP TABLE ' || ls_ex_tablename || ' PURGE';
        --pckg_utp_r_directory_util.utp_drop_directory(v_dir);
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
      RAISE;
    -- edit by huangxl, 20131012. end.
  END;


  PROCEDURE PROC_UTP_BIN_2TAB(Psi_tableName     IN VARCHAR2, -- 将要load数据的表名
                               Psi_fileNames     IN VARCHAR2, -- 文件名，多文件以逗号分隔
                               Psi_filePath      IN VARCHAR2, -- 文件所在的目录K路径
                               Psi_fieldTerminal IN VARCHAR2 DEFAULT ',', -- 文件中的字段分隔符,可以使用CHR(27)等其他分隔符
                               Psi_enclosed      IN VARCHAR2 DEFAULT '', --字段引用符
                               Psi_tableOwner    IN VARCHAR2 DEFAULT '', --load表的所属用户，默认为当前用户
                               Psi_dataFormat    IN VARCHAR2 DEFAULT 'YYYY-MM-DD HH24:MI:SS' --日期格式
                               )
  /******************************************************************************
        程序名称: PROC_UTP_BIN_2TAB
        模块名称: 数据文件导入到数据库指定表
        版本号：1.0.0
        创建日期：2013-07-17
        创建作者：持续集成研究小组 上海研发部
        发布类型：公开发布
        程序功能：执行自动测试脚本时将数据文件解析格式，导入到数据库表中
        处理逻辑：根据本次涉及的文件和表，将文件数据导入到指定表中
    ******************************************************************************/
   IS

    ls_column_name VARCHAR(500) := NULL;

    ls_table_name VARCHAR2(500) := upper(Psi_tableName);
    ls_file_name  VARCHAR2(500) := replace(replace(Psi_fileNames,
                                                  ',',
                                                  ''','''),
                                          ' ');
    ls_tableOwner VARCHAR2(300) := NULL;
    ls_dataFormat VARCHAR2(500) := NVL(Psi_dataFormat,
                                      'YYYY-MM-DD HH24:MI:SS');

    ls_enclosed VARCHAR2(2000) := NULL;
    ls_terminal VARCHAR2(2000) := NULL;

    ls_table_squence VARCHAR2(2000) := NULL;
    ls_ex_tablename  VARCHAR2(2000) := 'load_temp';

    ls_table_columns VARCHAR2(32767) := NULL;
    ls_table_col_ctl VARCHAR2(32767) := NULL; --FIELDS 里面文本数据格式化

    record_length    NUMBER(10) := 0; --BIN2TAB Special

    v_block          VARCHAR2(32767) := NULL;
    v_dot            NUMBER(3) := 0;
    --v_sql            VARCHAR2(2000) := NULL;
    --不再进行目录的每次创建，由数据库管理员统一创建完成20130927
    v_dir VARCHAR2(2000) :=  'LINK';
    --20130927 end

    CURSOR tab_col IS
      SELECT column_name,
             data_type,
             data_length,
             data_precision,
             data_scale,
             char_length
        FROM all_tab_columns
       WHERE (table_name = ls_table_name AND owner = ls_tableOwner)
          OR (OWNER || '.' || table_name = UPPER(ls_table_name))
       ORDER BY column_id;

  BEGIN
    SELECT INSTR(ls_table_name, '.') INTO v_dot FROM DUAL; ------20130722-----SH.SDC.ICBC.COM.CN
    ----CREATE OR REPLACE DIRECTORY MY_UT_DATA AS Psi_filePath---------20130726
    /*v_sql := ' GRANT READ, WRITE ON DIRECTORY MY_UT_DATA TO PUBLIC ';
      EXECUTE IMMEDIATE v_sql;
    */

    --不再进行目录的每次创建，由数据库管理员统一创建完成20130927
    --pckg_utp_r_directory_util.utp_create_directory(Psi_filePath, v_dir);
    --20130927 end

    IF Psi_tableOwner IS NULL THEN
      IF v_dot = 0 THEN
        ------20130722-----SH.SDC.ICBC.COM.CN -------START-----------
        SELECT SYS_CONTEXT('USERENV', 'SESSION_USER')
          INTO ls_tableOwner
          FROM DUAL;
      ELSE
        SELECT SUBSTR(upper(Psi_tableName), 1, v_dot - 1)
          INTO ls_tableOwner
          FROM DUAL;
          /*SELECT SUBSTR(upper(Psi_tableName),
                      v_dot + 1,
                      LENGTH(upper(Psi_tableName)))
          INTO ls_table_name
          FROM DUAL;*/
      END IF; ------20130722-----SH.SDC.ICBC.COM.CN --------END-------------
    ELSE
      ls_tableOwner := Psi_tableOwner;
    END IF;
    IF v_dot = 0 THEN
      ls_table_name := ls_tableOwner || '.' || ls_table_name;
    END IF;

    -----用于重建外部表字段 ls_table_columns--------------------------------------
    FOR cc IN tab_col LOOP
      --SELECT DECODE(cc.column_name, 'SCALE', 'X_SCALE', cc.column_name) INTO ls_column_name FROM dual;
      SELECT '"' || cc.column_name || '"' INTO ls_column_name FROM dual;
      IF cc.data_type = 'NUMBER' THEN
        IF cc.data_precision IS NOT NULL THEN
          ls_table_columns := ls_table_columns || ls_column_name ||
                              ' NUMBER(' || cc.data_precision || ',' ||
                              cc.data_scale || '),' || CHR(10);

          record_length := record_length + cc.data_precision;

          ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(' ||
                            cc.data_precision || '),' || CHR(10);

        ELSE
          ls_table_columns := ls_table_columns || ls_column_name ||
                              ' NUMBER,' || CHR(10);

                record_length := record_length + 8;

                ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(8),' ||
                              CHR(10);

        END IF;

      ELSIF cc.data_type in ('VARCHAR2', 'CHAR', 'NCHAR', 'NVARCHAR2') THEN
        ls_table_columns := ls_table_columns || ls_column_name || ' ' ||
                            cc.data_type || '(' || cc.char_length || '),' ||
                            CHR(10);

              record_length := record_length + cc.char_length;

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name || ' CHAR(' ||
                            cc.char_length || '),' || CHR(10);

      ELSIF cc.data_type = 'DATE' THEN
        ls_table_columns := ls_table_columns || ls_column_name || ' DATE,' ||
                            CHR(10);

        ls_table_col_ctl := ls_table_col_ctl || ls_column_name ||
                            ' CHAR date_format DATE mask "' ||
                            ls_dataFormat || '",' || CHR(10);

        record_length := record_length + 19;

      END IF;

    END LOOP;
    ls_table_columns := rtrim(rtrim(ls_table_columns, CHR(10)), ',');
    ls_table_col_ctl := rtrim(rtrim(ls_table_col_ctl, CHR(10)), ',');

    record_length := record_length + 1;

    --配置外部表参数
    IF Psi_enclosed IS NULL THEN
      ls_enclosed := '';
    ELSIF Psi_enclosed = '''' THEN
      ls_enclosed := 'OPTIONALLY ENCLOSED BY "''"';
    ELSE
      ls_enclosed := 'OPTIONALLY ENCLOSED BY ''' || Psi_enclosed || '''';
    END IF;

    IF Psi_fieldTerminal IS NULL THEN
      ls_terminal := 'TERMINATED BY '',''';
    ELSIF Psi_fieldTerminal = '''' THEN
      ls_terminal := 'TERMINATED BY "''"';
    ELSE
      ls_terminal := 'TERMINATED BY ''' || Psi_fieldTerminal || '''';
    END IF;

    --获取系统时间戳，建立唯一临时外部表表名，用以多用户并发
    ls_table_squence := TO_CHAR(SYSTIMESTAMP, 'HH24MISSFF');
    --dbms_output.put_line(ls_table_squence);
    ls_ex_tablename := ls_tableOwner || '.' || ls_ex_tablename || ls_table_squence;
    --ls_ex_tablename := ls_ex_tablename || ls_table_squence;


    v_block := 'CREATE TABLE ' || ls_ex_tablename || CHR(10) || '(' ||
               ls_table_columns || '
       )
      ORGANIZATION EXTERNAL
     (
       TYPE ORACLE_LOADER
       DEFAULT DIRECTORY ' || v_dir || '
       ACCESS PARAMETERS
      (
        RECORDS FIXED ' || record_length || '
        FIELDS ' || '(' || ls_table_col_ctl || CHR(10) || ')
      )
       LOCATION (''' || ls_file_name || ''')
     )';
    --------------------------MY_UT_DATA--------Psi_filePath-----------------20130726------------
    --dbms_output.put_line(v_block);
    EXECUTE IMMEDIATE v_block;

   -- EXECUTE IMMEDIATE 'DELETE FROM ' || ls_table_name;

    EXECUTE IMMEDIATE 'INSERT INTO ' || ls_table_name || ' SELECT * FROM ' || ' ' ||
                      ls_ex_tablename;

    EXECUTE IMMEDIATE 'DROP TABLE ' || ls_ex_tablename || ' PURGE';
    -- edit by huangxl, 20131012. 不再使用目录的动态创建和删除，由数据库管理员在最初时建立完成
    --pckg_utp_r_directory_util.utp_drop_directory(v_dir);
    -- edit by huangxl, 20131012.
  EXCEPTION
    WHEN OTHERS THEN
    -- edit by huangxl, 20131012. 异常情况下可能表并没有建立，此情况下不应异常。原先异常处理异常直接吃掉了，应该往外抛出。
      DBMS_OUTPUT.put_line(to_char(sqlerrm));
    -- edit by huangxl, 20131012. end.
  END;

PROCEDURE PROC_UTP_RANDOM_2TAB (
                                 Psi_tableName       IN VARCHAR2,                             -- 将要生成数据的表名
                                 Psi_tableOwner      IN VARCHAR2 DEFAULT '',            --表的所属用户，默认为当前用户
                                 Psi_SetStatement      IN VARCHAR2             --设置字段固定值的set语句部分
                                                                  )
/******************************************************************************
      程序名称: PROC_UTP_RANDOM_2TAB
      模块名称: 随机生成数据到数据库指定表
      版本号：1.0.0
      创建日期：2014-12-17
      创建作者：kfzx-zhougd
      发布类型：公开发布
      程序功能：
      处理逻辑：
  ******************************************************************************/
IS
   ls_column_name     VARCHAR (500) := NULL;

   ls_table_name      VARCHAR2 (500) := UPPER (Psi_tableName);

   ls_tableOwner      VARCHAR2 (300) := NULL;


   --ls_table_squence   VARCHAR2 (2000) := NULL;
   ls_ex_tablename    VARCHAR2 (2000) := UPPER (Psi_tableName);

   ls_table_columns   VARCHAR2 (32767) := NULL;         -- 字段信息
   ls_table_columns_Random   VARCHAR2 (32767) := NULL;      --字段信息对应的随机函数 或固定值
   ls_SetStatement   VARCHAR2 (32767) := NULL;      --设置字段固定值的set语句部分

   v_block            VARCHAR2 (32767) := NULL;
   v_dot              NUMBER (3) := 0;

   CURSOR tab_col
   IS
        SELECT column_name,
               data_type,
               data_precision,
               data_scale,
               char_length
          FROM all_tab_columns
         WHERE (table_name = UPPER(ls_table_name) AND owner = UPPER(ls_tableOwner))
               OR (OWNER || '.' || table_name = UPPER (ls_table_name))
      ORDER BY column_id;
BEGIN
   SELECT INSTR (ls_table_name, '.') INTO v_dot FROM DUAL;


   IF Psi_tableOwner IS NULL
   THEN
      IF v_dot = 0
      THEN
         ------20130722-----SH.SDC.ICBC.COM.CN -------START-----------
         SELECT SYS_CONTEXT ('USERENV', 'SESSION_USER')
           INTO ls_tableOwner
           FROM DUAL;
      ELSE
         SELECT SUBSTR (UPPER (Psi_tableName), 1, v_dot - 1)
           INTO ls_tableOwner
           FROM DUAL;

         SELECT SUBSTR (UPPER (Psi_tableName),
                        v_dot + 1,
                        LENGTH (UPPER (Psi_tableName)))
           INTO ls_table_name
           FROM DUAL;
      END IF;   ------20130722-----SH.SDC.ICBC.COM.CN --------END-------------
   ELSE
      ls_tableOwner := Psi_tableOwner;
   END IF;

   -----用于重建外部表字段 ls_table_columns--------------------------------------
   FOR cc IN tab_col
   LOOP
      SELECT '"' || cc.column_name || '"' INTO ls_column_name FROM dual;

      IF cc.data_type = 'NUMBER'
      THEN
         IF cc.data_precision IS NOT NULL
         THEN
            ls_table_columns :=
                  ls_table_columns
               || ls_column_name
               || ','
               || CHR (10);
               ls_table_columns_Random:=ls_table_columns_Random||' DBMS_RANDOM.VALUE(0,power(10,'||to_char(cc.data_precision-cc.data_scale) ||'))  ,'|| CHR (10);
         ELSE
            ls_table_columns :=
               ls_table_columns || ls_column_name || ',' || CHR (10);
               ls_table_columns_Random:=ls_table_columns_Random||' DBMS_RANDOM.VALUE(0,power(10,38)) ,'|| CHR (10);
         END IF;


      ELSIF cc.data_type IN ('VARCHAR2', 'CHAR', 'NCHAR', 'NVARCHAR2')
      THEN
         ls_table_columns :=
               ls_table_columns
            || ls_column_name
            || ','
            || CHR (10);

       ls_table_columns_Random:=ls_table_columns_Random||' DBMS_RANDOM.STRING('||'''x'''||','||to_CHAR(cc.char_length) ||') ,'|| CHR (10);


      ELSIF cc.data_type = 'DATE'
      THEN
         ls_table_columns :=
            ls_table_columns || ls_column_name || ','|| CHR (10);
               ls_table_columns_Random:=ls_table_columns_Random||' sysdate ,'|| CHR (10);

      ELSIF cc.data_type = 'TIMESTAMP(6)'
      THEN
         ls_table_columns :=
            ls_table_columns || ls_column_name || CHR (10);
               ls_table_columns_Random:=ls_table_columns_Random||' sysdate ,'|| CHR (10);

      ELSE     -- 其他字段类型默认字符 1
         ls_table_columns :=
               ls_table_columns
            || ls_column_name
            || ','
            || CHR (10);
                           ls_table_columns_Random:=ls_table_columns_Random||'''1'','|| CHR (10);


      END IF;
   END LOOP;

   ls_table_columns := RTRIM (RTRIM (ls_table_columns, CHR (10)), ',');
      ls_table_columns_Random := RTRIM (RTRIM (ls_table_columns_Random, CHR (10)), ',');


   --获取系统时间戳
   --ls_table_squence := TO_CHAR (SYSTIMESTAMP, 'HH24MISSFF');
   --dbms_output.put_line(ls_table_squence);
   --ls_ex_tablename := ls_ex_tablename || ls_table_squence;

   v_block :=
         'insert into '
      || ls_tableOwner
      ||'.'
      || ls_ex_tablename
      || CHR (10)
      || '('
      || ls_table_columns
      || '
       )
      '|| ' select ' ||ls_table_columns_Random || ' from dual connect by level <'||to_char( DBMS_RANDOM.VALUE(1,20));


   dbms_output.put_line(v_block);
   EXECUTE IMMEDIATE v_block;
   commit;
   if Psi_SetStatement is not null   then              --执行update 语句
                      ls_SetStatement:='update '||ls_tableOwner||'.'|| ls_table_name  || ' set '||Psi_SetStatement;
                       dbms_output.put_line(ls_SetStatement);
                       EXECUTE IMMEDIATE ls_SetStatement;
                       commit;
   end if;
   -- EXECUTE IMMEDIATE 'DELETE FROM ' || ls_table_name;

 --  EXECUTE IMMEDIATE   'INSERT /*+ PARALLEL */ INTO '
  --                  || ls_table_name
   --                 || ' SELECT * FROM '
    --                || ' '
      --              || ls_ex_tablename;

   --EXECUTE IMMEDIATE 'DROP TABLE ' || ls_ex_tablename || ' PURGE';
EXCEPTION
   WHEN OTHERS
   THEN
      BEGIN
         rollback;
      EXCEPTION
         WHEN OTHERS
         THEN
            NULL;
      END;

      RAISE;
END PROC_UTP_RANDOM_2TAB;

  /******************************************************************************************************************/
  --程序名称  proc_utp_tab_create_forcursor
  --程序功能  建立以i_createtablename为表名的表，其中内含i_columncount个VARCHAR2(4000)长度的字段
  --作者      kfzx-huangxl
  --日期      2013-10-14
  /******************************************************************************************************************/
  PROCEDURE proc_utp_tab_create_forcursor(i_createtablename IN VARCHAR2, -- 待创建的表名
                                          i_columncount     IN NUMBER -- 待创建的表列数
                                          ) IS
    v_block VARCHAR2(32767) := NULL;
  BEGIN
    v_block := 'CREATE TABLE ' || i_createtablename || chr(10) || '(';
    FOR i IN 1 .. i_columncount LOOP
      v_block := v_block || (CASE WHEN i > 1 THEN ', ' END) || 'col' || i || ' VARCHAR2(4000)';
    END LOOP;
    v_block := v_block || ')';
    EXECUTE IMMEDIATE v_block;
  END;

  /******************************************************************************************************************/
  --程序名称  proc_utp_tab_drop_forcursor
  --程序功能  删除i_droptablename为表名的表
  --作者      kfzx-huangxl
  --日期      2013-10-14
  /******************************************************************************************************************/
  PROCEDURE proc_utp_tab_drop_forcursor(i_droptablename IN VARCHAR2 -- 待删除的表名
                                        ) IS
  BEGIN
    EXECUTE IMMEDIATE 'DROP TABLE ' || i_droptablename;
  END;

  /******************************************************************************************************************/
  --程序名称  proc_delete_utptemp
  --程序功能  删除所有utplugin、utplsql留下的临时表
  --作者      kfzx-huangxl
  --日期      2013-10-17
  /******************************************************************************************************************/
  PROCEDURE proc_delete_utptemp IS
    vs_sql VARCHAR2(500);
  BEGIN
    FOR x IN (SELECT t.table_name
                FROM user_tables t
               WHERE t.table_name LIKE '%\_B$' ESCAPE chr(92)
                  OR t.table_name LIKE '%\_E$' ESCAPE chr(92)
                  OR t.table_name LIKE 'UTPLSQL\_TEMP\_%' ESCAPE chr(92)) LOOP
      --删除临时表
      vs_sql := 'DROP TABLE ' || x.table_name || ' PURGE';
      EXECUTE IMMEDIATE vs_sql;
    END LOOP;
  END;

  /******************************************************************************
      程序名称: PROC_BIG_TAB_BACKUP
      模块名称: 数据准备--大表备份
      版本号：1.0.0
      创建日期：2015-01-05
      创建作者：kfzx-jianghui01
      程序功能：执行自动测试脚本前将原环境中表进行备份
      处理逻辑：根据参数，通过重命名逻辑模拟表备份逻辑，提升大表处理效率
  ******************************************************************************/

  PROCEDURE PROC_BIG_TAB_BACKUP (TABLE_PRE IN VARCHAR2,
                                 TABLE_FLG IN VARCHAR2 DEFAULT '_B$') IS
    tab_count NUMBER(10);
    tab_exist EXCEPTION;
    os_msg    VARCHAR2(100);
    v_backup_sql VARCHAR2(1000);
    v_empty_sql  VARCHAR2(1000);
    table_name   VARCHAR2(100) := UPPER(TABLE_PRE);
    backup_table_name VARCHAR2(1000) := UPPER(table_name) || NVL(TABLE_FLG, '_B$');
    tmp_backup_table_name VARCHAR2(100);
    v_dot NUMBER(2);
  BEGIN
    -----判断这些待备份的表是否有已存在备份表的情况,REPLACE(TABLE_PRE,' ','')进行去空格处理
    -----判断这些待备份的表是否有已存在备份表的情况,REPLACE(TABLE_PRE,' ','')进行去空格处理
    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(table_name, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(table_name, ' ', '')) -
                               LENGTH(REPLACE(REPLACE(table_name, ' ', ''),
                                              ',',
                                              '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(table_name , ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(table_name, ' ', '')) -
                               LENGTH(REPLACE(REPLACE(table_name, ' ', ''), ',', '')) + 1));

    SELECT INSTR(table_name, '.') INTO v_dot FROM DUAL;
    -- 将备份表名去模式以用于ALTER TABLE
    -- 否则报错 OBE-14047: ALTER TABLE|INDEX RENAME 不能与其他分区组合
    IF v_dot > 0 THEN
      tmp_backup_table_name := SUBSTR(backup_table_name, v_dot + 1);
    END IF;

    IF tab_count = 0 THEN
      -- 待备份表重命名为备份表名
      v_backup_sql := 'ALTER TABLE ' || table_name || ' RENAME TO ' || tmp_backup_table_name;
      EXECUTE IMMEDIATE v_backup_sql;
      -- 以待备份表名创建新表
      v_empty_sql := 'CREATE TABLE ' || table_name || ' AS SELECT * FROM ' || backup_table_name || ' WHERE 1=2';
      EXECUTE IMMEDIATE v_empty_sql;
    ELSE
      RAISE tab_exist;
    END IF;
  EXCEPTION
    WHEN tab_exist THEN
      DBMS_OUTPUT.put_line('临时表名已存在于环境上,请检查!');
    WHEN OTHERS THEN
      os_msg := '备份表' || TABLE_PRE || '出错,出错原因是:' || to_char(sqlerrm);
      DBMS_OUTPUT.put_line(os_msg);
  END;

   /******************************************************************************
      程序名称: PROC_BIG_TAB_RESTORE
      模块名称: 数据准备--大表恢复
      版本号：1.0.0
      创建日期：2015-01-05
      创建作者：kfzx-jianghui01
      程序功能：执行自动测试脚本后将原先备份的表进行恢复
      处理逻辑：根据参数，通过重命名逻辑模拟表恢复逻辑，提升大表处理效率
  ******************************************************************************/

  PROCEDURE PROC_BIG_TAB_RESTORE (TABLE_PRE IN VARCHAR2,
                                  TABLE_FLG IN VARCHAR2 DEFAULT '_B$') IS
    tab_count         NUMBER(10);
    tab_noexist       EXCEPTION;
    os_msg            VARCHAR2(100);
    v_restore_sql     VARCHAR2(1000);
    v_drop_sql        VARCHAR2(1000);
    table_name        VARCHAR2(100) := UPPER(TABLE_PRE);
    tmp_table_name    VARCHAR2(100);
    backup_table_name VARCHAR2(1000) := table_name || NVL(TABLE_FLG, '_B$');
    v_dot NUMBER(2);
  BEGIN
    SELECT COUNT(*)
      INTO tab_count
      FROM all_tables
     WHERE table_name IN
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(table_name, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(table_name, ' ', '')) -
                               LENGTH(REPLACE(table_name, ',', '')) + 1))
        OR OWNER || '.' || table_name IN ----可能有前缀模式名
           (SELECT table_name || NVL(TABLE_FLG,'_B$') AS table_name
              FROM (SELECT TRIM(SUBSTR(txt,
                                       INSTR(txt, ',', 1, LEVEL) + 1,
                                       INSTR(txt, ',', 1, LEVEL + 1) -
                                       INSTR(txt, ',', 1, LEVEL) - 1)) AS table_name
                      FROM (SELECT ',' || REPLACE(table_name, ' ', '') || ',' txt
                              FROM DUAL)
                    CONNECT BY LEVEL <=
                               LENGTH(REPLACE(table_name, ' ', '')) -
                               LENGTH(REPLACE(table_name, ',', '')) + 1));

    backup_table_name := UPPER(backup_table_name);
    SELECT INSTR(table_name, '.') INTO v_dot FROM DUAL;
    IF v_dot > 0 THEN
      -- 将原表名去模式以用于ALTER TABLE
      -- 否则报错 OBE-14047: ALTER TABLE|INDEX RENAME 不能与其他分区组合
      tmp_table_name := SUBSTR(table_name, v_dot + 1);
    END IF;

    IF tab_count <> 0 THEN
      v_drop_sql := 'DROP TABLE ' || table_name;
      EXECUTE IMMEDIATE v_drop_sql;
      v_restore_sql := 'ALTER TABLE ' || backup_table_name || ' RENAME TO ' || tmp_table_name;
      EXECUTE IMMEDIATE v_restore_sql;
    ELSE
      RAISE tab_noexist;
    END IF;

    EXCEPTION
      WHEN tab_noexist THEN
        DBMS_OUTPUT.put_line('待清理的备份表名已不存在,请检查!');
      WHEN OTHERS THEN
        os_msg := '恢复表' || TABLE_PRE || '出错,出错原因是:' || to_char(sqlerrm);
        DBMS_OUTPUT.put_line(os_msg);
  END;

END PCKG_UTP_R_TOOLKIT;
